-- Add contextual HSK6 examples without overwriting user-edited content.
with hsk6_example_backfill (
  chinese,
  example_cn,
  example_pinyin,
  example_vi
) as (
  values
  ('暧昧', '他们之间的关系一直暧昧不清，让人难以捉摸。', 'Tāmen zhī jiān de guānxì yīzhí àimèi bù qīng, ràng rén nányǐ zhuōmō.', 'Mối quan hệ giữa họ luôn mập mờ khó hiểu, khiến người ta không thể đoán được.'),
  ('爱戴', '老师深受同学们的爱戴和尊敬。', 'Lǎoshī shēn shòu tóngxuémen de àidài hé zūnjìng.', 'Thầy giáo rất được các học sinh yêu thương và kính trọng.'),
  ('癌症', '早期发现癌症可以大大提高治愈率。', 'Zǎoqī fāxiàn áizhèng kěyǐ dàdà tígāo zhìyù lǜ.', 'Phát hiện ung thư sớm có thể tăng đáng kể tỷ lệ chữa khỏi.'),
  ('挨', '我们挨着墙站着，等待老师的指示。', 'Wǒmen āizhe qiáng zhàn zhe, děngdài lǎoshī de zhǐshì.', 'Chúng tôi đứng sát vào tường, chờ chỉ thị của thầy cô.'),
  ('爱不释手', '这本书内容精彩，我看得爱不释手。', 'Zhè běn shū nèiróng jīngcǎi, wǒ kàn dé ài bù shì shǒu.', 'Cuốn sách này rất hay, tôi đọc mê mải không muốn rời tay.'),
  ('安置', '政府为地震受灾群众安置了临时住所。', 'Zhèngfǔ wèi dìzhèn shòuzāi qúnzhòng ānzhì le línshí zhùsuǒ.', 'Chính phủ đã bố trí nơi ở tạm thời cho người dân bị ảnh hưởng bởi động đất.'),
  ('案件', '法院正在审理一起复杂的经济案件。', 'Fǎyuàn zhèngzài shěnlǐ yīqǐ fùzá de jīngjì ànjiàn.', 'Tòa án đang xét xử một vụ án kinh tế phức tạp.'),
  ('案例', '律师引用了多个成功的案例来支持他的观点。', 'Lǜshī yǐnyòng le duō gè chénggōng de ànlì lái zhīchí tā de guāndiǎn.', 'Luật sư đã trích dẫn nhiều án mẫu thành công để ủng hộ quan điểm của mình.'),
  ('按摩', '我每天晚上都会给自己做简单的按摩放松身体。', 'Wǒ měitiān wǎnshàng dōu huì gěi zìjǐ zuò jiǎndān de ànmó fàngsōng shēntǐ.', 'Tôi mỗi tối đều xoa bóp đơn giản cho bản thân để thư giãn cơ thể.'),
  ('暗示', '他的言语中暗示了对这件事的不满。', 'Tā de yányǔ zhōng ànshì le duì zhè jiàn shì de bùmǎn.', 'Lời nói của anh ta đã ám chỉ sự không hài lòng về chuyện này.'),
  ('安宁', '老人希望在家乡度过一个安宁的晚年。', 'Lǎorén xīwàng zài jiāxiāng dùguò yī gè ānníng de wǎnnián.', 'Người già hy vọng trải qua một tuổi già yên ổn ở quê nhà.'),
  ('熬', '他为了考试熬夜复习，非常辛苦。', 'Tā wèile kǎoshì áoyè fùxí, fēicháng xīnkǔ.', 'Anh ấy rất vất vả khi thức suốt đêm để ôn thi.'),
  ('奥秘', '科学家们一直在探索宇宙的奥秘。', 'Kēxuéjiā men yīzhí zài tànsuǒ yǔzhòu de àomì.', 'Các nhà khoa học luôn khám phá những huyền bí của vũ trụ.'),
  ('凹凸', '这条路因为多年破损，出现了许多凹凸不平的地方。', 'Zhè tiáo lù yīnwèi duōnián pòsǔn, chūxiàn le xǔduō āotū bùpíng de dìfāng.', 'Con đường này do hư hỏng nhiều năm đã xuất hiện nhiều chỗ lồi lõm không bằng phẳng.'),
  ('安详', '他的面容安详，看起来非常平静和满足。', 'Tā de miànróng ānxiáng, kàn qǐlái fēicháng píngjìng hé mǎnzú.', 'Khuôn mặt ông ấy ung dung, trông rất bình thản và hài lòng.'),
  ('昂贵', '这款手表的价格非常昂贵，只有少数人能买得起。', 'Zhè kuǎn shǒubiǎo de jiàgé fēicháng ángguì, zhǐyǒu shǎoshù rén néng mǎi dé qǐ.', 'Chiếc đồng hồ này có giá rất đắt đỏ, chỉ có vài người có thể mua được.'),
  ('颁布', '政府近日颁布了新的环境保护法规。', 'Zhèngfǔ jìnrì bānbù le xīn de huánjìng bǎohù fǎguī.', 'Chính phủ vừa ban hành luật bảo vệ môi trường mới.'),
  ('霸道', '他的管理方式太霸道，导致员工流失严重。', 'Tā de guǎnlǐ fāngshì tài bàdào, dǎozhì yuángōng liúshī yánzhòng.', 'Phương pháp quản lý của anh ta quá độc đoán, khiến nhân viên bỏ việc nhiều.'),
  ('败坏', '腐败行为严重败坏了公司的声誉。', 'Fǔbài xíngwéi yánzhòng bàihuài le gōngsī de shēngyù.', 'Hành vi tham nhũng nghiêm trọng làm hủy hoại danh tiếng công ty.'),
  ('罢工', '工人们因待遇问题决定举行罢工。', 'Gōngrén men yīn dàiyù wèntí juédìng jǔxíng bàgōng.', 'Các công nhân quyết định tổ chức bãi công vì vấn đề tiền lương.'),
  ('疤', '手臂上的疤是小时候摔伤留下的。', 'Shǒubì shàng de bā shì xiǎoshíhòu shuāi shāng liú xià de.', 'Vết sẹo trên cánh tay là do bị thương khi còn nhỏ để lại.'),
  ('摆脱', '她努力工作，终于摆脱了贫困的生活。', 'Tā nǔlì gōngzuò, zhōngyú bǎituō le pínkùn de shēnghuó.', 'Cô ấy làm việc chăm chỉ cuối cùng đã thoát khỏi cuộc sống nghèo khó.'),
  ('掰', '他用力掰断了那根树枝。', 'Tā yòng lì bāi duàn le nà gēn shùzhī.', 'Anh ấy dùng sức bẻ gãy cành cây đó.'),
  ('拜访', '我们明天计划去拜访老师，讨论毕业论文。', 'Wǒmen míngtiān jìhuà qù bàifǎng lǎoshī, tǎolùn bìyè lùnwén.', 'Chúng tôi dự định ngày mai đến thăm thầy giáo, thảo luận về luận văn tốt nghiệp.'),
  ('拜托', '我拜托朋友帮我照顾宠物几天。', 'Wǒ bàituō péngyǒu bāng wǒ zhàogù chǒngwù jǐ tiān.', 'Tôi nhờ bạn giúp chăm sóc thú cưng cho vài ngày.'),
  ('拜年', '春节的时候，我们都会去亲戚家拜年。', 'Chūnjié de shíhòu, wǒmen dōu huì qù qīnqì jiā bàinián.', 'Vào dịp Tết, chúng tôi đều đến nhà họ hàng chúc Tết.'),
  ('拔苗助长', '父母不应该拔苗助长，而应耐心等待孩子成长。', 'Fùmǔ bù yīnggāi bámiáo zhù zhǎng, ér yīng nàixīn děngdài háizi chéngzhǎng.', 'Cha mẹ không nên giục tốc bất đạt mà nên kiên nhẫn chờ đợi con trưởng thành.'),
  ('把手', '这个门的把手坏了，我们需要修理。', 'Zhège mén de bǎshǒu huài le, wǒmen xūyào xiūlǐ.', 'Tay nắm cửa này hỏng rồi, chúng ta cần sửa chữa.'),
  ('把关', '质量部门严格把关，确保产品达标。', 'Zhìliàng bùmén yángé bǎguān, quèbǎo chǎnpǐn dábiao.', 'Phòng chất lượng kiểm soát chặt chẽ, đảm bảo sản phẩm đạt tiêu chuẩn.'),
  ('扒', '他的手扒住栏杆，防止摔倒。', 'Tā de shǒu bā zhù lánggǎn, fángzhǐ shuāidǎo.', 'Tay anh ta nắm chặt tay vịn để tránh ngã.'),
  ('巴结', '他经常巴结领导，希望得到提拔。', 'Tā jīngcháng bājie lǐngdǎo, xīwàng dédào tíbá.', 'Anh ấy thường xuyên nịnh bợ lãnh đạo, hy vọng được thăng tiến.'),
  ('巴不得', '我巴不得马上去旅行，放松一下心情。', 'Wǒ bābùdé mǎshàng qù lǚxíng, fàngsōng yíxià xīnqíng.', 'Tôi rất mong được đi du lịch ngay lập tức để thư giãn.'),
  ('颁发', '学校将颁发奖学金给表现优秀的学生。', 'Xuéxiào jiāng bānfā jiǎngxuéjīn gěi biǎoxiàn yōuxiù de xuéshēng.', 'Trường sẽ trao tặng học bổng cho những học sinh có thành tích xuất sắc.'),
  ('绑架', '警方成功解救了一名被绑架的人质。', 'Jǐngfāng chénggōng jiějiù le yī míng bèi bǎngjià de rénzhì.', 'Cảnh sát đã giải cứu thành công một con tin bị bắt cóc.'),
  ('磅', '这箱水果重达二十磅，非常沉。', 'Zhè xiāng shuǐguǒ zhòng dá èrshí bàng, fēicháng chén.', 'Thùng trái cây này nặng tới hai mươi pound, rất nặng.'),
  ('版本', '这个软件的最新版本已经发布，可以免费下载。', 'Zhège ruǎnjiàn de zuìxīn bǎnběn yǐjīng fābù, kěyǐ miǎnfèi xiàzài.', 'Phiên bản mới nhất của phần mềm này đã được phát hành, có thể tải về miễn phí.'),
  ('榜样', '老师是学生们学习的榜样，激励他们不断进步。', 'Lǎoshī shì xuéshēngmen xuéxí de bǎngyàng, jīlì tāmen búduàn jìnbù.', 'Giáo viên là tấm gương học tập của học sinh, khích lệ họ không ngừng tiến bộ.'),
  ('斑', '这只动物的皮毛上有特别的斑点，很有特色。', 'Zhè zhī dòngwù de pímáo shàng yǒu tèbié de bāndiǎn, hěn yǒu tèsè.', 'Chú động vật này có những vết đốm đặc biệt trên lông rất đặc trưng.'),
  ('扮演', '她在话剧中扮演了一个勇敢的女主角。', 'Tā zài huàjù zhōng bànyǎn le yī gè yǒnggǎn de nǚ zhǔjiǎo.', 'Cô ấy đóng vai nữ chính dũng cảm trong vở kịch.'),
  ('半途而废', '学习语言需要坚持，不能半途而废。', 'Xuéxí yǔyán xūyào jiānchí, bùnéng bàntú ér fèi.', 'Học ngôn ngữ cần kiên trì, không thể bỏ cuộc giữa chừng.'),
  ('包装', '这款产品的包装设计非常精美，吸引了很多顾客购买。', 'Zhè kuǎn chǎnpǐn de bāozhuāng shèjì fēicháng jīngměi, xīyǐnle hěn duō gùkè gòumǎi.', 'Thiết kế bao bì của sản phẩm này rất tinh tế, thu hút nhiều khách hàng mua.'),
  ('包袱', '他背着沉重的包袱，艰难地走过了崎岖的山路。', 'Tā bēizhe chénzhòng de bāofu, jiānnán de zǒuguo qiūqū de shānlù.', 'Anh ấy đeo chiếc túi nặng trĩu, khó nhọc đi qua con đường núi hiểm trở.'),
  ('包庇', '警方发现有人包庇犯罪分子，正在展开调查。', 'Jǐngfāng fāxiàn yǒu rén bāobì fànzuì fènzǐ, zhèngzài zhǎnkāi diàochá.', 'Cảnh sát phát hiện có người bao che cho tội phạm, đang tiến hành điều tra.'),
  ('包围', '敌军用重兵包围了这座山谷，切断了所有的援军通路。', 'Díjūn yòng zhòng bīng bāowéi le zhè zuò shāngǔ, qiēduàn le suǒyǒu de yuánjūn tōnglù.', 'Địch quân dùng quân số đông bao vây thung lũng này, cắt đứt mọi đường tiếp viện.'),
  ('伴随', '技术的进步伴随了社会的快速发展和生活质量的提高。', 'Jìshù de jìnbù bàn suí le shèhuì de kuàisù fāzhǎn hé shēnghuó zhìliàng de tígāo.', 'Sự tiến bộ của công nghệ đồng hành cùng với sự phát triển nhanh chóng của xã hội và cải thiện chất lượng cuộc sống.'),
  ('伴侣', '他们经历了多年风雨，依然是彼此最坚强的伴侣。', 'Tāmen jīnglì le duō nián fēngyǔ, yīrán shì bǐcǐ zuì jiānqiáng de bànlǚ.', 'Họ trải qua nhiều năm thăng trầm, vẫn là những bạn đời vững chắc của nhau.'),
  ('饱和', '这个市场已经达到饱和状态，新产品很难找到突破口。', 'Zhège shìchǎng yǐjīng dádào bǎohé zhuàngtài, xīn chǎnpǐn hěn nán zhǎodào tūpò kǒu.', 'Thị trường này đã đạt tới trạng thái bão hòa, sản phẩm mới rất khó tìm được điểm đột phá.'),
  ('饱经沧桑', '老艺术家饱经沧桑，他的作品充满了人生阅历。', 'Lǎo yìshùjiā bǎojīng cāngsāng, tā de zuòpǐn chōngmǎn le rénshēng yuèlì.', 'Nghệ sĩ già trải qua bao thăng trầm, tác phẩm của ông đầy ắp kinh nghiệm sống.'),
  ('保管', '请您把重要文件交给专门的人员保管，避免遗失。', 'Qǐng nín bǎ zhòngyào wénjiàn jiāo gěi zhuānmén de rényuán bǎoguǎn, bìmiǎn yíshī.', 'Xin vui lòng giao tài liệu quan trọng cho nhân viên chuyên trách bảo quản, tránh bị mất.'),
  ('保密', '公司要求员工对客户信息严格保密，不能泄露任何细节。', 'Gōngsī yāoqiú yuángōng duì kèhù xìnxī yángé bǎomì, bù néng xièlòu rènhé xìjié.', 'Công ty yêu cầu nhân viên giữ bí mật nghiêm ngặt về thông tin khách hàng, không được tiết lộ bất kỳ chi tiết nào.'),
  ('保姆', '由于工作繁忙，他们雇了一位经验丰富的保姆照顾孩子。', 'Yóuyú gōngzuò fánmáng, tāmen gù le yī wèi jīngyàn fēngfù de bǎomǔ zhàogù háizi.', 'Vì công việc bận rộn, họ thuê một bảo mẫu có kinh nghiệm để chăm sóc con cái.'),
  ('保守', '他的想法比较保守，不太愿意接受新事物和变化。', 'Tā de xiǎngfǎ bǐjiào bǎoshǒu, bù tài yuànyì jiēshòu xīn shìwù hé biànhuà.', 'Ý tưởng của anh ấy khá bảo thủ, không mấy sẵn lòng tiếp nhận những điều mới và sự thay đổi.'),
  ('保卫', '军队肩负着保卫国家安全的重要使命。', 'Jūnduì jiānfù zhe bǎowèi guójiā ānquán de zhòngyào shǐmìng.', 'Quân đội đảm nhận trọng trách bảo vệ an ninh quốc gia.'),
  ('保养', '为了延长汽车的使用寿命，车主定期进行保养。', 'Wèile yáncháng qìchē de shǐyòng shòumìng, chēzhǔ dìngqí jìnxíng bǎoyǎng.', 'Để kéo dài tuổi thọ của ô tô, chủ xe định kỳ bảo dưỡng.'),
  ('保障', '政府出台新政策，保障低收入群体的基本生活需求。', 'Zhèngfǔ chūtái xīn zhèngcè, bǎozhàng dī shōurù qúntǐ de jīběn shēnghuó xūqiú.', 'Chính phủ ban hành chính sách mới để bảo vệ nhu cầu sinh hoạt cơ bản của nhóm thu nhập thấp.'),
  ('保重', '临别时，她叮嘱我多保重身体，不要太劳累。', 'Língbié shí, tā dīngzhǔ wǒ duō bǎozhòng shēntǐ, bù yào tài láolèi.', 'Khi chia tay, cô ấy dặn dò tôi phải bảo trọng sức khoẻ, đừng quá mệt mỏi.'),
  ('报仇', '他立志要为家人报仇，揭露那个犯罪集团的罪行。', 'Tā lìzhì yào wèi jiārén bàochóu, jiēlù nàgè fànzuì jítuán de zuìxíng.', 'Anh ấy quyết tâm báo thù cho gia đình, phơi bày tội ác của băng nhóm tội phạm đó.'),
  ('报酬', '这份工作虽然辛苦，但报酬丰厚值得付出努力。', 'Zhè fèn gōngzuò suīrán xīnkǔ, dàn bàochóu fēnghòu zhídé fùchū nǔlì.', 'Công việc này tuy vất vả nhưng thù lao hậu hĩnh đáng để cố gắng.'),
  ('报答', '我永远不会忘记父母的养育之恩，努力工作以报答他们。', 'Wǒ yǒngyuǎn bù huì wàngjì fùmǔ de yǎngyù zhī ēn, nǔlì gōngzuò yǐ bàodá tāmen.', 'Tôi sẽ không bao giờ quên ơn dưỡng dục của cha mẹ, cố gắng làm việc để trả ơn họ.'),
  ('报复', '他选择以理智面对困难，而不是盲目地报复对方。', 'Tā xuǎnzé yǐ lǐzhì miànduì kùnnán, ér bú shì mángmù de bàofù duìfāng.', 'Anh ấy chọn cách đối mặt khó khăn bằng lý trí, thay vì mù quáng báo thù đối phương.'),
  ('报警', '遇到紧急情况时应该立即报警求助。', 'Yù dào jǐn jí qíng kuàng shí yīng gāi lì jí bào jǐng qiú zhù.', 'Khi gặp tình huống khẩn cấp, nên lập tức báo cảnh sát nhờ giúp đỡ.'),
  ('报销', '出差的交通费可以向公司申请报销。', 'Chū chāi de jiāo tōng fèi kě yǐ xiàng gōng sī shēn qǐng bào xiāo.', 'Chi phí đi lại khi công tác có thể đề nghị công ty thanh toán chi phí.'),
  ('抱负', '年轻人应该有远大的抱负和理想。', 'Nián qīng rén yīng gāi yǒu yuǎn dà de bào fù hé lǐ xiǎng.', 'Người trẻ nên có hoài bão và lý tưởng lớn lao.'),
  ('暴力', '任何形式的暴力行为都应该被制止。', 'Rèn hé xíng shì de bào lì xíng wéi dōu yīng gāi bèi zhì zhǐ.', 'Mọi hình thức hành vi bạo lực đều nên bị ngăn chặn.'),
  ('暴露', '他的秘密终于在会议上暴露无遗。', 'Tā de mì mì zhōng yú zài huì yì shàng bào lù wú yí.', 'Bí mật của anh ta cuối cùng đã lộ rõ tại cuộc họp.'),
  ('曝光', '媒体曝光了这起公司的贪污丑闻。', 'Méi tǐ bào guāng le zhè qǐ gōng sī de tān wū chǒu wén.', 'Truyền thông đã phơi bày vụ bê bối tham nhũng của công ty này.'),
  ('爆发', '战争在边境地区突然爆发，局势紧张。', 'Zhàn zhēng zài biān jìng dì qū tū rán bào fā, jú shì jǐn zhāng.', 'Chiến tranh bùng nổ đột ngột ở khu vực biên giới, tình hình căng thẳng.'),
  ('爆炸', '工厂里的爆炸造成了严重的人员伤亡。', 'Gōng chǎng lǐ de bào zhà zào chéng le yán zhòng de rén yuán shāng wáng.', 'Vụ nổ trong nhà máy đã gây thương vong nghiêm trọng về người.'),
  ('贝壳', '海滩上散落着各种颜色的贝壳。', 'Hǎi tān shàng sàn luò zhe gè zhǒng yán sè de bèi ké.', 'Trên bãi biển rải rác những vỏ sò đủ màu sắc.'),
  ('被告', '法庭上被告坚决否认所有指控。', 'Fǎ tíng shàng bèi gào jiān jué fǒu rèn suǒ yǒu zhǐ kòng.', 'Bị cáo tại tòa kiên quyết phủ nhận tất cả các cáo buộc.'),
  ('被动', '在学习过程中，学生不能总是被动接受知识。', 'Zài xué xí guò chéng zhōng, xué shēng bù néng zǒng shì bèi dòng jiē shòu zhī shí.', 'Trong quá trình học, học sinh không thể lúc nào cũng bị động tiếp thu kiến thức.'),
  ('背诵', '老师要求学生每天背诵古诗以提高记忆力。', 'Lǎo shī yāo qiú xué shēng měi tiān bèi sòng gǔ shī yǐ tí gāo jì yì lì.', 'Giáo viên yêu cầu học sinh hàng ngày đọc thuộc thơ cổ để cải thiện trí nhớ.'),
  ('背叛', '他因背叛朋友而失去了所有信任。', 'Tā yīn bèi pàn péng you ér shī qù le suǒ yǒu xìn rèn.', 'Anh ta vì phản bội bạn bè mà mất hết niềm tin.'),
  ('本钱', '创业需要一定的本钱作为启动资金。', 'Chuàng yè xū yào yí dìng de běn qián zuò wèi qǐ dòng zī jīn.', 'Khởi nghiệp cần có một số tiền vốn nhất định làm vốn khởi động.'),
  ('本能', '面对危险，动物会本能地逃跑保护自己。', 'Miàn duì wēi xiǎn, dòng wù huì běn néng de táo pǎo bǎo hù zì jǐ.', 'Đối mặt với nguy hiểm, động vật sẽ bản năng chạy trốn để bảo vệ mình.'),
  ('悲惨', '战争带来了许多悲惨的故事和苦难。', 'Zhàn zhēng dài lái le xǔ duō bēi cǎn de gù shi hé kǔ nàn.', 'Chiến tranh đã mang đến nhiều câu chuyện bi thảm và đau khổ.'),
  ('悲哀', '听到亲人去世的消息，她感到非常悲哀。', 'Tīng dào qīn rén qù shì de xiāo xī, tā gǎn dào fēi cháng bēi āi.', 'Khi nghe tin người thân qua đời, cô ấy cảm thấy rất đau lòng.'),
  ('奔驰', '这辆跑车在高速公路上奔驰，非常抢眼。', 'Zhè liàng pǎo chē zài gāo sù gōng lù shàng bēn chí, fēi cháng qiǎng yǎn.', 'Chiếc xe thể thao này chạy băng băng trên đường cao tốc rất nổi bật.'),
  ('奔波', '他为了工作和家庭每天奔波在不同城市之间。', 'Tā wèi le gōng zuò hé jiā tíng měi tiān bēn bō zài bù tóng chéng shì zhī jiān.', 'Anh ấy hàng ngày bôn ba giữa các thành phố khác nhau vì công việc và gia đình.'),
  ('备忘录', '会议结束后，秘书整理了一份详细的备忘录。', 'Huì yì jié shù hòu, mì shū zhěng lǐ le yī fèn xiáng xì de bèi wàng lù.', 'Sau cuộc họp, thư ký đã soạn một bản ghi nhớ chi tiết.'),
  ('备份', '请记得每天晚上都要备份电脑里的重要文件。', 'Qǐng jìdé měitiān wǎnshang dōu yào bèifèn diànnǎo lǐ de zhòngyào wénjiàn.', 'Xin nhớ mỗi tối đều phải sao lưu các tập tin quan trọng trong máy tính.'),
  ('卑鄙', '他的行为非常卑鄙，让人难以原谅。', 'Tā de xíngwéi fēicháng bēibǐ, ràng rén nányǐ yuánliàng.', 'Hành động của anh ta rất bỉ ổi, khiến người ta khó tha thứ.'),
  ('北极', '科学家们正在研究北极地区的气候变化。', 'Kēxuéjiāmen zhèngzài yánjiū běijí dìqū de qìhòu biànhuà.', 'Các nhà khoa học đang nghiên cứu sự thay đổi khí hậu ở khu vực Bắc Cực.'),
  ('鼻涕', '孩子感冒了，一直流鼻涕，非常难受。', 'Háizi gǎnmàole, yīzhí liú bítì, fēicháng nánshòu.', 'Đứa trẻ bị cảm, luôn chảy nước mũi, rất khó chịu.'),
  ('闭塞', '那个山区交通闭塞，物资运输十分困难。', 'Nàgè shānqū jiāotōng bìsè, wùzī yùnshū shífēn kùnnán.', 'Khu vực núi đó giao thông tắc nghẽn, vận chuyển hàng hóa rất khó khăn.'),
  ('鄙视', '他对那些欺骗朋友的人充满鄙视。', 'Tā duì nàxiē qīpiàn péngyǒu de rén chōngmǎn bǐshì.', 'Anh ta khinh thường những người lừa dối bạn bè.'),
  ('逼迫', '他们被逼迫签署了不公平的合同。', 'Tāmen bèi bīpò qiānshǔle bù gōngpíng de hétóng.', 'Họ bị bắt buộc phải ký vào hợp đồng bất công.'),
  ('迸发', '创意的灵感突然迸发，让他完成了作品。', 'Chuàngyì de línggǎn túrán bèngfā, ràng tā wánchéngle zuòpǐn.', 'Cảm hứng sáng tạo bùng phát đột ngột, giúp anh ta hoàn thành tác phẩm.'),
  ('蹦', '小兔子在草地上开心地蹦来蹦去。', 'Xiǎo tùzi zài cǎodì shàng kāixīn de bèng lái bèng qù.', 'Con thỏ nhỏ vui vẻ nhảy bật trên bãi cỏ.'),
  ('笨拙', '虽然他动作笨拙，但学习态度非常认真。', 'Suīrán tā dòngzuò bènzhuō, dàn xuéxí tàidù fēicháng rènzhēn.', 'Dù anh ấy vụng về trong cử động, nhưng thái độ học tập rất nghiêm túc.'),
  ('甭', '这件事你甭担心，我会帮你解决的。', 'Zhè jiàn shì nǐ béng dānxīn, wǒ huì bāng nǐ jiějué de.', 'Việc này bạn không cần lo lắng, tôi sẽ giúp bạn giải quyết.'),
  ('比重', '钢铁在建筑材料中的比重非常重要。', 'Gāngtiě zài jiànzhù cáiliào zhōng de bǐzhòng fēicháng zhòngyào.', 'Tỉ trọng của thép trong vật liệu xây dựng rất quan trọng.'),
  ('比方', '比方说，如果你迟到，可能会错过重要内容。', 'Bǐfang shuō, rúguǒ nǐ chídào, kěnéng huì cuòguò zhòngyào nèiróng.', 'Ví dụ như, nếu bạn đến muộn, có thể sẽ bỏ lỡ nội dung quan trọng.'),
  ('比喻', '老师用鱼与水的比喻说明了友情的重要性。', 'Lǎoshī yòng yú yǔ shuǐ de bǐyù shuōmíng le yǒuqíng de zhòngyào xìng.', 'Giáo viên dùng phép so sánh cá và nước để giải thích tầm quan trọng của tình bạn.'),
  ('本身', '危险本身并不可怕，关键是如何应对。', 'Wēixiǎn běnshēn bìng bù kěpà, guānjiàn shì rúhé yìngduì.', 'Nguy hiểm tự nó không đáng sợ, quan trọng là cách đối phó.'),
  ('本人', '请本人携带身份证前来办理手续。', 'Qǐng běnrén xiédài shēnfènzhèng qiánlái bànlǐ shǒuxù.', 'Xin chính bản thân mang theo chứng minh nhân dân đến làm thủ tục.'),
  ('本事', '他的本事很大，什么困难都能解决。', 'Tā de běnshì hěn dà, shénme kùnnan dōu néng jiějué.', 'Bản lĩnh của anh ấy rất lớn, có thể giải quyết mọi khó khăn.'),
  ('弊病', '这个制度存在很多弊病，亟待改革。', 'Zhège zhìdù cúnzài hěn duō bìbìng, jídài gǎigé.', 'Chế độ này tồn tại nhiều mặt hạn chế, cần phải cải cách ngay.'),
  ('崩溃', '公司因经营不善而陷入财务崩溃。', 'Gōngsī yīn jīngyíng bùshàn ér xiànrù cáiwù bēngkuì.', 'Công ty rơi vào suy sụp tài chính vì kinh doanh không tốt.'),
  ('鞭策', '老师的严格鞭策让学生们更加努力学习。', 'Lǎoshī de yángé biāncè ràng xuéshēngmen gèngjiā nǔlì xuéxí.', 'Sự đôn đốc nghiêm khắc của giáo viên khiến học sinh học tập chăm chỉ hơn.'),
  ('遍布', '这个国家的山脉遍布各种珍稀植物和动物。', 'Zhè ge guó jiā de shān mài biàn bù gè zhǒng zhēn xī zhí wù hé dòng wù.', 'Dãy núi của quốc gia này phân bố rải rác các loại thực vật và động vật quý hiếm.'),
  ('边缘', '我们住在城市的边缘，环境既安静又自然。', 'Wǒ men zhù zài chéng shì de biān yuán, huán jìng jì ān jìng yòu zì rán.', 'Chúng tôi sống ở vùng ven thành phố, môi trường vừa yên tĩnh vừa tự nhiên.'),
  ('边疆', '军队加强了边疆的防守，确保国家安全。', 'Jūn duì jiā qiáng le biān jiāng de fáng shǒu, què bǎo guó jiā ān quán.', 'Quân đội tăng cường phòng thủ biên cương để đảm bảo an ninh quốc gia.'),
  ('边界', '这条河是两个国家的自然边界线。', 'Zhè tiáo hé shì liǎng gè guó jiā de zì rán biān jiè xiàn.', 'Con sông này là đường biên giới tự nhiên giữa hai quốc gia.'),
  ('边境', '边境地区的贸易活动因为政策变化而明显减少。', 'Biān jìng dì qū de mào yì huó dòng yīn wèi zhèng cè biàn huà ér míng xiǎn jiǎn shǎo.', 'Hoạt động thương mại ở khu vực biên thùy đã giảm rõ rệt vì sự thay đổi chính sách.'),
  ('辨认', '他能够准确辨认出照片中的每个人名字。', 'Tā néng gòu zhǔn què biàn rèn chū zhào piàn zhōng de měi gè rén míng zì.', 'Anh ấy có thể nhận biết chính xác tên của từng người trong bức ảnh.'),
  ('贬低', '不要轻易贬低别人的努力和付出，这样很不尊重。', 'Bù yào qīng yì biǎn dī bié rén de nǔ lì hé fù chū, zhè yàng hěn bù zūn zhòng.', 'Đừng dễ dàng hạ thấp sự nỗ lực và cống hiến của người khác, như vậy thật không tôn trọng.'),
  ('贬义', '这个词在不同语境中有时带有贬义，使用时需谨慎。', 'Zhè ge cí zài bù tóng yǔ jìng zhōng yǒu shí dài yǒu biǎn yì, shǐ yòng shí xū jǐn shèn.', 'Từ này trong các ngữ cảnh khác nhau đôi khi mang nghĩa xấu, cần thận trọng khi sử dụng.'),
  ('臂', '医生仔细检查了病人的右臂上是否有伤口。', 'Yī shēng zǐ xì jiǎn chá le bìng rén de yòu bì shàng shì fǒu yǒu shāng kǒu.', 'Bác sĩ kiểm tra kỹ xem cánh tay phải bệnh nhân có vết thương hay không.'),
  ('编织', '她花了几个小时编织这条温暖的毛衣送给母亲。', 'Tā huā le jǐ gè xiǎo shí biān zhī zhè tiáo wēn nuǎn de máo yī sòng gěi mǔ qīn.', 'Cô ấy đã tốn vài tiếng đồng hồ để đan chiếc áo len ấm gửi tặng mẹ.'),
  ('扁', '这把刀的刀刃被磨得很扁，所以切割效率很高。', 'Zhè bǎ dāo de dāo rèn bèi mó de hěn biǎn, suǒ yǐ qiē gē xiào lǜ hěn gāo.', 'Lưỡi dao này được mài rất dẹt nên hiệu quả cắt rất cao.'),
  ('弊端', '公司应及时发现并纠正管理上的弊端以避免损失。', 'Gōng sī yīng jí shí fā xiàn bìng jiū zhèng guǎn lǐ shàng de bì duān yǐ bì miǎn sǔn shī.', 'Công ty nên phát hiện và sửa chữa kịp thời những sai lầm trong quản lý để tránh tổn thất.'),
  ('变迁', '经过几十年的变迁，这座城市的面貌焕然一新。', 'Jīng guò jǐ shí nián de biàn qiān, zhè zuò chéng shì de miàn mào huàn rán yī xīn.', 'Sau vài chục năm thay đổi, bộ mặt thành phố này đã hoàn toàn mới mẻ.'),
  ('部署', '领导对新项目进行了详细的部署，确保按时完成。', 'Lǐng dǎo duì xīn xiàng mù jìn xíng le xiáng xì de bù shǔ, què bǎo àn shí wán chéng.', 'Lãnh đạo đã phân công chi tiết cho dự án mới để đảm bảo hoàn thành đúng hạn.'),
  ('部位', '按摩师重点针对身体疼痛的部位进行治疗。', 'Àn mó shī zhòng diǎn zhēn duì shēn tǐ téng tòng de bù wèi jìn xíng zhì liáo.', 'Nhà mát-xa tập trung điều trị các bộ phận cơ thể bị đau.'),
  ('辫子', '小女孩喜欢把头发编成两条辫子，看起来很可爱。', 'Xiǎo nǚ hái xǐ huān bǎ tóu fa biān chéng liǎng tiáo biàn zi, kàn qǐ lái hěn kě ài.', 'Cô bé thích tết tóc thành hai bím, trông rất dễ thương.'),
  ('辩证', '他用辩证的方法分析了这个复杂的问题。', 'Tā yòng biàn zhèng de fāng fǎ fēn xī le zhè ge fù zá de wèn tí.', 'Anh ấy dùng phương pháp biện chứng để phân tích vấn đề phức tạp này.'),
  ('辩解', '面对错误，他没有试图辩解，而是诚恳地道歉。', 'Miàn duì cuò wù, tā méi yǒu shì tú biàn jiě, ér shì chéng kěn de dào qiàn.', 'Đối mặt với sai lỗi, anh ấy không cố gắng giải thích mà chân thành xin lỗi.'),
  ('辩护', '律师提供了充分的证据为被告进行辩护。', 'Lǜ shī tí gōng le chōng fèn de zhèng jù wèi bèi gào jìn xíng biàn hù.', 'Luật sư đã cung cấp bằng chứng đầy đủ để biện hộ cho bị cáo.'),
  ('表态', '会议中各方代表纷纷表态支持这项改革方案。', 'Huì yì zhōng gè fāng dài biǎo fēn fēn biǎo tài zhī chí zhè xiàng gǎi gé fāng àn.', 'Trong cuộc họp, đại diện các bên lần lượt tỏ thái độ rõ ràng ủng hộ phương án cải cách này.'),
  ('表彰', '公司在年会上表彰了所有表现出色的员工。', 'Gōngsī zài nián huì shàng biǎo zhāng le suǒyǒu biǎoxiàn chūsè de yuángōng.', 'Công ty đã tuyên dương tất cả nhân viên có thành tích xuất sắc trong cuộc họp cuối năm.'),
  ('表决', '大会通过无记名投票方式对提案进行表决。', 'Dàhuì tōngguò wú jìmíng tóupiào fāngshì duì tí''àn jìnxíng biǎo jué.', 'Đại hội đã tiến hành biểu quyết đề án bằng hình thức bỏ phiếu kín.'),
  ('补贴', '政府每月给予低收入家庭一定金额的生活补贴。', 'Zhèngfǔ měi yuè jǐyǔ dī shōurù jiātíng yīdìng jīn''é de shēnghuó bǔ tiē.', 'Chính phủ hàng tháng trợ cấp một khoản tiền sinh hoạt cho các gia đình có thu nhập thấp.'),
  ('补救', '及时采取措施可以有效补救这个项目中的错误。', 'Jíshí cǎiqǔ cuòshī kěyǐ yǒuxiào bǔjiù zhège xiàngmù zhōng de cuòwù.', 'Việc áp dụng biện pháp kịp thời có thể cứu vãn lỗi trong dự án này một cách hiệu quả.'),
  ('补偿', '公司向因工受伤的员工提供医疗补偿和经济补偿。', 'Gōngsī xiàng yīn gōng shòushāng de yuángōng tígōng yīliáo bǔcháng hé jīngjì bǔcháng.', 'Công ty cung cấp bồi thường y tế và kinh tế cho nhân viên bị thương khi làm việc.'),
  ('薄弱', '这个地区的教育资源非常薄弱，亟需改善。', 'Zhège dìqū de jiàoyù zīyuán fēicháng bóruò, jí xū gǎishàn.', 'Nguồn lực giáo dục ở khu vực này rất yếu kém, cần cải thiện gấp.'),
  ('濒临', '河流因污染严重而濒临生态崩溃的边缘。', 'Héliú yīn wūrǎn yánzhòng ér bīnlín shēngtài bēngkuì de biānyuán.', 'Dòng sông đang kề cận bờ vực sụp đổ sinh thái do ô nhiễm nghiêm trọng.'),
  ('波涛', '大海的波涛在风暴中汹涌澎湃，异常壮观。', 'Dàhǎi de bōtāo zài fēngbào zhōng xiōngyǒng péngpài, yìcháng zhuàngguān.', 'Những con sóng to trên biển dâng trào dữ dội trong cơn bão, thật hùng vĩ.'),
  ('波浪', '海边的波浪轻轻拍打着沙滩，声音十分悦耳。', 'Hǎibiān de bōlàng qīngqīng pāidǎ zhe shātān, shēngyīn shífēn yuè''ěr.', 'Sóng biển nhẹ nhàng vỗ vào bờ cát, âm thanh rất dễ chịu.'),
  ('步伐', '团队成员必须保持一致的步伐才能完成任务。', 'Tuánduì chéngyuán bìxū bǎochí yīzhì de bùfá cáinéng wánchéng rènwù.', 'Các thành viên trong đội phải giữ nhịp bước đồng đều mới có thể hoàn thành nhiệm vụ.'),
  ('标题', '这篇文章的标题非常吸引读者的注意力。', 'Zhè piān wénzhāng de biāotí fēicháng xīyǐn dúzhě de zhùyì lì.', 'Tiêu đề của bài viết này rất thu hút sự chú ý của độc giả.'),
  ('标记', '请用红笔在文件上做出明显的标记。', 'Qǐng yòng hóngbǐ zài wénjiàn shàng zuò chū míngxiǎn de biāojì.', 'Xin hãy dùng bút đỏ đánh dấu rõ ràng trên tài liệu.'),
  ('标本', '科学家在野外收集了许多植物标本进行研究。', 'Kēxuéjiā zài yěwài shōují le xǔduō zhíwù biāoběn jìnxíng yánjiū.', 'Các nhà khoa học thu thập nhiều mẫu vật thực vật ngoài tự nhiên để nghiên cứu.'),
  ('播种', '春天是农民播种的季节，田野里到处忙碌。', 'Chūntiān shì nóngmín bōzhǒng de jìjié, tiányě lǐ dàochù mánglù.', 'Mùa xuân là mùa nông dân gieo hạt, trên cánh đồng đâu đâu cũng tấp nập.'),
  ('搏斗', '两只雄狮在草原上激烈搏斗，争夺领地。', 'Liǎng zhī xióngshī zài cǎoyuán shàng jīliè bódòu, zhēngduó lǐngdì.', 'Hai con sư tử đực vật lộn dữ dội trên thảo nguyên để tranh giành lãnh thổ.'),
  ('捕捉', '摄影师成功捕捉到了雪豹在山林中的身影。', 'Shèyǐngshī chénggōng bǔzhuō dào le xuěbào zài shānlín zhōng de shēnyǐng.', 'Nhiếp ảnh gia đã thành công bắt được hình ảnh con báo tuyết trong rừng núi.'),
  ('拨', '他轻轻拨开树枝，继续向前走去。', 'Tā qīngqīng bō kāi shùzhī, jìxù xiàng qián zǒu qù.', 'Anh ấy nhẹ nhàng gạt cành cây ra, tiếp tục bước về phía trước.'),
  ('憋', '他忍不住憋笑，差点在会议中出糗。', 'Tā rěn bu zhù biē xiào, chàdiǎn zài huìyì zhōng chū qiǔ.', 'Anh ấy không nhịn được cười, suýt chút nữa thì lộ điểm yếu trong cuộc họp.'),
  ('并非', '事实并非如大家所想的那样简单。', 'Shìshí bìngfēi rú dàjiā suǒ xiǎng de nàyàng jiǎndān.', 'Sự thật không phải đơn giản như mọi người nghĩ.'),
  ('并列', '这两个城市在人口数量上并列为全国前三。', 'Zhè liǎng gè chéngshì zài rénkǒu shùliàng shàng bìngliè wéi quánguó qián sān.', 'Hai thành phố này ngang hàng về dân số trong top ba cả nước.'),
  ('布置', '老师布置了很多作业给学生完成。', 'Lǎoshī bùzhì le hěn duō zuòyè gěi xuéshēng wánchéng.', 'Giáo viên đã giao nhiều bài tập cho học sinh làm.'),
  ('布局', '这幅画的布局非常讲究，色彩搭配和谐。', 'Zhè fú huà de bùjú fēicháng jiǎngjiu, sècǎi dāpèi héxié.', 'Bố cục của bức tranh này rất tỉ mỉ, phối màu hài hòa.'),
  ('布告', '公司发布了一则重要的布告通知全体员工。', 'Gōngsī fābù le yī zé zhòngyào de bùgào tōngzhī quántǐ yuángōng.', 'Công ty đã phát một thông báo quan trọng đến toàn thể nhân viên.'),
  ('哺乳', '初生的宝宝需要母亲哺乳才能健康成长。', 'Chūshēng de bǎobǎo xūyào mǔqīn bǔrǔ cáinéng jiànkāng chéngzhǎng.', 'Em bé sơ sinh cần được mẹ nuôi bằng sữa để phát triển khỏe mạnh.'),
  ('变质', '这瓶牛奶放久了，已经开始变质了。', 'Zhè píng niúnǎi fàng jiǔ le, yǐjīng kāishǐ biànzhì le.', 'Chai sữa này để lâu rồi, đã bắt đầu bị hỏng.'),
  ('变故', '他家突然发生了变故，全家人都很难过。', 'Tā jiā tūrán fāshēng le biàngù, quán jiārén dōu hěn nánguò.', 'Gia đình anh ấy đột nhiên gặp phải biến cố, cả nhà đều rất buồn.'),
  ('博览会', '这次国际博览会吸引了来自世界各地的参展者。', 'Zhè cì guójì bólǎnhuì xīyǐn le láizì shìjiè gèdì de cānzhǎn zhě.', 'Hội chợ quốc tế lần này thu hút người tham gia từ khắp nơi trên thế giới.'),
  ('博大精深', '中国传统文化博大精深，值得我们深入研究。', 'Zhōngguó chuántǒng wénhuà bódà jīngshēn, zhídé wǒmen shēnrù yánjiū.', 'Văn hóa truyền thống Trung Quốc rất thâm thúy, đáng để chúng ta nghiên cứu sâu.'),
  ('剥削', '工人们反对资本家的剥削行为，争取权益。', 'Gōngrén men fǎnduì zīběnjiā de bōxuē xíngwéi, zhēngqǔ quányì.', 'Công nhân phản đối hành vi bóc lột của chủ tư bản, đấu tranh vì quyền lợi.'),
  ('别致', '这家餐厅的装修风格别致，吸引了很多顾客。', 'Zhè jiā cāntīng de zhuāngxiū fēnggé biézhì, xīyǐn le hěn duō gùkè.', 'Phong cách trang trí của nhà hàng này rất đặc biệt, thu hút nhiều khách hàng.'),
  ('别扭', '他说话总让我感觉有点别扭，不太自然。', 'Tā shuōhuà zǒng ràng wǒ gǎnjué yǒudiǎn bièniu, bù tài zìrán.', 'Lời nói của anh ấy khiến tôi cảm thấy hơi khó chịu, không tự nhiên.'),
  ('别墅', '他们在郊区买了一栋漂亮的别墅。', 'Tāmen zài jiāoqū mǎi le yī dòng piàoliang de biéshù.', 'Họ đã mua một biệt thự đẹp ở ngoại ô.'),
  ('冰雹', '昨天下午突然下起了冰雹，天气很恶劣。', 'Zuótiān xiàwǔ tūrán xià qǐ le bīngbáo, tiānqì hěn èliè.', 'Chiều qua bất ngờ mưa đá, thời tiết rất xấu.'),
  ('便条', '他离开前在桌上留了一张便条说明原因。', 'Tā líkāi qián zài zhuō shàng liú le yī zhāng biàntiáo shuōmíng yuányīn.', 'Trước khi đi, anh ấy để lại một mảnh giấy nhớ trên bàn giải thích lý do.'),
  ('便利', '地铁的开通极大地便利了市民的出行。', 'Dìtiě de kāitōng jí dà de biànlì le shìmín de chūxíng.', 'Việc khai trương tàu điện ngầm đã rất thuận tiện cho người dân đi lại.'),
  ('便于', '这样的设计便于学生更好地进行小组讨论。', 'Zhèyàng de shèjì biànyú xuéshēng gèng hǎo de jìnxíng xiǎozǔ tǎolùn.', 'Thiết kế như thế này tiện cho học sinh thảo luận nhóm tốt hơn.'),
  ('伯母', '伯母热情地招待了我们一家人。', 'Bómǔ rèqíng de zhāodài le wǒmen yī jiā rén.', 'Dì gái chồng đã nhiệt tình tiếp đãi cả nhà chúng tôi.'),
  ('丙', '按照等级，丙类产品的质量较低。', 'Ànzhào děngjí, bǐng lèi chǎnpǐn de zhìliàng jiào dī.', 'Theo cấp độ, sản phẩm loại B có chất lượng thấp hơn.'),
  ('不顾', '他不顾危险，奋力救出了被困的人。', 'Tā bùgù wēixiǎn, fènlì jiù chū le bèi kùn de rén.', 'Anh ấy bất chấp nguy hiểm, cố gắng cứu người bị mắc kẹt.'),
  ('不言而喻', '这个问题的严重性是不言而喻的。', 'Zhège wèntí de yánzhòng xìng shì bù yán ér yù de.', 'Tầm nghiêm trọng của vấn đề này là rõ mồn một.'),
  ('不禁', '看到那么感人的电影，我不禁流下了眼泪。', 'Kàn dào nà me gǎn rén de diàn yǐng, wǒ bù jīn liú xià le yǎn lèi.', 'Xem bộ phim cảm động như vậy, tôi không kiềm được nước mắt.'),
  ('不相上下', '这两位选手的实力不相上下，比赛非常激烈。', 'Zhè liǎng wèi xuǎn shǒu de shí lì bù xiāng shàng xià, bǐ sài fēi cháng jī liè.', 'Thực lực của hai vận động viên này ngang tài ngang sức, cuộc thi rất căng thẳng.'),
  ('不由得', '听到这个消息，他不由得感到惊讶。', 'Tīng dào zhè ge xiāo xī, tā bù yóu dé gǎn dào jīng yà.', 'Nghe tin này, anh ấy đành phải cảm thấy ngạc nhiên.'),
  ('不止', '她的努力不止一次，终于获得了成功。', 'Tā de nǔ lì bù zhǐ yī cì, zhōng yú huò dé le chéng gōng.', 'Nỗ lực của cô ấy không chỉ một lần, cuối cùng đã thành công.'),
  ('不时', '他上课时不时低头查看手机，非常注意信息。', 'Tā shàng kè shí bù shí dī tóu chá kàn shǒu jī, fēi cháng zhù yì xìn xī.', 'Anh ấy khi lên lớp thỉnh thoảng cúi đầu xem điện thoại, rất để ý tin nhắn.'),
  ('不料', '大家都认为他会赢，不料他却输掉了比赛。', 'Dà jiā dōu rèn wéi tā huì yíng, bù liào tā què shū diào le bǐ sài.', 'Mọi người đều nghĩ anh ấy sẽ thắng, không ngờ anh ấy lại thua trận.'),
  ('不敢当', '您过奖了，我不敢当这么高的评价。', 'Nín guò jiǎng le, wǒ bù gǎn dāng zhè me gāo de píng jià.', 'Ông đã khen quá rồi, tôi không dám nhận sự đánh giá cao như vậy.'),
  ('不择手段', '为了实现目标，他不择手段，甚至违反了法律。', 'Wèi le shí xiàn mù biāo, tā bù zé shǒu duàn, shèn zhì wéi fǎn le fǎ lǜ.', 'Để đạt được mục tiêu, anh ta không từ thủ đoạn, thậm chí phạm pháp.'),
  ('不愧', '她不愧是公司的顶梁柱，工作能力很强。', 'Tā bù kuì shì gōng sī de dǐng liáng zhù, gōng zuò néng lì hěn qiáng.', 'Cô ấy xứng đáng là trụ cột của công ty, khả năng làm việc rất mạnh.'),
  ('不惜', '为了梦想，他不惜一切代价去努力奋斗。', 'Wèi le mèng xiǎng, tā bù xī yī qiè dài jià qù nǔ lì fèn dòu.', 'Vì ước mơ, anh ấy không tiếc mọi giá để cố gắng phấn đấu.'),
  ('不得已', '天气太糟糕，我们不得已取消了旅行计划。', 'Tiān qì tài zāo gāo, wǒ men bù dé yǐ qǔ xiāo le lǚ xíng jì huà.', 'Thời tiết quá tệ, chúng tôi bất đắc dĩ phải hủy kế hoạch du lịch.'),
  ('不屑一顾', '对于那些无理的批评，他根本不屑一顾。', 'Duì yú nà xiē wú lǐ de pī píng, tā gēn běn bù xiè yī gù.', 'Với những lời phê bình vô lý đó, anh ấy hoàn toàn không đáng quan tâm.'),
  ('不妨', '天气这么好，我们不妨去郊游放松一下。', 'Tiān qì zhè me hǎo, wǒ men bù fáng qù jiāo yóu fàng sōng yī xià.', 'Thời tiết đẹp như thế, chúng ta đừng ngại đi dã ngoại thư giãn một chút.'),
  ('不堪', '连续的加班让我感到疲惫不堪，必须休息。', 'Lián xù de jiā bān ràng wǒ gǎn dào pí bèi bù kān, bì xū xiū xī.', 'Làm thêm giờ liên tiếp khiến tôi cảm thấy mệt mỏi quá mức chịu đựng, phải nghỉ ngơi.'),
  ('不可思议', '他突然的成功真是不可思议，让人难以相信。', 'Tā tú rán de chéng gōng zhēn shì bù kě sī yì, ràng rén nán yǐ xiāng xìn.', 'Thành công đột ngột của anh ấy thật không thể tưởng tượng nổi, khiến người ta khó tin.'),
  ('不免', '遇到困难时，我们不免会感到失落和沮丧。', 'Yù dào kùn nán shí, wǒ men bù miǎn huì gǎn dào shī luò hé jǔ sàng.', 'Khi gặp khó khăn, chúng ta không tránh khỏi cảm thấy thất vọng và chán nản.'),
  ('不像话', '他的行为真是太不像话了，大家都很生气。', 'Tā de xíng wéi zhēn shì tài bù xiàng huà le, dà jiā dōu hěn shēng qì.', 'Hành động của anh ta thật chẳng ra làm sao cả, mọi người đều rất tức giận.'),
  ('馋', '我一看到美食就馋得流口水，根本控制不住自己。', 'Wǒ yī kàn dào měi shí jiù chán de liú kǒu shuǐ, gēn běn kòng zhì bù zhù zì jǐ.', 'Tôi cứ nhìn thấy đồ ăn ngon thì thèm chảy nước miếng, hoàn toàn không kiểm soát được bản thân.'),
  ('颤抖', '寒冷的天气使他的手不停地颤抖。', 'Hán lěng de tiān qì shǐ tā de shǒu bù tíng de chàn dǒu.', 'Thời tiết lạnh khiến tay anh ấy run rẩy không ngừng.'),
  ('雌雄', '这场比赛双方势均力敌，真正体现了雌雄对决。', 'Zhè chǎng bǐ sài shuāng fāng shì jūn lì dí, zhēn zhèng tǐ xiàn le cí xióng duì jué.', 'Trận đấu này hai bên ngang sức ngang tài, thực sự thể hiện cuộc sống mái thắng bại.'),
  ('除', '数学题里面，必须先做加法再做除法。', 'shù xué tí lǐ miàn, bì xū xiān zuò jiā fǎ zài zuò chú fǎ.', 'Trong bài toán, phải làm phép cộng trước rồi mới làm phép chia.'),
  ('陈述', '他在会议上详细陈述了项目的进展情况。', 'tā zài huì yì shàng xiáng xì chén shù le xiàng mù de jìn zhǎn qíng kuàng.', 'Anh ấy đã trình bày chi tiết tiến độ dự án tại cuộc họp.'),
  ('陈旧', '这种陈旧的思想已经不适合现代社会的发展。', 'zhè zhǒng chén jiù de sī xiǎng yǐ jīng bù shì hé xiàn dài shè huì de fā zhǎn.', 'Tư tưởng lỗi thời này không còn phù hợp với sự phát triển xã hội hiện đại.'),
  ('陈列', '博物馆里陈列着许多珍贵的历史文物。', 'bó wù guǎn lǐ chén liè zhe xǔ duō zhēn guì de lì shǐ wén wù.', 'Trong bảo tàng được trưng bày nhiều cổ vật lịch sử quý giá.'),
  ('阐述', '专家在讲座中阐述了人工智能的未来趋势。', 'zhuān jiā zài jiǎng zuò zhōng chǎn shù le rén gōng zhì néng de wèi lái qū shì.', 'Chuyên gia đã trình bày về xu hướng tương lai của trí tuệ nhân tạo trong buổi thuyết trình.'),
  ('锤', '工人用锤子敲打着铁钉。', 'gōng rén yòng chuí zi qiāo dǎ zhe tiě dīng.', 'Công nhân đang dùng cái búa đóng đinh sắt.'),
  ('钞票', '他从钱包里拿出几张钞票支付了账单。', 'tā cóng qián bāo lǐ ná chū jǐ zhāng chāo piào zhī fù le zhàng dān.', 'Anh ấy lấy vài tờ tiền từ ví ra để trả hóa đơn.'),
  ('重叠', '这两个声音在录音中重叠，导致听起来很混乱。', 'zhè liǎng gè shēng yīn zài lù yīn zhōng chóng dié, dǎo zhì tīng qǐ lái hěn hùn luàn.', 'Hai âm thanh này chồng lên nhau trong bản thu, làm cho nghe rất lộn xộn.'),
  ('采集', '科研人员采集了不同地区的植物样本进行分析。', 'kē yán rén yuán cǎi jí le bù tóng dì qū de zhí wù yàng běn jìn xíng fēn xī.', 'Nhân viên nghiên cứu đã thu thập mẫu thực vật từ các vùng khác nhau để phân tích.'),
  ('采购', '公司最近增加了办公设备的采购预算。', 'gōng sī zuì jìn zēng jiā le bàn gōng shè bèi de cǎi gòu yù suàn.', 'Công ty gần đây đã tăng ngân sách mua sắm thiết bị văn phòng.'),
  ('采纳', '经理采纳了员工提出的建议来改善工作流程。', 'jīng lǐ cǎi nà le yuán gōng tí chū de jiàn yì lái gǎi shàn gōng zuò liú chéng.', 'Quản lý đã tiếp thu đề xuất của nhân viên để cải thiện quy trình làm việc.'),
  ('迟钝', '由于疲劳，他的反应迟钝，做事效率低下。', 'yóu yú pí láo, tā de fǎn yìng chí dùn, zuò shì xiào lǜ dī xià.', 'Do mệt mỏi, phản ứng của anh ấy chậm chạp, hiệu quả làm việc thấp.'),
  ('迟缓', '交通事故导致救援行动进行得非常迟缓。', 'jiāo tōng shì gù dǎo zhì jiù yuán xíng dòng jìn xíng dé fēi cháng chí huǎn.', 'Tai nạn giao thông khiến hoạt động cứu hộ tiến hành rất chậm chạp.'),
  ('迟疑', '她在回答问题时表现出明显的迟疑和不确定。', 'tā zài huí dá wèn tí shí biǎo xiàn chū míng xiǎn de chí yí hé bù què dìng.', 'Cô ấy thể hiện sự lưỡng lự và không chắc chắn rõ ràng khi trả lời câu hỏi.'),
  ('超越', '这位运动员努力训练，终于超越了自己的极限。', 'zhè wèi yùn dòng yuán nǔ lì xùn liàn, zhōng yú chāo yuè le zì jǐ de jí xiàn.', 'Vận động viên này đã luyện tập chăm chỉ và cuối cùng vượt qua giới hạn của bản thân.'),
  ('赤道', '赤道附近的气候通常炎热而潮湿。', 'chì dào fù jìn de qì hòu tōng cháng yán rè ér cháo shī.', 'Khí hậu gần đường xích đạo thường nóng ẩm.'),
  ('赤字', '政府为了减少财政赤字，采取了多项紧缩措施。', 'zhèng fǔ wèi le jiǎn shǎo cái zhèng chì zì, cǎi qǔ le duō xiàng jǐn suō cuò shī.', 'Chính phủ đã áp dụng nhiều biện pháp thắt chặt để giảm thâm hụt tài chính.'),
  ('财政', '财政政策的调整直接影响国家经济的发展。', 'cái zhèng zhèng cè de tiáo zhěng zhí jiē yǐng xiǎng guó jiā jīng jì de fā zhǎn.', 'Điều chỉnh chính sách tài chính ảnh hưởng trực tiếp đến sự phát triển kinh tế quốc gia.'),
  ('财富', '科技创新是一个国家财富增长的重要动力。', 'kē jì chuàng xīn shì yí gè guó jiā cái fù zēng zhǎng de zhòng yào dòng lì.', 'Đổi mới công nghệ là động lực quan trọng cho sự gia tăng tài sản của một quốc gia.'),
  ('财务', '公司的财务部门负责监督所有的账目和报表。', 'gōng sī de cái wù bù mén fù zé jiān dū suǒ yǒu de zhàng mù hé bào biǎo.', 'Bộ phận tài vụ của công ty chịu trách nhiệm giám sát tất cả các sổ sách và báo cáo.'),
  ('诧异', '他对突然的消息感到非常诧异，无法相信。', 'Tā duì tūrán de xiāoxi gǎndào fēicháng chà yì, wúfǎ xiāngxìn.', 'Anh ấy cảm thấy rất kinh ngạc trước tin đột ngột, không thể tin được.'),
  ('诚挚', '我对你的帮助表示诚挚的感谢和敬意。', 'Wǒ duì nǐ de bāngzhù biǎoshì chéngzhì de gǎnxiè hé jìngyì.', 'Tôi bày tỏ sự cảm ơn chân thành và kính trọng đối với sự giúp đỡ của bạn.'),
  ('触犯', '他不小心触犯了公司的规定，导致被处罚。', 'Tā bù xiǎoxīn chùfàn le gōngsī de guīdìng, dǎozhì bèi chǔfá.', 'Anh ấy không cẩn thận đã xâm phạm quy định công ty và bị xử phạt.'),
  ('裁缝', '这位裁缝为我量身定做了一套合身的西装。', 'Zhè wèi cáiféng wèi wǒ liángshēn dìngzuò le yī tào héshēn de xīzhuāng.', 'Người thợ may này đã may đo cho tôi một bộ vest vừa vặn.'),
  ('裁员', '公司因经济不景气不得不进行大规模的裁员行动。', 'Gōngsī yīn jīngjì bù jǐngqì bùdébù jìnxíng dà guīmó de cáiyuán xíngdòng.', 'Công ty do kinh tế suy thoái buộc phải tiến hành đợt cắt giảm nhân viên lớn.'),
  ('裁判', '这场比赛的裁判判罚严格，没有任何偏袒。', 'Zhè chǎng bǐsài de cáipàn pànfá yángé, méiyǒu rènhé piāntǎn.', 'Trọng tài của trận đấu này phán xử nghiêm khắc, không thiên vị.'),
  ('衬托', '她的温柔性格衬托出他的坚强和可靠。', 'Tā de wēnróu xìnggé chèntuō chū tā de jiānqiáng hé kěkào.', 'Tính cách dịu dàng của cô ấy làm nổi bật sự mạnh mẽ và đáng tin cậy của anh ấy.'),
  ('草率', '做决定不能草率，需要经过反复考虑和讨论。', 'Zuò juédìng bù néng cǎoshuài, xūyào jīngguò fǎnfù kǎolǜ hé tǎolùn.', 'Không thể vội vàng khi đưa quyết định, cần phải cân nhắc và thảo luận kỹ lưỡng.'),
  ('草案', '律师正在修改合同草案，以确保内容合法合规。', 'Lǜshī zhèngzài xiūgǎi hétóng cǎo''àn, yǐ quèbǎo nèiróng héfǎ héguī.', 'Luật sư đang chỉnh sửa bản thảo hợp đồng để đảm bảo nội dung hợp pháp và đúng quy định.'),
  ('苍白', '他脸色苍白，显然是病了好几天。', 'Tā liǎnsè cāngbái, xiǎnrán shì bìng le hǎo jǐ tiān.', 'Mặt anh ấy trắng bệch, rõ ràng là đã ốm mấy ngày.'),
  ('船舶', '港口每天接纳大量各类船舶停靠和维修。', 'Gǎngkǒu měitiān jiēnà dàliàng gèlèi chuánbó tíngkào hé wéixiū.', 'Cảng mỗi ngày tiếp nhận và bảo dưỡng rất nhiều loại thuyền bè.'),
  ('舱', '船舱内布置得非常整洁，为旅客提供舒适环境。', 'Chuáncāng nèi bùzhì de fēicháng zhěngjié, wèi lǚkè tígōng shūshì huánjìng.', 'Buồng tàu được sắp xếp rất gọn gàng, cung cấp môi trường thoải mái cho hành khách.'),
  ('脆弱', '儿童的身体免疫力较脆弱，需要细心保护。', 'Értóng de shēntǐ miǎnyì lì jiào cuìruò, xūyào xìxīn bǎohù.', 'Sức đề kháng của trẻ em khá yếu, cần được bảo vệ chu đáo.'),
  ('缠绕', '藤蔓不断缠绕在树干上，形成了美丽的自然景观。', 'Téngwàn bùduàn chánrào zài shùgàn shàng, xíngchéng le měilì de zìrán jǐngguān.', 'Dây leo quấn quanh thân cây tạo nên cảnh quan thiên nhiên đẹp.'),
  ('纯粹', '他的动机不是为了利益，纯粹出于对工作的热爱。', 'Tā de dòngjī bù shì wèile lìyì, chúncuì chūyú duì gōngzuò de rè''ài.', 'Động cơ của anh ấy không vì lợi ích, chỉ đơn thuần xuất phát từ tình yêu công việc.'),
  ('纯洁', '他们保持着纯洁的友谊，从未受到外界影响。', 'Tāmen bǎochí zhe chúnjié de yǒuyì, cóng wèi shòudào wàijiè yǐngxiǎng.', 'Họ giữ mối quan hệ bạn bè trong sạch, chưa bao giờ bị ảnh hưởng từ bên ngoài.'),
  ('粗鲁', '在公共场合发表粗鲁言论是不礼貌的行为。', 'Zài gōnggòng chǎnghé fābiǎo cūlǔ yánlùn shì bù lǐmào de xíngwéi.', 'Phát ngôn thô lỗ ở nơi công cộng là hành vi bất lịch sự.'),
  ('筹备', '我们正在筹备明年的国际文化交流展览。', 'Wǒmen zhèngzài chóubèi míngnián de guójì wénhuà jiāoliú zhǎnlǎn.', 'Chúng tôi đang chuẩn bị triển lãm giao lưu văn hóa quốc tế vào năm tới.'),
  ('策略', '公司制定了新的市场营销策略以提升竞争力。', 'Gōngsī zhìdìng le xīn de shìchǎng yíngxiāo cèlüè yǐ tíshēng jìngzhēng lì.', 'Công ty đã thiết lập chiến lược marketing mới để nâng cao sức cạnh tranh.'),
  ('策划', '他们策划了一场精彩的晚会，吸引了众多观众。', 'Tāmen cèhuà le yī chǎng jīngcǎi de wǎnhuì, xīyǐn le zhòngduō guānzhòng.', 'Họ đã vạch ra kế hoạch cho một buổi dạ hội tuyệt vời, thu hút đông đảo khán giả.'),
  ('窜', '小偷看到警察后，立即从后门窜了出去。', 'Xiǎotōu kàn dào jǐngchá hòu, lìjí cóng hòumén cuàn le chūqù.', 'Tên trộm nhìn thấy cảnh sát liền lẻn ra cửa sau.'),
  ('穿越', '这部电影讲述了主人公穿越时空的奇妙故事。', 'Zhè bù diànyǐng jiǎngshù le zhǔréngōng chuānyuè shíkōng de qímiào gùshì.', 'Bộ phim này kể về câu chuyện kỳ diệu của nhân vật chính vượt qua không gian và thời gian.'),
  ('稠密', '这座城市的居民非常稠密，街道总是很拥挤。', 'Zhè zuò chéngshì de jūmín fēicháng chóumì, jiēdào zǒng shì hěn yōngjǐ.', 'Dân cư thành phố này rất đông đúc, các con phố luôn tắc nghẽn.'),
  ('称心如意', '他终于找到了一份称心如意的工作，生活变得更美好。', 'Tā zhōngyú zhǎodào le yī fèn chènxīn rúyì de gōngzuò, shēnghuó biàn de gèng měihǎo.', 'Cuối cùng anh ấy đã tìm được công việc vừa ý, cuộc sống trở nên tốt đẹp hơn.'),
  ('称号', '她因为出色的表现获得了最佳演员的称号。', 'Tā yīnwèi chūsè de biǎoxiàn huòdé le zuì jiā yǎnyuán de chēnghào.', 'Cô ấy vì thành tích xuất sắc mà nhận được danh hiệu diễn viên xuất sắc nhất.'),
  ('秤', '市场里有各种各样的秤，用来称量不同的水果。', 'Shìchǎng lǐ yǒu gè zhǒng gè yàng de chèng, yòng lái chēngliàng bùtóng de shuǐguǒ.', 'Ở chợ có đủ loại cân để cân các loại hoa quả khác nhau.'),
  ('磋商', '双方代表在会议上认真磋商合作的具体细节。', 'Shuāngfāng dàibiǎo zài huìyì shàng rènzhēn cuōshāng hézuò de jùtǐ xìjié.', 'Đại diện hai bên nghiêm túc bàn bạc các chi tiết cụ thể về hợp tác trong cuộc họp.'),
  ('磁带', '这些老旧的磁带保存了我们童年的许多回忆。', 'Zhèxiē lǎojiù de cídài bǎocún le wǒmen tóngnián de xǔduō huíyì.', 'Những cuốn băng từ cũ này giữ lại nhiều kỷ niệm thời thơ ấu của chúng tôi.'),
  ('盛', '这个大瓶子可以盛下五升水，非常实用。', 'Zhège dà píngzi kěyǐ chéng xià wǔ shēng shuǐ, fēicháng shíyòng.', 'Cái chai lớn này có thể chứa được năm lít nước, rất tiện dụng.'),
  ('畅销', '这本小说因为情节精彩而成为全球畅销书。', 'Zhè běn xiǎoshuō yīnwèi qíngjié jīngcǎi ér chéngwéi quánqiú chàngxiāoshū.', 'Cuốn tiểu thuyết này vì cốt truyện hấp dẫn nên trở thành sách bán chạy toàn cầu.'),
  ('畅通', '为了确保交通畅通，市政府加大了道路维修力度。', 'Wèile quèbǎo jiāotōng chàngtōng, shì zhèngfǔ jiā dà le dàolù wéixiū lìdù.', 'Để đảm bảo giao thông thông suốt, chính quyền thành phố đã tăng cường sửa chữa đường sá.'),
  ('炊烟', '傍晚时分，村庄上空袅袅炊烟升起，显得格外宁静。', 'Bàngwǎn shífēn, cūnzhuāng shàngkōng niǎo niǎo chuīyān shēngqǐ, xiǎnde géwài níngjìng.', 'Vào lúc hoàng hôn, khói bếp làng làng bốc lên, tạo nên cảnh yên bình đặc biệt.'),
  ('灿烂', '春天的花园里，花朵开得灿烂夺目，令人陶醉。', 'Chūntiān de huāyuán lǐ, huāduǒ kāi dé cànlàn duómù, lìng rén táozuì.', 'Trong khu vườn mùa xuân, những bông hoa nở rộ rực rỡ, khiến người ta say mê.'),
  ('澄清', '他发表声明澄清了有关他的误解和传闻。', 'Tā fābiǎo shēngmíng chéngqīng le yǒuguān tā de wùjiě hé chuánwén.', 'Anh ấy đã đưa ra tuyên bố làm rõ những hiểu lầm và tin đồn về mình.'),
  ('潮流', '年轻人总是喜欢追赶最新的时尚潮流。', 'Niánqīng rén zǒng shì xǐhuān zhuīgǎn zuìxīn de shíshàng cháoliú.', 'Người trẻ luôn thích chạy theo những trào lưu thời trang mới nhất.'),
  ('测量', '工程师们利用先进设备测量了桥梁的受力情况。', 'Gōngchéngshī men lìyòng xiānjìn shèbèi cèliáng le qiáoliáng de shòulì qíngkuàng.', 'Các kỹ sư đã sử dụng thiết bị tiên tiến để đo đạc tình trạng chịu lực của cây cầu.'),
  ('沉闷', '这场会议气氛沉闷，大家都显得无精打采。', 'Zhè chǎng huìyì qìfēn chénmèn, dàjiā dōu xiǎnde wújīngdǎcǎi.', 'Buổi họp này không khí u ám, mọi người đều tỏ ra mệt mỏi.'),
  ('沉重', '失去亲人的打击让他感到心情异常沉重。', 'Shīqù qīnrén de dǎjī ràng tā gǎndào xīnqíng yìcháng chénzhòng.', 'Cú sốc mất người thân khiến anh ấy cảm thấy tâm trạng rất nặng nề.'),
  ('沉着', '面对突发状况，他依然保持沉着冷静，妥善处理。', 'Miànduì tūfā zhuàngkuàng, tā yīrán bǎochí chénzhuó lěngjìng, tuǒshàn chǔlǐ.', 'Đối mặt với tình huống bất ngờ, anh ấy vẫn giữ bình tĩnh để xử lý ổn thỏa.'),
  ('沉淀', '经过长时间静置，水中的杂质逐渐沉淀到底部。', 'Jīngguò cháng shíjiān jìngzhì, shuǐ zhōng de zázhì zhújiàn chéndiàn dào dǐbù.', 'Sau một thời gian dài để yên, các tạp chất trong nước dần lắng xuống đáy.'),
  ('沉思', '他独自坐在湖边沉思未来的人生路。', 'Tā dúzì zuò zài hú biān chénsī wèilái de rénshēng lù.', 'Anh ấy ngồi một mình bên hồ, trầm ngâm suy nghĩ về con đường cuộc đời tương lai.'),
  ('残酷', '战争的残酷让很多无辜的人失去了家园。', 'Zhànzhēng de cánkù ràng hěn duō wúgū de rén shīqù le jiāyuán.', 'Sự tàn khốc của chiến tranh khiến nhiều người vô tội mất nhà cửa.'),
  ('残疾', '他因为意外变成了残疾，但依然乐观生活。', 'Tā yīnwèi yìwài biàn chéngle cánjí, dàn yīrán lèguān shēnghuó.', 'Anh ấy bị tàn tật do tai nạn, nhưng vẫn sống lạc quan.'),
  ('残留', '工厂废水中还残留着一定量的有害物质。', 'Gōngchǎng fèishuǐ zhōng hái cánliú zhe yīdìng liàng de yǒuhài wùzhí.', 'Trong nước thải của nhà máy còn tồn lại một lượng chất độc hại nhất định.'),
  ('残忍', '那些犯罪分子的行为非常残忍，让人愤怒。', 'Nàxiē fànzuì fènzǐ de xíngwéi fēicháng cánrěn, ràng rén fènnù.', 'Hành vi tàn nhẫn của những tội phạm kia khiến người ta phẫn nộ.'),
  ('次序', '请按照报名的先后次序进入考试教室。', 'Qǐng ànzhào bàomíng de xiānhòu cìxù jìnrù kǎoshì jiàoshì.', 'Xin hãy vào phòng thi theo thứ tự đăng ký từ trước đến sau.'),
  ('次品', '这批产品中有十个次品需要退换。', 'Zhè pī chǎnpǐn zhōng yǒu shí gè cìpǐn xūyào tuìhuàn.', 'Trong lô sản phẩm này có mười cái loại hai cần trả lại hoặc đổi.'),
  ('橙', '他每天早上都会喝一杯新鲜的橙汁。', 'Tā měitiān zǎoshang dūhuì hē yī bēi xīnxiān de chéngzhī.', 'Mỗi sáng anh ấy đều uống một ly nước cam tươi.'),
  ('柴油', '这辆卡车使用柴油作为燃料，效率很高。', 'Zhè liàng kǎchē shǐyòng cháiyóu zuòwéi ránliào, xiàolǜ hěn gāo.', 'Chiếc xe tải này sử dụng dầu diesel làm nhiên liệu, hiệu suất rất cao.'),
  ('查获', '警方近日查获了一批走私的毒品和武器。', 'Jǐngfāng jìnrì cháhuò le yī pī zǒusī de dúpǐn hé wǔqì.', 'Cảnh sát gần đây đã khám xét thu giữ một lô ma túy và vũ khí buôn lậu.'),
  ('朝代', '汉朝是中国历史上一个重要的朝代。', 'Hàn cháo shì Zhōngguó lìshǐ shàng yīgè zhòngyào de cháodài.', 'Triều đại Hán là một triều đại quan trọng trong lịch sử Trung Quốc.'),
  ('昌盛', '这个国家经过多年的改革变得经济昌盛。', 'Zhège guójiā jīngguò duō nián de gǎigé biàn dé jīngjì chāngshèng.', 'Quốc gia này trở nên kinh tế hưng thịnh sau nhiều năm cải cách.'),
  ('敞开', '夏日的窗户常常敞开，让微风吹进来。', 'Xiàrì de chuānghù chángcháng chǎngkāi, ràng wéifēng chuījìnlái.', 'Cửa sổ mùa hè thường mở toang để gió nhẹ thổi vào.'),
  ('操练', '士兵们每天都要进行严格的操练。', 'Shìbīng men měitiān dōu yào jìnxíng yángé de cāoliàn.', 'Các lính mỗi ngày đều phải tiến hành thao luyện nghiêm ngặt.'),
  ('操纵', '他通过操纵市场价格获利。', 'Tā tōngguò cāozòng shìchǎng jiàgé huòlì.', 'Anh ta thu lợi bằng cách thao túng giá cả thị trường.'),
  ('操劳', '为了家庭幸福，父母一直辛苦操劳。', 'Wèile jiātíng xìngfú, fùmǔ yīzhí xīnkǔ cāoláo.', 'Vì hạnh phúc gia đình, cha mẹ luôn chăm chỉ làm việc vất vả.'),
  ('操作', '这台设备操作简单，适合新手使用。', 'Zhè tái shèbèi cāozuò jiǎndān, shìhé xīnshǒu shǐyòng.', 'Thiết bị này thao tác đơn giản, phù hợp cho người mới dùng.'),
  ('撤销', '法院决定撤销对他的指控。', 'Fǎyuàn juédìng chèxiāo duì tā de zhǐkòng.', 'Tòa án quyết định hủy bỏ cáo buộc đối với anh ta.'),
  ('撤退', '敌军在激烈交战后不得不撤退。', 'Díjūn zài jīliè jiāozhàn hòu bùdébù chètuì.', 'Quân địch buộc phải rút lui sau cuộc giao chiến ác liệt.'),
  ('摧残', '战争带来的破坏摧残了这座古城。', 'Zhànzhēng dàilái de pòhuài cuīcán le zhè zuò gǔchéng.', 'Sự tàn phá do chiến tranh mang lại đã phá hủy thành phố cổ này.'),
  ('搓', '他用手搓着衣服上的污渍，不肯轻易放弃。', 'Tā yòng shǒu cuō zhe yīfu shàng de wūzì, bù kěn qīngyì fàngqì.', 'Anh ấy dùng tay chà xát vết bẩn trên áo, không chịu dễ dàng bỏ cuộc.'),
  ('搀', '老爷爷摔倒了，我赶紧上前搀扶他站起来。', 'Lǎoyéye shuāidǎo le, wǒ gǎnjǐn shàngqián chān fú tā zhàn qǐlái.', 'Ông lão bị ngã, tôi nhanh chóng tiến lên đỡ ông ấy đứng dậy.'),
  ('插座', '这台电脑的插座坏了，插不上电源。', 'Zhè tái diànnǎo de chāzuò huài le, chā bù shàng diànyuán.', 'Ổ cắm máy tính này hỏng rồi, không cắm được nguồn điện.'),
  ('挫折', '面对人生的挫折，我们应该保持积极乐观的态度。', 'Miànduì rénshēng de cuòzhé, wǒmen yīnggāi bǎochí jījí lèguān de tàidù.', 'Đối mặt với những thất bại trong cuộc sống, chúng ta nên giữ thái độ tích cực lạc quan.'),
  ('持久', '这场比赛考验选手的持久耐力和心理素质。', 'Zhè chǎng bǐsài kǎoyàn xuǎnshǒu de chíjiǔ nàilì hé xīnlǐ sùzhì.', 'Trận đấu này thử thách sức bền lâu dài và phẩm chất tâm lý của vận động viên.'),
  ('承诺', '他向家人承诺会努力工作，不让大家失望。', 'Tā xiàng jiārén chéngnuò huì nǔlì gōngzuò, bù ràng dàjiā shīwàng.', 'Anh ấy đã hứa với gia đình sẽ làm việc chăm chỉ, không để mọi người thất vọng.'),
  ('承包', '公司承包了这座桥的修建工程，任务十分艰巨。', 'Gōngsī chéngbāo le zhè zuò qiáo de xiūjiàn gōngchéng, rènwù shífēn jiānjù.', 'Công ty nhận thầu dự án xây dựng cây cầu này, nhiệm vụ vô cùng khó khăn.'),
  ('承办', '这个活动由我们学校承办，确保各项工作顺利进行。', 'Zhège huódòng yóu wǒmen xuéxiào chéngbàn, quèbǎo gè xiàng gōngzuò shùnlì jìnxíng.', 'Sự kiện này do trường chúng tôi đăng cai tổ chức, đảm bảo mọi công việc diễn ra suôn sẻ.'),
  ('才干', '他凭借卓越的才干，迅速赢得了领导的认可。', 'Tā píngjiè zhuóyuè de cáigàn, xùnsù yíngdé le lǐngdǎo de rènkě.', 'Anh ấy nhờ tài năng xuất sắc mà nhanh chóng giành được sự công nhận của lãnh đạo.'),
  ('成本', '企业必须严格控制生产成本，才能保持竞争优势。', 'Qǐyè bìxū yángé kòngzhì shēngchǎn chéngběn, cáinéng bǎochí jìngzhēng yōushì.', 'Doanh nghiệp phải kiểm soát nghiêm ngặt chi phí sản xuất mới có thể giữ được lợi thế cạnh tranh.'),
  ('成效', '这项新政策实施后，取得了显著的成效。', 'Zhè xiàng xīn zhèngcè shíshī hòu, qǔdé le xiǎnzhù de chéngxiào.', 'Chính sách mới này sau khi thực hiện đã đạt được hiệu quả rõ rệt.'),
  ('成心', '他成心隐瞒了事情的真相，导致问题更加严重。', 'Tā chéngxīn yǐnmán le shìqíng de zhēnxiàng, dǎozhì wèntí gèngjiā yánzhòng.', 'Anh ta cố tình che giấu sự thật của sự việc, khiến vấn đề trở nên nghiêm trọng hơn.'),
  ('成天', '他成天抱怨工作，却从不主动解决问题。', 'Tā chéngtiān bàoyuàn gōngzuò, què cóng bù zhǔdòng jiějué wèntí.', 'Anh ta suốt ngày than phiền công việc, nhưng không bao giờ chủ động giải quyết vấn đề.'),
  ('成员', '每个团队成员都应该积极参与项目的各项环节。', 'Měi gè tuánduì chéngyuán dōu yīnggāi jījí cānyù xiàngmù de gè xiàng huánjié.', 'Mỗi thành viên trong nhóm nên tích cực tham gia vào các khâu của dự án.'),
  ('成交', '双方经过多次谈判，最终成功成交了这笔大订单。', 'Shuāngfāng jīngguò duō cì tánpàn, zuìzhōng chénggōng chéngjiāo le zhè bǐ dà dìngdān.', 'Hai bên sau nhiều lần đàm phán cuối cùng đã thành công ký được đơn hàng lớn này.'),
  ('慈祥', '奶奶脸上总是带着慈祥的微笑，让人感到温暖。', 'Nǎinai liǎn shàng zǒng shì dàizhe cíxiáng de wēixiào, ràng rén gǎndào wēnnuǎn.', 'Trên khuôn mặt bà luôn nở nụ cười hiền từ, khiến người ta cảm thấy ấm áp.'),
  ('慈善', '他积极参与各种慈善活动，帮助有需要的人。', 'Tā jījí cānyù gè zhǒng císhàn huódòng, bāngzhù yǒu xūyào de rén.', 'Anh ấy tích cực tham gia các hoạt động từ thiện, giúp đỡ những người cần thiết.'),
  ('惩罚', '对于违纪行为，公司将采取严厉的惩罚措施。', 'Duìyú wéijì xíngwéi, gōngsī jiāng cǎiqǔ yánlì de chéngfá cuòshī.', 'Đối với hành vi vi phạm kỷ luật, công ty sẽ áp dụng các biện pháp trừng phạt nghiêm khắc.'),
  ('彩票', '他每周都会买几张彩票，希望能够中大奖。', 'Tā měi zhōu dū huì mǎi jǐ zhāng cǎipiào, xīwàng nénggòu zhòng dà jiǎng.', 'Anh ấy mỗi tuần đều mua vài tờ vé số, hy vọng có thể trúng giải lớn.'),
  ('床单', '每隔一周我都会换一次床单，保持卧室清洁。', 'Měi gé yī zhōu wǒ dū huì huàn yī cì chuángdān, bǎochí wòshì qīngjié.', 'Cứ mỗi tuần tôi thay ga giường một lần để giữ phòng ngủ sạch sẽ.'),
  ('差别', '这两种方法在效果上存在明显差别。', 'Zhè liǎng zhǒng fāngfǎ zài xiàoguǒ shàng cúnzài míngxiǎn chābié.', 'Hai phương pháp này có sự khác biệt rõ ràng về hiệu quả.'),
  ('巢穴', '鸟儿在树上的巢穴里孵蛋。', 'Niǎor zài shù shàng de cháoxué lǐ fū dàn.', 'Chim đang ấp trứng trong tổ trên cây.'),
  ('川流不息', '城市的街道上川流不息的车辆令人目不暇接。', 'Chéngshì de jiēdào shàng chuānliú bùxī de chēliàng lìng rén mùbùxiájiē.', 'Trên đường phố thành phố, dòng xe cộ tấp nập khiến người ta không kịp nhìn.'),
  ('崇高', '他的理想体现了崇高的人格追求。', 'Tā de lǐxiǎng tǐxiàn le chónggāo de réngé zhuīqiú.', 'Lý tưởng của anh ấy thể hiện sự theo đuổi phẩm cách cao cả.'),
  ('崇敬', '我们对老师充满崇敬之情。', 'Wǒmen duì lǎoshī chōngmǎn chóngjìng zhī qíng.', 'Chúng tôi đầy lòng ngưỡng mộ và tôn kính thầy cô.'),
  ('崇拜', '年轻人常常崇拜偶像歌手。', 'Niánqīng rén chángcháng chóngbài ǒuxiàng gēshǒu.', 'Giới trẻ thường rất sùng bái thần tượng ca sĩ.'),
  ('岔', '前面的路口有一个岔道，需要左转。', 'Qiánmiàn de lùkǒu yǒu yīgè chàdào, xūyào zuǒ zhuǎn.', 'Ngã rẽ phía trước có một đường rẽ, cần phải rẽ trái.'),
  ('层次', '文章的结构层次分明，逻辑清晰。', 'Wénzhāng de jiégòu céngcì fēnmíng, luójí qīngxī.', 'Cấu trúc bài viết có trình tự rõ ràng, logic mạch lạc.'),
  ('层出不穷', '科技创新层出不穷，推动社会发展。', 'Kējì chuàngxīn céngchūbùqióng, tuīdòng shèhuì fāzhǎn.', 'Các sáng tạo công nghệ xuất hiện liên tục, thúc đẩy sự phát triển xã hội.'),
  ('尝试', '他决定尝试一种新的解决问题的方法。', 'Tā juédìng chángshì yī zhǒng xīn de jiějuéfāngfǎ de fāngfǎ.', 'Anh ấy quyết định thử một phương pháp mới để giải quyết vấn đề.'),
  ('处置', '公司及时处置了发生的安全隐患。', 'Gōngsī jíshí chǔzhì le fāshēng de ānquán yǐnhuàn.', 'Công ty đã xử lý kịp thời những nguy cơ an toàn phát sinh.'),
  ('处境', '他在经济困难的处境中依然保持乐观。', 'Tā zài jīngjì kùnnán de chǔjìng zhōng yīrán bǎochí lèguān.', 'Anh ấy vẫn giữ tinh thần lạc quan dù trong hoàn cảnh kinh tế khó khăn.'),
  ('处分', '公司对违反规定的员工进行了处分。', 'Gōngsī duì wéifǎn guīdìng de yuángōng jìnxíng le chǔfèn.', 'Công ty đã trừng phạt nhân viên vi phạm quy định.'),
  ('城堡', '这座古老的城堡吸引了很多游客前来参观。', 'Zhè zuò gǔlǎo de chéngbǎo xīyǐn le hěn duō yóukè qián lái cānguān.', 'Tòa thành cổ này thu hút nhiều khách du lịch đến tham quan.'),
  ('垂直', '这面墙与地面垂直，没有任何倾斜。', 'Zhè miàn qiáng yǔ dìmiàn chuízhí, méiyǒu rènhé qīngxié.', 'Bức tường này vuông góc với mặt đất, không hề nghiêng ngả.'),
  ('场面', '婚礼的场面庄重而热烈，令人难忘。', 'Hūnlǐ de chǎngmiàn zhuāngzhòng ér rèliè, lìng rén nánwàng.', 'Cảnh đám cưới trang nghiêm và nhiệt liệt, khiến người ta khó quên.'),
  ('场所', '图书馆是学习和阅读的理想场所。', 'Túshūguǎn shì xuéxí hé yuèdú de lǐxiǎng chǎngsuǒ.', 'Thư viện là nơi lý tưởng để học tập và đọc sách.'),
  ('场合', '在正式场合要注意着装得体。', 'Zài zhèngshì chǎnghé yào zhùyì zhuózhuāng détǐ.', 'Trong những hoàn cảnh trang trọng cần chú ý ăn mặc phù hợp.'),
  ('嘲笑', '不要嘲笑别人的错误，要给予理解和帮助。', 'Bùyào cháoxiào biérén de cuòwù, yào jǐyǔ lǐjiě hé bāngzhù.', 'Đừng cười nhạo lỗi lầm của người khác, hãy thông cảm và giúp đỡ.'),
  ('嘈杂', '街道上的嘈杂声让人无法安静思考。', 'Jiēdào shàng de cáozá shēng ràng rén wúfǎ ānjìng sīkǎo.', 'Âm thanh ồn ào trên đường phố khiến người ta không thể yên tĩnh suy nghĩ.'),
  ('喘气', '他跑完比赛后气喘吁吁，需要几分钟来喘气。', 'Tā pǎo wán bǐsài hòu qì chuǎn xū xū, xūyào jǐ fēnzhōng lái chuǎn qì.', 'Anh ấy sau khi chạy xong cuộc thi thì thở dốc, cần vài phút để hít thở.'),
  ('呈现', '这幅画用色彩鲜艳的线条呈现了热闹的城市街景。', 'Zhè fú huà yòng sècǎi xiānyàn de xiàntiáo chéngxiàn le rènào de chéngshì jiējǐng.', 'Bức tranh này dùng các đường nét màu sắc rực rỡ để bày ra cảnh phố thị náo nhiệt.'),
  ('吹牛', '不要总是吹牛，你的朋友们都看得出来你在夸张。', 'Bù yào zǒng shì chuīniú, nǐ de péngyǒu men dōu kàn de chūlái nǐ zài kuāzhāng.', 'Đừng lúc nào cũng nói phét, bạn bè của bạn đều thấy rõ bạn đang nói quá.'),
  ('吹捧', '记者们对这位新导演的作品进行了过多的吹捧。', 'Jìzhě men duì zhè wèi xīn dǎoyǎn de zuòpǐn jìnxíng le guòduō de chuīpěng.', 'Các nhà báo đã tâng bốc quá mức tác phẩm của đạo diễn trẻ này.'),
  ('吃苦', '只有经历过吃苦的人才能真正体会成功的意义。', 'Zhǐ yǒu jīnglì guò chīkǔ de rén cáinéng zhēnzhèng tǐhuì chénggōng de yìyì.', 'Chỉ những người trải qua gian khổ mới có thể thực sự hiểu được ý nghĩa của thành công.'),
  ('吃力', '他最近工作太多，做事情变得非常吃力。', 'Tā zuìjìn gōngzuò tài duō, zuò shìqíng biàn de fēicháng chīlì.', 'Gần đây anh ấy có quá nhiều việc, làm việc trở nên rất tốn sức.'),
  ('参谋', '将军召集高级军官作为参谋讨论作战计划。', 'Jiāngjūn zhàojí gāojí jūnguān zuòwéi cānmóu tǎolùn zuòzhàn jìhuà.', 'Tướng quân triệu tập các sĩ quan cao cấp làm tham mưu để thảo luận kế hoạch tác chiến.'),
  ('参照', '设计图纸时应参照国家标准严格执行。', 'Shèjì túzhǐ shí yīng cānzhào guójiā biāozhǔn yángé zhíxíng.', 'Khi thiết kế bản vẽ cần tham khảo tiêu chuẩn quốc gia để thực hiện nghiêm túc.'),
  ('刺', '树上的荆棘刺破了他的手指，疼得直流血。', 'Shù shàng de jīngjí cì pò le tā de shǒuzhǐ, téng de zhí liú xuè.', 'Gai trên cây làm thủng tay anh ấy, đau đến chảy máu.'),
  ('刹那', '那一刹那的光辉永远铭刻在我的记忆里。', 'Nà yī chànà de guānghuī yǒngyuǎn míngkè zài wǒ de jìyì lǐ.', 'Khoảnh khắc chớp nhoáng đó mãi khắc sâu trong ký ức của tôi.'),
  ('初步', '我们已对市场进行了初步调查，收集了有用信息。', 'Wǒmen yǐ duì shìchǎng jìnxíng le chūbù diàochá, shōují le yǒuyòng xìnxī.', 'Chúng tôi đã tiến hành cuộc khảo sát bước đầu về thị trường, thu thập được thông tin hữu ích.'),
  ('创立', '这家公司由他于十年前创立，现已成为行业领头企业。', 'Zhè jiā gōngsī yóu tā yú shí nián qián chuànglì, xiàn yǐ chéngwéi hángyè lǐngtóu qǐyè.', 'Công ty này do anh ấy sáng lập cách đây mười năm, nay đã trở thành doanh nghiệp dẫn đầu ngành.'),
  ('创新', '只有不断创新，企业才能在激烈竞争中立于不败之地。', 'Zhǐ yǒu bùduàn chuàngxīn, qǐyè cáinéng zài jīliè jìngzhēng zhōng lì yú bù bài zhī dì.', 'Chỉ có liên tục sáng tạo, doanh nghiệp mới có thể đứng vững trong cạnh tranh gay gắt.'),
  ('创作', '这位艺术家用心创作出许多令人感动的作品。', 'Zhè wèi yìshùjiā yòngxīn chuàngzuò chū xǔduō lìng rén gǎndòng de zuòpǐn.', 'Nghệ sĩ này chăm chỉ sáng tác nhiều tác phẩm gây xúc động.'),
  ('创业', '他怀着梦想独立创业，终于开办了自己的公司。', 'Tā huáizhe mèngxiǎng dúlì chuàngyè, zhōngyú kāibàn le zìjǐ de gōngsī.', 'Anh ấy với ước mơ khởi nghiệp độc lập cuối cùng đã mở công ty riêng.'),
  ('出身', '她出身贫寒，但凭努力考上了名牌大学。', 'Tā chūshēn pínhán, dàn píng nǔlì kǎo shàng le míngpái dàxué.', 'Cô ấy xuất thân nghèo khó, nhưng nhờ cố gắng đã đậu vào trường đại học danh tiếng.'),
  ('出路', '面对困境，他努力寻找新的出路来改变现状。', 'Miànduì kùnjìng, tā nǔlì xúnzhǎo xīn de chūlù lái gǎibiàn xiànzhuàng.', 'Đối diện khó khăn, anh ấy nỗ lực tìm đường ra mới để thay đổi hiện trạng.'),
  ('出神', '听着美妙的音乐，她静静地出神，忘记了时间。', 'Tīng zhe měimiào de yīnyuè, tā jìngjìng de chū shén, wàngjì le shíjiān.', 'Nghe nhạc hay, cô ấy lặng lẽ xuất thần, quên mất thời gian.'),
  ('出息', '父母总希望孩子有出息，将来能成就一番事业。', 'Fùmǔ zǒng xīwàng háizi yǒu chūxī, jiānglái néng chéngjiù yī fān shìyè.', 'Cha mẹ luôn mong con có tiền đồ, tương lai có thể thành tựu sự nghiệp.'),
  ('出卖', '他背叛朋友，出卖了大家的秘密，令众人震惊。', 'Tā bèipàn péngyǒu, chūmài le dàjiā de mìmì, lìng zhòng rén zhènjīng.', 'Anh ta phản bội bạn bè, bán đứng bí mật của mọi người khiến mọi người kinh ngạc.'),
  ('凑合', '我们需要凑合几个人才能完成这个项目。', 'Wǒmen xūyào còuhe jǐ gèrén cáinéng wánchéng zhège xiàngmù.', 'Chúng ta cần gom góp vài người mới có thể hoàn thành dự án này.'),
  ('冲突', '两国之间因为领土问题发生了严重的冲突。', 'Liǎng guó zhī jiān yīnwèi lǐngtǔ wèntí fāshēngle yánzhòng de chōngtú.', 'Hai quốc gia đã xảy ra xung đột nghiêm trọng vì vấn đề lãnh thổ.'),
  ('冲动', '他在冲动之下做出了错误的决定。', 'Tā zài chōngdòng zhī xià zuò chūle cuòwù de juédìng.', 'Anh ta đã đưa ra quyết định sai lầm vì bồng bột.'),
  ('冲击', '地震的冲击导致建筑物严重受损。', 'Dìzhèn de chōngjī dǎozhì jiànzhùwù yánzhòng shòusǔn.', 'Cú xung kích của trận động đất đã khiến các công trình bị hư hại nghiêm trọng.'),
  ('充足', '为了完成任务，必须保证资源充足。', 'Wèile wánchéng rènwu, bìxū bǎozhèng zīyuán chōngzú.', 'Để hoàn thành nhiệm vụ, phải đảm bảo nguồn lực đầy đủ.'),
  ('充沛', '他每天都保持充沛的精力投入工作。', 'Tā měitiān dōu bǎochí chōngpèi de jīnglì tóurù gōngzuò.', 'Anh ấy mỗi ngày đều giữ được nguồn năng lượng dồi dào để làm việc.'),
  ('充当', '她在这次活动中充当了志愿者的角色。', 'Tā zài zhè cì huódòng zhōng chōngdāngle zhìyuàn zhě de juésè.', 'Cô ấy đã đảm đương vai trò tình nguyện viên trong sự kiện lần này.'),
  ('充实', '利用假期充实自己的专业知识是明智的选择。', 'Lìyòng jiàqī chōngshí zìjǐ de zhuānyè zhīshì shì míngzhì de xuǎnzé.', 'Tận dụng kỳ nghỉ để tăng cường kiến thức chuyên môn của bản thân là lựa chọn sáng suốt.'),
  ('储蓄', '他每个月都会把一部分工资储蓄起来。', 'Tā měi gè yuè dōu huì bǎ yī bùfen gōngzī chǔxù qǐlái.', 'Anh ấy hàng tháng đều dành một phần lương để gửi tiết kiệm.'),
  ('储存', '食物需要在冷藏室中储存以保持新鲜。', 'Shíwù xūyào zài lěngcáng shì zhōng chǔcún yǐ bǎochí xīnxiān.', 'Thức ăn cần được cất giữ trong tủ lạnh để giữ tươi.'),
  ('储备', '国家有足够的粮食储备应对紧急情况。', 'Guójiā yǒu zúgòu de liángshí chǔbèi yìngduì jǐnjí qíngkuàng.', 'Quốc gia có dự trữ lương thực đầy đủ để ứng phó với các tình huống khẩn cấp.'),
  ('偿还', '他努力工作是为了按时偿还贷款。', 'Tā nǔlì gōngzuò shì wèile ànshí chánghuán dàikuǎn.', 'Anh ấy chăm chỉ làm việc để trả nợ đúng hạn.'),
  ('倡议', '学校提出了节约用水的倡议，鼓励同学们参与。', 'Xuéxiào tíchūle jiéyuē yòngshuǐ de chàngyì, gǔlì tóngxuémen cānyù.', 'Trường học đã đưa ra sáng kiến tiết kiệm nước và khuyến khích học sinh tham gia.'),
  ('倡导', '环保组织倡导大家减少使用塑料袋。', 'Huánbǎo zǔzhī chàngdǎo dàjiā jiǎnshǎo shǐyòng sùliào dài.', 'Tổ chức bảo vệ môi trường khởi xướng mọi người giảm sử dụng túi nhựa.'),
  ('侧面', '照片从侧面展示了建筑的宏伟结构。', 'Zhàopiàn cóng cèmiàn zhǎnshìle jiànzhù de hóngwěi jiégòu.', 'Bức ảnh từ góc nghiêng phô bày cấu trúc hùng vĩ của tòa nhà.'),
  ('伺候', '因为生病，他的家人每天都细心伺候他。', 'Yīnwèi shēngbìng, tā de jiārén měitiān dōu xìxīn cìhòu tā.', 'Vì ốm đau, gia đình anh ấy chăm sóc anh rất chu đáo hàng ngày.'),
  ('传达', '领导会议决定后会及时传达到每个部门。', 'Lǐngdǎo huìyì juédìng hòu huì jíshí chuándá dào měi gè bùmén.', 'Sau khi lãnh đạo họp quyết định, sẽ truyền đạt kịp thời đến từng bộ phận.'),
  ('传授', '老师耐心地传授了我们写作的技巧。', 'Lǎoshī nàixīn de chuánshòule wǒmen xiězuò de jìqiǎo.', 'Giáo viên kiên nhẫn truyền thụ kỹ năng viết cho chúng tôi.'),
  ('传单', '商店发放的传单介绍了最新的促销活动。', 'Shāngdiàn fāfàng de chuándān jièshàole zuìxīn de cùxiāo huódòng.', 'Tờ rơi do cửa hàng phát tán giới thiệu chương trình khuyến mãi mới nhất.'),
  ('仓库', '公司新建了一个大型仓库以存放货物。', 'Gōngsī xīnjiànle yí gè dàxíng cāngkù yǐ cúnfàng huòwù.', 'Công ty đã xây dựng một kho lớn để lưu trữ hàng hóa.'),
  ('仓促', '他仓促地写完了这份报告，结果有很多错误。', 'Tā cāngcù de xiě wánle zhè fèn bàogào, jiéguǒ yǒu hěn duō cuòwù.', 'Anh ấy vội vã viết xong bản báo cáo này, kết quả có rất nhiều lỗi.'),
  ('从容', '面对突发情况，她表现得非常从容，不急不躁。', 'Miànduì tūfā qíngkuàng, tā biǎoxiàn de fēicháng cóngróng, bù jí bù zào.', 'Đối mặt với tình huống bất ngờ, cô ấy thể hiện rất ung dung, không vội vàng cũng không sốt ruột.'),
  ('产业', '这个城市的科技产业发展迅速，吸引了很多投资。', 'Zhège chéngshì de kējì chǎnyè fāzhǎn xùnsù, xīyǐnle hěn duō tóuzī.', 'Ngành công nghiệp công nghệ của thành phố này phát triển nhanh chóng, thu hút nhiều vốn đầu tư.'),
  ('乘', '我们计划明天早上乘高铁去上海参加会议。', 'Wǒmen jìhuà míngtiān zǎoshang chéng gāotiě qù shànghǎi cānjiā huìyì.', 'Chúng tôi dự định sáng mai sẽ đáp tàu cao tốc đi Thượng Hải tham dự hội nghị.'),
  ('串', '他买了一串葡萄和一些水果糖作为礼物。', 'Tā mǎile yī chuàn pútáo hé yīxiē shuǐguǒ táng zuòwéi lǐwù.', 'Anh ấy mua một chuỗi nho và một ít kẹo trái cây làm quà.'),
  ('丛', '花园里有一丛漂亮的玫瑰花在盛开。', 'Huāyuán lǐ yǒu yī cóng piàoliang de méiguī huā zài shèngkāi.', 'Trong vườn hoa có một bụi hoa hồng đẹp đang nở rộ.'),
  ('丑恶', '人们对这种丑恶行径表示强烈谴责。', 'Rénmen duì zhè zhǒng chǒu''è xíngjìng biǎoshì qiángliè qiǎnzé.', 'Mọi người lên án mạnh mẽ những hành động xấu xa này.'),
  ('颠簸', '长时间的颠簸让旅客感到十分疲惫。', 'Cháng shíjiān de diānbǒ ràng lǚkè gǎndào shífēn píbèi.', 'Chuyến đi dài với nhiều chỗ lắc lư đã khiến hành khách cảm thấy rất mệt mỏi.'),
  ('颠倒', '这张图片的上下颠倒了，需要重新调整。', 'Zhè zhāng túpiàn de shàngxià diāndǎo le, xūyào chóngxīn tiáozhěng.', 'Bức ảnh này bị đảo ngược trên dưới, cần phải điều chỉnh lại.'),
  ('顿时', '听到这个消息，他顿时感到非常激动和惊讶。', 'Tīngdào zhège xiāoxi, tā dùnshí gǎndào fēicháng jīdòng hé jīngyà.', 'Nghe tin này, anh ấy lập tức cảm thấy rất xúc động và ngạc nhiên.'),
  ('雕塑', '公园中央竖立着一座著名的历史人物雕塑。', 'Gōngyuán zhōngyāng shùlì zhe yī zuò zhùmíng de lìshǐ rénwù diāosù.', 'Ở trung tâm công viên dựng một bức tượng điêu khắc nhân vật lịch sử nổi tiếng.'),
  ('雕刻', '他花了三年时间雕刻了这座精美的木制艺术品。', 'Tā huāle sān nián shíjiān diāokè le zhè zuò jīngměi de mùzhì yìshùpǐn.', 'Anh ấy đã dành ba năm để điêu khắc tác phẩm nghệ thuật bằng gỗ tinh xảo này.'),
  ('陡峭', '这一条登山路非常陡峭，只有经验丰富者能通过。', 'Zhè yī tiáo dēngshān lù fēicháng dǒuqiào, zhǐyǒu jīngyàn fēngfù zhě néng tōngguò.', 'Con đường leo núi này rất dốc thẳng đứng, chỉ những người có kinh nghiệm mới có thể đi qua.'),
  ('队伍', '运动员们排着整齐的队伍进入比赛场地。', 'Yùndòngyuán men páizháo zhěngqí de duìwǔ jìnrù bǐsài chǎngdì.', 'Các vận động viên xếp thành hàng ngũ chỉnh tề tiến vào sân thi đấu.'),
  ('逮捕', '警方迅速逮捕了涉嫌盗窃的犯罪嫌疑人。', 'Jǐngfāng xùnsù dàibǔ le shèxián dàoqiè de fànzuì xiányírén.', 'Cảnh sát nhanh chóng bắt giữ nghi phạm trộm cắp.'),
  ('递增', '近年来，该公司的利润呈现递增的趋势。', 'Jìnnián lái, gāi gōngsī de lìrùn chěngxiàn dì zēng de qūshì.', 'Trong những năm gần đây, lợi nhuận của công ty này có xu hướng tăng dần.'),
  ('达成', '双方经过多次谈判，最终达成了合作协议。', 'Shuāngfāng jīngguò duō cì tánpàn, zuìzhōng dáchéng le hézuò xiéyì.', 'Hai bên sau nhiều lần đàm phán cuối cùng đã đạt được thỏa thuận hợp tác.'),
  ('蹬', '他用力蹬自行车的踏板，快速前进。', 'Tā yònglì dèng zìxíngchē de tàbǎn, kuàisù qiánjìn.', 'Anh ấy dùng sức đạp bàn đạp xe đạp, tiến về phía trước rất nhanh.'),
  ('跌', '他不小心跌倒在地，膝盖擦伤了。', 'Tā bù xiǎoxīn diēdǎo zài dì, xīgài cāshāng le.', 'Anh ấy bất cẩn té ngã xuống đất, đầu gối bị trầy xước.'),
  ('赌博', '赌博不仅浪费钱财，还容易引发家庭矛盾。', 'Dǔbó bùjǐn làngfèi qiáncái, hái róngyì yǐnfā jiātíng máodùn.', 'Cờ bạc không những lãng phí tiền bạc mà còn dễ gây ra mâu thuẫn gia đình.'),
  ('调动', '公司决定将他从销售部调动到市场部工作以发挥特长。', 'Gōngsī juédìng jiāng tā cóng xiāoshòu bù diàodòng dào shìchǎng bù gōngzuò yǐ fāhuī tècháng.', 'Công ty quyết định điều động anh ấy từ phòng bán hàng sang phòng thị trường để phát huy thế mạnh.'),
  ('诞辰', '今天是中国著名诗人的诞辰纪念日，学校举行了纪念活动。', 'Jīntiān shì Zhōngguó zhùmíng shīrén de dànchén jìniàn rì, xuéxiào jǔxíng le jìniàn huódòng.', 'Hôm nay là ngày sinh nhật của nhà thơ nổi tiếng Trung Quốc, trường tổ chức hoạt động kỷ niệm.'),
  ('诞生', '这个城市的现代工业正是在二十世纪初诞生的。', 'Zhège chéngshì de xiàndài gōngyè zhèng shì zài èrshí shìjì chū dànshēng de.', 'Ngành công nghiệp hiện đại của thành phố này chính là ra đời vào đầu thế kỷ 20.'),
  ('蛋白质', '人体需要摄入足够的蛋白质来维持正常的生理功能。', 'Réntǐ xūyào shèrù zúgòu de dànbáizhì lái wéichí zhèngcháng de shēnglǐ gōngnéng.', 'Cơ thể con người cần hấp thụ đủ protein để duy trì chức năng sinh lý bình thường.'),
  ('董事长', '新任董事长在会上发表了激动人心的演讲，获得大家认可。', 'Xīn rèn dǒngshìzhǎng zài huì shàng fābiǎo le jīdòng rénxīn de yǎnjiǎng, huòdé dàjiā rènkě.', 'Chủ tịch hội đồng quản trị mới đã có bài phát biểu đầy cảm hứng tại cuộc họp và được mọi người công nhận.'),
  ('胆怯', '面对陌生人，他表现得有些胆怯，不敢主动说话。', 'Miànduì mòshēng rén, tā biǎoxiàn de yǒuxiē dǎnqiè, bù gǎn zhǔdòng shuōhuà.', 'Đối mặt với người lạ, anh ấy biểu hiện hơi nhút nhát, không dám chủ động nói chuyện.'),
  ('答辩', '毕业生们紧张地准备着即将到来的论文答辩环节。', 'Bìyè shēngmen jǐnzhāng de zhǔnbèi zhe jíjiāng dàolái de lùnwén dábiàn huánjié.', 'Các sinh viên tốt nghiệp đang chuẩn bị căng thẳng cho phần bảo vệ luận văn sắp tới.'),
  ('答复', '老板很快给了邮件的答复，明确了项目的下一步计划。', 'Lǎobǎn hěn kuài gěi le yóujiàn de dáfù, míngquè le xiàngmù de xià yībù jìhuà.', 'Ông chủ đã nhanh chóng trả lời thư điện tử, làm rõ kế hoạch bước tiếp của dự án.'),
  ('等级', '这款软件按照功能复杂度被划分为不同的等级类别。', 'Zhè kuǎn ruǎnjiàn ànzhào gōngnéng fùzá dù bèi huàfēn wéi bùtóng de děngjí lèibié.', 'Phần mềm này được phân loại theo các cấp bậc khác nhau dựa trên độ phức tạp của chức năng.'),
  ('等候', '乘客们在车站耐心等候巴士的到来，准备开始旅程。', 'Chéngkè men zài chēzhàn nàixīn děnghòu bāshì de dàolái, zhǔnbèi kāishǐ lǚchéng.', 'Hành khách kiên nhẫn chờ đợi xe buýt đến ở bến để chuẩn bị bắt đầu hành trình.'),
  ('端正', '他为人端正，工作认真，深受同事和领导的好评。', 'Tā wéirén duānzhèng, gōngzuò rènzhēn, shēn shòu tóngshì hé lǐngdǎo de hǎopíng.', 'Anh ấy là người đoan chính, làm việc nghiêm túc, được đồng nghiệp và lãnh đạo đánh giá cao.'),
  ('端午节', '每年端午节，我们都会一起包粽子纪念屈原的爱国精神。', 'Měi nián Duānwǔ Jié, wǒmen dōu huì yīqǐ bāo zòngzi jìniàn Qū Yuán de àiguó jīngshén.', 'Mỗi năm Tết Đoan Ngọ, chúng tôi đều cùng nhau gói bánh chưng để tưởng nhớ tinh thần yêu nước của Khuất Nguyên.'),
  ('端', '服务员端着一盘热气腾腾的菜走进了餐厅。', 'Fúwùyuán duān zhe yì pán rè qì téngténg de cài zǒu jìn le cāntīng.', 'Bồi bàn bê một đĩa thức ăn nóng hổi bước vào nhà hàng.'),
  ('稻谷', '秋天到了，农民们忙着收割成熟的稻谷。', 'Qiūtiān dào le, nóngmín men máng zhe shōugē chéngshú de dàogǔ.', 'Mùa thu đến rồi, nông dân đang bận thu hoạch hạt thóc chín.'),
  ('短促', '会议时间很短促，大家需要迅速讨论并作出决定。', 'Huìyì shíjiān hěn duǎncù, dàjiā xūyào xùnsù tǎolùn bìng zuò chū juédìng.', 'Thời gian họp rất ngắn, mọi người cần nhanh chóng thảo luận và đưa ra quyết định.'),
  ('瞪', '他因为被误解而气愤，瞪着对方不说话。', 'Tā yīnwèi bèi wùjiě ér qìfèn, dèng zhe duìfāng bù shuōhuà.', 'Anh ấy tức giận vì bị hiểu lầm, trợn mắt nhìn đối phương không nói lời nào.'),
  ('督促', '老师每天都会督促学生按时完成作业。', 'Lǎoshī měitiān dūhu cu xú shēng ànshí wánchéng zuòyè.', 'Giáo viên hàng ngày đôn đốc học sinh hoàn thành bài tập đúng hạn.'),
  ('盯', '他盯着电脑屏幕，专心致志地完成工作。', 'Tā dīng zhe diànnǎo píngmù, zhuānxīn zhìzhì de wánchéng gōngzuò.', 'Anh ấy nhìn chằm chằm vào màn hình máy tính, tập trung làm xong công việc.'),
  ('盗窃', '警方成功抓获了一伙涉嫌盗窃的犯罪分子。', 'Jǐngfāng chénggōng zhuāhuò le yī huǒ shèxián dàoqiè de fànzuì fènzǐ.', 'Cảnh sát đã bắt giữ thành công một nhóm tội phạm nghi ngờ trộm cắp.'),
  ('登陆', '军队在黎明时分顺利完成了敌方海岸的登陆行动。', 'Jūnduì zài límíng shífēn shùnlì wánchéng le dífāng hǎi''àn de dēnglù xíngdòng.', 'Quân đội đã hoàn thành suôn sẻ cuộc đổ bộ vào bờ biển địch vào lúc bình minh.'),
  ('登录', '请您先登录账户才能继续操作。', 'Qǐng nín xiān dēng lù zhàng hù cái néng jì xù cāo zuò.', 'Xin bạn vui lòng đăng nhập tài khoản trước khi tiếp tục thao tác.'),
  ('电源', '电脑出现问题时，请检查电源是否已连接。', 'Diàn nǎo chū xiàn wèn tí shí, qǐng jiǎn chá diàn yuán shì fǒu yǐ lián jiē.', 'Khi máy tính gặp vấn đề, hãy kiểm tra xem nguồn điện đã được kết nối hay chưa.'),
  ('独裁', '历史上许多独裁政权都以镇压异见为特征。', 'Lì shǐ shàng xǔ duō dú cái zhèng quán dōu yǐ zhèn yā yì jiàn wéi tè zhēng.', 'Trong lịch sử, nhiều chế độ độc tài đều có đặc điểm là đàn áp ý kiến khác.'),
  ('点缀', '她用鲜花点缀了整个房间，使气氛更加温馨。', 'Tā yòng xiān huā diǎn zhuì le zhěng gè fáng jiān, shǐ qì fēn gèng jiā wēn xīn.', 'Cô ấy dùng hoa tươi để tô điểm toàn bộ căn phòng, làm không khí thêm ấm áp.'),
  ('灯笼', '中秋节夜晚，我们一起挂起了红色的灯笼。', 'Zhōng qiū jié yè wǎn, wǒ men yī qǐ guà qǐ le hóng sè de dēng lóng.', 'Đêm Trung thu, chúng tôi cùng nhau treo đèn lồng đỏ.'),
  ('淡水', '这座城市的饮用水主要来自附近的淡水湖。', 'Zhè zuò chéng shì de yǐn yòng shuǐ zhǔ yào lái zì fù jìn de dàn shuǐ hú.', 'Nước uống chính của thành phố này chủ yếu đến từ hồ nước ngọt gần đó.'),
  ('淡季', '旅游淡季时，景点的门票价格会有所下降。', 'Lǚ yóu dàn jì shí, jǐng diǎn de mén piào jià gé huì yǒu suǒ xià jiàng.', 'Vào mùa trái mùa du lịch, giá vé vào các điểm tham quan sẽ giảm.'),
  ('毒品', '政府加大力度打击毒品贩运和吸食行为。', 'Zhèng fǔ jiā dà lì dù dǎ jí dú pǐn fàn yùn hé xī shí xíng wéi.', 'Chính phủ tăng cường mạnh tay triệt phá hoạt động buôn bán và sử dụng ma túy.'),
  ('歹徒', '街头歹徒抢劫了路人的钱包后迅速逃离。', 'Jiē tóu dǎi tú qiǎng jié le lù rén de qián bāo hòu xùn sù táo lí.', 'Tên vô lại trên đường phố cướp bóp ví của người đi đường rồi nhanh chóng bỏ chạy.'),
  ('档次', '这款汽车的档次比上一代有了显著提升。', 'Zhè kuǎn qì chē de dàng cì bǐ shàng yī dài yǒu le xiǎn zhù tí shēng.', 'Mức đẳng cấp của mẫu ô tô này đã được nâng cao rõ rệt so với thế hệ trước.'),
  ('档案', '员工的个人档案应保存在公司秘书处。', 'Yuán gōng de gè rén dàng àn yīng bǎo cún zài gōng sī mì shū chù.', 'Hồ sơ cá nhân của nhân viên nên được lưu tại phòng thư ký công ty.'),
  ('栋', '新建的小区里有十栋现代化的住宅楼。', 'Xīn jiàn de xiǎo qū lǐ yǒu shí dòng xiàn dài huà de zhù zhái lóu.', 'Khu chung cư mới xây có mười tòa nhà dân cư hiện đại.'),
  ('杜绝', '为了杜绝浪费，工厂采取了严格的节能措施。', 'Wèi le dù jué làng fèi, gōng chǎng cǎi qǔ le yán gé de jié néng cuò shī.', 'Để chặn đứng lãng phí, nhà máy đã áp dụng các biện pháp tiết kiệm năng lượng nghiêm ngặt.'),
  ('断绝', '他们因误会而断绝了多年的友谊。', 'Tā men yīn wù huì ér duàn jué le duō nián de yǒu yì.', 'Vì hiểu lầm mà họ đã cắt đứt tình bạn nhiều năm trời.'),
  ('断定', '根据现有证据，警方断定嫌疑人是罪犯。', 'Gēn jù xiàn yǒu zhèng jù, jǐng fāng duàn dìng xián yí rén shì zuì fàn.', 'Dựa trên bằng chứng hiện có, cảnh sát dám chắc nghi phạm là tội phạm.'),
  ('斗争', '工人们为了权益展开了长期的斗争。', 'Gōng rén men wèi le quán yì zhǎn kāi le cháng qī de dòu zhēng.', 'Công nhân đã tiến hành cuộc đấu tranh dài hạn vì quyền lợi.'),
  ('敌视', '双方因为利益冲突而产生了敌视情绪。', 'Shuāng fāng yīn wèi lì yì chōng tū ér chǎn shēng le dí shì qíng xù.', 'Hai bên nảy sinh cảm xúc thù địch do xung đột lợi ích.'),
  ('搭配', '这件衣服和那双鞋子搭配得非常协调。', 'Zhè jiàn yī fú hé nà shuāng xié zi dā pèi dé fēi cháng xié tiáo.', 'Chiếc áo này kết hợp với đôi giày kia rất hài hòa.'),
  ('搭档', '这次比赛中，他们作为搭档表现得非常出色。', 'Zhè cì bǐ sài zhōng, tā men zuò wéi dā dàng biǎo xiàn dé fēi cháng chū sè.', 'Trong cuộc thi lần này, họ thể hiện rất xuất sắc với tư cách là người hợp tác.'),
  ('搭', '他用木头搭了一个简易的房子。', 'Tā yòng mù tóu dā le yī gè jiǎn yì de fáng zi.', 'Anh ta dùng gỗ để đắp một ngôi nhà đơn giản.'),
  ('捣乱', '小孩子在教室里捣乱，影响了大家的学习情绪。', 'Xiǎo háizi zài jiàoshì lǐ dǎoluàn, yǐngxiǎng le dàjiā de xuéxí qíngxù.', 'Đứa trẻ đang phá đám trong lớp học, ảnh hưởng đến tinh thần học tập của mọi người.'),
  ('担保', '他敢担保这款产品的质量绝对可靠。', 'Tā gǎn dānbǎo zhè kuǎn chǎnpǐn de zhìliàng juéduì kěkào.', 'Anh ấy dám đảm bảo chất lượng sản phẩm này tuyệt đối đáng tin cậy.'),
  ('抵达', '飞机将在下午三点准时抵达机场。', 'Fēijī jiāng zài xiàwǔ sān diǎn zhǔnshí dǐdá jīchǎng.', 'Máy bay sẽ đến sân bay đúng giờ vào lúc 3 giờ chiều.'),
  ('抵抗', '士兵们奋力抵抗敌军的进攻，守卫阵地。', 'Shìbīngmen fènlì dǐkàng dí jūn de jìngōng, shǒuwèi zhèndì.', 'Binh sĩ nỗ lực chống lại cuộc tấn công của quân địch, bảo vệ trận địa.'),
  ('抵制', '消费者联合抵制那些存在质量问题的产品。', 'Xiāofèi zhě liánhé dǐzhì nàxiē cúnzài zhìliàng wèntí de chǎnpǐn.', 'Người tiêu dùng cùng nhau ngăn chặn những sản phẩm có vấn đề về chất lượng.'),
  ('打量', '他悄悄地打量新同事的穿着和举止。', 'Tā qiāoqiāo de dǎliang xīn tóngshì de chuānzhuó hé jǔzhǐ.', 'Anh ấy âm thầm thăm dò cách ăn mặc và cử chỉ của đồng nghiệp mới.'),
  ('打猎', '爷爷小时候常常和朋友一起去山里打猎。', 'Yéyé xiǎoshíhòu chángcháng hé péngyǒu yìqǐ qù shān lǐ dǎliè.', 'Ông thường cùng bạn bè đi săn bắn trong rừng lúc còn nhỏ.'),
  ('打架', '学校禁止学生在校园里打架斗殴。', 'Xuéxiào jìnzhǐ xuéshēng zài xiàoyuán lǐ dǎjià dòu''ōu.', 'Trường học cấm học sinh đánh nhau trong khuôn viên trường.'),
  ('打官司', '因为合同纠纷，他们决定通过打官司解决问题。', 'Yīnwèi hétóng jiūfēn, tāmen juédìng tōngguò dǎ guānsī jiějué wèntí.', 'Do tranh chấp hợp đồng, họ quyết định giải quyết vấn đề bằng cách kiện tụng.'),
  ('打包', '餐厅服务员帮我们把剩菜打包带走。', 'Cāntīng fúwùyuán bāng wǒmen bǎ shèng cài dǎbāo dài zǒu.', 'Nhân viên nhà hàng giúp chúng tôi đóng hộp món ăn thừa để mang về.'),
  ('打击', '这次事件严重打击了公司的声誉。', 'Zhè cì shìjiàn yánzhòng dǎjī le gōngsī de shēngyù.', 'Sự kiện lần này đã đả kích nghiêm trọng đến uy tín công ty.'),
  ('打仗', '古代军队常常在边境地区打仗保卫国家。', 'Gǔdài jūnduì chángcháng zài biānjìng dìqū dǎzhàng bǎowèi guójiā.', 'Quân đội thời cổ đại thường đánh nhau ở biên giới để bảo vệ quốc gia.'),
  ('惦记', '她总是惦记远方的家人，时常打电话问候。', 'Tā zǒng shì diànjì yuǎnfāng de jiārén, shícháng dǎ diànhuà wènhòu.', 'Cô ấy luôn nghĩ đến gia đình ở xa và thường xuyên gọi điện hỏi thăm.'),
  ('怠慢', '他对客人表现得有些怠慢，让人感觉不舒服。', 'Tā duì kèrén biǎoxiàn de yǒuxiē dàimàn, ràng rén gǎnjué bù shūfú.', 'Anh ấy đối xử lạnh nhạt với khách khiến người ta cảm thấy không thoải mái.'),
  ('得罪', '我无意得罪你，如果有什么误会请告诉我。', 'Wǒ wúyì dézuì nǐ, rúguǒ yǒu shénme wùhuì qǐng gàosù wǒ.', 'Tôi không cố ý đắc tội với bạn, nếu có hiểu lầm gì xin hãy nói với tôi.'),
  ('得天独厚', '这片土地得天独厚，适合种植各种作物。', 'Zhè piàn tǔdì détiān dúhòu, shìhé zhòngzhí gè zhǒng zuòwù.', 'Mảnh đất này được ưu ái thiên nhiên, thích hợp để trồng các loại cây trồng.'),
  ('得力', '他在工作中得力助手的支持，效率大大提高。', 'Tā zài gōngzuò zhōng délì zhùshǒu de zhīchí, xiàolǜ dàdà tígāo.', 'Anh ấy được trợ thủ đắc lực ủng hộ trong công việc, hiệu suất tăng lên đáng kể.'),
  ('得不偿失', '盲目投资可能会得不偿失，必须谨慎考虑。', 'Mángmù tóuzī kěnéng huì débùchángshī, bìxū jǐnshèn kǎolǜ.', 'Đầu tư mù quáng có thể lợi ít hại nhiều, phải phải suy nghĩ thận trọng.'),
  ('当面', '请你当面向他道歉，解决误会比较有效。', 'Qǐng nǐ dāngmiàn xiàng tā dàoqiàn, jiějué wùhuì bǐjiào yǒuxiào.', 'Xin bạn hãy xin lỗi anh ấy trước mặt để giải quyết hiểu lầm hiệu quả hơn.'),
  ('当选', '他成功当选为学生会主席，获得大家认可。', 'Tā chénggōng dāngxuǎn wèi xuéshēng huì zhǔxí, huòdé dàjiā rènkě.', 'Anh ấy thành công trúng cử chức chủ tịch hội sinh viên, được mọi người công nhận.'),
  ('当场', '事故发生后，警方立即进行了当场调查。', 'shì gù fā shēng hòu ， jǐng fāng lì jí jìn xíng le dāng chǎng diào chá 。', 'Sau khi tai nạn xảy ra, cảnh sát đã tiến hành điều tra tại chỗ ngay lập tức.'),
  ('当务之急', '面对疫情扩散，控制传播成为当务之急。', 'miàn duì yì qíng kuò sàn ， kòng zhì chuán bō chéng wéi dāng wù zhī jí 。', 'Trước sự lây lan của dịch bệnh, kiểm soát truyền nhiễm trở thành việc cấp bách.'),
  ('当前', '当前经济形势复杂，需要谨慎应对。', 'dāng qián jīng jì xíng shì fù zá ， xū yào jǐn shèn yìng duì 。', 'Hiện nay tình hình kinh tế phức tạp, cần phải ứng phó thận trọng.'),
  ('当初', '我当初没想到事情会发展成这样。', 'wǒ dāng chū méi xiǎng dào shì qíng huì fā zhǎn chéng zhè yàng 。', 'Lúc đầu tôi không nghĩ sự việc sẽ phát triển như thế này.'),
  ('当代', '当代艺术反映了社会多样化的特点。', 'dāng dài yì shù fǎn yìng le shè huì duō yàng huà de tè diǎn 。', 'Nghệ thuật đương đại phản ánh đặc điểm đa dạng của xã hội.'),
  ('当事人', '法庭上当事人陈述了自己的观点。', 'fǎ tíng shàng dāng shì rén chén shù le zì jǐ de guān diǎn 。', 'Người đương sự đã trình bày quan điểm của mình tại tòa.'),
  ('带领', '老师带领学生参观了博物馆的展览。', 'lǎo shī dài lǐng xué shēng cān guān le bó wù guǎn de zhǎn lǎn 。', 'Giáo viên dẫn dắt học sinh tham quan triển lãm bảo tàng.'),
  ('导航', '这款手机应用可以帮助用户实时导航。', 'zhè kuǎn shǒu jī yìng yòng kě yǐ bāng zhù yòng hù shí shí dǎo háng 。', 'Ứng dụng trên điện thoại này có thể giúp người dùng chỉ đường theo thời gian thực.'),
  ('导弹', '新型导弹具备更高的精准打击能力。', 'xīn xíng dǎo dàn jù bèi gèng gāo de jīng zhǔn dǎ jī néng lì 。', 'Tên lửa mới có khả năng tấn công chính xác cao hơn.'),
  ('导向', '这次培训的内容主要导向提高团队合作能力。', 'zhè cì péi xùn de nèi róng zhǔ yào dǎo xiàng tí gāo tuán duì hé zuò néng lì 。', 'Nội dung đào tạo lần này chủ yếu hướng dẫn nâng cao khả năng hợp tác nhóm.'),
  ('对联', '春节期间，人们喜欢在门口贴对联。', 'chūn jié qī jiān ， rén men xǐ huān zài mén kǒu tiē duì lián 。', 'Trong thời gian Tết Nguyên đán, mọi người thích dán câu đối ở cửa.'),
  ('对策', '公司针对市场变化制定了有效的对策。', 'gōng sī zhēn duì shì chǎng biàn huà zhì dìng le yǒu xiào de duì cè 。', 'Công ty đã xây dựng các đối sách hiệu quả nhằm thích ứng với biến động thị trường.'),
  ('对立', '政治观点的对立导致了激烈的争论。', 'zhèng zhì guān diǎn de duì lì dǎo zhì le jī liè de zhēng lùn 。', 'Sự đối lập trong quan điểm chính trị dẫn đến các cuộc tranh luận gay gắt.'),
  ('对称', '建筑的设计追求完美的对称美感。', 'jiàn zhù de shè jì zhuī qiú wán měi de duì chèn měi gǎn 。', 'Thiết kế kiến trúc theo đuổi vẻ đẹp đối xứng hoàn hảo.'),
  ('对照', '我们需要对照标准来评估工作进展。', 'wǒ men xū yào duì zhào biāo zhǔn lái píng gū gōng zuò jìn zhǎn 。', 'Chúng ta cần đối chiếu theo tiêu chuẩn để đánh giá tiến độ công việc.'),
  ('对抗', '两国之间的经济对抗加剧了贸易紧张。', 'liǎng guó zhī jiān de jīng jì duì kàng jiā jù le mào yì jǐn zhāng 。', 'Cuộc đối kháng kinh tế giữa hai nước làm gia tăng căng thẳng thương mại.'),
  ('对应', '每个学生都有对应的导师负责指导。', 'měi gè xué shēng dōu yǒu duì yìng de dǎo shī fù zé zhǐ dǎo 。', 'Mỗi học sinh đều có một người hướng dẫn tương ứng chịu trách nhiệm chỉ dẫn.'),
  ('对付', '面对压力，他学会了有效地对付困难。', 'miàn duì yā lì ， tā xué huì le yǒu xiào de duì fù kùn nán 。', 'Đối mặt với áp lực, anh ấy đã học cách đối phó hiệu quả với khó khăn.'),
  ('定期', '我们建议客户定期检查设备的运行状况。', 'wǒ men jiàn yì kè hù dìng qī jiǎn chá shè bèi de yùn xíng zhuàng kuàng 。', 'Chúng tôi khuyên khách hàng định kỳ kiểm tra tình trạng vận hành thiết bị.'),
  ('定义', '科学家对这个现象提供了新的定义。', 'kē xué jiā duì zhè ge xiàn xiàng tí gōng le xīn de dìng yì 。', 'Các nhà khoa học đã đưa ra định nghĩa mới về hiện tượng này.'),
  ('奠定', '这次合作为公司的未来发展奠定了坚实的基础。', 'Zhè cì hézuò wèi gōngsī de wèilái fāzhǎn diàndìngle jiānshí de jīchǔ.', 'Lần hợp tác này đã đặt nền móng vững chắc cho sự phát triển tương lai của công ty.'),
  ('大致', '我大致了解了会议的内容，但细节还需要讨论。', 'Wǒ dàzhì liǎojiěle huìyì de nèiróng, dàn xìjié hái xūyào tǎolùn.', 'Tôi đại khái đã hiểu nội dung cuộc họp, nhưng chi tiết thì vẫn cần thảo luận.'),
  ('大臣', '古代的大臣们常常会向皇帝进言建策。', 'Gǔdài de dàchénmen chángcháng huì xiàng huángdì jìnyán jiàncè.', 'Các đại thần thời xưa thường hay góp ý với hoàng đế và đề xuất kế sách.'),
  ('大肆', '他们在公共场合大肆宣传自己的产品和服务。', 'Tāmen zài gōnggòng chǎnghé dà sì xuānchuán zìjǐ de chǎnpǐn hé fúwù.', 'Họ công khai không kiêng dè quảng bá sản phẩm và dịch vụ của mình ở nơi công cộng.'),
  ('大意', '因为大意，他忘记了带重要的文件。', 'Yīnwèi dàyì, tā wàngjìle dài zhòngyào de wénjiàn.', 'Vì sơ ý, anh ấy đã quên mang theo tài liệu quan trọng.'),
  ('大体', '这份报告大体反映了当前经济的状况。', 'Zhè fèn bàogào dàtǐ fǎnyìngle dāngqián jīngjì de zhuàngkuàng.', 'Báo cáo này nhìn chung phản ánh tình hình kinh tế hiện tại.'),
  ('大伙儿', '大伙儿一起去公园野餐，天气非常好。', 'Dàhuǒr yīqǐ qù gōngyuán yěcān, tiānqì fēicháng hǎo.', 'Mọi người cùng nhau đi dã ngoại ở công viên, thời tiết rất đẹp.'),
  ('大不了', '这次迟到没关系，大不了下次注意就好了。', 'Zhè cì chídào méi guānxi, dàbùliǎo xià cì zhùyì jiù hǎole.', 'Lần này đến muộn cũng không sao, chẳng qua lần sau chú ý là được.'),
  ('多元化', '为了适应市场需求，公司开始推行多元化战略。', 'Wèile shìyìng shìchǎng xūqiú, gōngsī kāishǐ tuīxíng duōyuánhuà zhànlüè.', 'Để thích ứng với nhu cầu thị trường, công ty bắt đầu triển khai chiến lược đa nguyên hóa.'),
  ('堵塞', '早高峰时段，这条路经常因为交通堵塞而缓慢。', 'Zǎo gāofēng shíduàn, zhè tiáo lù jīngcháng yīnwèi jiāotōng dǔsè ér huǎnmàn.', 'Vào giờ cao điểm sáng, con đường này thường bị tắc nghẽn giao thông nên rất chậm.'),
  ('堤坝', '洪水来临时，堤坝起到了重要的防护作用。', 'Hóngshuǐ láilín shí, dībà qǐdàole zhòngyào de fánghù zuòyòng.', 'Khi lũ lụt đến, đê điều đã phát huy vai trò bảo vệ quan trọng.'),
  ('堕落', '如果不及时改正错误，人的品德可能会堕落。', 'Rúguǒ bù jíshí gǎizhèng cuòwù, rén de pǐndé kěnéng huì duòluò.', 'Nếu không sửa chữa sai lầm kịp thời, phẩm đức của con người có thể sẽ sa đọa.'),
  ('堆积', '仓库里堆积了很多货物，空间变得非常狭小。', 'Cāngkù lǐ duījīle hěn duō huòwù, kōngjiān biàn de fēicháng xiáxiǎo.', 'Trong kho chất đống rất nhiều hàng hóa làm không gian trở nên rất chật hẹp.'),
  ('垫', '他在椅子上垫了一个小垫子以增加舒适感。', 'Tā zài yǐzi shàng diànle yí ge xiǎo diànzi yǐ zēngjiā shūshì gǎn.', 'Anh ta để một cái đệm nhỏ trên ghế để tăng cảm giác thoải mái.'),
  ('地质', '这个地区的地质结构复杂，需要进行详细勘测。', 'Zhège dìqū de dìzhì jiégòu fùzá, xūyào jìnxíng xiángxì kāncè.', 'Cấu trúc địa chất của khu vực này phức tạp, cần tiến hành khảo sát chi tiết.'),
  ('地步', '经过长时间的争论，问题终于解决到了满意的地步。', 'Jīngguò cháng shíjiān de zhēnglùn, wèntí zhōngyú jiějué dào le mǎnyì de dìbù.', 'Sau một thời gian dài tranh luận, vấn đề cuối cùng đã được giải quyết đến mức hài lòng.'),
  ('地势', '这片地区的地势起伏很大，不适合大规模建设。', 'Zhè piàn dìqū de dìshì qǐfú hěn dà, bù shìhé dà guīmó jiànshè.', 'Địa thế của khu vực này nhấp nhô rất lớn, không phù hợp để xây dựng quy mô lớn.'),
  ('哆嗦', '寒冷的冬天让他全身都哆嗦不停。', 'Hánlěng de dōngtiān ràng tā quánshēn dōu duōsuō bùtíng.', 'Mùa đông lạnh khiến toàn thân anh ấy run cầm cập không ngừng.'),
  ('吊', '工人们正在用吊车把重物吊到高处。', 'Gōngrénmen zhèngzài yòng diàochē bǎ zhòngwù diào dào gāochù.', 'Công nhân đang dùng cần cẩu để móc đồ nặng lên cao.'),
  ('叼', '小狗叼着玩具跑来跑去，看起来很开心。', 'Xiǎo gǒu diāo zhe wánjù pǎo lái pǎo qù, kàn qǐlái hěn kāixīn.', 'Chú chó nhỏ ngậm đồ chơi chạy tới chạy lui, trông rất vui vẻ.'),
  ('叮嘱', '妈妈一再叮嘱我出门要注意安全。', 'Māmā yīzài dīngzhǔ wǒ chūmén yào zhùyì ānquán.', 'Mẹ liên tục căn dặn tôi khi ra ngoài phải chú ý an toàn.'),
  ('动静', '半夜里房间里突然传来了奇怪的动静。', 'Bànyè lǐ fángjiān lǐ túrán chuán lái le qíguài de dòngjìng.', 'Lúc nửa đêm, trong phòng bỗng nhiên phát ra động tĩnh lạ.'),
  ('动身', '我们准备明天一早动身去旅游。', 'Wǒmen zhǔnbèi míngtiān yī zǎo dòngshēn qù lǚyóu.', 'Chúng tôi chuẩn bị sáng mai khởi hành đi du lịch.'),
  ('动荡', '政治动荡导致经济发展缓慢。', 'Zhèngzhì dòngdàng dǎozhì jīngjì fāzhǎn huǎnmàn.', 'Biến động chính trị dẫn đến phát triển kinh tế chậm chạp.'),
  ('动脉', '医生说他动脉有堵塞，需要手术治疗。', 'Yīshēng shuō tā dòngmài yǒu dǔsè, xūyào shǒushù zhìliáo.', 'Bác sĩ nói động mạch của anh ấy bị tắc, cần phẫu thuật điều trị.'),
  ('动机', '调查发现他的犯罪动机十分复杂。', 'Diàochá fāxiàn tā de fànzuì dòngjī shífēn fùzá.', 'Cuộc điều tra phát hiện động cơ phạm tội của anh ta rất phức tạp.'),
  ('动手', '只讨论不如动手实践才能学到真正的技能。', 'Zhǐ tǎolùn bùrú dòngshǒu shíjiàn cáinéng xué dào zhēnzhèng de jìnéng.', 'Chỉ thảo luận không bằng bắt tay thực hành mới học được kỹ năng thật sự.'),
  ('动态', '他时刻关注市场的最新动态以调整策略。', 'Tā shíkè guānzhù shìchǎng de zuìxīn dòngtài yǐ tiáozhěng cèlüè.', 'Anh ấy luôn theo dõi động thái mới nhất của thị trường để điều chỉnh chiến lược.'),
  ('动员', '学校动员全体师生参加环保志愿活动。', 'Xuéxiào dòngyuán quántǐ shīshēng cānjiā huánbǎo zhìyuàn huódòng.', 'Trường huy động tất cả giáo viên và học sinh tham gia hoạt động tình nguyện bảo vệ môi trường.'),
  ('动力', '他的成功给了我继续努力的动力。', 'Tā de chénggōng gěi le wǒ jìxù nǔlì de dònglì.', 'Thành công của anh ta đã cho tôi động lực tiếp tục cố gắng.'),
  ('冻结', '银行账户因为涉嫌违法行为被暂时冻结。', 'Yínháng zhànghù yīnwèi shèxián wéifǎ xíngwéi bèi zànshí dòngjié.', 'Tài khoản ngân hàng bị tạm thời đóng băng vì nghi ngờ hành vi vi phạm pháp luật.'),
  ('典礼', '毕业典礼上，校长发表了热情洋溢的讲话。', 'Bìyè diǎnlǐ shàng, xiàozhǎng fābiǎo le rèqíng yángyì de jiǎnghuà.', 'Tại lễ tốt nghiệp, hiệu trưởng đã có bài phát biểu đầy nhiệt huyết.'),
  ('典型', '他是勇敢面对困难的典型代表。', 'Tā shì yǒnggǎn miànduì kùnnán de diǎnxíng dàibiǎo.', 'Anh ấy là đại diện điển hình của người dũng cảm đối mặt với khó khăn.'),
  ('兜', '他在裤子兜里放了一把钥匙。', 'Tā zài kùzi dōu lǐ fàng le yī bǎ yàoshi.', 'Anh ấy để một chiếc chìa khóa trong túi quần.'),
  ('党', '她积极参加党的各项活动，表现出高度责任感。', 'Tā jījí cānjiā dǎng de gè xiàng huódòng, biǎoxiàn chū gāodù zérèn gǎn.', 'Cô ấy tích cực tham gia các hoạt động của đảng, thể hiện tinh thần trách nhiệm cao.'),
  ('兑现', '公司承诺的奖金将在月底兑现给员工。', 'Gōngsī chéngnuò de jiǎngjīn jiāng zài yuèdǐ duìxiàn gěi yuángōng.', 'Tiền thưởng mà công ty hứa sẽ được thực hiện và trao cho nhân viên vào cuối tháng.'),
  ('倒闭', '经济不景气导致多家小企业纷纷倒闭。', 'Jīngjì bù jǐngqì dǎozhì duō jiā xiǎo qǐyè fēnfēn dǎobì.', 'Tình hình kinh tế ảm đạm khiến nhiều doanh nghiệp nhỏ lần lượt đóng cửa.'),
  ('代理', '他被公司授权代理销售新产品。', 'Tā bèi gōngsī shòuquán dàilǐ xiāoshòu xīn chǎnpǐn.', 'Anh ta được công ty ủy quyền đại diện bán sản phẩm mới.'),
  ('代价', '为了成功，他付出了巨大的代价。', 'Wèile chénggōng, tā fùchū le jùdà de dàijià.', 'Để thành công, anh ấy đã phải trả giá rất đắt.'),
  ('丢人', '在公众场合出丑真是太丢人了。', 'Zài gōngzhòng chǎnghé chūchǒu zhēn shì tài diūrén le.', 'Bị hớ hênh trước đám đông thật sự rất mất mặt.'),
  ('丢三落四', '他总是丢三落四，经常忘记带钥匙和手机。', 'Tā zǒng shì diū sān là sì, jīngcháng wàngjì dài yàoshi hé shǒujī.', 'Anh ấy luôn hay quên, thường quên mang chìa khóa và điện thoại.'),
  ('东道主', '作为东道主，我们应该热情接待每一位客人。', 'Zuòwéi dōngdàozhǔ, wǒmen yīnggāi rèqíng jiēdài měi yī wèi kèrén.', 'Là chủ nhà, chúng ta nên nhiệt tình tiếp đón mỗi vị khách.'),
  ('东张西望', '小孩子在教室里东张西望，根本没专心听讲。', 'Xiǎo háizi zài jiàoshì lǐ dōngzhāngxīwàng, gēnběn méi zhuānxīn tīngjiǎng.', 'Đứa trẻ trong lớp nhìn quanh nhìn quất, hoàn toàn không chăm chú nghe giảng.'),
  ('丁', '建筑工地上需要很多丁来完成安装工作。', 'Jiànzhù gōngdì shàng xūyào hěn duō dīng lái wánchéng ānzhuāng gōngzuò.', 'Trên công trường xây dựng cần nhiều người công nhân để hoàn thành việc lắp đặt.'),
  ('额外', '公司给员工发放了额外的奖金以表彰他们的努力。', 'Gōngsī gěi yuángōng fāfàng le éwài de jiǎngjīn yǐ biǎozhāng tāmen de nǔlì.', 'Công ty trao thưởng thêm ngoài định mức cho nhân viên để khen ngợi nỗ lực của họ.'),
  ('遏制', '政府采取措施遏制空气污染问题的进一步恶化。', 'Zhèngfǔ cǎiqǔ cuòshī èzhì kōngqì wūrǎn wèntí de jìnyíbù èhuà.', 'Chính phủ áp dụng biện pháp kiềm chế vấn đề ô nhiễm không khí trở nên xấu đi thêm.'),
  ('而已', '这只是我的个人看法而已，没有其他意思。', 'Zhè zhǐshì wǒ de gèrén kànfǎ éryǐ, méiyǒu qítā yìsi.', 'Đây chỉ là ý kiến cá nhân của tôi mà thôi, không có ý gì khác.'),
  ('恶心', '闻到那股味道后，我立刻感到恶心想呕吐。', 'Wéndào nà gǔ wèidào hòu, wǒ lìkè gǎndào ěxīn xiǎng ǒutù.', 'Ngửi thấy mùi đó tôi ngay lập tức cảm thấy buồn nôn muốn nôn.'),
  ('恶化', '如果不及时治疗，病情可能会迅速恶化。', 'Rúguǒ bù jíshí zhìliáo, bìngqíng kěnéng huì xùnsù èhuà.', 'Nếu không chữa trị kịp thời, tình trạng bệnh có thể xấu đi nhanh chóng.'),
  ('恩怨', '我们应该放下过往的恩怨，重新开始友谊。', 'Wǒmen yīnggāi fàngxià guòwǎng de ēnyuàn, chóngxīn kāishǐ yǒuyì.', 'Chúng ta nên bỏ qua những ân oán trong quá khứ, bắt đầu lại tình bạn.'),
  ('二氧化碳', '汽车排放的二氧化碳是导致气候变化的主要原因之一。', 'Qìchē páifàng de èryǎnghuàtàn shì dǎozhì qìhòu biànhuà de zhǔyào yuányīn zhī yī.', 'Khí CO2 do ô tô thải ra là một trong những nguyên nhân chính gây biến đổi khí hậu.'),
  ('飞跃', '这项新技术实现了通信速度的巨大飞跃。', 'Zhè xiàng xīn jìshù shíxiàn le tōngxìn sùdù de jùdà fēiyuè.', 'Kỹ thuật mới này đã đạt được bước nhảy vọt lớn về tốc độ truyền thông.'),
  ('飞翔', '海鸥在海面上自由自在地飞翔，景色十分美丽。', 'Hǎi''ōu zài hǎimiàn shàng zìyóu zìzài de fēixiáng, jǐngsè shífēn měilì.', 'Chim hải âu tự do bay lượn trên mặt biển, cảnh sắc rất đẹp.'),
  ('飞禽走兽', '森林里有各种各样的飞禽走兽，非常丰富多样。', 'Sēnlín lǐ yǒu gèzhǒng gèyàng de fēiqín zǒushòu, fēicháng fēngfù duōyàng.', 'Trong rừng có đủ loại chim muông thú vật rất phong phú đa dạng.'),
  ('风趣', '他的演讲风趣幽默，吸引了全场观众的注意。', 'Tā de yǎnjiǎng fēngqù yōumò, xīyǐn le quánchǎng guānzhòng de zhùyì.', 'Bài phát biểu của anh ấy dí dỏm hài hước, thu hút sự chú ý của toàn bộ khán giả.'),
  ('风气', '公司正在努力改善工作环境，改变不良的风气。', 'Gōngsī zhèngzài nǔlì gǎishàn gōngzuò huánjìng, gǎibiàn bùliáng de fēngqì.', 'Công ty đang cố gắng cải thiện môi trường làm việc, thay đổi lối sống không tốt.'),
  ('风暴', '强烈的风暴导致沿海地区发生严重的洪水灾害。', 'Qiángliè de fēngbào dǎozhì yánhǎi dìqū fāshēng yánzhòng de hóngshuǐ zāihài.', 'Cơn bão mạnh gây ra lụt lội nghiêm trọng ở khu vực ven biển.'),
  ('风度', '他在公众面前总是保持优雅的风度。', 'Tā zài gōngzhòng miànqián zǒng shì bǎochí yōuyǎ de fēngdù.', 'Anh ấy luôn giữ phong độ thanh lịch trước công chúng.'),
  ('风土人情', '旅行中了解当地的风土人情能够增进文化交流。', 'Lǚxíng zhōng liǎojiě dāngdì de fēngtǔ rénqíng nénggòu zēngjìn wénhuà jiāoliú.', 'Khi du lịch tìm hiểu phong tục tập quán địa phương có thể thúc đẩy giao lưu văn hóa.'),
  ('风味', '这道菜融合了多种调料，风味独特，非常受欢迎。', 'Zhè dào cài rónghé le duō zhǒng tiáoliào, fēngwèi dútè, fēicháng shòu huānyíng.', 'Món ăn này hòa quyện nhiều loại gia vị, phong vị đặc biệt, rất được ưa chuộng.'),
  ('风光', '这条山路的风光非常迷人，吸引了很多游客。', 'Zhè tiáo shānlù de fēngguāng fēicháng mírén, xīyǐn le hěnduō yóukè.', 'Phong cảnh của con đường núi này rất đẹp, thu hút nhiều du khách.'),
  ('非法', '警方严厉打击任何非法经营的行为，维护市场秩序。', 'Jǐngfāng yánlì dǎjī rènhé fēifǎ jīngyíng de xíngwéi, wéihù shìchǎng zhìxù.', 'Cảnh sát nghiêm khắc trấn áp mọi hành vi kinh doanh phi pháp, giữ trật tự thị trường.'),
  ('附属', '这所大学附属的医院设备先进，服务周到。', 'Zhè suǒ dàxué fùshǔ de yīyuàn shèbèi xiānjìn, fúwù zhōudào.', 'Bệnh viện thuộc đại học này có thiết bị tiên tiến, dịch vụ chu đáo.'),
  ('附和', '他只是附和别人的观点，没有自己的看法。', 'Tā zhǐshì fùhè biérén de guāndiǎn, méiyǒu zìjǐ de kànfǎ.', 'Anh ta chỉ hùa theo quan điểm của người khác, không có ý kiến riêng.'),
  ('附件', '请查收邮件中的附件，有您需要的文件。', 'Qǐng cháshōu yóujiàn zhōng de fùjiàn, yǒu nín xūyào de wénjiàn.', 'Vui lòng kiểm tra phần đính kèm trong email, có tài liệu bạn cần.'),
  ('防治', '政府加大对传染病的防治力度，保障公众健康。', 'Zhèngfǔ jiādà duì chuánrǎnbìng de fángzhì lìdù, bǎozhàng gōngzhòng jiànkāng.', 'Chính phủ tăng cường phòng và chữa bệnh truyền nhiễm, bảo vệ sức khỏe cộng đồng.'),
  ('防止', '为了防止火灾，工厂安装了先进的消防设备。', 'Wèile fángzhǐ huǒzāi, gōngchǎng ānzhuāng le xiānjìn de xiāofáng shèbèi.', 'Để ngăn ngừa cháy nổ, nhà máy đã lắp đặt thiết bị phòng cháy hiện đại.'),
  ('防御', '军队加强了边境的防御措施，防止敌人入侵。', 'Jūnduì jiāqiáng le biānjìng de fángyù cuòshī, fángzhǐ dírén rùqīn.', 'Quân đội tăng cường các biện pháp phòng ngự biên giới để ngăn chặn kẻ địch xâm nhập.'),
  ('防守', '这支球队以顽强的防守闻名，难以被攻破。', 'Zhè zhī qiúduì yǐ wánqiáng de fángshǒu wénmíng, nányǐ bèi gōngpò.', 'Đội bóng này nổi tiếng với khả năng phòng thủ kiên cường, khó bị đánh bại.'),
  ('锋利', '这把刀锋利无比，可以轻松切割各种材料。', 'Zhè bǎ dāo fēnglì wúbǐ, kěyǐ qīngsōng qiēgē gèzhǒng cáiliào.', 'Con dao này sắc bén vô cùng, có thể dễ dàng cắt mọi chất liệu.'),
  ('逢', '每逢节假日，父母都会带我们去旅游。', 'Měi féng jiéjiàrì, fùmǔ dōu huì dài wǒmen qù lǚyóu.', 'Mỗi khi đến dịp lễ, bố mẹ đều đưa chúng tôi đi du lịch.'),
  ('辐射', '核电站周围的辐射水平必须严格监测。', 'Hé diàn zhàn zhōuwéi de fúshè shuǐpíng bìxū yángé jiāncè.', 'Mức độ bức xạ quanh nhà máy điện hạt nhân phải được giám sát nghiêm ngặt.'),
  ('辅助', '医生使用先进设备辅助诊断，提高了治愈率。', 'Yīshēng shǐyòng xiānjìn shèbèi fǔzhù zhěnduàn, tígāo le zhìyù lǜ.', 'Bác sĩ sử dụng thiết bị hiện đại để hỗ trợ chẩn đoán, nâng cao tỉ lệ chữa khỏi.'),
  ('赋予', '这个职位赋予了他更多的责任和权力。', 'Zhège zhíwèi fùyǔ le tā gèng duō de zérèn hé quánlì.', 'Vị trí này đã trao cho anh ta nhiều trách nhiệm và quyền hạn hơn.'),
  ('贩卖', '警方查获了一起非法贩卖毒品的案件。', 'Jǐngfāng cháhuò le yī qǐ fēifǎ fànmài dúpǐn de ànjiàn.', 'Cảnh sát đã phát hiện một vụ buôn lậu ma túy bất hợp pháp.'),
  ('负担', '高昂的学费让许多家庭感到沉重的负担。', 'Gāo''áng de xuéfèi ràng xǔduō jiātíng gǎndào chénzhòng de fùdān.', 'Học phí cao khiến nhiều gia đình cảm thấy gánh nặng lớn.'),
  ('诽谤', '他因诽谤他人而被法院起诉，声誉受损。', 'Tā yīn fěibàng tārén ér bèi fǎyuàn qǐsù, shēngyù shòusǔn.', 'Anh ta bị tòa án kiện vì phỉ báng người khác, danh tiếng bị tổn hại.'),
  ('访问', '公司领导明天将访问合作伙伴，洽谈项目细节。', 'Gōngsī lǐngdǎo míngtiān jiāng fǎngwèn hézuò huǒbàn, qiàtán xiàngmù xìjié.', 'Lãnh đạo công ty sẽ đến thăm đối tác ngày mai để thảo luận chi tiết dự án.'),
  ('覆盖', '云层覆盖了整个城市，阳光无法直射地面。', 'Yúncéng fùgàile zhěnggè chéngshì, yángguāng wúfǎ zhíshè dìmiàn.', 'Lớp mây bao phủ toàn bộ thành phố, ánh nắng không thể chiếu xuống mặt đất.'),
  ('范畴', '自由和权利属于法律保护的范畴。', 'Zìyóu hé quánlì shǔyú fǎlǜ bǎohù de fànchóu.', 'Tự do và quyền lợi thuộc phạm trù được pháp luật bảo vệ.'),
  ('腹泻', '他的腹泻严重，需要马上去医院治疗。', 'Tā de fùxiè yánzhòng, xūyào mǎshàng qù yīyuàn zhìliáo.', 'Anh ấy bị ỉa chảy nặng, cần phải đi bệnh viện chữa ngay.'),
  ('腐败', '食品如果保存不当，很容易腐败变质。', 'Shípǐn rúguǒ bǎocún bù dàng, hěn róngyì fǔbài biànzhì.', 'Thực phẩm nếu bảo quản không đúng cách thì rất dễ bị ôi thiu hỏng.'),
  ('腐蚀', '金属在潮湿环境中会被腐蚀得越来越严重。', 'Jīnshǔ zài cháoshī huánjìng zhōng huì bèi fǔshí dé yuèláiyuè yánzhòng.', 'Kim loại trong môi trường ẩm ướt sẽ bị ăn mòn ngày càng nghiêm trọng.'),
  ('腐烂', '水果放久了就会腐烂，散发出难闻的气味。', 'Shuǐguǒ fàng jiǔ le jiù huì fǔlàn, sànfā chū nánwén de qìwèi.', 'Trái cây để lâu sẽ bị thối rữa, tỏa ra mùi khó chịu.'),
  ('腐朽', '这座古老的木屋因为年久失修而变得腐朽不堪。', 'Zhè zuò gǔlǎo de mùwū yīnwèi nián jiǔ shīxiū ér biàn dé fǔxiǔ bùkān.', 'Ngôi nhà gỗ cổ này vì lâu năm không sửa chữa nên đã mục nát không thể chịu nổi.'),
  ('肺', '吸烟对肺造成严重的伤害，影响健康。', 'Xīyān duì fèi zàochéng yánzhòng de shānghài, yǐngxiǎng jiànkāng.', 'Hút thuốc lá gây tổn thương nghiêm trọng cho phổi, ảnh hưởng đến sức khỏe.'),
  ('肥沃', '这片土地肥沃，非常适合种植各种农作物。', 'Zhè piàn tǔdì féiwò, fēicháng shìhé zhòngzhí gèzhǒng nóngzuòwù.', 'Mảnh đất này màu mỡ, rất thích hợp để trồng nhiều loại cây trồng.'),
  ('纺织', '这个地区以纺织业闻名，生产多种织物。', 'Zhège dìqū yǐ fǎngzhī yè wénmíng, shēngchǎn duō zhǒng zhīwù.', 'Khu vực này nổi tiếng với ngành dệt, sản xuất nhiều loại vải.'),
  ('繁殖', '许多动物在春天开始繁殖，增加种群数量。', 'Xǔduō dòngwù zài chūntiān kāishǐ fánzhí, zēngjiā zhǒngqún shùliàng.', 'Nhiều động vật bắt đầu sinh sôi vào mùa xuân để tăng số lượng quần thể.'),
  ('繁忙', '由于工作繁忙，他几乎没有时间休息。', 'Yóuyú gōngzuò fánmáng, tā jīhū méiyǒu shíjiān xiūxí.', 'Vì công việc bận rộn nên anh ấy gần như không có thời gian nghỉ ngơi.'),
  ('繁华', '这座城市的商业区非常繁华，吸引大量游客。', 'Zhè zuò chéngshì de shāngyè qū fēicháng fánhuá, xīyǐn dàliàng yóukè.', 'Khu thương mại của thành phố này rất phồn hoa, thu hút nhiều du khách.'),
  ('繁体字', '台湾地区主要使用繁体字作为书写标准。', 'Táiwān dìqū zhǔyào shǐyòng fántǐzì zuòwéi shūxiě biāozhǔn.', 'Khu vực Đài Loan chủ yếu dùng chữ phồn thể làm tiêu chuẩn viết.'),
  ('粉色', '她喜欢穿粉色的裙子，看起来非常温柔。', 'Tā xǐhuan chuān fěnsè de qúnzi, kàn qǐlái fēicháng wēnróu.', 'Cô ấy thích mặc váy màu hồng, trông rất dịu dàng.'),
  ('粉碎', '强烈的冲击力使玻璃窗粉碎成无数碎片。', 'Qiángliè de chōngjī lì shǐ bōli chuāng fěnsuì chéng wúshù suìpiàn.', 'Lực va đập mạnh làm cửa kính vỡ vụn thành vô số mảnh.'),
  ('粉末', '制药厂要求原料必须是纯净的粉末状。', 'Zhìyào chǎng yāoqiú yuánliào bìxū shì chúnjìng de fěnmò zhuàng.', 'Nhà máy dược phẩm yêu cầu nguyên liệu phải là dạng bột tinh khiết.'),
  ('符号', '数学中使用不同的符号来表示各种运算。', 'Shùxué zhōng shǐyòng bùtóng de fúhào lái biǎoshì gèzhǒng yùnsuàn.', 'Trong toán học sử dụng các kí hiệu khác nhau để biểu thị các phép toán.'),
  ('福气', '他觉得自己很有福气，生活幸福美满。', 'Tā juéde zìjǐ hěn yǒu fúqì, shēnghuó xìngfú měimǎn.', 'Anh ấy cảm thấy mình rất có phúc, cuộc sống hạnh phúc viên mãn.'),
  ('福利', '公司为员工提供了优厚的福利待遇。', 'Gōngsī wèi yuángōng tígōngle yōuhòu de fúlì dàiyù.', 'Công ty cung cấp cho nhân viên các chế độ phúc lợi tốt.'),
  ('番', '请你把书翻一番，查找需要的信息。', 'Qǐng nǐ bǎ shū fān yī fān, cházhǎo xūyào de xìnxī.', 'Xin bạn hãy lật sách lên để tìm kiếm thông tin cần thiết.'),
  ('泛滥', '暴雨导致河水泛滥，淹没了大片农田。', 'Bàoyǔ dǎozhì héshuǐ fànlàn, yānmòle dàpiàn nóngtián.', 'Mưa lớn gây ra nước sông tràn lan, làm ngập lụt nhiều diện tích ruộng.'),
  ('法人', '这家公司的法人代表在会议上发表了重要讲话。', 'Zhè jiā gōngsī de fǎrén dàibiǎo zài huìyì shàng fābiǎo le zhòngyào jiǎnghuà.', 'Người đại diện pháp nhân của công ty này đã phát biểu bài nói quan trọng trong cuộc họp.'),
  ('沸腾', '水壶里的水已经沸腾，可以倒出来泡茶了。', 'Shuǐhú lǐ de shuǐ yǐjīng fèiténg, kěyǐ dào chū lái pào chá le.', 'Nước trong ấm đã sôi sùng sục, có thể đổ ra để pha trà rồi.'),
  ('服气', '经过你的解释，我终于服气你的观点了。', 'Jīngguò nǐ de jiěshì, wǒ zhōngyú fúqì nǐ de guāndiǎn le.', 'Sau khi nghe giải thích của bạn, tôi cuối cùng đã chịu phục quan điểm của bạn.'),
  ('服从', '在军队里，士兵必须严厉服从命令。', 'Zài jūnduì lǐ, shìbīng bìxū yánlì fúcóng mìnglìng.', 'Trong quân đội, binh lính phải nghiêm túc phục tùng mệnh lệnh.'),
  ('方针', '公司的发展方针需要根据市场变化不断调整。', 'Gōngsī de fāzhǎn fāngzhēn xūyào gēnjù shìchǎng biànhuà búduàn tiáozhěng.', 'Phương châm phát triển của công ty cần phải điều chỉnh liên tục theo biến động của thị trường.'),
  ('方言', '虽然大家说普通话，但他们也会用自己的方言交流。', 'Suīrán dàjiā shuō pǔtōnghuà, dàn tāmen yě huì yòng zìjǐ de fāngyán jiāoliú.', 'Mặc dù mọi người nói tiếng phổ thông, nhưng họ cũng dùng tiếng địa phương để giao tiếp.'),
  ('方圆', '这个公园的方圆大约有一公里，很适合散步。', 'Zhège gōngyuán de fāngyuán dàyuē yǒu yī gōnglǐ, hěn shìhé sànbù.', 'Chu vi hình tròn của công viên này khoảng một cây số, rất thích hợp để đi dạo.'),
  ('方位', '通过地图，你可以确定自己的方位和目标位置。', 'Tōngguò dìtú, nǐ kěyǐ quèdìng zìjǐ de fāngwèi hé mùbiāo wèizhì.', 'Thông qua bản đồ, bạn có thể xác định phương hướng và vị trí mục tiêu của mình.'),
  ('敷衍', '他对工作总是敷衍了事，效率很低。', 'Tā duì gōngzuò zǒng shì fūyǎnle shì, xiàolǜ hěn dī.', 'Anh ấy luôn làm việc qua quýt, hiệu suất rất thấp.'),
  ('放射', '这个设备可以放射出特殊的光线进行治疗。', 'Zhège shèbèi kěyǐ fàngshè chū tèshū de guāngxiàn jìnxíng zhìliáo.', 'Thiết bị này có thể chiếu ra tia sáng đặc biệt để điều trị.'),
  ('放大', '用显微镜可以把细胞结构放大数千倍。', 'Yòng xiǎnwēijìng kěyǐ bǎ xìbāo jiégòu fàngdà shù qiān bèi.', 'Sử dụng kính hiển vi có thể phóng to cấu trúc tế bào lên hàng nghìn lần.'),
  ('抚摸', '母亲轻轻地抚摸宝宝的头发，表示关爱。', 'Mǔqīn qīngqīng de fǔmō bǎobǎo de tóufa, biǎoshì guān''ài.', 'Mẹ nhẹ nhàng xoa đầu em bé, thể hiện tình yêu thương.'),
  ('抚养', '单亲家庭中，父亲独自抚养三个孩子非常辛苦。', 'Dānqīn jiātíng zhōng, fùqīn dúzì fǔyǎng sān gè háizi fēicháng xīnkǔ.', 'Trong gia đình đơn thân, người cha một mình nuôi dưỡng ba đứa trẻ rất vất vả.'),
  ('愤怒', '他听到不公平的待遇后，感到非常愤怒。', 'Tā tīng dào bù gōngpíng de dàiyù hòu, gǎndào fēicháng fènnù.', 'Sau khi nghe về sự đối xử bất công, anh ta cảm thấy rất phẫn nộ.'),
  ('废除', '政府决定废除过时的法规以促进经济发展。', 'Zhèngfǔ juédìng fèichú guòshí de fǎguī yǐ cùjìn jīngjì fāzhǎn.', 'Chính phủ quyết định xóa bỏ các quy định lỗi thời để thúc đẩy phát triển kinh tế.'),
  ('废寝忘食', '他为了完成论文，废寝忘食地工作了好几天。', 'Tā wèile wánchéng lùnwén, fèiqǐnwàngshí de gōngzuò le hǎo jǐ tiān.', 'Anh ấy vì hoàn thành luận văn mà quên ăn quên ngủ làm việc mấy ngày liền.'),
  ('废墟', '地震后，城市变成了一片废墟，灾民急需帮助。', 'Dìzhèn hòu, chéngshì biànchéng le yí piàn fèixū, zāimín jíxū bāngzhù.', 'Sau động đất, thành phố trở thành một đống hoang tàn, người dân gặp nạn rất cần giúp đỡ.'),
  ('幅度', '这次降价的幅度达到了百分之二十，吸引了很多顾客。', 'Zhè cì jiàngjià de fúdù dádào le bǎi fēn zhī èrshí, xīyǐn le hěn duō gùkè.', 'Biên độ giảm giá lần này đạt đến 20%, thu hút rất nhiều khách hàng.'),
  ('封闭', '由于疫情严重，学校暂时封闭不对外开放。', 'Yóuyú yìqíng yánzhòng, xuéxiào zànshí fēngbì bù duìwài kāifàng.', 'Do dịch bệnh nghiêm trọng, trường học tạm thời đóng cửa không mở ra bên ngoài.'),
  ('封锁', '政府为了防止病毒传播，封锁了部分交通要道。', 'Zhèngfǔ wèile fángzhǐ bìngdú chuánbò, fēngsuǒ le bùfèn jiāotōng yàodào.', 'Chính phủ để ngăn chặn virus lây lan đã phong tỏa một số tuyến đường giao thông.'),
  ('封建', '中国封建社会经历了几千年的历史变迁。', 'Zhōngguó fēngjiàn shèhuì jīnglì le jǐ qiān nián de lìshǐ biànqiān.', 'Xã hội phong kiến Trung Quốc trải qua hàng nghìn năm biến đổi lịch sử.'),
  ('富裕', '这个地区的发展使居民的生活变得更加富裕。', 'Zhège dìqū de fāzhǎn shǐ jūmín de shēnghuó biàn dé gèng jiā fùyù.', 'Sự phát triển của khu vực này khiến đời sống người dân trở nên giàu có hơn.'),
  ('奉献', '他为社会奉献了自己所有的时间和精力。', 'Tā wèi shèhuì fèngxiàn le zìjǐ suǒyǒu de shíjiān hé jīnglì.', 'Anh ấy đã hiến dâng toàn bộ thời gian và sức lực của mình cho xã hội.'),
  ('夫妇', '那对夫妇在社区里非常受人尊敬。', 'Nà duì fūfù zài shèqū lǐ fēicháng shòu rén zūnjìng.', 'Cặp vợ chồng đó rất được mọi người trong cộng đồng kính trọng.'),
  ('夫人', '总统夫人在晚宴上发表了感人的演讲。', 'Zǒngtǒng fūrén zài wǎnyàn shàng fābiǎo le gǎnrén de yǎnjiǎng.', 'Phu nhân tổng thống đã có bài phát biểu xúc động tại bữa tiệc tối.'),
  ('复活', '科学家们希望能够使濒危物种在未来复活。', 'Kēxuéjiā men xīwàng nénggòu shǐ bīnwēi wùzhǒng zài wèilái fùhuó.', 'Các nhà khoa học hy vọng có thể làm các loài sắp tuyệt chủng sống lại trong tương lai.'),
  ('复兴', '文化复兴运动促进了民族自豪感的提高。', 'Wénhuà fùxīng yùndòng cùjìn le mínzú zìháo gǎn de tígāo.', 'Phong trào phục hưng văn hóa đã thúc đẩy sự nâng cao lòng tự hào dân tộc.'),
  ('坟墓', '人们每年都会去坟墓前祭拜祖先。', 'Rénmen měi nián dōu huì qù fénmù qián jìbài zǔxiān.', 'Mọi người mỗi năm đều đến trước mộ phần để tưởng nhớ tổ tiên.'),
  ('吩咐', '老师详细吩咐学生们如何准备明天的考试。', 'Lǎoshī xiángxì fēnfù xuéshēngmen rúhé zhǔnbèi míngtiān de kǎoshì.', 'Giáo viên đã căn dặn học sinh chi tiết cách chuẩn bị cho kỳ thi ngày mai.'),
  ('否决', '委员会最终否决了这项不合理的提案。', 'Wěiyuánhuì zuìzhōng fǒujué le zhè xiàng bù hélǐ de tí''àn.', 'Ủy ban cuối cùng đã phủ quyết đề án không hợp lý này.'),
  ('发财', '他梦想通过自己的努力快速发财。', 'Tā mèngxiǎng tōngguò zìjǐ de nǔlì kuàisù fācái.', 'Anh ấy mơ ước trở nên giàu có nhanh chóng nhờ nỗ lực bản thân.'),
  ('发誓', '我发誓以后再也不会犯同样的错误。', 'Wǒ fāshì yǐhòu zài yě bú huì fàn tóngyàng de cuòwù.', 'Tôi thề sẽ không bao giờ mắc sai lầm giống như thế nữa.'),
  ('发觉', '经过调查，他终于发觉了问题的根源所在。', 'Jīngguò diàochá, tā zhōngyú fājué le wèntí de gēnyuán suǒzài.', 'Sau cuộc điều tra, cuối cùng anh ấy phát hiện ra nguồn gốc của vấn đề.'),
  ('发行', '出版社计划下个月发行这本新书。', 'Chūbǎnshè jìhuà xià gè yuè fāxíng zhè běn xīn shū.', 'Nhà xuất bản dự định phát hành cuốn sách mới này vào tháng tới.'),
  ('发育', '儿童的身体发育需要充足的营养和运动。', 'Értóng de shēntǐ fāyù xūyào chōngzú de yíngyǎng hé yùndòng.', 'Sự phát triển cơ thể của trẻ em cần đủ dinh dưỡng và vận động.'),
  ('发炎', '伤口不及时处理可能会发炎感染。', 'Shāngkǒu bù jíshí chǔlǐ kěnéng huì fāyán gǎnrǎn.', 'Vết thương nếu không xử lý kịp thời có thể bị viêm nhiễm.'),
  ('发扬', '我们应该发扬传统美德，促进社会和谐。', 'Wǒmen yīnggāi fāyáng chuántǒng měidé, cùjìn shèhuì héxié.', 'Chúng ta nên phát huy phẩm chất truyền thống tốt đẹp để thúc đẩy xã hội hài hòa.'),
  ('发布', '公司今天发布了最新的产品型号。', 'Gōngsī jīntiān fābù le zuìxīn de chǎnpǐn xínghào.', 'Công ty hôm nay đã công bố mẫu sản phẩm mới nhất.'),
  ('发射', '卫星成功发射进入预定轨道。', 'Wèixīng chénggōng fāshè jìnrù yùdìng guǐdào.', 'Vệ tinh đã được phóng thành công vào quỹ đạo dự kiến.'),
  ('发呆', '他因为听到奇怪的消息，整个人发呆了好久。', 'Tā yīnwèi tīngdào qíguài de xiāoxi, zhěng gèrén fādāi le hǎo jiǔ.', 'Anh ấy vì nghe tin lạ nên cả người đờ ra rất lâu.'),
  ('发动', '政府决定发动这场运动以改善社会环境。', 'Zhèngfǔ juédìng fādòng zhè chǎng yùndòng yǐ gǎishàn shèhuì huánjìng.', 'Chính phủ quyết định phát động cuộc vận động này để cải thiện môi trường xã hội.'),
  ('反驳', '他冷静地反驳了对方提出的不合理意见。', 'Tā lěngjìng de fǎnbó le duìfāng tíchū de bù hélǐ yìjiàn.', 'Anh ấy bình tĩnh phản bác ý kiến không hợp lý mà đối phương đưa ra.'),
  ('反馈', '客户的反馈对我们改进产品非常有帮助。', 'Kèhù de fǎnkuì duì wǒmen gǎijìn chǎnpǐn fēicháng yǒu bāngzhù.', 'Phản hồi của khách hàng rất hữu ích cho việc cải tiến sản phẩm của chúng tôi.'),
  ('反面', '书的反面印有作者的简介和照片。', 'Shū de fǎnmiàn yìn yǒu zuòzhě de jiǎnjiè hé zhàopiàn.', 'Mặt sau của cuốn sách có in phần giới thiệu và ảnh của tác giả.'),
  ('反问', '他听了我的话后，反问我是否确定这样做。', 'Tā tīng le wǒ de huà hòu, fǎnwèn wǒ shìfǒu quèdìng zhèyàng zuò.', 'Anh ấy nghe lời tôi rồi hỏi lại xem tôi có chắc chắn làm như vậy không.'),
  ('反抗', '年轻一代开始反抗传统的束缚和限制。', 'Niánqīng yīdài kāishǐ fǎnkàng chuántǒng de shùfù hé xiànzhì.', 'Thế hệ trẻ bắt đầu phản kháng những ràng buộc và giới hạn truyền thống.'),
  ('反感', '他对这种不公平的待遇产生了强烈的反感。', 'Tā duì zhè zhǒng bù gōngpíng de dàiyù chǎnshēng le qiángliè de fǎngǎn.', 'Anh ta phát sinh ác cảm mạnh mẽ với cách đối xử không công bằng này.'),
  ('反思', '经过这次失败，我们需要认真反思自己的错误。', 'Jīngguò zhè cì shībài, wǒmen xūyào rènzhēn fǎnsī zìjǐ de cuòwù.', 'Sau thất bại này, chúng ta cần suy ngẫm nghiêm túc về những sai lầm của mình.'),
  ('反常', '今年的气温反常地高，导致农作物受损严重。', 'Jīnnián de qìwēn fǎncháng de gāo, dǎozhì nóngzuòwù shòusǔn yánzhòng.', 'Nhiệt độ năm nay cao bất thường, gây ra thiệt hại nghiêm trọng cho cây trồng.'),
  ('反射', '光线在镜面上反射，形成了清晰的影像。', 'Guāngxiàn zài jìngmiàn shàng fǎnshè, xíngchéng le qīngxī de yǐngxiàng.', 'Ánh sáng phản chiếu trên mặt gương, tạo thành hình ảnh rõ ràng.'),
  ('反之', '勤奋学习能取得好成绩，反之就可能落后。', 'Qínfèn xuéxí néng qǔdé hǎo chéngjī, fǎnzhī jiù kěnéng luòhòu.', 'Học tập chăm chỉ có thể đạt kết quả tốt, ngược lại thì có thể bị tụt lại.'),
  ('副', '他担任副经理，协助经理管理公司事务。', 'Tā dānrèn fù jīnglǐ, xiézhù jīnglǐ guǎnlǐ gōngsī shìwù.', 'Anh ấy giữ chức phó giám đốc, hỗ trợ giám đốc quản lý công việc công ty.'),
  ('分量', '这道菜的分量很足，吃完后非常饱。', 'Zhè dào cài de fènliàng hěn zú, chī wán hòu fēicháng bǎo.', 'Phần ăn của món này rất nhiều, ăn xong cảm thấy rất no.'),
  ('分辨', '他很难分辨这些相似的颜色区别。', 'Tā hěn nán fēnbiàn zhèxiē xiāngsì de yánsè qūbié.', 'Anh ấy rất khó phân biệt sự khác nhau giữa những màu sắc tương tự này.'),
  ('分解', '科学家成功地分解了这种复杂的化学物质。', 'Kēxuéjiā chénggōng de fēnjiě le zhè zhǒng fùzá de huàxué wùzhì.', 'Các nhà khoa học đã thành công trong việc phân giải chất hóa học phức tạp này.'),
  ('分裂', '内部的分裂导致了组织的效率下降。', 'Nèibù de fēnliè dǎozhì le zǔzhī de xiàolǜ xiàjiàng.', 'Sự phân tách bên trong đã dẫn đến hiệu suất của tổ chức giảm sút.'),
  ('分红', '今年公司分红丰厚，员工都感到非常满意。', 'Jīnnián gōngsī fēnhóng fēnghòu, yuángōng dōu gǎndào fēicháng mǎnyì.', 'Năm nay công ty chia tiền thưởng phong phú, nhân viên đều cảm thấy rất hài lòng.'),
  ('分泌', '人体内某些腺体会分泌激素调节身体功能。', 'Réntǐ nèi mǒuxiē xiàntǐ huì fēnmì jīsù tiáojié shēntǐ gōngnéng.', 'Một số tuyến trong cơ thể người sẽ bài tiết hormone điều chỉnh chức năng cơ thể.'),
  ('分歧', '双方在合作中出现了严重的分歧，难以达成共识。', 'Shuāngfāng zài hézuò zhōng chūxiàn le yánzhòng de fēnqí, nányǐ dáchéng gòngshí.', 'Hai bên trong hợp tác đã xuất hiện bất đồng nghiêm trọng, khó đạt được đồng thuận.'),
  ('分明', '他的态度分明，使人很容易理解他的观点。', 'Tā de tàidù fēnmíng, shǐ rén hěn róngyì lǐjiě tā de guāndiǎn.', 'Thái độ của anh ấy rõ ràng, khiến người ta rất dễ hiểu quan điểm của anh.'),
  ('分散', '孩子们的注意力在游乐场里很容易分散。', 'Háizimen de zhùyìlì zài yóulèchǎng lǐ hěn róngyì fēnsàn.', 'Sự chú ý của bọn trẻ dễ dàng bị phân tán trong khu vui chơi.'),
  ('分寸', '说话要讲分寸，不能伤害他人的感情。', 'Shuōhuà yào jiǎng fēncùn, bùnéng shānghài tārén de gǎnqíng.', 'Nói chuyện phải đúng mực, không được làm tổn thương tình cảm người khác.'),
  ('凡是', '凡是参加考试的学生都要提前半小时到场。', 'Fánshì cānjiā kǎoshì de xuéshēng dōu yào tíqián bàn xiǎoshí dàochǎng.', 'Phàm là học sinh tham gia kỳ thi đều phải đến trước nửa tiếng.'),
  ('俯视', '站在山顶俯视，整个城市尽收眼底。', 'Zhàn zài shāndǐng fǔshì, zhěnggè chéngshì jǐn shōu yǎndǐ.', 'Đứng trên đỉnh núi nhìn xuống, toàn bộ thành phố hiện ra trong tầm mắt.'),
  ('俘虏', '战争中，双方都俘虏了大量士兵。', 'Zhànzhēng zhōng, shuāngfāng dōu fúlǔ le dàliàng shìbīng.', 'Trong chiến tranh, hai bên đều bắt được nhiều tù binh.'),
  ('丰盛', '节日的晚餐准备得非常丰盛，令人垂涎欲滴。', 'Jiérì de wǎncān zhǔnbèi de fēicháng fēngshèng, lìng rén chuíxián yù dī.', 'Bữa tối ngày lễ chuẩn bị vô cùng phong phú, khiến người ta thòm thèm.'),
  ('丰满', '她的身材丰满，给人一种健康的感觉。', 'Tā de shēncái fēngmǎn, gěi rén yī zhǒng jiànkāng de gǎnjué.', 'Dáng người cô ấy đầy đặn, tạo cảm giác khỏe mạnh.'),
  ('丰收', '今年秋天的稻谷丰收，农民们脸上洋溢着喜悦。', 'Jīnnián qiūtiān de dàogǔ fēngshōu, nóngmín men liǎn shàng yángyì zhe xǐyuè.', 'Vụ lúa mùa thu năm nay bội thu, nụ cười vui sướng hiện trên khuôn mặt người nông dân.'),
  ('鼓动', '他在大会上鼓动大家积极参与环保活动。', 'Tā zài dàhuì shàng gǔdòng dàjiā jījí cānyù huánbǎo huódòng.', 'Anh ấy đã vận động mọi người tích cực tham gia các hoạt động bảo vệ môi trường trong cuộc họp.'),
  ('鸽子', '公园里有很多鸽子在追逐嬉戏。', 'Gōngyuán lǐ yǒu hěnduō gēzi zài zhuīzhú xīxì.', 'Có rất nhiều bồ câu đang đuổi nhau vui chơi trong công viên.'),
  ('高超', '他的厨艺高超，做出的菜肴美味无比。', 'Tā de chúyì gāochāo, zuò chū de càiyáo měiwèi wúbǐ.', 'Kỹ năng nấu ăn của anh ấy rất cao siêu, món ăn làm ra ngon đến không gì sánh bằng.'),
  ('高潮', '故事的高潮部分紧张刺激，让人难以忘怀。', 'Gùshì de gāocháo bùfèn jǐnzhāng cìjī, ràng rén nányǐ wànghuái.', 'Phần cao trào của câu chuyện căng thẳng kích thích, khiến người ta khó quên.'),
  ('高涨', '群众的热情高涨，为公益活动贡献力量。', 'Qúnzhòng de rèqíng gāozhǎng, wèi gōngyì huódòng gòngxiàn lìliàng.', 'Nhiệt tình của quần chúng dâng cao, góp sức vào các hoạt động từ thiện.'),
  ('高明', '他的解决方案非常高明，成功解决了难题。', 'Tā de jiějué fāng''àn fēicháng gāomíng, chénggōng jiějué le nántí.', 'Phương án giải quyết của anh ấy rất cao minh, đã thành công giải quyết vấn đề khó khăn.'),
  ('高峰', '交通高峰时段，市中心的路况非常拥堵。', 'Jiāotōng gāofēng shíduàn, shì zhōngxīn de lùkuàng fēicháng yōngdǔ.', 'Vào giờ cao điểm giao thông, tình trạng đường phố trung tâm thành phố rất tắc nghẽn.'),
  ('高尚', '他为人高尚，总是帮助有需要的人。', 'Tā wéirén gāoshàng, zǒng shì bāngzhù yǒu xūyào de rén.', 'Anh ấy có phẩm chất cao thượng, luôn giúp đỡ những người cần sự giúp đỡ.'),
  ('骨干', '公司骨干员工是企业发展的重要力量。', 'Gōngsī gǔgàn yuángōng shì qǐyè fāzhǎn de zhòngyào lìliàng.', 'Nhân viên cốt cán của công ty là lực lượng quan trọng cho sự phát triển doanh nghiệp.'),
  ('顾问', '这位专家被聘为企业的管理顾问。', 'Zhè wèi zhuānjiā bèi pìn wèi qǐyè de guǎnlǐ gùwèn.', 'Chuyên gia này được mời làm cố vấn quản lý cho doanh nghiệp.'),
  ('顾虑', '他对未来的发展有些顾虑，不敢轻易决定。', 'Tā duì wèilái de fāzhǎn yǒuxiē gùlǜ, bù gǎn qīngyì juédìng.', 'Anh ấy có một vài băn khoăn về sự phát triển tương lai, không dám quyết định một cách dễ dàng.'),
  ('革命', '历史上的这场革命改变了国家的命运。', 'Lìshǐ shàng de zhè chǎng gémìng gǎibiàn le guójiā de mìngyùn.', 'Cuộc cách mạng trong lịch sử này đã thay đổi vận mệnh quốc gia.'),
  ('雇佣', '公司计划雇佣更多有经验的员工来提高效率。', 'Gōngsī jìhuà gùyōng gèng duō yǒu jīngyàn de yuángōng lái tígāo xiàolǜ.', 'Công ty dự định thuê thêm nhiều nhân viên có kinh nghiệm để nâng cao hiệu quả.'),
  ('隔阂', '文化差异常常导致人们之间产生隔阂。', 'Wénhuà chāyì chángcháng dǎozhì rénmen zhī jiān chǎnshēng géhé.', 'Sự khác biệt văn hóa thường dẫn đến bất hòa giữa mọi người.'),
  ('隔离', '为了防止病毒传播，病人被要求隔离十四天。', 'Wèile fángzhǐ bìngdú chuánbō, bìngrén bèi yāoqiú gélí shísì tiān.', 'Để ngăn ngừa lây lan virus, bệnh nhân được yêu cầu cách li 14 ngày.'),
  ('钩子', '墙上挂着一个铁钩子，用来挂钥匙。', 'Qiáng shàng guàzhe yīgè tiě gōuzi, yòng lái guà yàoshi.', 'Trên tường treo một cái móc sắt dùng để treo chìa khóa.'),
  ('钙', '孩子每天都需要摄取足够的钙来促进骨骼健康。', 'Háizi měitiān dōu xūyào shèqǔ zúgòu de gài lái cùjìn gǔgé jiànkāng.', 'Trẻ em mỗi ngày cần hấp thụ đủ canxi để thúc đẩy xương khỏe mạnh.'),
  ('过问', '领导不应该过问员工的私事，尊重他们的隐私更重要。', 'Lǐngdǎo bù yīnggāi guòwèn yuángōng de sīshì, zūnzhòng tāmen de yǐnsī gèng zhòngyào.', 'Lãnh đạo không nên hỏi han quá nhiều về chuyện riêng của nhân viên, tôn trọng riêng tư của họ mới quan trọng.'),
  ('过瘾', '这次旅行真是过瘾，风景美得让人难忘。', 'Zhè cì lǚxíng zhēn shì guòyǐn, fēngjǐng měi de ràng rén nánwàng.', 'Chuyến du lịch này thật đã đời, cảnh đẹp khiến người ta khó quên.'),
  ('过滤', '为了保证水质安全，我们必须彻底过滤自来水。', 'Wèile bǎozhèng shuǐzhì ānquán, wǒmen bìxū chèdǐ guòlǜ zì lái shuǐ.', 'Để đảm bảo an toàn chất lượng nước, chúng ta phải lọc kỹ nước máy.'),
  ('过渡', '经济体制的过渡阶段充满了挑战和机遇。', 'Jīngjì tǐzhì de guòdù jiēduàn chōngmǎnle tiǎozhàn hé jīyù.', 'Giai đoạn quá độ của thể chế kinh tế đầy thử thách và cơ hội.'),
  ('过度', '长时间的过度劳累会对身体健康造成严重影响。', 'Cháng shíjiān de guòdù láolèi huì duì shēntǐ jiànkāng zàochéng yánzhòng yǐngxiǎng.', 'Lao động quá mức trong thời gian dài sẽ gây ảnh hưởng nghiêm trọng đến sức khỏe.'),
  ('过奖', '您太过奖了，我不过是尽了自己本分。', 'Nín tài guòjiǎng le, wǒ bùguò shì jìnle zìjǐ běnfèn.', 'Ngài khen quá rồi, tôi chỉ đang làm đúng bổn phận của mình thôi.'),
  ('过失', '他承认了自己的过失，并表示愿意改正错误。', 'Tā chéngrèn le zìjǐ de guòshī, bìng biǎoshì yuànyì gǎizhèng cuòwù.', 'Anh ấy thừa nhận lỗi lầm của mình và bày tỏ mong muốn sửa chữa sai sót.'),
  ('过于', '她对工作过于专注，常常忽略了身体健康。', 'Tā duì gōngzuò guòyú zhuānzhù, chángcháng hūlüèle shēntǐ jiànkāng.', 'Cô ấy quá chú tâm vào công việc, thường bỏ qua sức khỏe bản thân.'),
  ('辜负', '我们不能辜负父母多年的养育之恩。', 'Wǒmen bùnéng gūfù fùmǔ duōnián de yǎngyù zhī''ēn.', 'Chúng ta không thể phụ lòng công dưỡng dục nhiều năm của cha mẹ.'),
  ('轨道', '高铁的轨道维护对于列车的安全运行至关重要。', 'Gāotiě de guǐdào wéihù duìyú lièchē de ānquán yùnxíng zhìguān zhòngyào.', 'Bảo trì đường ray tàu cao tốc rất quan trọng để đảm bảo vận hành an toàn.'),
  ('跪', '传统仪式中，人们通常会跪下来表示尊敬。', 'Chuántǒng yíshì zhōng, rénmen tōngcháng huì guì xiàlái biǎoshì zūnjìng.', 'Trong nghi lễ truyền thống, người ta thường quỳ xuống để thể hiện sự kính trọng.'),
  ('跟随', '小狗喜欢跟随主人到处跑，形影不离。', 'Xiǎo gǒu xǐhuān gēnsuí zhǔrén dàochù pǎo, xíngyǐng bù lí.', 'Con chó nhỏ thích theo chủ đi khắp nơi, luôn không rời.'),
  ('跟踪', '侦探秘密跟踪了嫌疑人几天，终于找到证据。', 'Zhēntàn mìmì gēnzōng le xiányírén jǐ tiān, zhōngyú zhǎodào zhèngjù.', 'Thám tử bí mật theo dấu nghi phạm vài ngày, cuối cùng tìm được bằng chứng.'),
  ('跟前', '祖母静静地坐在我跟前，讲述过去的故事。', 'Zǔmǔ jìngjìng de zuò zài wǒ gēnqián, jiǎngshù guòqù de gùshì.', 'Bà ngoại ngồi yên lặng bên cạnh tôi kể những câu chuyện ngày xưa.'),
  ('贵族', '那个城堡曾是古代贵族的居住地，非常宏伟。', 'Nàgè chéngbǎo céng shì gǔdài guìzú de jūzhù dì, fēicháng hóngwěi.', 'Tòa lâu đài đó từng là nơi ở của quý tộc cổ đại, rất nguy nga.'),
  ('贯彻', '我们必须彻底贯彻公司的安全生产制度，确保员工安全。', 'Wǒmen bìxū chèdǐ guànchè gōngsī de ānquán shēngchǎn zhìdù, quèbǎo yuángōng ānquán.', 'Chúng ta phải quán triệt triệt để các quy định an toàn sản xuất của công ty để bảo đảm an toàn cho nhân viên.'),
  ('规范', '为了提高服务质量，公司制定了严格的操作规范。', 'Wèile tígāo fúwù zhìliàng, gōngsī zhìdìngle yángé de cāozuò guīfàn.', 'Để nâng cao chất lượng dịch vụ, công ty đã ban hành các quy phạm thao tác nghiêm ngặt.'),
  ('规章', '新入职员工必须认真学习公司的各项规章制度。', 'Xīn rùzhí yuángōng bìxū rènzhēn xuéxí gōngsī de gè xiàng guīzhāng zhìdù.', 'Nhân viên mới phải học kỹ các bản qui định của công ty.'),
  ('规格', '这批产品的尺寸和规格都符合国家标准要求。', 'Zhè pī chǎnpǐn de chǐcùn hé guīgé dōu fúhé guójiā biāozhǔn yāoqiú.', 'Kích thước và qui cách của lô sản phẩm này đều đáp ứng yêu cầu tiêu chuẩn quốc gia.'),
  ('规划', '城市规划部门正在制定未来十年的发展规划。', 'Chéngshì guīhuà bùmén zhèngzài zhìdìng wèilái shí nián de fāzhǎn guīhuà.', 'Bộ phận qui hoạch đô thị đang lập kế hoạch phát triển cho mười năm tới.'),
  ('观光', '假期里，我们计划去云南观光，欣赏美丽的风景。', 'Jiàqī lǐ, wǒmen jìhuà qù Yúnnán guānguāng, xīnshǎng měilì de fēngjǐng.', 'Kỳ nghỉ, chúng tôi dự định đi Vân Nam tham quan, ngắm cảnh đẹp.'),
  ('股份', '他拥有公司五十百分之一的股份，是主要股东之一。', 'Tā yǒngyǒu gōngsī wǔshí bǎi fēn zhī yī de gǔfèn, shì zhǔyào gǔdōng zhī yī.', 'Anh ấy sở hữu 1/50 cổ phần của công ty, là một trong những cổ đông chính.'),
  ('股东', '股东大会决定了公司来年的经营策略和发展方向。', 'Gǔdōng dàhuì juédìngle gōngsī láinián de jīngyíng cèlüè hé fāzhǎn fāngxiàng.', 'Đại hội cổ đông đã quyết định chiến lược kinh doanh và hướng phát triển năm tới của công ty.'),
  ('耕地', '农民们正在努力扩大耕地面积，提高粮食产量。', 'Nóngmínmen zhèngzài nǔlì kuòdà gēngdì miànjī, tígāo liángshí chǎnliàng.', 'Người nông dân đang cố gắng mở rộng diện tích đất trồng để tăng sản lượng lương thực.'),
  ('罐', '厨房里有很多罐子，用来储存各种调料和食品。', 'Chúfáng lǐ yǒu hěn duō guànzi, yòng lái chǔcún gè zhǒng tiáoliào hé shípǐn.', 'Trong bếp có nhiều lọ dùng để lưu trữ các loại gia vị và thực phẩm.'),
  ('纲领', '这个组织的纲领明确指出促进社会公平与正义。', 'Zhège zǔzhī de gānglǐng míngquè zhǐchū cùjìn shèhuì gōngpíng yǔ zhèngyì.', 'Cương lĩnh của tổ chức này rõ ràng chỉ ra việc thúc đẩy công bằng và công lý xã hội.'),
  ('管辖', '这个区域由市政府直接管辖，实行统一管理。', 'Zhège qūyù yóu shì zhèngfǔ zhíjiē guǎnxiá, shíxíng tǒngyī guǎnlǐ.', 'Khu vực này được chính quyền thành phố trực tiếp quản lý và thực hiện quản lý thống nhất.'),
  ('稿件', '编辑正在审核你提交的稿件，稍后会通知你结果。', 'Biānjí zhèngzài shěnhé nǐ tíjiāo de gǎojiàn, shāo hòu huì tōngzhī nǐ jiéguǒ.', 'Biên tập viên đang xem xét bản thảo bạn gửi và sẽ thông báo kết quả sau.'),
  ('盖章', '请在合同每一页都盖章，以确保合同具有法律效力。', 'Qǐng zài hétóng měi yī yè dōu gài zhāng, yǐ quèbǎo hétóng jùyǒu fǎlǜ xiàolì.', 'Xin hãy đóng dấu ở mỗi trang hợp đồng để đảm bảo hợp đồng có giá trị pháp lý.'),
  ('疙瘩', '他的脸上长了几个疙瘩，可能是过敏引起的。', 'Tā de liǎn shàng zhǎngle jǐ gè gēda, kěnéng shì guòmǐn yǐnqǐ de.', 'Trên mặt anh ấy mọc vài mụn, có thể do dị ứng gây ra.'),
  ('灌溉', '为了保证农作物生长，需要及时进行灌溉和施肥。', 'Wèile bǎozhèng nóngzuòwù shēngzhǎng, xūyào jíshí jìnxíng guàngài hé shīféi.', 'Để đảm bảo cây trồng phát triển, cần tưới tiêu và bón phân kịp thời.'),
  ('港湾', '渔船在港湾里停靠，等待下一次出海的机会。', 'Yúchuán zài gǎngwān lǐ tíngkào, děngdài xià yī cì chū hǎi de jīhuì.', 'Tàu cá đang đậu trong bến cảng, chờ cơ hội ra khơi lần tiếp theo.'),
  ('港口', '这个港口每天都有大量货物进出口，经济非常繁忙。', 'Zhège gǎngkǒu měitiān dōu yǒu dàliàng huòwù jìn chūkǒu, jīngjì fēicháng fánmáng.', 'Cảng này mỗi ngày có khối lượng lớn hàng hóa xuất nhập, kinh tế rất nhộn nhịp.'),
  ('歌颂', '很多诗人用优美的诗句歌颂祖国的壮丽山河。', 'Hěn duō shīrén yòng yōuměi de shījù gēsòng zǔguó de zhuànglì shānhé.', 'Nhiều thi sĩ dùng những câu thơ hay để ca tụng đất nước tươi đẹp.'),
  ('棍棒', '历史上有些地方的管理者通过棍棒来维持秩序。', 'Lìshǐ shàng yǒuxiē dìfāng de guǎnlǐ zhě tōngguò gùnbàng lái wéichí zhìxù.', 'Trong lịch sử, có nơi quản lý duy trì trật tự bằng gậy gộc.'),
  ('格式', '请按照指定格式提交你的申请材料以便审核。', 'Qǐng ànzhào zhǐdìng géshì tíjiāo nǐ de shēnqǐng cáiliào yǐbiàn shěnhé.', 'Vui lòng gửi tài liệu xin việc của bạn theo đúng quy cách được chỉ định để tiện xét duyệt.'),
  ('格局', '这座建筑的内部格局设计非常独特，吸引了很多游客。', 'Zhè zuò jiànzhú de nèibù géjú shèjì fēicháng dútè, xīyǐn le hěn duō yóukè.', 'Bố cục bên trong của tòa kiến trúc này rất độc đáo, thu hút nhiều du khách.'),
  ('根源', '我们必须找到问题的根源，才能真正解决它。', 'Wǒmen bìxū zhǎodào wèntí de gēnyuán, cáinéng zhēnzhèng jiějué tā.', 'Chúng ta phải tìm ra nguồn cơn của vấn đề thì mới có thể giải quyết triệt để.'),
  ('根深蒂固', '这种传统观念在农村地区根深蒂固，不容易改变。', 'Zhè zhǒng chuántǒng guānniàn zài nóngcūn dìqū gēnshēn dìgù, bù róngyì gǎibiàn.', 'Quan niệm truyền thống này đã thâm căn cố đế ở vùng nông thôn, rất khó thay đổi.'),
  ('果断', '面对突发情况，他表现得非常果断，迅速做出了决策。', 'Miàn duì tūfā qíngkuàng, tā biǎoxiàn dé fēicháng guǒduàn, xùnsù zuòchū le juécè.', 'Khi đối mặt tình huống bất ngờ, anh ấy thể hiện sự quyết đoán rất nhanh chóng đưa ra quyết định.'),
  ('构思', '艺术家在创作之前会仔细构思作品的整体风格。', 'Yìshùjiā zài chuàngzuò zhīqián huì zǐxì gòusī zuòpǐn de zhěngtǐ fēnggé.', 'Nghệ sĩ thường suy nghĩ kỹ lưỡng về ý tưởng tổng thể cho tác phẩm trước khi sáng tác.'),
  ('杠杆', '利用财务杠杆可以放大投资收益，但风险也相应增加。', 'Lìyòng cáiwù gànggǎn kěyǐ fàngdà tóuzī shōuyì, dàn fēngxiǎn yě xiāngyìng zēngjiā.', 'Sử dụng đòn bẩy tài chính có thể khuếch đại lợi nhuận đầu tư, nhưng rủi ro cũng tăng theo.'),
  ('更正', '请及时更正报告中的错误数据，确保信息准确无误。', 'Qǐng jíshí gēngzhèng bàogào zhōng de cuòwù shùjù, quèrèn xìnxī zhǔnquè wúwù.', 'Vui lòng sửa kịp thời các dữ liệu sai trong báo cáo để đảm bảo thông tin chính xác.'),
  ('更新', '软件开发团队正在努力更新系统以提高用户体验。', 'Ruǎnjiàn kāifā tuánduì zhèngzài nǔlì gēngxīn xìtǒng yǐ tígāo yònghù tǐyàn.', 'Nhóm phát triển phần mềm đang cố gắng cập nhật hệ thống để nâng cao trải nghiệm người dùng.'),
  ('故障', '由于硬件故障，机器暂停运行，需要尽快修理。', 'Yóuyú yìngjiàn gùzhàng, jīqì zàntíng yùnxíng, xūyào jǐnkuài xiūlǐ.', 'Do sự cố phần cứng, máy ngừng hoạt động, cần sửa chữa càng sớm càng tốt.'),
  ('故乡', '每当春节临近，他总是怀念远方的故乡和亲人。', 'Měi dāng chūnjié línjìn, tā zǒng shì huáiniàn yuǎnfāng de gùxiāng hé qīnrén.', 'Mỗi khi Tết đến gần, anh ấy luôn nhớ về quê hương xa xôi và người thân.'),
  ('攻击', '网络攻击对公司数据安全构成了严重威胁。', 'Wǎngluò gōngjí duì gōngsī shùjù ānquán gòuchéng le yánzhòng wēixié.', 'Cuộc tấn công mạng đã tạo thành mối đe dọa nghiêm trọng đối với an toàn dữ liệu của công ty.'),
  ('攻克', '科研人员经过多年努力终于攻克了这项技术难题。', 'Kēyán rényuán jīngguò duō nián nǔlì zhōngyú gōngkè le zhè xiàng jìshù nántí.', 'Các nhà nghiên cứu sau nhiều năm nỗ lực cuối cùng đã phá vỡ khó khăn kỹ thuật này.'),
  ('改良', '农民采用新技术改良了作物品种，增加了产量。', 'Nóngmín cǎiyòng xīn jìshù gǎiliáng le zuòwù pǐnzhǒng, zēngjiā le chǎnliàng.', 'Nông dân dùng kỹ thuật mới cải tạo giống cây trồng, tăng sản lượng.'),
  ('搁', '请把书搁在桌子上，别放在地板上。', 'Qǐng bǎ shū gē zài zhuōzi shàng, bié fàng zài dìbǎn shàng.', 'Hãy để sách lên bàn, đừng để trên sàn nhà.'),
  ('拐杖', '老人因腿伤需要拐杖辅助才能正常行走。', 'Lǎorén yīn tuǐ shāng xūyào guǎizhàng fǔzhù cáinéng zhèngcháng xíngzǒu.', 'Ông cụ vì bị thương chân nên cần gậy chống giúp di chuyển bình thường.'),
  ('感染', '医生提醒我们要注意卫生，防止细菌感染。', 'Yīshēng tíxǐng wǒmen yào zhùyì wèishēng, fángzhǐ xìjūn gǎnrǎn.', 'Bác sĩ nhắc chúng ta phải chú ý vệ sinh để phòng tránh nhiễm khuẩn.'),
  ('感慨', '听完他的经历，我深深感慨人生的无常。', 'Tīng wán tā de jīnglì, wǒ shēnshēn gǎnkǎi rénshēng de wúcháng.', 'Nghe xong câu chuyện của anh ấy, tôi rất xúc động trước sự vô thường của cuộc đời.'),
  ('惯例', '按照惯例，公司每年都会组织员工旅游。', 'Ànzhào guànlì, gōngsī měinián dōu huì zǔzhī yuángōng lǚyóu.', 'Theo thông lệ, công ty hàng năm đều tổ chức cho nhân viên đi du lịch.'),
  ('恭敬', '学生们对老师表现出恭敬的态度，遵守课堂纪律。', 'Xuéshēngmen duì lǎoshī biǎoxiàn chū gōngjìng de tàidù, zūnshǒu kètáng jìlǜ.', 'Các học sinh thể hiện thái độ cung kính đối với giáo viên và tuân thủ kỷ luật lớp học.'),
  ('归还', '请您务必在规定时间内归还借阅的图书。', 'Qǐng nín wùbì zài guīdìng shíjiān nèi guīhuán jièyuè de túshū.', 'Xin ông/bà nhất định phải trả về những cuốn sách đã mượn trong thời hạn quy định.'),
  ('归根到底', '归根到底，问题的关键在于管理不善。', 'Guī gēn dào dǐ, wèntí de guānjiàn zàiyú guǎnlǐ bù shàn.', 'Xét đến cùng, mấu chốt của vấn đề chính là quản lý kém.'),
  ('广阔', '这片广阔的草原是许多野生动物的家园。', 'Zhè piàn guǎngkuò de cǎoyuán shì xǔduō yěshēng dòngwù de jiāyuán.', 'Đồng cỏ rộng lớn này là nơi cư trú của nhiều loài động vật hoang dã.'),
  ('干预', '政府不应该干预市场的正常运行。', 'Zhèngfǔ bù yīnggāi gànyù shìchǎng de zhèngcháng yùnxíng.', 'Chính phủ không nên can dự vào hoạt động bình thường của thị trường.'),
  ('干涉', '他总是干涉别人的私人事务，令人不满。', 'Tā zǒng shì gānshè biérén de sīrén shìwù, lìng rén bù mǎn.', 'Anh ta luôn can thiệp vào việc riêng tư của người khác, làm người ta khó chịu.'),
  ('干旱', '今年的干旱导致农作物严重减产。', 'Jīnnián de gānhàn dǎozhì nóngzuòwù yánzhòng jiǎnchǎn.', 'Năm nay khô hạn đã gây ra mất mùa nghiêm trọng.'),
  ('干扰', '噪音干扰了我们的正常休息。', 'Zàoyīn gānrǎo le wǒmen de zhèngcháng xiūxí.', 'Tiếng ồn làm nhiễu loạn giấc nghỉ bình thường của chúng tôi.'),
  ('干劲', '他工作时总是充满干劲，非常积极主动。', 'Tā gōngzuò shí zǒng shì chōngmǎn gànjìn, fēicháng jījí zhǔdòng.', 'Anh ấy lúc làm việc luôn tràn đầy tinh thần hăng hái, rất tích cực và chủ động.'),
  ('巩固', '我们需要巩固已有的基础，才能取得更大进步。', 'Wǒmen xūyào gǒnggù yǐ yǒu de jīchǔ, cáinéng qǔdé gèng dà jìnbù.', 'Chúng ta cần củng cố nền tảng hiện có mới có thể đạt được tiến bộ lớn hơn.'),
  ('工艺品', '这家店里出售许多精美的传统工艺品。', 'Zhè jiā diàn lǐ chūshòu xǔduō jīngměi de chuántǒng gōngyìpǐn.', 'Cửa hàng này bán nhiều đồ mỹ nghệ truyền thống tinh xảo.'),
  ('岗位', '他在公司担任会计岗位已有多年经验。', 'Tā zài gōngsī dānrèn kuàijì gǎngwèi yǐ yǒu duō nián jīngyàn.', 'Anh ấy đảm nhận cương vị kế toán trong công ty đã nhiều năm kinh nghiệm.'),
  ('尴尬', '面对那个突发问题，她显得非常尴尬。', 'Miànduì nàgè túfā wèntí, tā xiǎnde fēicháng gāngà.', 'Đối mặt với vấn đề bất ngờ đó, cô ấy tỏ ra rất bối rối.'),
  ('宫殿', '故宫是北京最著名的古代宫殿之一。', 'Gùgōng shì Běijīng zuì zhùmíng de gǔdài gōngdiàn zhī yī.', 'Cố Cung là một trong những cung điện cổ nổi tiếng nhất ở Bắc Kinh.'),
  ('官方', '公司已经通过官方渠道发布了最新通知。', 'Gōngsī yǐjīng tōngguò guānfāng qúdào fābù le zuìxīn tōngzhī.', 'Công ty đã công bố thông báo mới nhất qua kênh chính thức.'),
  ('孤立', '这个村庄因交通不便而相对孤立。', 'Zhège cūnzhuāng yīn jiāotōng bùbiàn ér xiāngduì gūlì.', 'Ngôi làng này tương đối cô lập do giao thông bất tiện.'),
  ('孤独', '他搬到新城市后感到非常孤独。', 'Tā bān dào xīn chéngshì hòu gǎndào fēicháng gūdú.', 'Sau khi chuyển đến thành phố mới, anh ấy cảm thấy rất cô độc.'),
  ('姑且', '这个问题我们姑且先放一放，待会再讨论。', 'Zhège wèntí wǒmen gūqiě xiān fàng yī fàng, dàihuì zài tǎolùn.', 'Vấn đề này chúng ta tạm thời để sang một bên, lát nữa sẽ thảo luận.'),
  ('国防', '强大的国防能力是国家安全的重要保障。', 'Qiángdà de guófáng nénglì shì guójiā ānquán de zhòngyào bǎozhàng.', 'Năng lực quốc phòng mạnh mẽ là bảo đảm quan trọng cho an ninh quốc gia.'),
  ('国务院', '国务院近日发布了有关经济发展的新政策。', 'Guówùyuàn jìnrì fābù le yǒuguān jīngjì fāzhǎn de xīn zhèngcè.', 'Chính phủ gần đây đã ban hành chính sách mới liên quan đến phát triển kinh tế.'),
  ('固然', '固然他的建议有道理，但也需要考虑实际情况。', 'Gùrán tā de jiànyì yǒu dàolǐ, dàn yě xūyào kǎolǜ shíjì qíngkuàng.', 'Tuy rằng đề nghị của anh ấy có lý, nhưng cũng cần cân nhắc thực tế.'),
  ('固有', '这种文化习俗是我们民族固有的传统。', 'Zhè zhǒng wénhuà xísú shì wǒmen mínzú gùyǒu de chuántǒng.', 'Phong tục văn hóa này là truyền thống vốn có của dân tộc chúng ta.'),
  ('固执', '他固执地坚持自己的观点，不愿听取别人意见。', 'Tā gùzhí de jiānchí zìjǐ de guāndiǎn, bù yuàn tīngqǔ biérén yìjiàn.', 'Anh ấy cố chấp giữ quan điểm của mình, không muốn nghe ý kiến người khác.'),
  ('固体', '水在低温下会变成固体状态，即冰。', 'Shuǐ zài dī wēn xià huì biàn chéng gùtǐ zhuàngtài, jí bīng.', 'Nước ở nhiệt độ thấp sẽ chuyển thành thể rắn, tức là băng.'),
  ('告辞', '会议结束后，他向大家正式告辞离开了。', 'Huìyì jiéshù hòu, tā xiàng dàjiā zhèngshì gàocí líkāi le.', 'Sau khi cuộc họp kết thúc, anh ấy đã chính thức cáo từ mọi người ra về.'),
  ('告诫', '老师反复告诫学生不要迟到。', 'Lǎoshī fǎnfù gàojiè xuésheng bú yào chídào.', 'Giáo viên nhiều lần khuyên bảo học sinh đừng đến muộn.'),
  ('各抒己见', '在讨论会上，大家各抒己见，气氛非常热烈。', 'Zài tǎolùn huì shàng, dàjiā gè shū jǐ jiàn, qìfēn fēicháng rèliè.', 'Tại cuộc họp thảo luận, mọi người phát biểu ý kiến của mình, không khí rất sôi nổi.'),
  ('古董', '这家店专门出售各种珍贵古董和收藏品。', 'Zhè jiā diàn zhuānmén chūshòu gèzhǒng zhēnguì gǔdǒng hé shōucángpǐn.', 'Cửa hàng này chuyên bán các loại đồ cổ và đồ sưu tầm quý giá.'),
  ('古怪', '他的穿着风格非常古怪，引起了很多人的注意。', 'Tā de chuānzhuó fēnggé fēicháng gǔguài, yǐnqǐ le hěn duō rén de zhùyì.', 'Phong cách ăn mặc của anh ta rất kì quái, thu hút sự chú ý của nhiều người.'),
  ('勾结', '警方发现他与犯罪集团有勾结行为。', 'Jǐngfāng fāxiàn tā yǔ fànzuì jítuán yǒu gōujié xíngwéi.', 'Cảnh sát phát hiện anh ta có hành vi câu kết với nhóm tội phạm.'),
  ('功效', '这种草药的功效已经被科学验证。', 'Zhè zhǒng cǎoyào de gōngxiào yǐjīng bèi kēxué yànzhèng.', 'Công hiệu của loại thảo dược này đã được khoa học chứng minh.'),
  ('功劳', '他的努力为团队取得了巨大的功劳。', 'Tā de nǔlì wèi tuánduì qǔdé le jùdà de gōngláo.', 'Nỗ lực của anh ấy mang lại công lao to lớn cho đội nhóm.'),
  ('割', '农民们正忙着割稻子迎接丰收季节。', 'Nóngmínmen zhèng mángzhe gē dàozi yíngjiē fēngshōu jìjié.', 'Những người nông dân đang bận rộn cắt lúa đón mùa vụ bội thu.'),
  ('关照', '感谢你的关照，让我在新环境中感到温暖。', 'Gǎnxiè nǐ de guānzhào, ràng wǒ zài xīn huánjìng zhōng gǎndào wēnnuǎn.', 'Cảm ơn sự giúp đỡ của bạn, khiến tôi cảm thấy ấm áp trong môi trường mới.'),
  ('关怀', '父母的关怀是孩子成长过程中最重要的支持。', 'Fùmǔ de guānhuái shì háizi chéngzhǎng guòchéng zhōng zuì zhòngyào de zhīchí.', 'Sự quan tâm của cha mẹ là hỗ trợ quan trọng nhất trong quá trình trưởng thành của trẻ.'),
  ('共鸣', '这部电影引起了观众强烈的共鸣。', 'Zhè bù diànyǐng yǐnqǐ le guānzhòng qiángliè de gòngmíng.', 'Bộ phim này đã gây ra sự đồng cảm mạnh mẽ với khán giả.'),
  ('共计', '我们共计完成了三百个订单。', 'Wǒmen gòngjì wánchéng le sānbǎi gè dìngdān.', 'Chúng tôi tính tổng cộng đã hoàn thành ba trăm đơn hàng.'),
  ('共和国', '中华人民共和国是世界上人口最多的共和国之一。', 'Zhōnghuá Rénmín Gònghéguó shì shìjiè shàng rénkǒu zuì duō de gònghéguó zhī yī.', 'Nước Cộng hòa Nhân dân Trung Hoa là một trong những nước Cộng hòa có dân số đông nhất thế giới.'),
  ('公道', '这个市场的价格非常公道，值得购买。', 'Zhège shìchǎng de jiàgé fēicháng gōngdào, zhídé gòumǎi.', 'Giá cả của thị trường này rất phải chăng, đáng để mua.'),
  ('公证', '合同签订后需要到公证处进行公证。', 'Hétóng qiāndìng hòu xūyào dào gōngzhèng chù jìnxíng gōngzhèng.', 'Sau khi ký hợp đồng cần đến cơ quan công chứng để công chứng.'),
  ('公认', '他是这领域内公认的专家。', 'Tā shì zhè lǐngyù nèi gōngrèn de zhuānjiā.', 'Anh ta là chuyên gia được công nhận trong lĩnh vực này.'),
  ('公然', '他公然在会上反对领导的决定，引起了大家的注意。', 'Tā gōngrán zài huì shàng fǎnduì lǐngdǎo de juédìng, yǐnqǐ le dàjiā de zhùyì.', 'Anh ấy công khai phản đối quyết định của lãnh đạo trong cuộc họp, gây sự chú ý của mọi người.'),
  ('公民', '作为一个公民，他有义务遵守国家的法律和规定。', 'Zuòwéi yí gè gōngmín, tā yǒu yìwù zūnshǒu guójiā de fǎlǜ hé guīdìng.', 'Là một công dân, anh ấy có nghĩa vụ tuân thủ luật pháp và quy định của quốc gia.'),
  ('公正', '法官必须保证审判过程的公正，才能维护司法权威。', 'Fǎguān bìxū bǎozhèng shěnpàn guòchéng de gōngzhèng, cáinéng wéihù sīfǎ quánwēi.', 'Thẩm phán phải đảm bảo quá trình xét xử công bằng thì mới duy trì được uy quyền tư pháp.'),
  ('公式', '这个数学题需要用到特殊的公式才能解决。', 'Zhège shùxué tí xūyào yòng dào tèshū de gōngshì cáinéng jiějué.', 'Bài toán này cần sử dụng công thức đặc biệt mới có thể giải quyết.'),
  ('公安局', '遇到紧急情况，请立即联系当地公安局寻求帮助。', 'Yù dào jǐnjí qíngkuàng, qǐng lìjí liánxì dāngdì gōng''ānjú xúnqiú bāngzhù.', 'Gặp tình huống khẩn cấp, xin liên hệ ngay sở công an địa phương để được giúp đỡ.'),
  ('公告', '公司发布了新的招聘公告，欢迎有才华的人申请。', 'Gōngsī fābù le xīn de zhāopìn gōnggào, huānyíng yǒu cáihuá de rén shēnqǐng.', 'Công ty đã phát hành thông cáo tuyển dụng mới, chào đón những người tài năng ứng tuyển.'),
  ('公务', '他因公务繁忙，经常出差各地。', 'Tā yīn gōngwù fánmáng, jīngcháng chūchāi gè dì.', 'Anh ấy vì công vụ bận rộn, thường xuyên đi công tác nhiều nơi.'),
  ('公关', '这家公司雇佣了专业的公关团队来提升品牌形象。', 'Zhè jiā gōngsī gùyōng le zhuānyè de gōngguān tuánduì lái tíshēng pǐnpái xíngxiàng.', 'Công ty này thuê đội ngũ quan hệ công chúng chuyên nghiệp để nâng cao hình ảnh thương hiệu.'),
  ('光辉', '他在历史上留下了不可磨灭的光辉业绩。', 'Tā zài lìshǐ shàng liú xià le bùkě mómiè de guānghuī yèjì.', 'Anh ấy đã để lại những thành tích huy hoàng không thể phai mờ trong lịch sử.'),
  ('光荣', '为国家服务是一件光荣而有意义的事情。', 'Wèi guójiā fúwù shì yī jiàn guāngróng ér yǒu yìyì de shìqíng.', 'Phục vụ cho đất nước là một việc đầy vinh quang và ý nghĩa.'),
  ('光芒', '太阳的光芒穿过云层洒在大地上，温暖而明亮。', 'Tàiyáng de guāngmáng chuānguò yúncéng sǎ zài dàdì shàng, wēnnuǎn ér míngliàng.', 'Tia sáng của mặt trời xuyên qua những đám mây chiếu rọi xuống mặt đất, ấm áp và rực rỡ.'),
  ('光彩', '她的表演为晚会增添了许多光彩。', 'Tā de biǎoyǎn wèi wǎnhuì zēngtiān le xǔduō guāngcǎi.', 'Phần trình diễn của cô ấy đã làm cho buổi tiệc thêm phần rực rỡ.'),
  ('供给', '政府承诺将供给足够的资源支持教育事业发展。', 'Zhèngfǔ chéngnuò jiāng gōngjǐ zúgòu de zīyuán zhīchí jiàoyù shìyè fāzhǎn.', 'Chính phủ cam kết sẽ cung cấp đủ nguồn lực để hỗ trợ phát triển sự nghiệp giáo dục.'),
  ('供不应求', '节日期间，市场上的鲜花出现了供不应求的情况。', 'Jiérì qíjiān, shìchǎng shàng de xiānhuā chūxiàn le gōng bù yìng qiú de qíngkuàng.', 'Trong dịp lễ, hoa tươi trên thị trường xảy ra tình trạng cung không đủ cầu.'),
  ('个体', '小型个体经济在推动地方发展中起到了重要作用。', 'Xiǎoxíng gètǐ jīngjì zài tuīdòng dìfāng fāzhǎn zhōng qǐ dào le zhòngyào zuòyòng.', 'Kinh tế cá thể nhỏ đã đóng vai trò quan trọng trong thúc đẩy phát triển địa phương.'),
  ('黄昏', '黄昏时分，城市的灯光开始点亮，景色美丽动人。', 'Huánghūn shífēn, chéngshì de dēngguāng kāishǐ diǎnliàng, jǐngsè měilì dòngrén.', 'Lúc hoàng hôn, đèn thành phố bắt đầu sáng lên, cảnh sắc đẹp mê hồn.'),
  ('还原', '科学家们努力还原古代遗迹的真实面貌。', 'Kēxuéjiāmen nǔlì huányuán gǔdài yíjī de zhēnshí miànmào.', 'Các nhà khoa học nỗ lực phục hồi lại diện mạo thật của di tích cổ đại.'),
  ('辉煌', '公司在过去的十年中取得了辉煌的业绩。', 'Gōngsī zài guòqù de shí nián zhōng qǔdé le huīhuáng de yèjì.', 'Công ty đã đạt được những thành tích huy hoàng trong mười năm qua.'),
  ('轰动', '这部电影上映后在全国引起了轰动效应。', 'Zhè bù diànyǐng shàngyìng hòu zài quánguó yǐnqǐ le hōngdòng xiàoyìng.', 'Bộ phim này sau khi ra rạp đã gây ra hiệu ứng chấn động trên toàn quốc.'),
  ('贿赂', '法律严禁任何形式的贿赂行为，否则将受到严惩。', 'Fǎlǜ yánjìn rènhé xíngshì de huìlù xíngwéi, fǒuzé jiāng shòudào yánchěng.', 'Pháp luật nghiêm cấm mọi hình thức hối lộ, nếu không sẽ bị nghiêm trị.'),
  ('货币', '国家发行的货币代表了经济发展的水平。', 'Guójiā fāxíng de huòbì dàibiǎo le jīngjì fāzhǎn de shuǐpíng.', 'Tiền tệ do nhà nước phát hành thể hiện mức độ phát triển kinh tế.'),
  ('豪迈', '他以豪迈的姿态迎接了人生的新挑战。', 'Tā yǐ háomài de zītài yíngjiē le rénshēng de xīn tiǎozhàn.', 'Anh ấy đón nhận thử thách mới trong cuộc sống với phong thái khí phách hào hùng.'),
  ('话筒', '主持人紧握话筒开始了精彩的演讲。', 'Zhǔchí rén jǐn wò huàtǒng kāishǐ le jīngcǎi de yǎnjiǎng.', 'Người dẫn chương trình chặt chẽ cầm micro bắt đầu bài thuyết trình tuyệt vời.'),
  ('行列', '运动员们整齐地排列在行列中准备出发。', 'Yùndòngyuán men zhěngqí de páiliè zài hángliè zhōng zhǔnbèi chūfā.', 'Các vận động viên xếp hàng ngăn nắp chuẩn bị xuất phát.'),
  ('荤', '他因为健康原因决定减少荤菜的摄入。', 'Tā yīn wèi jiànkāng yuányīn juédìng jiǎnshǎo hūncài de shèrù.', 'Anh ấy quyết định giảm lượng đồ mặn vì lý do sức khỏe.'),
  ('荒谬', '他的说法完全荒谬，没有任何依据。', 'Tā de shuōfǎ wánquán huāngmiù, méiyǒu rènhé yījù.', 'Lời nói của anh ta hoàn toàn hoang vu, không có cơ sở gì.'),
  ('荒唐', '这件荒唐的事情让所有人都感到惊讶。', 'Zhè jiàn huāngtáng de shìqíng ràng suǒyǒu rén dōu gǎndào jīngyà.', 'Việc hoang đường này khiến mọi người đều ngạc nhiên.'),
  ('荒凉', '冬天的山村显得格外荒凉，没有一点生机。', 'Dōngtiān de shāncūn xiǎnde géwài huāngliáng, méiyǒu yīdiǎn shēngjī.', 'Làng núi vào mùa đông trông đặc biệt hoang sơ, không có chút sức sống.'),
  ('花蕾', '春天来了，花蕾逐渐绽放出美丽的花朵。', 'Chūntiān lái le, huālěi zhújiàn zhànfàng chū měilì de huāduǒ.', 'Mùa xuân đến, những nụ hoa dần dần nở ra những bông hoa đẹp.'),
  ('花瓣', '风吹落满地的花瓣，像铺上了彩色的地毯。', 'Fēng chuī luò mǎn dì de huābàn, xiàng pū shàng le cǎisè de dìtǎn.', 'Cánh hoa rụng đầy đất bị gió thổi bay, giống như trải một tấm thảm nhiều màu.'),
  ('航行', '这艘船计划在太平洋上航行三个月。', 'Zhè sōu chuán jìhuà zài tàipíngyáng shàng hángxíng sān gè yuè.', 'Con tàu này dự định đi vận chuyển trên Thái Bình Dương trong ba tháng.'),
  ('航空', '航空技术的进步大大推动了全球交通的发展。', 'Hángkōng jìshù de jìnbù dàdà tuīdòng le quánqiú jiāotōng de fāzhǎn.', 'Tiến bộ trong công nghệ hàng không đã thúc đẩy mạnh mẽ sự phát triển giao thông toàn cầu.'),
  ('航天', '中国在航天领域取得了显著的成就。', 'Zhōngguó zài hángtiān lǐngyù qǔdé le xiǎnzhù de chéngjiù.', 'Trung Quốc đã đạt được thành tựu nổi bật trong lĩnh vực hàng không vũ trụ.'),
  ('胡须', '他的胡须修剪得很整齐，看起来十分精神。', 'Tā de húxū xiūjiǎn de hěn zhěngqí, kàn qǐlái shífēn jīngshén.', 'Râu của anh ấy được cắt tỉa rất gọn gàng, trông rất tinh thần.'),
  ('胡乱', '不要胡乱猜测事实，要有理有据地分析。', 'Bù yào húlùn cāicè shìshí, yào yǒu lǐ yǒu jù de fēnxī.', 'Đừng đoán mò loạn xạ về sự thật, phải phân tích có lý có chứng.'),
  ('耗费', '完成这个项目将耗费大量的人力和物力。', 'Wánchéng zhège xiàngmù jiāng hàofèi dàliàng de rénlì hé wùlì.', 'Hoàn thành dự án này sẽ tốn rất nhiều nhân lực và vật lực.'),
  ('罕见', '这种珍禽极为罕见，很少有人有机会见到。', 'Zhè zhǒng zhēn qín jí wèi hǎnjiàn, hěn shǎo yǒu rén yǒu jīhuì jiàn dào.', 'Loài chim quý này rất hiếm thấy, ít người có cơ hội gặp.'),
  ('缓和', '两国关系开始缓和，外交谈判也逐渐顺利。', 'Liǎng guó guānxì kāishǐ huǎnhé, wàijiāo tánpàn yě zhújiàn shùnlì.', 'Quan hệ hai nước bắt đầu hòa dịu, các cuộc đàm phán ngoại giao cũng dần thuận lợi.'),
  ('皇帝', '那位皇帝在位期间实行了许多改革措施。', 'Nà wèi huángdì zàiwèi qījiān shíxíng le xǔduō gǎigé cuòshī.', 'Vị hoàng đế đó đã thực hiện nhiều biện pháp cải cách trong thời gian trị vì.'),
  ('皇后', '皇后在宫中拥有极高的威望和权力。', 'Huánghòu zài gōng zhōng yǒngyǒu jí gāo de wēiwàng hé quánlì.', 'Hoàng hậu trong cung có uy tín và quyền lực rất cao.'),
  ('痕迹', '犯罪现场留下了明显的痕迹，警方正在调查。', 'Fànzuì xiànchǎng liú xiàle míngxiǎn de hénjì, jǐngfāng zhèngzài diàochá.', 'Hiện trường phạm tội để lại dấu vết rõ ràng, cảnh sát đang điều tra.'),
  ('画蛇添足', '他本来做得很好，结果画蛇添足反而弄巧成拙。', 'Tā běnlái zuò dé hěn hǎo, jiéguǒ huà shé tiān zú fǎn''ér nòng qiǎo chéng zhuō.', 'Anh ấy vốn làm rất tốt, nhưng vẽ rắn thêm chân lại khiến việc trở nên tệ hơn.'),
  ('环节', '这个项目的每个环节都必须严格把关，确保质量。', 'Zhège xiàngmù de měi gè huánjié dōu bìxū yángé bǎguān, quèbǎo zhìliàng.', 'Mỗi mắt xích của dự án này đều phải kiểm soát nghiêm ngặt để đảm bảo chất lượng.'),
  ('狠心', '他狠心离开家乡，去陌生的城市打拼。', 'Tā hěnxīn líkāi jiāxiāng, qù mòshēng de chéngshì dǎpīn.', 'Anh ấy nhẫn tâm rời bỏ quê hương, đến thành phố xa lạ để gây dựng sự nghiệp.'),
  ('烘', '师傅用火烘茶叶，使其香气更加浓郁。', 'Shīfu yòng huǒ hōng cháyè, shǐ qí xiāngqì gèngjiā nóngyù.', 'Thợ dùng lửa sấy trà, làm cho mùi thơm thêm đậm đà.'),
  ('火药', '古代战争中，火药的发明极大地改变了战术。', 'Gǔdài zhànzhēng zhōng, huǒyào de fāmíng jídà dì gǎibiànle zhànshù.', 'Trong chiến tranh cổ đại, phát minh ra thuốc súng đã thay đổi chiến thuật một cách lớn lao.'),
  ('火箭', '科学家成功发射了一枚新的火箭，进入太空轨道。', 'Kēxuéjiā chénggōng fāshèle yī méi xīn de huǒjiàn, jìnrù tàikōng guǐdào.', 'Các nhà khoa học đã phóng thành công một quả tên lửa mới vào quỹ đạo không gian.'),
  ('火焰', '篝火的火焰在夜晚跳动，温暖了大家的心。', 'Gōuhuǒ de huǒyàn zài yèwǎn tiàodòng, wēnnuǎnle dàjiā de xīn.', 'Ngọn lửa trại nhảy múa trong đêm tối, sưởi ấm trái tim mọi người.'),
  ('湖泊', '这片地区分布着许多清澈的湖泊，风景优美。', 'Zhè piàn dìqū fēnbù zhe xǔduō qīngchè de húpō, fēngjǐng yōuměi.', 'Khu vực này phân bố rất nhiều hồ nước trong xanh, phong cảnh rất đẹp.'),
  ('混淆', '不要把事实和谣言混淆，否则很容易误解。', 'Bù yào bǎ shìshí hé yáoyán hùnxiáo, fǒuzé hěn róngyì wùjiě.', 'Đừng để lẫn lộn sự thật và tin đồn, nếu không rất dễ bị hiểu lầm.'),
  ('混浊', '这条河流因工业废水排放变得十分混浊。', 'Zhè tiáo héliú yīn gōngyè fèishuǐ páifàng biàndé shífēn húnzhuó.', 'Dòng sông này trở nên rất đục vì nước thải công nghiệp.'),
  ('混合', '将不同颜色的颜料混合，可以调出新的颜色。', 'Jiāng bùtóng yánsè de yánliào hùnhé, kěyǐ tiáo chū xīn de yánsè.', 'Trộn các màu sơn khác nhau có thể pha ra màu mới.'),
  ('混乱', '交通事故导致道路一片混乱，车辆无法通行。', 'Jiāotōng shìgù dǎozhì dàolù yīpiàn hùnluàn, chēliàng wúfǎ tōngxíng.', 'Tai nạn giao thông khiến đường phố hỗn loạn, xe cộ không thể đi lại.'),
  ('海滨', '我们计划去海滨度假，享受阳光和海风。', 'Wǒmen jìhuà qù hǎibīn dùjià, xiǎngshòu yángguāng hé hǎifēng.', 'Chúng tôi dự định đi nghỉ mát ven biển, tận hưởng ánh nắng và gió biển.'),
  ('海拔', '这座山峰的海拔超过三千米，攀登难度很大。', 'Zhè zuò shānfēng de hǎibá chāoguò sānqiān mǐ, pāndēng nándù hěn dà.', 'Đỉnh núi này có độ cao trên mực nước biển hơn 3000 mét, việc leo núi rất khó khăn.'),
  ('浑身', '运动后他浑身出汗，但觉得非常舒畅。', 'Yùndòng hòu tā húnshēn chū hàn, dàn juéde fēicháng shūchàng.', 'Sau khi vận động, khắp người anh ấy đẫm mồ hôi nhưng cảm thấy rất dễ chịu.'),
  ('活该', '他不努力学习，考试成绩差，活该失败。', 'Tā bù nǔlì xuéxí, kǎoshì chéngjī chà, huógāi shībài.', 'Anh ta không chăm học, điểm thi kém, đáng đời thất bại.'),
  ('活力', '年轻人充满了活力，能够迎接各种挑战。', 'Niánqīngrén chōngmǎnle huólì, nénggòu yíngjiē gèzhǒng tiǎozhàn.', 'Người trẻ tuổi tràn đầy sức sống, có thể đón nhận mọi thử thách.'),
  ('洪水', '连续降雨导致洪水泛滥，许多村庄受灾严重。', 'Liánxù jiàngyǔ dǎozhì hóngshuǐ fànlàn, xǔduō cūnzhuāng shòuzāi yánzhòng.', 'Mưa kéo dài gây ra lũ lụt, nhiều làng mạc chịu thiệt hại nặng nề.'),
  ('汇报', '他向领导汇报了项目的最新进展情况。', 'Tā xiàng lǐngdǎo huìbào le xiàngmù de zuìxīn jìnzhǎn qíngkuàng.', 'Anh ấy đã báo cáo với lãnh đạo về tiến độ mới nhất của dự án.'),
  ('毫米', '这张纸的厚度只有一毫米，非常薄。', 'Zhè zhāng zhǐ de hòudù zhǐ yǒu yī háomǐ, fēicháng bó.', 'Độ dày của tờ giấy này chỉ có một milimet, rất mỏng.'),
  ('毫无', '他对这个问题毫无头绪，完全不知道怎么办。', 'Tā duì zhège wèntí háo wú tóuxù, wánquán bù zhīdào zěnme bàn.', 'Anh ta hoàn toàn không có manh mối gì về vấn đề này, hoàn toàn không biết phải làm sao.'),
  ('毁灭', '战争给城市带来了毁灭性的破坏和灾难。', 'Zhànzhēng gěi chéngshì dài lái le huǐmiè xìng de pòhuài hé zāinàn.', 'Chiến tranh đã gây ra sự hủy diệt nghiêm trọng và thảm họa cho thành phố.'),
  ('欢乐', '节日的夜晚充满了欢乐和笑声。', 'Jiérì de yèwǎn chōngmǎn le huānlè hé xiàoshēng.', 'Đêm lễ hội tràn ngập niềm vui và tiếng cười.'),
  ('横', '这条街道横穿整个城市，交通非常繁忙。', 'Zhè tiáo jiēdào héng chuān zhěnggè chéngshì, jiāotōng fēicháng fánmáng.', 'Con đường này chạy ngang qua toàn bộ thành phố, giao thông rất bận rộn.'),
  ('晃', '船在海浪中不停地晃动，让乘客感到不适。', 'Chuán zài hǎilàng zhōng bù tíng de huǎngdòng, ràng chéngkè gǎndào bùshì.', 'Con tàu rung lắc không ngừng trong sóng biển khiến hành khách cảm thấy khó chịu.'),
  ('昏迷', '事故后他昏迷了三天才逐渐恢复意识。', 'Shìgù hòu tā hūnmí le sān tiān cái zhújiàn huīfù yìshí.', 'Sau tai nạn, anh ấy hôn mê ba ngày mới dần dần hồi phục ý thức.'),
  ('捍卫', '士兵们誓死捍卫国家的尊严和安全。', 'Shìbīngmen shì sǐ hànwèi guójiā de zūnyán hé ānquán.', 'Các chiến sĩ thề bảo vệ danh dự và an ninh của đất nước đến cùng.'),
  ('挥霍', '他年轻时喜欢挥霍无度，后来才明白节俭的重要性。', 'Tā niánqīng shí xǐhuan huīhuò wúdù, hòulái cái míngbái jiéjiǎn de zhòngyào xìng.', 'Khi còn trẻ anh ta thích phung phí vô độ, sau đó mới hiểu được tầm quan trọng của việc tiết kiệm.'),
  ('患者', '医生耐心地为每一位患者解答疑问。', 'Yīshēng nàixīn de wèi měi yī wèi huànzhě jiědá yíwèn.', 'Bác sĩ kiên nhẫn giải đáp thắc mắc cho từng bệnh nhân.'),
  ('悔恨', '他因错过了重要的机会而深感悔恨。', 'Tā yīn cuòguò le zhòngyào de jīhuì ér shēn gǎn huǐhèn.', 'Anh ấy cảm thấy rất hối hận vì đã bỏ lỡ cơ hội quan trọng.'),
  ('恨不得', '看到朋友受伤，她恨不得马上帮忙治疗。', 'Kàn dào péngyǒu shòushāng, tā hèn bù dé mǎshàng bāngmáng zhìliáo.', 'Nhìn thấy bạn bị thương, cô ấy hận chẳng thể giúp chữa trị ngay lập tức.'),
  ('恍然大悟', '听完老师的解释，我才恍然大悟其中的道理。', 'Tīng wán lǎoshī de jiěshì, wǒ cái huǎngrán dà wù qízhōng de dàolǐ.', 'Nghe xong lời giảng giải của thầy, tôi mới bỗng nhiên hiểu ra lý lẽ bên trong.'),
  ('忽略', '他忽略了细节，导致计划失败。', 'Tā hūlüè le xìjié, dǎozhì jìhuà shībài.', 'Anh ta đã bỏ qua những chi tiết, dẫn đến kế hoạch thất bại.'),
  ('寒暄', '见面后，他们进行了简短的寒暄，气氛很友好。', 'Jiànmiàn hòu, tāmen jìnxíng le jiǎnduǎn de hánxuān, qìfēn hěn yǒuhǎo.', 'Sau khi gặp nhau, họ có những lời xã giao ngắn gọn, bầu không khí rất thân thiện.'),
  ('宏观', '经济学家从宏观角度分析市场变化。', 'Jīngjìxué jiā cóng hóngguān jiǎodù fēnxī shìchǎng biànhuà.', 'Chuyên gia kinh tế phân tích sự biến đổi của thị trường từ góc độ vĩ mô.'),
  ('宏伟', '这座宏伟的宫殿吸引了无数游客前来参观。', 'Zhè zuò hóngwěi de gōngdiàn xīyǐn le wúshù yóukè qián lái cānguān.', 'Cung điện to lớn này thu hút vô số khách du lịch đến tham quan.'),
  ('回顾', '回顾过去，我们学到了很多宝贵的经验。', 'Huígù guòqù, wǒmen xué dào le hěn duō bǎoguì de jīngyàn.', 'Nhìn lại quá khứ, chúng ta đã học được nhiều kinh nghiệm quý báu.'),
  ('回避', '面对争议，他选择了回避问题而不作回应。', 'Miànduì zhēngyì, tā xuǎnzé le huíbì wèntí ér bù zuò huíyìng.', 'Đối mặt với tranh cãi, anh ấy chọn tránh né vấn đề mà không phản hồi.'),
  ('回收', '政府大力推动垃圾回收以保护环境。', 'Zhèngfǔ dàlì tuīdòng lājī huíshōu yǐ bǎohù huánjìng.', 'Chính phủ tích cực thúc đẩy thu hồi rác thải để bảo vệ môi trường.'),
  ('回报', '他决定用一生的努力来回报父母的养育之恩。', 'Tā juédìng yòng yīshēng de nǔlì lái huíbào fùmǔ de yǎngyù zhī ēn.', 'Anh ấy quyết định dùng cả đời nỗ lực để báo đáp công ơn sinh dưỡng của cha mẹ.'),
  ('嘿', '嘿，你怎么突然出现在这里，吓了我一跳！', 'Hēi, nǐ zěnme túrán chūxiàn zài zhèlǐ, xiàle wǒ yī tiào!', 'Ôi, sao cậu lại xuất hiện ở đây đột ngột thế, làm tôi giật mình đấy!'),
  ('嗨', '嗨，大家好久不见了，我们聚会吧！', 'Hāi, dàjiā hǎojiǔ bùjiàn le, wǒmen jùhuì ba!', 'Ê, mọi người lâu rồi không gặp, chúng ta tụ tập đi!'),
  ('喉咙', '感冒时喉咙疼痛，讲话都会感到不舒服。', 'Gǎnmào shí hóulóng téngtòng, jiǎnghuà dōu huì gǎndào bú shūfu.', 'Khi bị cảm, cổ họng bị đau, nói chuyện cũng cảm thấy khó chịu.'),
  ('哼', '他哼着小曲走进房间，显得心情不错。', 'Tā hēng zhe xiǎoqǔ zǒu jìn fángjiān, xiǎnde xīnqíng búcuò.', 'Anh ấy rên rỉ ngân nga bài hát nhỏ bước vào phòng, trông tâm trạng khá tốt.'),
  ('哄', '父母用玩具哄孩子睡觉，非常有耐心。', 'Fùmǔ yòng wánjù hǒng háizi shuìjiào, fēicháng yǒu nàixīn.', 'Cha mẹ dùng đồ chơi để dỗ dành con ngủ, rất kiên nhẫn.'),
  ('和谐', '这个社区倡导居民之间和谐相处，共建美好家园。', 'Zhège shèqū chàngdǎo jūmín zhījiān héxié xiāngchǔ, gòngjiàn měihǎo jiāyuán.', 'Khu cộng đồng này thúc đẩy cư dân sống hòa bình với nhau, cùng xây dựng ngôi nhà tốt đẹp.'),
  ('和解', '经过长时间的协商，他们终于达成了和解协议。', 'Jīngguò cháng shíjiān de xiéshāng, tāmen zhōngyú dáchéng le héjiě xiéyì.', 'Sau thời gian dài thương lượng, họ cuối cùng đã đạt được thỏa thuận hòa giải.'),
  ('和蔼', '老师对待学生非常和蔼，大家都很喜欢他。', 'Lǎoshī duìdài xuéshēng fēicháng hé''ǎi, dàjiā dōu hěn xǐhuān tā.', 'Giáo viên đối xử với học sinh rất hòa nhã, mọi người đều rất thích ông ấy.'),
  ('和睦', '邻里之间保持和睦关系，有助于营造良好环境。', 'Línlǐ zhījiān bǎochí hémù guānxì, yǒuzhù yú yíngzào liánghǎo huánjìng.', 'Giữ quan hệ hòa thuận giữa các hàng xóm giúp tạo nên môi trường tốt.'),
  ('和气', '他性格和气，从不与人争吵，因此很受欢迎。', 'Tā xìnggé héqì, cóng bù yǔ rén zhēngchǎo, yīncǐ hěn shòu huānyíng.', 'Anh ấy tính cách hòa hợp, không bao giờ cãi nhau với ai, nên rất được yêu mến.'),
  ('呼啸', '冬天的风呼啸着穿过山谷，带来刺骨的寒意。', 'Dōngtiān de fēng hūxiào zhe chuānguò shāngǔ, dàilái cìgǔ de hányì.', 'Gió mùa đông rú rít thổi qua thung lũng, mang theo cái lạnh thấu xương.'),
  ('呼唤', '她在森林里不停地呼唤失踪的宠物，希望它能听到。', 'Tā zài sēnlín lǐ bù tíng dì hūhuàn shīzōng de chǒngwù, xīwàng tā néng tīngdào.', 'Cô ấy không ngừng gọi tên thú cưng bị mất trong rừng, hy vọng nó có thể nghe thấy.'),
  ('呼吁', '环保组织呼吁大家减少使用塑料袋，保护地球环境。', 'Huánbǎo zǔzhī hūyù dàjiā jiǎnshǎo shǐyòng sùliào dài, bǎohù dìqiú huánjìng.', 'Nhóm bảo vệ môi trường kêu gọi mọi người giảm sử dụng túi nhựa để bảo vệ môi trường trái đất.'),
  ('呵', '呵，你没想到他会突然出现吧？', 'Hē, nǐ méi xiǎngdào tā huì túrán chūxiàn ba?', 'Ôa, bạn không ngờ anh ấy lại xuất hiện đột ngột đúng không?'),
  ('吼', '生气的时候，他忍不住大声吼叫发泄情绪。', 'Shēngqì de shíhòu, tā rěnbuzhù dàshēng hǒujiào fāxiè qíngxù.', 'Khi tức giận, anh ấy không kìm được mà gào to để xả cảm xúc.'),
  ('含糊', '他的回答含糊不清，让人难以理解他的意思。', 'Tā de huídá hánhú bù qīng, ràng rén nányǐ lǐjiě tā de yìsi.', 'Câu trả lời của anh ta mơ hồ không rõ ràng, khiến người khác khó hiểu ý của anh ấy.'),
  ('含义', '这句话的含义非常深刻，需要仔细分析。', 'Zhè jù huà de hányì fēicháng shēnkè, xūyào zǐxì fēnxī.', 'Ý nghĩa của câu này rất sâu sắc, cần phải phân tích kỹ lưỡng.'),
  ('后顾之忧', '他专心工作，不受家庭的后顾之忧影响。', 'Tā zhuānxīn gōngzuò, bù shòu jiātíng de hòugù zhī yōu yǐngxiǎng.', 'Anh ấy tập trung làm việc mà không bị nỗi lo về sau của gia đình ảnh hưởng.'),
  ('后勤', '军队的后勤保障是胜利的重要保障之一。', 'Jūnduì de hòuqín bǎozhàng shì shènglì de zhòngyào bǎozhàng zhī yī.', 'Hậu cần quân đội là một trong những yếu tố quan trọng bảo đảm chiến thắng.'),
  ('后代', '我们应该保护环境，为后代创造更好的生活条件。', 'Wǒmen yīnggāi bǎohù huánjìng, wèi hòudài chuàngzào gèng hǎo de shēnghuó tiáojiàn.', 'Chúng ta nên bảo vệ môi trường để tạo điều kiện sống tốt hơn cho đời sau.'),
  ('合算', '买这台电脑虽然贵，但性能好，还是很合算的。', 'Mǎi zhè tái diànnǎo suīrán guì, dàn xìngnéng hǎo, háishì hěn hésuàn de.', 'Mua chiếc máy tính này tuy đắt nhưng hiệu suất tốt, vẫn rất được lợi.'),
  ('合成', '这种药物是由多种化学物质合成的。', 'Zhè zhǒng yàowù shì yóu duō zhǒng huàxué wùzhì héchéng de.', 'Loại thuốc này được hợp thành từ nhiều chất hóa học.'),
  ('合并', '两家公司决定合并，以增强市场竞争力。', 'Liǎng jiā gōngsī juédìng hébìng, yǐ zēngqiáng shìchǎng jìngzhēng lì.', 'Hai công ty quyết định hợp lại để tăng cường sức cạnh tranh trên thị trường.'),
  ('合伙', '他们合伙开了一家餐厅，生意蒸蒸日上。', 'Tāmen héhuǒ kāile yī jiā cāntīng, shēngyì zhēngzhēng rì shàng.', 'Họ làm chung mở một nhà hàng, kinh doanh rất phát đạt.'),
  ('号召', '领导号召大家积极参与志愿者活动。', 'Lǐngdǎo hàozhào dàjiā jījí cānyù zhìyuàn zhě huódòng.', 'Lãnh đạo hiệu triệu mọi người tích cực tham gia hoạt động tình nguyện.'),
  ('华侨', '华侨在国外为祖国的发展做出了重要贡献。', 'Huáqiáo zài guówài wèi zǔguó de fāzhǎn zuòchūle zhòngyào gòngxiàn.', 'Hoa kiều ở nước ngoài đã đóng góp quan trọng cho sự phát triển của đất nước.'),
  ('华丽', '她穿了一件华丽的晚礼服参加舞会。', 'Tā chuānle yī jiàn huálì de wǎn lǐfú cānjiā wǔhuì.', 'Cô ấy mặc một chiếc váy dạ hội hoa lệ để dự tiệc khiêu vũ.'),
  ('化验', '医生让病人做血液化验来检查健康状况。', 'Yīshēng ràng bìngrén zuò xuèyè huàyàn lái jiǎnchá jiànkāng zhuàngkuàng.', 'Bác sĩ yêu cầu bệnh nhân làm xét nghiệm máu để kiểm tra tình trạng sức khỏe.'),
  ('化肥', '农民们使用化肥来提高农作物的产量。', 'Nóngmínmen shǐyòng huàféi lái tígāo nóngzuòwù de chǎnliàng.', 'Nông dân sử dụng phân bón hóa học để tăng năng suất cây trồng.'),
  ('化石', '这块化石证明了这里曾经存在过恐龙。', 'Zhè kuài huàshí zhèngmíngle zhèlǐ céngjīng cúnzài guò kǒnglóng.', 'Hóa thạch này chứng minh rằng nơi đây từng tồn tại khủng long.'),
  ('化妆', '演员在后台仔细化妆准备上台表演。', 'Yǎnyuán zài hòutái zǐxì huàzhuāng zhǔnbèi shàngtái biǎoyǎn.', 'Diễn viên trang điểm cẩn thận ở hậu trường chuẩn bị lên sân khấu biểu diễn.'),
  ('划分', '老师根据成绩把学生划分为几个不同的小组。', 'Lǎoshī gēnjù chéngjī bǎ xuéshēng huàfēn wéi jǐ gè bùtóng de xiǎozǔ.', 'Giáo viên dựa vào thành tích chia học sinh thành vài nhóm khác nhau.'),
  ('候选', '他是本次选举的候选人之一，支持率很高。', 'Tā shì běn cì xuǎnjǔ de hòuxuǎn rén zhī yī, zhīchí lǜ hěn gāo.', 'Anh ấy là một trong những người được đề cử trong cuộc bầu cử này, tỷ lệ ủng hộ rất cao.'),
  ('会晤', '两国领导人将在明天举行正式会晤。', 'Liǎng guó lǐngdǎorén jiāng zài míngtiān jǔxíng zhèngshì huìwù.', 'Lãnh đạo hai quốc gia sẽ tổ chức gặp mặt chính thức vào ngày mai.'),
  ('饥饿', '很多地区的人民因为饥饿正在等待救援。', 'Hěn duō dìqū de rénmín yīnwèi jī''è zhèngzài děngdài jiùyuán.', 'Người dân nhiều vùng đang chờ cứu trợ vì đói khát.'),
  ('颈椎', '长时间低头玩手机容易导致颈椎疼痛。', 'Cháng shíjiān dītóu wán shǒujī róngyì dǎozhì jǐngzhuī téngtòng.', 'Đầu lâu chơi điện thoại dễ gây đau cổ.'),
  ('鞠躬', '演员向观众鞠躬感谢大家的掌声。', 'Yǎnyuán xiàng guānzhòng jūgōng gǎnxiè dàjiā de zhǎngshēng.', 'Diễn viên cúi người cảm ơn tiếng vỗ tay của khán giả.'),
  ('集团', '这家集团在国际市场上拥有很大的影响力。', 'Zhè jiā jítuán zài guójì shìchǎng shàng yōngyǒu hěn dà de yǐngxiǎng lì.', 'Tập đoàn này có ảnh hưởng lớn trên thị trường quốc tế.'),
  ('降临', '冬天的降临让整个城市披上了银白的外衣。', 'Dōngtiān de jiànglín ràng zhěnggè chéngshì pī shàngle yín bái de wàiyī.', 'Sự đến của mùa đông khiến toàn thành phố khoác lên chiếc áo trắng bạc.'),
  ('阶层', '社会的不同阶层对政策有着各自的反应。', 'Shè huì de bù tóng jiē céng duì zhèng cè yǒu zhe gè zì de fǎn yìng.', 'Các tầng lớp xã hội khác nhau có những phản ứng riêng đối với chính sách.'),
  ('间隔', '座位之间的间隔足够保证乘客的舒适感。', 'Zuò wèi zhī jiān de jiàn gé zú gòu bǎo zhèng chéng kè de shū shì gǎn.', 'Khoảng cách giữa các ghế đủ để đảm bảo sự thoải mái cho hành khách.'),
  ('间谍', '那个电影讲述了一名间谍在异国的冒险故事。', 'Nà ge diàn yǐng jiǎng shù le yī míng jiàn dié zài yì guó de mào xiǎn gù shì.', 'Bộ phim kể về câu chuyện phiêu lưu của một gián điệp ở nước ngoài.'),
  ('间接', '他通过朋友间接得知了公司的机密消息。', 'Tā tōng guò péng yǒu jiàn jiē dé zhī le gōng sī de jī mì xiāo xī.', 'Anh ấy gián tiếp biết được tin mật của công ty qua bạn bè.'),
  ('镜头', '导演用一个长镜头展现了城市的繁华景象。', 'Dǎo yǎn yòng yī gè cháng jìng tóu zhǎn xiàn le chéng shì de fán huá jǐng xiàng.', 'Đạo diễn sử dụng một ống kính dài để thể hiện cảnh phồn hoa của thành phố.'),
  ('锦上添花', '他的成功让家人的幸福锦上添花。', 'Tā de chéng gōng ràng jiā rén de xìng fú jǐn shàng tiān huā.', 'Thành công của anh ấy làm tăng thêm niềm hạnh phúc cho gia đình.'),
  ('鉴定', '专家对这幅画进行了仔细的鉴定以确定真伪。', 'Zhuān jiā duì zhè fú huà jìn xíng le zǐ xì de jiàn dìng yǐ què dìng zhēn wěi.', 'Chuyên gia đã tiến hành giám định kỹ lưỡng bức tranh này để xác định thật giả.'),
  ('鉴别', '消费者要学会鉴别商品的质量和真伪。', 'Xiāo fèi zhě yào xué huì jiàn bié shāng pǐn de zhì liàng hé zhēn wěi.', 'Người tiêu dùng cần học cách phân biệt chất lượng và thật giả của hàng hóa.'),
  ('鉴于', '鉴于当前的经济形势，公司决定调整发展战略。', 'Jiàn yú dāng qián de jīng jì xíng shì, gōng sī jué dìng tiáo zhěng fā zhǎn zhàn lüè.', 'Xét thấy tình hình kinh tế hiện tại, công ty quyết định điều chỉnh chiến lược phát triển.'),
  ('金融', '金融危机对全球经济造成了严重影响。', 'Jīn róng wēi jī duì quán qiú jīng jì zào chéng le yán zhòng yǐng xiǎng.', 'Khủng hoảng tài chính đã gây ảnh hưởng nghiêm trọng đến nền kinh tế toàn cầu.'),
  ('酒精', '医生建议病人在服药期间避免饮用含酒精的饮料。', 'Yī shēng jiàn yì bìng rén zài fú yào qī jiān bì miǎn yǐn yòng hán jiǔ jīng de yǐn liào.', 'Bác sĩ khuyên bệnh nhân tránh uống đồ uống có cồn trong thời gian dùng thuốc.'),
  ('迹象', '市场出现了经济复苏的积极迹象。', 'Shì chǎng chū xiàn le jīng jì fù sū de jī jí jì xiàng.', 'Thị trường xuất hiện những dấu hiệu tích cực của sự phục hồi kinh tế.'),
  ('进而', '他先完成了基础研究，进而开展了应用开发。', 'Tā xiān wán chéng le jī chǔ yán jiū, jìn ér kāi zhǎn le yìng yòng kāi fā.', 'Anh ấy trước tiên hoàn thành nghiên cứu cơ bản, tiến tới phát triển ứng dụng.'),
  ('进攻', '球队在比赛中采取了积极的进攻策略。', 'Qiú duì zài bǐ sài zhōng cǎi qǔ le jī jí de jìn gōng cè lüè.', 'Đội bóng đã áp dụng chiến thuật tấn công tích cực trong trận đấu.'),
  ('进展', '项目的各项工作都取得了显著的进展。', 'Xiàng mù de gè xiàng gōng zuò dōu qǔ dé le xiǎn zhù de jìn zhǎn.', 'Các công việc của dự án đều đã đạt được tiến triển đáng kể.'),
  ('进化', '生物的进化过程揭示了适应环境的重要性。', 'Shēng wù de jìn huà guò chéng jiē shì le shì yìng huán jìng de zhòng yào xìng.', 'Quá trình tiến hóa của sinh vật cho thấy tầm quan trọng của việc thích nghi với môi trường.'),
  ('近来', '近来天气变化无常，需要注意防护。', 'Jìn lái tiān qì biàn huà wú cháng, xū yào zhù yì fáng hù.', 'Gần đây thời tiết biến đổi thất thường, cần chú ý phòng chống.'),
  ('较量', '两位棋手经过长时间的较量，最终分出胜负。', 'Liǎng wèi qí shǒu jīng guò cháng shí jiān de jiào liàng, zuì zhōng fēn chū shèng fù.', 'Hai kỳ thủ đấu trí suốt thời gian dài cuối cùng phân định thắng thua.'),
  ('践踏', '我们应该保护环境，避免对自然资源的践踏。', 'Wǒ men yīng gāi bǎo hù huán jìng, bì miǎn duì zì rán zī yuán de jiàn tà.', 'Chúng ta nên bảo vệ môi trường, tránh giẫm đạp lên tài nguyên thiên nhiên.'),
  ('记载', '这本古籍中记载了许多珍贵的历史资料。', 'Zhè běn gǔ jí zhōng jì zǎi le xǔ duō zhēn guì de lì shǐ zī liào.', 'Trong cuốn cổ thư này có ghi chép rất nhiều tư liệu lịch sử quý giá.'),
  ('记性', '他的记性非常好，能记住很多复杂的细节。', 'Tā de jì xìng fēicháng hǎo, néng jì zhù hěn duō fùzá de xìjié.', 'Trí nhớ của anh ấy rất tốt, có thể nhớ được nhiều chi tiết phức tạp.'),
  ('讥笑', '同学们不应该讥笑别人的错误，而是要互相帮助。', 'Tóngxuémen bù yīnggāi jīxiào biérén de cuòwù, ér shì yào hùxiāng bāngzhù.', 'Các bạn học không nên chê cười lỗi của người khác mà nên giúp đỡ nhau.'),
  ('计较', '我们不要太计较小问题，应该看重整体效果。', 'Wǒmen bù yào tài jìjiào xiǎo wèntí, yīnggāi kànzhòng zhěngtǐ xiàoguǒ.', 'Chúng ta không nên quá so đo những vấn đề nhỏ mà nên coi trọng hiệu quả tổng thể.'),
  ('警惕', '面对陌生人的接近，大家都应该保持警惕。', 'Miànduì mòshēng rén de jiējìn, dàjiā dōu yīnggāi bǎochí jǐngtì.', 'Đối mặt với việc người lạ tiếp cận, mọi người đều nên giữ cảnh giác.'),
  ('警告', '公司多次警告他不要迟到，但他依然不改。', 'Gōngsī duō cì jǐnggào tā bù yào chídào, dàn tā yīrán bù gǎi.', 'Công ty nhiều lần cảnh cáo anh ta không được đến muộn, nhưng anh ta vẫn không thay đổi.'),
  ('解雇', '由于公司调整，他被迫解雇，感到非常失落。', 'Yóuyú gōngsī tiáozhěng, tā bèi pò jiěgù, gǎndào fēicháng shīluò.', 'Do công ty điều chỉnh, anh ấy bị buộc đuổi việc, cảm thấy rất thất vọng.'),
  ('解除', '我们终于解除误会，双方达成了共识。', 'Wǒmen zhōngyú jiěchú wùhuì, shuāngfāng dáchéng le gòngshí.', 'Cuối cùng chúng tôi đã xua tan hiểu lầm và hai bên đạt được đồng thuận.'),
  ('解散', '会议结束后，大家有序地解散回家。', 'Huìyì jiéshù hòu, dàjiā yǒuxù de jiěsàn huí jiā.', 'Sau khi cuộc họp kết thúc, mọi người lần lượt giải tán về nhà.'),
  ('解放', '经历漫长的斗争，人民终于获得了解放。', 'Jīnglì màncháng de dòuzhēng, rénmín zhōngyú huòdé le jiěfàng.', 'Trải qua cuộc đấu tranh dài, nhân dân cuối cùng đã giành được sự giải phóng.'),
  ('解剖', '医学学生在实验室里认真进行人体解剖练习。', 'Yīxué xuéshēng zài shíyànshì lǐ rènzhēn jìnxíng réntǐ jiěpōu liànxí.', 'Sinh viên y học nghiêm túc tiến hành thực hành giải phẫu cơ thể người trong phòng thí nghiệm.'),
  ('解体', '这个组织因为内部矛盾最终走向了解体。', 'Zhège zǔzhī yīnwèi nèibù máodùn zuìzhōng zǒuxiàng le jiětí.', 'Tổ chức này vì mâu thuẫn nội bộ cuối cùng dẫn đến giải thể.'),
  ('角落', '孩子躲在教室的角落里偷偷玩手机。', 'Háizi duǒ zài jiàoshì de jiǎoluò lǐ tōutōu wán shǒujī.', 'Đứa trẻ trốn ở góc lớp để chơi điện thoại lén lút.'),
  ('觉醒', '经历了一次挫折后，他终于觉醒，开始努力改变自己。', 'Jīnglì le yīcì cuòzhé hòu, tā zhōngyú juéxǐng, kāishǐ nǔlì gǎibiàn zìjǐ.', 'Sau một lần thất bại, anh ấy cuối cùng đã thức tỉnh và bắt đầu cố gắng thay đổi bản thân.'),
  ('觉悟', '只有提高觉悟，才能真正面对生活的挑战。', 'Zhǐyǒu tígāo juéwù, cáinéng zhēnzhèng miànduì shēnghuó de tiǎozhàn.', 'Chỉ khi nâng cao giác ngộ thì mới thực sự đối mặt với thử thách của cuộc sống.'),
  ('见闻', '旅行开阔了眼界，增加了很多见闻。', 'Lǚxíng kāikuò le yǎnjiè, zēngjiā le hěn duō jiànwén.', 'Du lịch đã mở rộng tầm mắt, tăng thêm nhiều hiểu biết.'),
  ('见解', '专家们对于这个问题有不同的见解和看法。', 'Zhuānjiāmen duìyú zhège wèntí yǒu bùtóng de jiànjiě hé kànfǎ.', 'Các chuyên gia có những kiến giải và cách nhìn khác nhau về vấn đề này.'),
  ('见多识广', '他见多识广，能够解决各种复杂的问题。', 'Tā jiàn duō shí guǎng, nénggòu jiějué gèzhǒng fùzá de wèntí.', 'Anh ấy hiểu rộng biết nhiều, có thể giải quyết nhiều vấn đề phức tạp.'),
  ('见义勇为', '他见义勇为，勇敢地救了落水的孩子。', 'Tā jiànyì yǒngwéi, yǒnggǎn de jiù le luòshuǐ de háizi.', 'Anh ấy thấy chuyện bất bình chẳng tha, dũng cảm cứu đứa trẻ bị rơi xuống nước.'),
  ('茎', '这棵植物的茎又粗又直，非常结实。', 'Zhè kē zhíwù de jīng yòu cū yòu zhí, fēicháng jiēshí.', 'Thân cây của cây này vừa to vừa thẳng, rất chắc chắn.'),
  ('节奏', '音乐的节奏感强，让人忍不住跟着跳舞。', 'Yīnyuè de jiézòu gǎn qiáng, ràng rén rěn bù zhù gēnzhe tiàowǔ.', 'Nhịp điệu của âm nhạc rất mạnh, khiến người ta không thể không nhảy theo.'),
  ('节制', '为了健康，他决定节制饮食和减少零食摄入。', 'Wèi le jiànkāng, tā juédìng jiézhì yǐnshí hé jiǎnshǎo língshí shèrù.', 'Để khỏe mạnh, anh ấy quyết định tiết chế ăn uống và giảm ăn đồ ăn vặt.'),
  ('艰难', '创业初期的日子非常艰难，但他们坚持了下来。', 'Chuàngyè chūqī de rìzi fēicháng jiānnán, dàn tāmen jiānchí le xiàlái.', 'Những ngày đầu khởi nghiệp rất gian nan, nhưng họ đã kiên trì vượt qua.'),
  ('舰艇', '这艘舰艇配备了先进的火力系统和雷达设备。', 'Zhè sōu jiàntǐng pèibèi le xiānjìn de huǒlì xìtǒng hé léidá shèbèi.', 'Chiến hạm này được trang bị hệ thống hỏa lực và thiết bị radar tiên tiến.'),
  ('聚精会神', '学生们聚精会神地听讲，准备迎接期末考试。', 'Xuéshēngmen jù jīng huì shén de tīngjiǎng, zhǔnbèi yíngjiē qímò kǎoshì.', 'Các học sinh tập trung tinh thần nghe giảng để chuẩn bị cho kỳ thi cuối kỳ.'),
  ('缴纳', '居民必须在月底前缴纳物业管理费，否则将会被罚款。', 'Jūmín bìxū zài yuèdǐ qián jiǎonà wùyè guǎnlǐ fèi, fǒuzé jiāng huì bèi fákuǎn.', 'Người dân phải nộp phí quản lý bất động sản trước cuối tháng, nếu không sẽ bị phạt.'),
  ('继承', '他继承了祖父的遗产，同时也承担了相应的责任。', 'Tā jìchéng le zǔfù de yíchǎn, tóngshí yě chéngdān le xiāngyìng de zérèn.', 'Anh ấy thừa kế tài sản của ông nội, đồng thời cũng gánh vác trách nhiệm tương ứng.'),
  ('绝望', '在多次失败后，她一度感到绝望，但最终重新振作。', 'Zài duō cì shībài hòu, tā yíduàn gǎndào juéwàng, dàn zuìzhōng chóngxīn zhènzuò.', 'Sau nhiều lần thất bại, cô ấy từng cảm thấy tuyệt vọng nhưng cuối cùng đã vực dậy.'),
  ('给予', '老师给予学生们充分的鼓励和支持，帮助他们成长。', 'Lǎoshī jǐyǔ xuéshēngmen chōngfèn de gǔlì hé zhīchí, bāngzhù tāmen chéngzhǎng.', 'Giáo viên cho các học sinh sự động viên và hỗ trợ đầy đủ để giúp họ trưởng thành.'),
  ('结算', '请在月底前完成所有账单的结算工作，避免延误。', 'Qǐng zài yuèdǐ qián wánchéng suǒyǒu zhàngdān de jiésuàn gōngzuò, bìmiǎn yánwù.', 'Xin vui lòng hoàn tất công việc kết toán tất cả hóa đơn trước cuối tháng để tránh chậm trễ.'),
  ('结晶', '经过数个月的努力，这个科研项目终于有了结晶。', 'Jīngguò shù gè yuè de nǔlì, zhège kēyán xiàngmù zhōngyú yǒu le jiéjīng.', 'Sau nhiều tháng cố gắng, dự án nghiên cứu này cuối cùng đã có kết tinh.'),
  ('结局', '所有的努力最终导致了一个令人满意的结局。', 'Suǒyǒu de nǔlì zuìzhōng dǎozhì le yīgè lìng rén mǎnyì de jiéjú.', 'Mọi nỗ lực cuối cùng đã dẫn đến một kết cục làm hài lòng mọi người.'),
  ('经费', '项目申请因缺少经费而不得不暂时搁置。', 'Xiàngmù shēnqǐng yīn quēshǎo jīngfèi ér bùdébù zànshí gēzhì.', 'Đơn xin dự án phải tạm hoãn do thiếu kinh phí.'),
  ('经纬', '地图上详细标注了该地区的经纬线位置。', 'Dìtú shàng xiángxì biāozhù le gāi dìqū de jīngwěi xiàn wèizhì.', 'Trên bản đồ có đánh dấu chi tiết vị trí kinh tuyến và vĩ tuyến của khu vực đó.'),
  ('纪要', '会议纪要将在明天发送给所有部门负责人。', 'Huìyì jìyào jiāng zài míngtiān fāsòng gěi suǒyǒu bùmén fùzé rén.', 'Biên bản cuộc họp sẽ được gửi đến tất cả trưởng phòng vào ngày mai.'),
  ('级别', '这个职位的级别比之前的要高很多，责任也更大。', 'Zhège zhíwèi de jíbié bǐ zhīqián de yào gāo hěnduō, zérèn yě gèng dà.', 'Cấp bậc của vị trí này cao hơn nhiều so với trước, trách nhiệm cũng lớn hơn.'),
  ('纠纷', '邻居之间因为停车位置产生了纠纷，双方需协商解决。', 'Línjū zhījiān yīnwèi tíngchē wèizhì chǎnshēng le jiūfēn, shuāngfāng xū xiéshāng jiějué.', 'Giữa hàng xóm xảy ra tranh chấp vì vị trí đỗ xe, hai bên cần thương lượng giải quyết.'),
  ('纠正', '老师耐心地帮助学生纠正了发音中的错误。', 'Lǎoshī nàixīn de bāngzhù xuéshēng jiūzhèng le fāyīn zhōng de cuòwù.', 'Giáo viên kiên nhẫn giúp học sinh sửa chữa lỗi phát âm.'),
  ('紧迫', '这项任务非常紧迫，必须在明天上午之前完成。', 'Zhè xiàng rènwu fēicháng jǐnpò, bìxū zài míngtiān shàngwǔ zhīqián wánchéng.', 'Nhiệm vụ này rất cấp bách, phải hoàn thành trước sáng ngày mai.'),
  ('精通', '他精通多种语言，因此很适合做翻译工作。', 'Tā jīngtōng duō zhǒng yǔyán, yīncǐ hěn shìhé zuò fānyì gōngzuò.', 'Anh ấy tinh thông nhiều ngôn ngữ, vì vậy rất phù hợp với công việc phiên dịch.'),
  ('精致', '她家的装修风格非常精致，充满艺术气息。', 'Tā jiā de zhuāngxiū fēnggé fēicháng jīngzhì, chōngmǎn yìshù qìxī.', 'Phong cách trang trí nhà cô ấy rất tinh tế, tràn đầy không khí nghệ thuật.'),
  ('精简', '为了提高效率，公司决定精简管理层的职位。', 'Wèi le tí gāo xiào lǜ, gōng sī jué dìng jīng jiǎn guǎn lǐ céng de zhí wèi.', 'Để nâng cao hiệu quả, công ty quyết định cắt bớt các vị trí quản lý.'),
  ('精确', '这个仪器可以精确测量温度变化。', 'Zhè ge yí qì kě yǐ jīng què cè liáng wēn dù biàn huà.', 'Dụng cụ này có thể đo nhiệt độ thay đổi một cách chính xác.'),
  ('精益求精', '他在绘画上精益求精，作品越来越完美。', 'Tā zài huì huà shàng jīng yì qiú jīng, zuò pǐn yuè lái yuè wán měi.', 'Anh ấy đã giỏi còn muốn giỏi hơn trong hội họa, tác phẩm ngày càng hoàn hảo.'),
  ('精打细算', '她精打细算，确保每一分钱都用得合理。', 'Tā jīng dǎ xì suàn, què bǎo měi yī fēn qián dōu yòng dé hé lǐ.', 'Cô ấy tính toán chi li, bảo đảm mỗi đồng tiền đều dùng hợp lý.'),
  ('精心', '为了这次展览，策展人精心准备了许多作品。', 'Wèi le zhè cì zhǎn lǎn, cè zhǎn rén jīng xīn zhǔn bèi le xǔ duō zuò pǐn.', 'Để chuẩn bị cho triển lãm này, người tổ chức đã cẩn thận chuẩn bị nhiều tác phẩm.'),
  ('精密', '这台机器使用精密零件，确保运行稳定。', 'Zhè tái jī qì shǐ yòng jīng mì líng jiàn, què bǎo yùn xíng wěn dìng.', 'Máy này sử dụng các bộ phận chính xác, đảm bảo vận hành ổn định.'),
  ('精华', '这本书总结了中华文化的精华部分。', 'Zhè běn shū zǒng jié le Zhōng huá wén huà de jīng huá bù fen.', 'Cuốn sách này tóm tắt phần tinh hoa của văn hóa Trung Hoa.'),
  ('籍贯', '他的籍贯是湖南，但他在北京长大。', 'Tā de jí guàn shì Húnán, dàn tā zài Běi jīng zhǎng dà.', 'Nguyên quán của anh ấy là Hồ Nam, nhưng anh lớn lên ở Bắc Kinh.'),
  ('简陋', '那个村庄的学校条件十分简陋，缺乏基本设施。', 'Nà gè cūn zhuāng de xué xiào tiáo jiàn shí fēn jiǎn lòu, quē fá jī běn shè shī.', 'Trường học ở làng đó rất tồi tàn, thiếu các trang thiết bị cơ bản.'),
  ('简要', '请你用简要的语言介绍一下你的工作内容。', 'Qǐng nǐ yòng jiǎn yào de yǔ yán jiè shào yī xià nǐ de gōng zuò nèi róng.', 'Hãy dùng lời ngắn gọn để giới thiệu về nội dung công việc của bạn.'),
  ('简化', '为了方便学习，老师将课程内容进行了简化。', 'Wèi le fāng biàn xué xí, lǎo shī jiāng kè chéng nèi róng jìn xíng le jiǎn huà.', 'Để thuận tiện học tập, giáo viên đã đơn giản hóa nội dung khóa học.'),
  ('简体字', '大部分中国大陆地区使用简体字书写。', 'Dà bù fèn Zhōng guó dà lù dì qū shǐ yòng jiǎn tǐ zì shū xiě.', 'Phần lớn khu vực đại lục Trung Quốc sử dụng chữ giản thể để viết.'),
  ('竭尽全力', '运动员们竭尽全力争取比赛的胜利。', 'Yùn dòng yuán men jié jìn quán lì zhēng qǔ bǐ sài de shèng lì.', 'Các vận động viên dốc toàn lực tranh giành chiến thắng trong trận đấu.'),
  ('竞选', '他决定竞选市长，希望带来改变。', 'Tā jué dìng jìng xuǎn shì zhǎng, xī wàng dài lái gǎi biàn.', 'Anh ấy quyết định vận động tranh cử chức thị trưởng, hy vọng mang đến sự thay đổi.'),
  ('竞赛', '学校每年都会举办各类竞赛激发学生兴趣。', 'Xué xiào měi nián dōu huì jǔ bàn gè lèi jìng sài jī fā xué shēng xìng qù.', 'Mỗi năm trường đều tổ chức nhiều loại thi đấu để kích thích sự hứng thú của học sinh.'),
  ('监视', '系统全天候监视网络安全，防止攻击。', 'Xì tǒng quán tiān hòu jiān shì wǎng luò ān quán, fáng zhǐ gōng jī.', 'Hệ thống theo dõi an ninh mạng 24/7 để ngăn chặn các cuộc tấn công.'),
  ('监督', '监管部门负责监督食品安全标准的执行情况。', 'Jiān dū bù mén fù zé jiān dū shí pǐn ān quán biāo zhǔn de zhí xíng qíng kuàng.', 'Cơ quan giám sát chịu trách nhiệm giám sát việc thực thi tiêu chuẩn an toàn thực phẩm.'),
  ('监狱', '罪犯被判处十年监狱服刑。', 'Zuì fàn bèi pàn chǔ shí nián jiān yù fú xíng.', 'Tội phạm bị kết án thụ hình trong mười năm ở nhà tù.'),
  ('皆', '参加会议的人员皆须提前签到。', 'Cān jiā huì yì de rén yuán jiē xū tí qián qiān dào.', 'Những người tham dự hội nghị đều phải đăng ký trước.'),
  ('疾病', '新研究旨在预防老年常见的慢性疾病发生。', 'Xīn yán jiū zhǐ zài yù fáng lǎo nián cháng jiàn de màn xìng jí bìng fā shēng.', 'Nghiên cứu mới nhằm phòng ngừa các bệnh mãn tính phổ biến ở người cao tuổi.'),
  ('界限', '我们必须明确工作和生活的界限，保证两者平衡。', 'Wǒmen bìxū míngquè gōngzuò hé shēnghuó de jièxiàn, bǎozhèng liǎng zhě pínghéng.', 'Chúng ta phải xác định rõ ranh giới giữa công việc và cuộc sống để đảm bảo cân bằng.'),
  ('煎', '妈妈在厨房里煎鸡蛋，非常专注和认真。', 'Māmā zài chúfáng lǐ jiān jīdàn, fēicháng zhuānzhù hé rènzhēn.', 'Mẹ đang rán trứng trong bếp, rất tập trung và nghiêm túc.'),
  ('焦点', '这次会议的焦点是解决目前的经济难题。', 'Zhè cì huìyì de jiāodiǎn shì jiějué mùqián de jīngjì nántí.', 'Tâm điểm của cuộc họp lần này là giải quyết các khó khăn kinh tế hiện nay.'),
  ('焦急', '得知孩子安全归来，父母终于放下了焦急的心情。', 'Dézhī háizi ānquán guīlái, fùmǔ zhōngyú fàngxiàle jiāojí de xīnqíng.', 'Khi biết con quay về an toàn, cha mẹ cuối cùng cũng hết lo lắng.'),
  ('激情', '运动员在比赛中发挥出满腔的激情和斗志。', 'Yùndòngyuán zài bǐsài zhōng fāhuī chū mǎnqiāng de jīqíng hé dòuzhì.', 'Vận động viên thể hiện sự hăng hái và tinh thần chiến đấu trong trận đấu.'),
  ('激发', '老师的话语激发了学生们的学习兴趣和动力。', 'Lǎoshī de huàyǔ jīfāle xuéshēngmen de xuéxí xìngqù hé dònglì.', 'Lời nói của thầy cô đã khơi gợi hứng thú và động lực học tập của học sinh.'),
  ('激励', '公司大会上经理鼓励大家，要不断努力并激励员工进步。', 'Gōngsī dàhuì shàng jīnglǐ gǔlì dàjiā, yào bùduàn nǔlì bìng jīlì yuángōng jìnbù.', 'Trong cuộc họp công ty, quản lý khích lệ mọi người phải không ngừng cố gắng và động viên nhân viên tiến bộ.'),
  ('溅', '下雨时路上积水被汽车溅起水花，弄脏了行人的鞋子。', 'Xiàyǔ shí lù shàng jīshuǐ bèi qìchē jiàn qǐ shuǐhuā, nòng zāngle xíngrén de xiézi.', 'Khi trời mưa, nước đọng trên đường bị xe cộ bắn tung tóe làm bẩn giày của người đi bộ.'),
  ('浸泡', '把茶叶浸泡在热水中几分钟，味道会更浓郁。', 'Bǎ cháyè jìnpào zài rèshuǐ zhōng jǐ fēnzhōng, wèidào huì gèng nóngyù.', 'Ngâm trà trong nước nóng vài phút sẽ làm hương vị đậm đà hơn.'),
  ('津津有味', '他吃着妈妈做的饭菜，脸上露出津津有味的表情。', 'Tā chī zhe māmā zuò de fàncài, liǎn shàng lùchū jīnjīnyǒuwèi de biǎoqíng.', 'Anh ấy ăn món mẹ làm một cách say sưa với biểu cảm ngon lành trên mặt.'),
  ('沮丧', '考试失利让他感到沮丧，但他决定继续努力。', 'Kǎoshì shīlì ràng tā gǎndào jǔsàng, dàn tā juédìng jìxù nǔlì.', 'Thi trượt khiến anh ta buồn rầu, nhưng anh quyết định tiếp tục cố gắng.'),
  ('检验', '科学家们正在检验新药的有效性和安全性。', 'Kēxuéjiāmen zhèngzài jiǎnyàn xīn yào de yǒuxiàoxìng hé ānquán xìng.', 'Các nhà khoa học đang kiểm nghiệm tính hiệu quả và an toàn của thuốc mới.'),
  ('检讨', '会议结束后，他认真检讨了自己的工作失误。', 'Huìyì jiéshù hòu, tā rènzhēn jiǎntǎo le zìjǐ de gōngzuò shīwù.', 'Sau cuộc họp, anh ấy nghiêm túc kiểm điểm về lỗi sai trong công việc của mình.'),
  ('桨', '划船时，每个人都用力挥动桨，船才前进得更快。', 'Huáchuán shí, měi gèrén dōu yònglì huī dòng jiǎng, chuán cái qiánjìn de gèng kuài.', 'Khi chèo thuyền, mọi người đều mạnh mẽ vung mái chèo để thuyền tiến nhanh hơn.'),
  ('极限', '为了突破自己的极限，他每天坚持训练几个小时。', 'Wèile tūpò zìjǐ de jíxiàn, tā měitiān jiānchí xùnliàn jǐ gè xiǎoshí.', 'Để vượt qua giới hạn bản thân, anh ấy kiên trì luyện tập vài giờ mỗi ngày.'),
  ('极端', '天气的极端变化对农作物生长造成了很大影响。', 'Tiānqì de jíduān biànhuà duì nóngzuòwù shēngzhǎng zàochéngle hěn dà yǐngxiǎng.', 'Sự biến đổi cực đoan của thời tiết đã gây ảnh hưởng lớn đến sự phát triển của cây trồng.'),
  ('杰出', '他是一位在科学领域非常杰出的专家，获得了多项大奖。', 'Tā shì yī wèi zài kēxué lǐngyù fēicháng jiéchū de zhuānjiā, huòdéle duō xiàng dàjiǎng.', 'Anh ấy là chuyên gia kiệt xuất trong lĩnh vực khoa học, đã nhận nhiều giải thưởng.'),
  ('机遇', '在全球化的趋势下，我们迎来了更多发展的机遇。', 'Zài quánqiú huà de qūshì xià, wǒmen yíngláile gèng duō fāzhǎn de jīyù.', 'Dưới xu thế toàn cầu hóa, chúng ta đón nhận nhiều thời cơ phát triển hơn.'),
  ('机灵', '小孩很机灵，很快就明白了老师的意思。', 'Xiǎohái hěn jīlíng, hěn kuài jiù míngbáile lǎoshī de yìsi.', 'Đứa trẻ rất thông minh lanh lợi, rất nhanh hiểu được ý của thầy cô.'),
  ('机械', '这个工厂使用了先进的机械设备提高生产效率。', 'Zhège gōngchǎng shǐyòngle xiānjìn de jīxiè shèbèi tígāo shēngchǎn xiàolǜ.', 'Nhà máy này sử dụng thiết bị máy móc tiên tiến để nâng cao hiệu quả sản xuất.'),
  ('机构', '这个机构专门负责环境保护方面的研究和宣传。', 'Zhè ge jī gòu zhuān mén fù zé huán jìng bǎo hù fāng miàn de yán jiū hé xuān chuán.', 'Cơ cấu này chuyên phụ trách nghiên cứu và tuyên truyền về bảo vệ môi trường.'),
  ('机智', '他在紧急情况下表现出极高的机智，成功化解了危机。', 'Tā zài jǐn jí qíng kuàng xià biǎo xiàn chū jí gāo de jī zhì, chéng gōng huà jiě le wēi jī.', 'Anh ấy thể hiện sự tinh nhanh rất cao trong tình huống khẩn cấp và thành công hóa giải khủng hoảng.'),
  ('机密', '只有授权人员才能接触这些机密文件。', 'Zhǐ yǒu shòu quán rén yuán cái néng jiē chù zhè xiē jī mì wén jiàn.', 'Chỉ có nhân viên được ủy quyền mới được tiếp cận những tài liệu cơ mật này.'),
  ('机动', '救护车是一种具备高度机动性的紧急车辆。', 'Jiù hù chē shì yī zhǒng jù bèi gāo dù jī dòng xìng de jǐn jí chē liàng.', 'Xe cứu thương là một loại phương tiện khẩn cấp có tính cơ động cao.'),
  ('晋升', '经过几年的努力，她终于被公司晋升为部门经理。', 'Jīng guò jǐ nián de nǔ lì, tā zhōng yú bèi gōng sī jìn shēng wèi bù mén jīng lǐ.', 'Sau vài năm nỗ lực, cô ấy cuối cùng được công ty thăng chức làm trưởng phòng.'),
  ('敬礼', '军人在仪式上向国旗敬礼，表达爱国之情。', 'Jūn rén zài yí shì shàng xiàng guó qí jìng lǐ, biǎo dá ài guó zhī qíng.', 'Quân nhân tại buổi lễ chào cờ, bày tỏ tình yêu nước.'),
  ('敬业', '他以敬业精神赢得了同事们的一致尊重。', 'Tā yǐ jìng yè jīng shén yíng dé le tóng shì men de yī zhì zūn zhòng.', 'Anh ấy đã giành được sự tôn trọng đồng đều của đồng nghiệp nhờ tinh thần mẫn cán.'),
  ('教养', '父母的良好教养对孩子的成长至关重要。', 'Fù mǔ de liáng hǎo jiào yǎng duì hái zi de chéng zhǎng zhì guān zhòng yào.', 'Gia giáo tốt của cha mẹ rất quan trọng đối với sự trưởng thành của trẻ.'),
  ('救济', '政府设立专项基金，用于灾区的救济工作。', 'Zhèng fǔ shè lì zhuān xiàng jī jīn, yòng yú zāi qū de jiù jì gōng zuò.', 'Chính phủ thành lập quỹ đặc biệt dùng để cứu tế khu vực bị thiên tai.'),
  ('搅拌', '请将搅拌机打开，均匀搅拌蛋糕糊直到顺滑。', 'Qǐng jiāng jiǎo bàn jī dǎ kāi, jūn yún jiǎo bàn dàn gāo hú zhí dào shùn huá.', 'Vui lòng bật máy khuấy và khuấy đều hỗn hợp làm bánh cho đến khi mịn.'),
  ('揭露', '这篇报道揭露了企业内部的腐败问题。', 'Zhè piān bào dào jiē lù le qǐ yè nèi bù de fǔ bài wèn tí.', 'Bài báo này phơi bày vấn đề tham nhũng bên trong doanh nghiệp.'),
  ('接连', '这几天我们接连收到客户的投诉，必须及时处理。', 'Zhè jǐ tiān wǒ men jiē lián shōu dào kè hù de tóu sù, bì xū jí shí chǔ lǐ.', 'Mấy ngày nay chúng tôi liên tiếp nhận được khiếu nại của khách hàng, phải xử lý kịp thời.'),
  ('据悉', '据悉，公司将在年底发布最新的产品。', 'Jù xī, gōng sī jiāng zài nián dǐ fā bù zuì xīn de chǎn pǐn.', 'Được biết, công ty sẽ ra mắt sản phẩm mới nhất vào cuối năm.'),
  ('拣', '他在市场上仔细拣选了最新鲜的水果。', 'Tā zài shì chǎng shàng zǐ xì jiǎn xuǎn le zuì xīn xiān de shuǐ guǒ.', 'Anh ấy cẩn thận lựa chọn những loại trái cây tươi nhất ở chợ.'),
  ('拘留', '警方因涉嫌犯罪将嫌疑人拘留调查。', 'Jǐng fāng yīn shè xián fàn zuì jiāng xián yí rén jū liú diào chá.', 'Cảnh sát tạm giữ nghi phạm để điều tra do bị nghi ngờ phạm tội.'),
  ('拘束', '在正式场合他显得有些拘束，不太自然。', 'Zài zhèng shì chǎng hé tā xiǎn de yǒu xiē jū shù, bù tài zì rán.', 'Anh ấy có vẻ hơi bó buộc, không tự nhiên trong dịp chính thức.'),
  ('技巧', '学习绘画不仅需要天赋也需要掌握各种技巧。', 'Xué xí huì huà bù jǐn xū yào tiān fù yě xū yào zhǎng wò gè zhǒng jì qiǎo.', 'Học vẽ không chỉ cần thiên bẩm mà còn phải thành thạo các kỹ xảo khác nhau.'),
  ('截至', '截至目前，全国已有超过五百万人接种疫苗。', 'Jié zhì mù qián, quán guó yǐ yǒu chāo guò wǔ bǎi wàn rén jiē zhòng yì miáo.', 'Tính đến hiện tại, trên toàn quốc đã có hơn 5 triệu người tiêm vắc xin.'),
  ('截止', '申请报名的截止日期是下周五，请大家务必准时提交。', 'Shēn qǐng bào míng de jié zhǐ rì qī shì xià zhōu wǔ, qǐng dà jiā wù bì zhǔn shí tí jiāo.', 'Ngày kết thúc đăng ký là thứ Sáu tuần sau, mọi người nhất định phải nộp đúng hạn.'),
  ('戒备', '边境地区已经提高戒备，防止非法入侵。', 'Biān jìng dì qū yǐ jīng tí gāo jiè bèi, fáng zhǐ fēi fǎ rù qīn.', 'Khu vực biên giới đã nâng cao cảnh giác để phòng chống xâm nhập bất hợp pháp.'),
  ('惊讶', '听到这个消息后，他感到非常惊讶，几乎说不出话来。', 'Tīng dào zhège xiāoxi hòu, tā gǎndào fēicháng jīngyà, jīhū shuō bù chū huà lái.', 'Sau khi nghe tin này, anh ấy cảm thấy rất kinh ngạc, gần như không thể nói được lời nào.'),
  ('惊奇', '她对新发明的科技产品表现出极大的惊奇和兴趣。', 'Tā duì xīn fāmíng de kējì chǎnpǐn biǎoxiàn chū jídà de jīngqí hé xìngqù.', 'Cô ấy thể hiện sự sửng sốt và quan tâm lớn đối với sản phẩm công nghệ mới phát minh.'),
  ('惊动', '他的突然出现惊动了全场，大家都纷纷转头看去。', 'Tā de tūrán chūxiàn jīngdòng le quánchǎng, dàjiā dōu fēnfēn zhuǎn tóu kàn qù.', 'Sự xuất hiện đột ngột của anh ta đã làm kinh động toàn hội trường, mọi người đều quay đầu nhìn.'),
  ('急躁', '在遇到困难时，急躁只会让事情变得更糟糕。', 'Zài yù dào kùnnán shí, jízào zhǐ huì ràng shìqíng biàn dé gèng zāogāo.', 'Khi gặp khó khăn, sự sốt ruột chỉ làm mọi việc trở nên tồi tệ hơn.'),
  ('急功近利', '他做事总是急功近利，缺乏长远的规划和考量。', 'Tā zuòshì zǒng shì jí gōng jìn lì, quēfá chángyuǎn de guīhuà hé kǎoliáng.', 'Anh ta làm việc luôn ăn xổi ở thì, thiếu kế hoạch và suy nghĩ dài hạn.'),
  ('急剧', '由于环境污染，空气质量在过去几年内急剧下降。', 'Yóuyú huánjìng wūrǎn, kōngqì zhìliàng zài guòqù jǐ nián nèi jíjù xiàjiàng.', 'Do ô nhiễm môi trường, chất lượng không khí giảm nhanh chóng trong vài năm qua.'),
  ('急切', '她急切地等待医生的诊断结果，心情十分紧张。', 'Tā jíqiè dì děngdài yīshēng de zhěnduàn jiéguǒ, xīnqíng shífēn jǐnzhāng.', 'Cô ấy cấp thiết chờ đợi kết quả chẩn đoán của bác sĩ, tâm trạng rất căng thẳng.'),
  ('急于求成', '年轻人往往急于求成，忽视了基础的重要性。', 'Niánqīng rén wǎngwǎng jí yú qiú chéng, hūshì le jīchǔ de zhòngyào xìng.', 'Người trẻ thường mong muốn nhanh thành công, bỏ qua tầm quan trọng của nền tảng.'),
  ('忌讳', '在这个文化中，提起某些话题被视为忌讳，大家避而不谈。', 'Zài zhège wénhuà zhōng, tíqǐ mǒuxiē huàtí bèi shìwéi jìhuì, dàjiā bì ér bù tán.', 'Trong văn hóa này, nhắc đến một số chủ đề được coi là kiêng kị, mọi người tránh nói đến.'),
  ('居民', '这里的居民生活安静而祥和，社区关系非常融洽。', 'Zhèlǐ de jūmín shēnghuó ānjìng ér xiánghé, shèqū guānxì fēicháng róngqià.', 'Cư dân ở đây sống yên tĩnh và hòa bình, mối quan hệ trong cộng đồng rất hòa thuận.'),
  ('居住', '他选择在城市中心居住，方便上下班和购物。', 'Tā xuǎnzé zài chéngshì zhōngxīn jūzhù, fāngbiàn shàng xià bān hé gòuwù.', 'Anh ấy chọn sống ở trung tâm thành phố để thuận tiện đi làm và mua sắm.'),
  ('局面', '经过多方努力，终于扭转了当前的紧张局面。', 'Jīngguò duōfāng nǔlì, zhōngyú niǔzhuǎn le dāngqián de jǐnzhāng júmiàn.', 'Sau nhiều nỗ lực từ các bên, cuối cùng đã xoay chuyển được cục diện căng thẳng hiện tại.'),
  ('局限', '他的视野有局限，需要多去体验不同的生活才能开阔。', 'Tā de shìyě yǒu júxiàn, xūyào duō qù tǐyàn bùtóng de shēnghuó cáinéng kāikuò.', 'Tầm nhìn của anh ấy có giới hạn, cần trải nghiệm nhiều cuộc sống khác nhau mới có thể mở rộng.'),
  ('局部', '这幅画的局部细节表现了画家的独特风格。', 'Zhè fú huà de júbù xìjié biǎoxiàn le huàjiā de dútè fēnggé.', 'Chi tiết cục bộ của bức tranh thể hiện phong cách độc đáo của họa sĩ.'),
  ('局势', '国际局势复杂多变，各国都在密切关注。', 'Guójì júshì fùzá duōbiàn, gèguó dōu zài mìqiè guānzhù.', 'Thế cuộc quốc tế phức tạp biến đổi, các quốc gia đều theo dõi sát sao.'),
  ('就近', '学校建议学生就近报名参加社区的志愿活动。', 'Xuéxiào jiànyì xuéshēng jiùjìn bàomíng cānjiā shèqū de zhìyuàn huódòng.', 'Nhà trường khuyên học sinh đăng ký tham gia hoạt động tình nguyện tại khu vực lân cận.'),
  ('就职', '新校长将在下个月正式就职，开展各项教育改革。', 'Xīn xiàozhǎng jiāng zài xià gè yuè zhèngshì jiùzhí, kāizhǎn gè xiàng jiàoyù gǎigé.', 'Hiệu trưởng mới sẽ chính thức nhận chức vào tháng tới, bắt đầu các cải cách giáo dục.'),
  ('就业', '大学毕业生面临严峻的就业压力和激烈的竞争。', 'Dàxué bìyè shēng miànlín yánjùn de jiùyè yālì hé jīliè de jìngzhēng.', 'Sinh viên tốt nghiệp đại học đối mặt với áp lực việc làm nghiêm trọng và cạnh tranh gay gắt.'),
  ('尖锐', '他提出的批评言辞尖锐，但有助于改进工作。', 'Tā tíchū de pīpíng yáncí jiānruì, dàn yǒu zhù yú gǎijìn gōngzuò.', 'Lời phê bình sắc nhọn của anh ấy giúp cải thiện công việc.'),
  ('尖端', '我们公司的研发部门专注于尖端技术的开发和创新。', 'Wǒmen gōngsī de yánfā bùmén zhuānzhù yú jiānduān jìshù de kāifā hé chuàngxīn.', 'Phòng nghiên cứu và phát triển của công ty chúng tôi tập trung vào việc phát triển và đổi mới công nghệ mũi nhọn.'),
  ('将近', '这条路将近五公里长，走完需要一个小时。', 'Zhè tiáo lù jiāng jìn wǔ gōng lǐ cháng, zǒu wán xū yào yī gè xiǎo shí.', 'Con đường này gần 5 km, đi hết mất khoảng một giờ.'),
  ('将就', '饭菜不太好，不过我们只能将就着吃了。', 'Fàn cài bù tài hǎo, bù guò wǒ men zhǐ néng jiāng jiù zhe chī le.', 'Món ăn không ngon lắm, nhưng chúng ta chỉ có thể chấp nhận ăn vậy.'),
  ('将军', '历史上很多将军都在这场战役中立下了赫赫战功。', 'Lì shǐ shàng hěn duō jiāng jūn dōu zài zhè chǎng zhàn yì zhōng lì xià le hè hè zhàn gōng.', 'Trong lịch sử, nhiều tướng quân đã lập công lớn trong trận chiến này.'),
  ('寄托', '他把所有的希望都寄托在孩子的未来身上。', 'Tā bǎ suǒ yǒu de xī wàng dōu jì tuō zài hái zi de wèi lái shēn shàng.', 'Anh ấy gửi gắm tất cả hy vọng vào tương lai của con cái.'),
  ('寂静', '深夜的森林里异常寂静，连一点声音都没有。', 'Shēn yè de sēn lín lǐ yì cháng jì jìng, lián yī diǎn shēng yīn dōu méi yǒu.', 'Trong rừng sâu về đêm yên tĩnh bất thường, chẳng có một tiếng động nào.'),
  ('家常', '他的家常菜做得很好吃，特别是红烧肉。', 'Tā de jiā cháng cài zuò de hěn hǎo chī, tè bié shì hóng shāo ròu.', 'Món ăn đời thường của anh ấy nấu rất ngon, đặc biệt là thịt kho.'),
  ('家属', '事故发生后，医生马上通知了受伤者的家属。', 'Shì gù fā shēng hòu, yī shēng mǎ shàng tōng zhī le shòu shāng zhě de jiā shǔ.', 'Sau khi xảy ra tai nạn, bác sĩ ngay lập tức thông báo cho gia quyến người bị thương.'),
  ('家喻户晓', '他的名字已经家喻户晓，人人都知道他的贡献。', 'Tā de míng zì yǐ jīng jiā yù hù xiǎo, rén rén dōu zhī dào tā de gòng xiàn.', 'Tên của anh ấy đã trở nên nhà nhà đều biết, ai cũng biết đến những đóng góp của anh.'),
  ('家伙', '那个家伙不仅聪明，而且非常勤奋。', 'Nà gè jiā huǒ bù jǐn cōng míng, ér qiě fēi cháng qín fèn.', 'Anh chàng đó không những thông minh mà còn rất chăm chỉ.'),
  ('季度', '公司将在本季度结束时公布最新的财务报告。', 'Gōng sī jiāng zài běn jì dù jié shù shí gōng bù zuì xīn de cái wù bào gào.', 'Công ty sẽ công bố báo cáo tài chính mới nhất vào cuối quý này.'),
  ('季军', '他在全国比赛中获得了季军，表现非常出色。', 'Tā zài quán guó bǐ sài zhōng huò dé le jì jūn, biǎo xiàn fēi cháng chū sè.', 'Anh ấy giành giải ba trong cuộc thi toàn quốc, thể hiện rất xuất sắc.'),
  ('嫉妒', '她因为朋友的成功感到嫉妒，却不愿承认。', 'Tā yīn wèi péng yǒu de chéng gōng gǎn dào jí dù, què bù yuàn chéng rèn.', 'Cô ấy ghen tị vì thành công của bạn nhưng không muốn thừa nhận.'),
  ('娇气', '别太娇气了，遇到困难要坚强面对。', 'Bié tài jiāo qì le, yù dào kùn nán yào jiān qiáng miàn duì.', 'Đừng quá ẻo lả, gặp khó khăn phải kiên cường đối mặt.'),
  ('奖赏', '老师给予表现优异的学生以丰富的奖赏。', 'Lǎo shī jǐ yǔ biǎo xiàn yōu yì de xué shēng yǐ fēng fù de jiǎng shǎng.', 'Giáo viên tặng thưởng phong phú cho những học sinh có thành tích ưu tú.'),
  ('奖励', '公司制定了新的奖励制度以激励员工积极工作。', 'Gōng sī zhì dìng le xīn de jiǎng lì zhì dù yǐ jī lì yuán gōng jī jí gōng zuò.', 'Công ty đề ra hệ thống thưởng mới để khích lệ nhân viên làm việc tích cực.'),
  ('夹杂', '这篇文章的内容夹杂了多种不同的观点。', 'Zhè piān wén zhāng de nèi róng jiā zá le duō zhǒng bù tóng de guān diǎn.', 'Nội dung bài viết này xen lẫn nhiều quan điểm khác nhau.'),
  ('境界', '经过多年的修炼，他达到了很高的艺术境界。', 'Jīng guò duō nián de xiū liàn, tā dá dào le hěn gāo de yì shù jìng jiè.', 'Sau nhiều năm tu luyện, anh ấy đã đạt tới cảnh giới nghệ thuật cao.'),
  ('基金', '这个基金专门用于支持环保项目的发展。', 'Zhè ge jī jīn zhuān mén yòng yú zhī chí huán bǎo xiàng mù de fā zhǎn.', 'Quỹ này chuyên dùng để hỗ trợ phát triển các dự án bảo vệ môi trường.'),
  ('基地', '科学家们在南极建立了研究基地进行长期考察。', 'Kē xué jiā men zài nán jí jiàn lì le yán jiū jī dì jìn xíng cháng qī kǎo chá.', 'Các nhà khoa học đã xây dựng căn cứ nghiên cứu tại Nam Cực để tiến hành khảo sát lâu dài.'),
  ('基因', '基因的变化可能影响一个人的健康状况和特性。', 'Jī yīn de biàn huà kě néng yǐng xiǎng yī gè rén de jiàn kāng zhuàng kuàng hé tè xìng.', 'Sự thay đổi của gen có thể ảnh hưởng đến tình trạng sức khỏe và đặc điểm của một người.'),
  ('坚韧', '他展现了坚韧的意志，克服了所有困难。', 'Tā zhǎnxiàn le jiān rèn de yìzhì, kèfú le suǒyǒu kùnnán.', 'Anh ấy thể hiện ý chí vững chắc, vượt qua mọi khó khăn.'),
  ('坚硬', '这块岩石非常坚硬，连锤子都敲不开。', 'Zhè kuài yánshí fēicháng jiān yìng, lián chuízi dōu qiāo bù kāi.', 'Viên đá này rất cứng, ngay cả búa cũng không đập vỡ được.'),
  ('坚实', '他靠着坚实的基础，实现了自己的梦想。', 'Tā kào zhe jiān shí de jīchǔ, shíxiàn le zìjǐ de mèngxiǎng.', 'Anh ấy dựa vào nền tảng chắc chắn để thực hiện giấc mơ của mình.'),
  ('坚定', '她对理想的追求始终保持坚定的态度。', 'Tā duì lǐxiǎng de zhuīqiú shǐzhōng bǎochí jiān dìng de tàidù.', 'Cô ấy luôn giữ thái độ kiên định trong việc theo đuổi lý tưởng.'),
  ('坚固', '这座桥梁结构坚固，能够承受大风大雨。', 'Zhè zuò qiáoliáng jiégòu jiān gù, nénggòu chéngshòu dà fēng dà yǔ.', 'Cây cầu này có kết cấu kiên cố, có thể chịu được gió lớn và mưa to.'),
  ('咀嚼', '他细细咀嚼每一口食物，享受美味。', 'Tā xìxì jǔjué měi yī kǒu shíwù, xiǎngshòu měiwèi.', 'Anh ấy nhai kỹ từng miếng thức ăn, tận hưởng hương vị thơm ngon.'),
  ('君子', '君子以诚信和礼仪赢得别人的尊重。', 'Jūnzǐ yǐ chéngxìn hé lǐyí yíngdé biérén de zūnzhòng.', 'Quân tử dùng sự thành tín và lễ nghĩa để giành được sự tôn trọng của người khác.'),
  ('吉祥', '新年的到来预示着吉祥和幸福。', 'Xīnnián de dàolái yùshì zhe jíxiáng hé xìngfú.', 'Sự đến của năm mới báo hiệu cát tường và hạnh phúc.'),
  ('及早', '我们应及早采取措施，防止问题恶化。', 'Wǒmen yīng jí zǎo cǎiqǔ cuòshī, fángzhǐ wèntí èhuà.', 'Chúng ta nên sớm có biện pháp để ngăn ngừa vấn đề trở nên nghiêm trọng.'),
  ('卷', '请把这张纸卷起来，方便携带。', 'Qǐng bǎ zhè zhāng zhǐ juǎn qǐlái, fāngbiàn xiédài.', 'Xin hãy cuộn tờ giấy này lại để tiện mang theo.'),
  ('即将', '他即将开始新的工作，充满期待。', 'Tā jí jiāng kāishǐ xīn de gōngzuò, chōngmǎn qídài.', 'Anh ấy sắp bắt đầu công việc mới và đầy hy vọng.'),
  ('即便', '即便遇到困难，他也从不轻易放弃。', 'Jíbiàn yù dào kùnnán, tā yě cóng bù qīngyì fàngqì.', 'Dù có gặp khó khăn, anh ấy cũng không bao giờ dễ dàng từ bỏ.'),
  ('加工', '这些原材料需要经过特殊加工才能使用。', 'Zhèxiē yuáncáiliào xūyào jīngguò tèshū jiāgōng cáinéng shǐyòng.', 'Những nguyên liệu này cần phải trải qua gia công đặc biệt mới có thể sử dụng.'),
  ('加剧', '污染问题因工业发展而加剧，令人担忧。', 'Wūrǎn wèntí yīn gōngyè fāzhǎn ér jiājù, lìng rén dānyōu.', 'Vấn đề ô nhiễm trở nên trầm trọng hơn do sự phát triển công nghiệp, khiến người ta lo ngại.'),
  ('剪彩', '领导在开幕式上主持了剪彩仪式。', 'Lǐngdǎo zài kāimù shì shàng zhǔchí le jiǎn cǎi yíshì.', 'Lãnh đạo đã chủ trì lễ cắt băng khai trương tại buổi lễ.'),
  ('剧烈', '剧烈的运动可能导致身体受伤。', 'Jùliè de yùndòng kěnéng dǎozhì shēntǐ shòushāng.', 'Vận động mạnh có thể gây ra chấn thương cho cơ thể.'),
  ('剧本', '编剧花了几个月时间写完这个剧本。', 'Biānjù huā le jǐ gè yuè shíjiān xiě wán zhège jùběn.', 'Biên kịch đã dành vài tháng để hoàn thành kịch bản này.'),
  ('剑', '古代战士常常挥舞着锋利的剑作战。', 'Gǔdài zhànshì chángcháng huīwǔ zhe fēnglì de jiàn zuòzhàn.', 'Chiến sĩ thời cổ đại thường xuyên vung thanh kiếm sắc bén để chiến đấu.'),
  ('决策', '高层领导正在商讨公司的重要决策。', 'Gāocéng lǐngdǎo zhèngzài shāngtǎo gōngsī de zhòngyào juécè.', 'Lãnh đạo cấp cao đang thảo luận những quyết sách quan trọng của công ty.'),
  ('军队', '军队在自然灾害发生时积极参与救援工作。', 'Jūnduì zài zìrán zāihài fāshēng shí jījí cānyù jiùyuán gōngzuò.', 'Quân đội tích cực tham gia công tác cứu trợ khi thiên tai xảy ra.'),
  ('兢兢业业', '他在工作中一直兢兢业业，毫不马虎。', 'Tā zài gōngzuò zhōng yīzhí jīngjīng yèyè, háo bù mǎhǔ.', 'Anh ấy trong công việc luôn cần cù chăm chỉ, không bao giờ cẩu thả.'),
  ('僵硬', '他的身体因为长时间运动不足变得僵硬。', 'Tā de shēntǐ yīnwèi cháng shíjiān yùndòng bùzú biàn dé jiāngyìng.', 'Cơ thể anh ấy trở nên rắn chắc vì lâu ngày không vận động đủ.'),
  ('健全', '公司需要建立一个健全的管理体系来提升效率。', 'Gōngsī xūyào jiànlì yīgè jiànquán de guǎnlǐ tǐxì lái tíshēng xiàolǜ.', 'Công ty cần xây dựng một hệ thống quản lý kiện toàn để nâng cao hiệu quả.'),
  ('借鉴', '我们应该借鉴国外的先进经验促进发展。', 'Wǒmen yīnggāi jièjiàn guówài de xiānjìn jīngyàn cùjìn fāzhǎn.', 'Chúng ta nên học hỏi kinh nghiệm tiên tiến của nước ngoài để thúc đẩy phát triển.'),
  ('借助', '借助现代科技，教育得到了极大改善。', 'Jièzhù xiàndài kējì, jiàoyù dédàole jídà gǎishàn.', 'Nhờ vào công nghệ hiện đại, giáo dục đã được cải thiện rất nhiều.'),
  ('倔强', '他的性格非常倔强，从不轻易认输。', 'Tā de xìnggé fēicháng juéjiàng, cóng bù qīngyì rènshū.', 'Tính cách của anh ấy rất quật cường, không bao giờ dễ dàng chịu thua.'),
  ('侥幸', '这次考试我侥幸通过了，但没有掌握好知识。', 'Zhè cì kǎoshì wǒ jiǎoxìng tōngguòle, dàn méiyǒu zhǎngwò hǎo zhīshì.', 'Lần thi này tôi ăn may qua được, nhưng không nắm chắc kiến thức.'),
  ('佳肴', '宴会上摆满了各种美味佳肴，令人垂涎欲滴。', 'Yànhuì shàng bǎi mǎnle gèzhǒng měiwèi jiāyáo, lìng rén chuíxián yù dī.', 'Bữa tiệc được bày đầy các món ngon khiến ai cũng thèm thuồng.'),
  ('交涉', '双方通过交涉解决了贸易中的分歧。', 'Shuāngfāng tōngguò jiāoshè jiějué le màoyì zhōng de fēnqí.', 'Hai bên đã giải quyết bất đồng trong thương mại thông qua đàm phán.'),
  ('交易', '公司与多家供应商进行了长期交易合作。', 'Gōngsī yǔ duō jiā gōngyìng shāng jìnxíngle chángqí jiāoyì hézuò.', 'Công ty đã tiến hành hợp tác giao dịch lâu dài với nhiều nhà cung cấp.'),
  ('交叉', '两条道路在市中心交叉形成一个大型十字路口。', 'Liǎng tiáo dàolù zài shì zhōngxīn jiāochā xíngchéng yīgè dàxíng shízì lùkǒu.', 'Hai con đường giao nhau ở trung tâm thành phố tạo thành một ngã tư lớn.'),
  ('交代', '他认真交代了工作内容和注意事项。', 'Tā rènzhēn jiāodài le gōngzuò nèiróng hé zhùyì shìxiàng.', 'Anh ấy đã cẩn thận bàn giao nội dung công việc và những điều cần lưu ý.'),
  ('井', '村子里有一口古老的井，供居民取水。', 'Cūnzi lǐ yǒu yì kǒu gǔlǎo de jǐng, gōng jūmín qǔ shuǐ.', 'Trong làng có một giếng nước cổ cung cấp nước cho dân cư.'),
  ('举足轻重', '这个职位在公司中举足轻重，影响决策方向。', 'Zhège zhíwèi zài gōngsī zhōng jǔzúqīngzhòng, yǐngxiǎng juécè fāngxiàng.', 'Vị trí này trong công ty có vị thế trung tâm, ảnh hưởng đến hướng quyết định.'),
  ('举动', '他的每一个举动都受到媒体的关注。', 'Tā de měi yīgè jǔdòng dōu shòudào méitǐ de guānzhù.', 'Mọi cử động của anh ấy đều được giới truyền thông quan tâm.'),
  ('举世瞩目', '这场比赛成为举世瞩目的体育盛事。', 'Zhè chǎng bǐsài chéngwéi jǔshì zhǔmù de tǐyù shèngshì.', 'Trận đấu này trở thành sự kiện thể thao gây chú ý toàn thế giới.'),
  ('靠拢', '随着时间推移，双方的意见逐渐靠拢。', 'Suízhe shíjiān tuīyí, shuāngfāng de yìjiàn zhújiàn kàolǒng.', 'Theo thời gian trôi qua, ý kiến hai bên dần tiến gần nhau.'),
  ('跨', '他每一步都跨得很大，显示出自信和力量。', 'Tā měi yībù dōu kuà dé hěn dà, xiǎnshì chū zìxìn hé lìliàng.', 'Anh ấy mỗi bước đều sải rộng, thể hiện sự tự tin và sức mạnh.'),
  ('课题', '这个课题需要大量数据和深入分析才能完成。', 'Zhège kètí xūyào dàliàng shùjù hé shēnrù fēnxī cáinéng wánchéng.', 'Đề bài này cần nhiều dữ liệu và phân tích sâu để hoàn thành.'),
  ('苦涩', '他回忆起那段经历，心中充满了苦涩。', 'Tā huíyì qǐ nà duàn jīnglì, xīnzhōng chōngmǎnle kǔsè.', 'Anh ấy khi nhớ lại quãng thời gian đó, lòng đầy khổ sở.'),
  ('苦尽甘来', '经历了多年困苦之后，他们终于迎来了苦尽甘来的时刻。', 'Jīnglìle duōnián kùnkǔ zhīhòu, tāmen zhōngyú yíngláile kǔ jìn gān lái de shíkè.', 'Sau nhiều năm trải qua khó khăn, cuối cùng họ đã đến lúc khổ tận cam lai.'),
  ('考验', '这次比赛是对运动员身体和心理的双重考验。', 'Zhè cì bǐsài shì duì yùndòngyuán shēntǐ hé xīnlǐ de shuāngchóng kǎoyàn.', 'Cuộc thi này là sự thử thách cả thể chất và tinh thần của vận động viên.'),
  ('考核', '公司每年都会对员工进行严格的考核。', 'Gōngsī měi nián dōu huì duì yuángōng jìnxíng yángé de kǎohé.', 'Công ty mỗi năm đều tiến hành sát hạch nghiêm ngặt nhân viên.'),
  ('考察', '校长带队到乡村学校进行教学情况的考察。', 'Xiàozhǎng dàiduì dào xiāngcūn xuéxiào jìnxíng jiàoxué qíngkuàng de kǎochá.', 'Hiệu trưởng dẫn đoàn đi khảo sát tình hình giảng dạy ở trường làng.'),
  ('考古', '他们在这个遗址进行了为期三个月的考古发掘。', 'Tāmen zài zhège yízhǐ jìnxíngle wéiqí sāngè yuè de kǎogǔ fājué.', 'Họ đã tiến hành khai quật khảo cổ tại di tích này trong ba tháng.'),
  ('筐', '农民把新采摘的水果装进大筐里准备运走。', 'Nóngmín bǎ xīn cǎizhāi de shuǐguǒ zhuāng jìn dà kuāng lǐ zhǔnbèi yùn zǒu.', 'Nông dân bỏ trái cây mới hái vào giỏ lớn chuẩn bị vận chuyển đi.'),
  ('空隙', '门框和墙壁之间有一个小空隙需要填补。', 'Mén kuàng hé qiángbì zhījiān yǒu yīgè xiǎo kòngxì xūyào tiánbǔ.', 'Giữa khung cửa và tường có một khe hở nhỏ cần phải lấp đầy.'),
  ('空虚', '他在成功之后感到内心一片空虚，缺乏目标。', 'Tā zài chénggōng zhīhòu gǎndào nèixīn yīpiàn kōngxū, quēfá mùbiāo.', 'Sau khi thành công, anh ấy cảm thấy nội tâm trống rỗng, thiếu mục tiêu.'),
  ('空白', '请填写表格上的所有内容，空白处不能留空。', 'Qǐng tiánxiě biǎogé shàng de suǒyǒu nèiróng, kòngbái chù bùnéng liúkōng.', 'Hãy điền hết các nội dung trên mẫu đơn, phần trống không được bỏ trống.'),
  ('空洞', '他的承诺听起来很空洞，没有实质内容。', 'Tā de chéngnuò tīng qǐlái hěn kōngdòng, méiyǒu shízhì nèiróng.', 'Lời hứa của anh ta nghe rất sáo rỗng, không có nội dung thực chất.'),
  ('空想', '我们不能只停留在空想，要付诸行动才行。', 'Wǒmen bùnéng zhǐ tíngliú zài kōngxiǎng, yào fùzhū xíngdòng cái xíng.', 'Chúng ta không thể chỉ dừng lại ở ảo tưởng, phải thực hiện hành động mới được.'),
  ('空前绝后', '这场胜利是中国足球历史上的空前绝后。', 'Zhè chǎng shènglì shì Zhōngguó zúqiú lìshǐ shàng de kōngqián jué hòu.', 'Chiến thắng này là chưa từng có trong lịch sử bóng đá Trung Quốc.'),
  ('科目', '学生们最喜欢的科目是数学和英语。', 'Xuéshēng men zuì xǐhuān de kēmù shì shùxué hé yīngyǔ.', 'Các học sinh thích nhất các môn học là toán và tiếng Anh.'),
  ('磕', '他不小心磕到了桌角，手指受了伤。', 'Tā bù xiǎoxīn kē dàole zhuō jiǎo, shǒuzhǐ shòule shāng.', 'Anh ta không cẩn thận đập vào góc bàn, bị thương ở ngón tay.'),
  ('砍伐', '他们因为砍伐森林过度导致生态环境恶化。', 'Tāmen yīnwèi kǎnfá sēnlín guòdù dǎozhì shēngtài huánjìng èhuà.', 'Họ đã gây suy thoái môi trường sinh thái do chặt phá rừng quá mức.'),
  ('矿产', '这个地区富含丰富的矿产资源，是经济发展的重要基础。', 'Zhège dìqū fù hán fēngfù de kuàngchǎn zīyuán, shì jīngjì fāzhǎn de zhòngyào jīchǔ.', 'Khu vực này chứa nhiều khoáng sản phong phú, là nền tảng quan trọng của phát triển kinh tế.'),
  ('看待', '我们应该以积极的态度看待生活中的挑战。', 'Wǒmen yīnggāi yǐ jījí de tàidù kàndài shēnghuó zhōng de tiǎozhàn.', 'Chúng ta nên nhìn nhận các thử thách trong cuộc sống với thái độ tích cực.'),
  ('渴望', '年轻人渴望实现自己的梦想和目标。', 'Niánqīng rén kěwàng shíxiàn zìjǐ de mèngxiǎng hé mùbiāo.', 'Những người trẻ khát vọng thực hiện ước mơ và mục tiêu của mình.'),
  ('款待', '主人热情款待了所有远道而来的客人。', 'Zhǔrén rèqíng kuǎndài le suǒyǒu yuǎndào ér lái de kèrén.', 'Chủ nhà nhiệt tình khoản đãi tất cả khách từ xa đến.'),
  ('款式', '这款新手机的款式时尚，深受年轻人喜爱。', 'Zhè kuǎn xīn shǒujī de kuǎnshì shíshàng, shēn shòu niánqīngrén xǐ''ài.', 'Kiểu dáng của chiếc điện thoại mới này rất thời trang, được giới trẻ yêu thích.'),
  ('框架', '这座建筑的框架设计非常坚固，保证了安全性。', 'Zhè zuò jiànzhú de kuàngjià shèjì fēicháng jiāngù, bǎozhèngle ānquán xìng.', 'Khung của tòa nhà này được thiết kế rất chắc chắn, đảm bảo an toàn.'),
  ('枯萎', '植物因为缺水而开始枯萎，叶子变得干枯了。', 'Zhíwù yīnwèi quēshuǐ ér kāishǐ kūwěi, yèzi biàn dé gānkū le.', 'Cây bắt đầu khô héo vì thiếu nước, lá trở nên héo khô.'),
  ('枯燥', '长期从事枯燥的工作让他感到非常无聊。', 'Chángqī cóngshì kūzào de gōngzuò ràng tā gǎndào fēicháng wúliáo.', 'Làm công việc khô khan lâu dài khiến anh ấy cảm thấy rất buồn chán.'),
  ('旷课', '因为生病他连续几天旷课，没有告诉老师。', 'Yīnwèi shēngbìng tā liánxù jǐ tiān kuàngkè, méiyǒu gàosu lǎoshī.', 'Vì bị ốm, anh ấy trốn học mấy ngày liền mà không nói với giáo viên.'),
  ('捆绑', '工人用绳子将箱子牢固地捆绑在一起。', 'Gōngrén yòng shéngzi jiāng xiāngzi láogù de kǔnbǎng zài yīqǐ.', 'Công nhân dùng dây thừng buộc chặt các thùng lại với nhau.'),
  ('挎', '她挎着一个大包，边走边打电话。', 'Tā kuà zhe yī gè dà bāo, biān zǒu biān dǎ diànhuà.', 'Cô ấy đeo một túi lớn, vừa đi vừa gọi điện thoại.'),
  ('抗议', '市民们自发地走上街头抗议不公正的政策。', 'Shìmín men zìfā de zǒu shàng jiētóu kàngyì bù gōngzhèng de zhèngcè.', 'Người dân tự phát xuống đường phản đối chính sách bất công.'),
  ('扩散', '病毒在城市中迅速扩散，令大家高度紧张。', 'Bìngdú zài chéngshì zhōng xùnsù kuòsàn, lìng dàjiā gāodù jǐnzhāng.', 'Vi rút lan rộng nhanh chóng trong thành phố khiến mọi người rất lo lắng.'),
  ('扩张', '公司计划在明年扩张业务，进入更多市场。', 'Gōngsī jìhuà zài míngnián kuòzhāng yèwù, jìnrù gèng duō shìchǎng.', 'Công ty dự định mở rộng kinh doanh năm sau, tiến vào nhiều thị trường hơn.'),
  ('扩充', '为了提高竞争力，他们正积极扩充团队人员。', 'Wèile tígāo jìngzhēng lì, tāmen zhèng jījí kuòchōng tuánduì rényuán.', 'Để nâng cao sức cạnh tranh, họ đang tích cực tăng thêm thành viên nhóm.'),
  ('扣', '这件衬衫的扣子坏了，需要马上修理。', 'Zhè jiàn chènshān de kòuzi huài le, xūyào mǎshàng xiūlǐ.', 'Cúc áo sơ mi này bị hỏng, cần sửa ngay lập tức.'),
  ('扛', '他一个人扛起了沉重的箱子，毫不费力。', 'Tā yīgè rén káng qǐ le chénzhòng de xiāngzi, háo bù fèilì.', 'Anh ấy một mình vác chiếc vali nặng mà không hề vất vả.'),
  ('慷慨', '他对需要帮助的人总是非常慷慨大方。', 'Tā duì xūyào bāngzhù de rén zǒng shì fēicháng kāngkǎi dàfāng.', 'Anh ấy luôn rất hào phóng với những người cần giúp đỡ.'),
  ('恳切', '她恳切地请求老师给予再次机会。', 'Tā kěnqiè de qǐngqiú lǎoshī jǐyǔ zài cì jīhuì.', 'Cô ấy khẩn thiết xin thầy giáo cho cơ hội lần nữa.'),
  ('恐惧', '面对未知的挑战，他内心充满了恐惧。', 'Miànduì wèizhī de tiǎozhàn, tā nèixīn chōngmǎn le kǒngjù.', 'Đối mặt với thử thách chưa biết, trong lòng anh ấy đầy sợ hãi.'),
  ('恐怖', '这部电影的恐怖场景让观众毛骨悚然。', 'Zhè bù diànyǐng de kǒngbù chǎngjǐng ràng guānzhòng máogǔsǒngrán.', 'Cảnh kinh dị của bộ phim khiến khán giả rùng mình.'),
  ('恐吓', '歹徒用暴力手段恐吓无辜的居民。', 'Dǎitú yòng bàolì shǒuduàn kǒnghè wúgū de jūmín.', 'Bọn cướp dùng bạo lực đe dọa cư dân vô tội.'),
  ('快活', '孩子们在公园里快活地玩耍，笑声不断。', 'Háizimen zài gōngyuán lǐ kuàihuó de wánshuǎ, xiàoshēng búduàn.', 'Bọn trẻ chơi đùa vui vẻ trong công viên, tiếng cười không ngớt.'),
  ('开除', '因违反校规，他被学校严肃地开除了。', 'Yīn wéifǎn xiàoguī, tā bèi xuéxiào yánsù de kāichú le.', 'Vì vi phạm nội quy, cậu ấy đã bị trường nghiêm khắc khai trừ.'),
  ('开阔', '山区的视野开阔，让人心情非常舒畅。', 'Shānqū de shìyě kāikuò, ràng rén xīnqíng fēicháng shūchàng.', 'Tầm nhìn rộng mở của vùng núi khiến người ta cảm thấy rất dễ chịu.'),
  ('开采', '煤矿工人每天都在努力开采地下的煤炭资源。', 'Méi kuàng gōng rén měi tiān dōu zài nǔ lì kāi cǎi dì xià de méi tán zī yuán.', 'Công nhân mỏ than mỗi ngày đều cố gắng khai thác tài nguyên than dưới lòng đất.'),
  ('开辟', '他们计划开辟一条新的运输路线以提高效率。', 'Tā men jì huà kāi pì yī tiáo xīn de yùn shū lù xiàn yǐ tí gāo xiào lǜ.', 'Họ dự định mở một tuyến vận chuyển mới để nâng cao hiệu quả.'),
  ('开朗', '她性格开朗，总是能够带给大家好心情。', 'Tā xìng gé kāi lǎng, zǒng shì néng gòu dài gěi dà jiā hǎo xīn qíng.', 'Cô ấy tính cách lạc quan, luôn có thể mang lại tâm trạng tốt cho mọi người.'),
  ('开明', '这位校长以开明的教育理念赢得了师生的尊重。', 'Zhè wèi xiào zhǎng yǐ kāi míng de jiào yù lǐ niàn yíng dé le shī shēng de zūn zhòng.', 'Hiệu trưởng này đã giành được sự tôn trọng của thầy cô và học sinh nhờ vào tư tưởng giáo dục tiến bộ.'),
  ('开支', '公司必须合理控制各项开支以保证利润增长。', 'Gōng sī bì xū hé lǐ kòng zhì gè xiàng kāi zhī yǐ bǎo zhèng lì rùn zēng zhǎng.', 'Công ty phải kiểm soát hợp lý các khoản chi tiêu để đảm bảo lợi nhuận tăng trưởng.'),
  ('开拓', '农民们努力开拓荒地，增加耕种面积。', 'Nóng mín men nǔ lì kāi tuò huāng dì, zēng jiā gēng zhòng miàn jī.', 'Người nông dân cố gắng khai khẩn đất hoang, tăng diện tích canh tác.'),
  ('开展', '学校近日开展了一系列丰富多彩的文化活动。', 'Xué xiào jìn rì kāi zhǎn le yī xì liè fēng fù duō cǎi de wén huà huó dòng.', 'Trường học gần đây đã triển khai một loạt các hoạt động văn hóa đa dạng và phong phú.'),
  ('宽敞', '新买的公寓房间宽敞明亮，非常适合一家人居住。', 'Xīn mǎi de gōng yù fáng jiān kuān chang míng liàng, fēi cháng shì hé yī jiā rén jū zhù.', 'Căn hộ mới mua rộng rãi và sáng sủa, rất phù hợp để cả gia đình sinh sống.'),
  ('宽容', '遇到别人犯错时，我们应该保持宽容的态度。', 'Yù dào bié rén fàn cuò shí, wǒ men yīng gāi bǎo chí kuān róng de tài dù.', 'Khi gặp người khác phạm sai lầm, chúng ta nên giữ thái độ khoan dung.'),
  ('客户', '公司的成功离不开对客户需求的深入了解和服务。', 'Gōng sī de chéng gōng lí bù kāi duì kè hù xū qiú de shēn rù liǎo jiě hé fú wù.', 'Sự thành công của công ty không thể thiếu sự hiểu biết sâu sắc và phục vụ nhu cầu khách hàng.'),
  ('孔', '这块木板上有几个孔，方便安装钉子。', 'Zhè kuài mù bǎn shàng yǒu jǐ gè kǒng, fāng biàn ān zhuāng dīng zi.', 'Trên tấm gỗ này có vài cái lỗ, thuận tiện để lắp đinh.'),
  ('坑', '道路上有个大坑，过路车辆需要绕行以防事故。', 'Dào lù shàng yǒu gè dà kēng, guò lù chē liàng xū yào rào xíng yǐ fáng shì gù.', 'Trên đường có một cái hố lớn, xe cộ qua lại cần đi vòng để tránh tai nạn.'),
  ('啃', '小兔子喜欢啃胡萝卜，这已经成为它的习惯。', 'Xiǎo tù zi xǐ huān kěn hú luó bo, zhè yǐ jīng chéng wéi tā de xí guàn.', 'Con thỏ nhỏ thích gặm cà rốt, điều này đã trở thành thói quen của nó.'),
  ('哭泣', '失去亲人的孩子在角落里默默地哭泣。', 'Shī qù qīn rén de hái zi zài jiǎo luò lǐ mò mò de kū qì.', 'Đứa trẻ mất người thân đang lặng lẽ khóc trong góc.'),
  ('可观', '经过几年的努力，公司业绩有了可观的增长。', 'Jīng guò jǐ nián de nǔ lì, gōng sī yè jì yǒu le kě guān de zēng zhǎng.', 'Sau vài năm nỗ lực, thành tích của công ty đã có sự tăng trưởng khả quan.'),
  ('可行', '这个方案经过评估后，被认为是切实可行的。', 'Zhè gè fāng àn jīng guò píng gū hòu, bèi rèn wéi shì qiè shí kě xíng de.', 'Kế hoạch này sau khi đánh giá được coi là khả thi thực tế.'),
  ('可恶', '他那种自私自利的行为真是让人觉得可恶。', 'Tā nà zhǒng zì sī zì lì de xíng wéi zhēn shì ràng rén jué dé kě wù.', 'Hành động ích kỷ của anh ta thật sự khiến người ta cảm thấy đáng ghét.'),
  ('可口', '这家餐厅的菜肴色香味俱佳，非常可口。', 'Zhè jiā cān tīng de cài yáo sè xiāng wèi jù jiā, fēi cháng kě kǒu.', 'Món ăn của nhà hàng này có màu sắc, hương thơm và mùi vị đều xuất sắc, rất vừa miệng.'),
  ('口音', '他说话带有浓重的南方口音，让人一听就知道他来自哪里。', 'Tā shuō huà dài yǒu nóng zhòng de nán fāng kǒu yīn, ràng rén yī tīng jiù zhī dào tā lái zì nǎ lǐ.', 'Anh ấy nói chuyện mang giọng miền Nam rất đậm, khiến người nghe ngay lập tức biết anh ấy từ đâu đến.'),
  ('口腔', '定期刷牙和漱口有助于维护口腔健康。', 'Dìng qī shuā yá hé shù kǒu yǒu zhù yú wèi hù kǒu qiāng jiàn kāng.', 'Đánh răng và súc miệng thường xuyên có lợi cho việc bảo vệ sức khỏe khoang miệng.'),
  ('口气', '他的口气很强硬，让人难以反驳。', 'Tā de kǒu qì hěn qiáng yìng, ràng rén nán yǐ fǎn bó.', 'Khẩu khí của anh ấy rất cứng rắn, khiến người ta khó phản bác.'),
  ('口头', '我们只达成了一个口头协议，还需要书面确认。', 'Wǒmen zhǐ dáchéng le yí gè kǒu tóu xié yì, hái xū yào shū miàn quèrèn.', 'Chúng ta chỉ đạt được một thỏa thuận miệng, vẫn cần xác nhận bằng văn bản.'),
  ('卡通', '孩子们喜欢看各种有趣的卡通片。', 'Hái zi men xǐ huān kàn gè zhǒng yǒu qù de kǎ tōng piàn.', 'Bọn trẻ thích xem đủ loại phim hoạt hình thú vị.'),
  ('勘探', '科学家们正在加紧对该地区的矿产资源进行勘探。', 'Kē xué jiā men zhèng zài jiā jǐn duì gāi dì qū de kuàng chǎn zī yuán jìn xíng kān tàn.', 'Các nhà khoa học đang gấp rút thăm dò tài nguyên khoáng sản của khu vực này.'),
  ('刻不容缓', '面对环保问题，采取措施刻不容缓。', 'Miàn duì huán bǎo wèn tí, cǎi qǔ cuò shī kè bù róng huǎn.', 'Đối mặt với vấn đề bảo vệ môi trường, việc thực hiện các biện pháp là vô cùng cấp bách.'),
  ('刊登', '这篇报道被著名报纸刊登了。', 'Zhè piān bào dǎo bèi zhù míng bào zhǐ kān dēng le.', 'Bài báo này đã được đăng trên một tờ báo nổi tiếng.'),
  ('刊物', '他经常给专业刊物投稿。', 'Tā jīng cháng gěi zhuān yè kān wù tóu gǎo.', 'Anh ấy thường xuyên gửi bài cho các tạp chí chuyên ngành.'),
  ('况且', '他还年轻，况且经验也不足。', 'Tā hái nián qīng, kuàng qiě jīng yàn yě bù zú.', 'Anh ta còn trẻ, huống hồ kinh nghiệm cũng không đủ.'),
  ('克制', '在激烈争吵时，他努力克制自己的情绪。', 'Zài jī liè zhēng chǎo shí, tā nǔ lì kè zhì zì jǐ de qíng xù.', 'Khi tranh cãi gay gắt, anh ấy cố gắng kiềm chế cảm xúc của mình.'),
  ('侃侃而谈', '他在会议上侃侃而谈，展示了丰富的知识。', 'Tā zài huì yì shàng kǎn kǎn ér tán, zhǎn shì le fēng fù de zhī shì.', 'Anh ấy nói năng đĩnh đạc tại cuộc họp, thể hiện kiến thức phong phú.'),
  ('亏损', '公司今年连续几个季度出现了严重亏损。', 'Gōng sī jīn nián lián xù jǐ gè jì dù chū xiàn le yán zhòng kuī sǔn.', 'Công ty năm nay liên tiếp nhiều quý gặp phải tình trạng hao tổn nghiêm trọng.'),
  ('亏待', '不要亏待那些一直支持你的人。', 'Bù yào kuī dài nà xiē yì zhí zhī chí nǐ de rén.', 'Đừng đối đãi kém với những người luôn ủng hộ bạn.'),
  ('黎明', '黎明时分，鸟儿开始歌唱。', 'Lí míng shí fēn, niǎo ér kāi shǐ gē chàng.', 'Rạng sáng, những chú chim bắt đầu hót.'),
  ('领袖', '他被尊为改革的领袖人物。', 'Tā bèi zūn wéi gǎi gé de lǐng xiù rén wù.', 'Anh ấy được tôn là lãnh tụ của cuộc cải cách.'),
  ('领悟', '经过反复思考，他终于领悟了问题的关键。', 'Jīng guò fǎn fù sī kǎo, tā zhōng yú lǐng wù le wèn tí de guān jiàn.', 'Sau nhiều lần suy nghĩ, cuối cùng anh ấy đã lĩnh hội được căn nguyên của vấn đề.'),
  ('领土', '保卫国家的领土是每个公民的责任。', 'Bǎo wèi guó jiā de lǐng tǔ shì měi gè gōng mín de zé rèn.', 'Bảo vệ lãnh thổ của đất nước là trách nhiệm của mỗi công dân.'),
  ('领先', '他在比赛中始终保持领先地位。', 'Tā zài bǐ sài zhōng shǐ zhōng bǎo chí lǐng xiān dì wèi.', 'Anh ấy luôn giữ vị trí dẫn đầu trong cuộc thi.'),
  ('领会', '要仔细领会老师的讲解内容。', 'Yào zǐ xì lǐng huì lǎo shī de jiǎng jiě nèi róng.', 'Phải cẩn thận lĩnh hội nội dung giảng giải của giáo viên.'),
  ('领事馆', '遇到紧急情况，应立即联系领事馆寻求帮助。', 'Yù dào jǐn jí qíng kuàng, yīng lì jí lián xì lǐng shì guǎn xún qiú bāng zhù.', 'Gặp tình huống khẩn cấp, nên lập tức liên hệ lãnh sự quán để nhờ trợ giúp.'),
  ('雷达', '飞机利用雷达系统监测天气变化。', 'Fēi jī lì yòng léi dá xì tǒng jiān cè tiān qì biàn huà.', 'Máy bay sử dụng hệ thống radar để giám sát sự thay đổi thời tiết.'),
  ('零星', '零星的雨点打在窗户上，发出轻微的声音。', 'Língxīng de yǔdiǎn dǎ zài chuānghù shàng, fāchū qīngwēi de shēngyīn.', 'Những hạt mưa lác đác rơi trên cửa sổ, phát ra tiếng động nhẹ.'),
  ('隆重', '学校为毕业生举办了一场隆重的毕业典礼。', 'Xuéxiào wèi bìyè shēng jǔbànle yī chǎng lóngzhòng de bìyè diǎnlǐ.', 'Trường tổ chức một buổi lễ tốt nghiệp long trọng cho sinh viên.'),
  ('里程碑', '这次成功的合作成为我们公司的一个重要里程碑。', 'Zhè cì chénggōng de hézuò chéngwéi wǒmen gōngsī de yīgè zhòngyào lǐchéngbēi.', 'Sự hợp tác thành công lần này đã trở thành một cột mốc quan trọng của công ty chúng tôi.'),
  ('连锁', '这家连锁超市在全国拥有上百家分店。', 'Zhè jiā liánsuǒ chāoshì zài quánguó yǒngyǒu shàng bǎi jiā fēndiàn.', 'Chuỗi siêu thị này có hơn trăm cửa hàng chi nhánh trên toàn quốc.'),
  ('连年', '由于连年干旱，农作物的产量大幅减少。', 'Yóuyú liánnián gānhàn, nóngzuòwù de chǎnliàng dàfú jiǎnshǎo.', 'Do nhiều năm liền hạn hán, sản lượng nông sản giảm mạnh.'),
  ('连同', '请把所有材料连同申请表一并提交给办公室。', 'Qǐng bǎ suǒyǒu cáiliào liántóng shēnqǐng biǎo yībìng tíjiāo gěi bàngōngshì.', 'Vui lòng nộp tất cả tài liệu cùng với đơn đăng ký cho văn phòng.'),
  ('辽阔', '我们站在山顶，俯瞰辽阔的草原和奔流的河流。', 'Wǒmen zhàn zài shāndǐng, fǔkàn liáokuò de cǎoyuán hé bēnliú de héliú.', 'Chúng tôi đứng trên đỉnh núi, nhìn xuống đồng cỏ bát ngát và dòng sông chảy mạnh.'),
  ('轮船', '游客们乘坐轮船在湖上享受美丽的风景。', 'Yóukè men chéngzuò lúnchuán zài hú shàng xiǎngshòu měilì de fēngjǐng.', 'Du khách đi tàu thủy để tận hưởng phong cảnh tuyệt đẹp trên hồ.'),
  ('轮胎', '汽车的轮胎在雨天路面打滑，驾驶员必须小心。', 'Qìchē de lúntāi zài yǔ tiān lùmiàn dǎhuá, jiàshǐyuán bìxū xiǎoxīn.', 'Lốp xe ô tô bị trượt trên mặt đường ướt, tài xế phải cẩn thận.'),
  ('轮廓', '他用铅笔勾勒出人物的基本轮廓，然后进行细节描绘。', 'Tā yòng qiānbǐ gōulè chū rénwù de jīběn lúnkuò, ránhòu jìnxíng xìjié miáohuì.', 'Anh ấy dùng bút chì phác thảo đường viền cơ bản của nhân vật, rồi tiếp tục vẽ chi tiết.'),
  ('谅解', '我希望你能够谅解我的难处，不要太苛刻。', 'Wǒ xīwàng nǐ nénggòu liàngjiě wǒ de nánchǔ, bùyào tài kēkè.', 'Tôi hy vọng bạn có thể thông cảm cho khó khăn của tôi, đừng quá khắt khe.'),
  ('论证', '科学家们通过实验数据来论证他们的假设。', 'Kēxuéjiā men tōngguò shíyàn shùjù lái lùnzhèng tāmen de jiǎshè.', 'Các nhà khoa học dùng dữ liệu thực nghiệm để luận chứng giả thuyết của họ.'),
  ('论坛', '国际经济论坛吸引了来自世界各地的专家学者。', 'Guójì jīngjì lùntán xīyǐnle láizì shìjiè gèdì de zhuānjiā xuézhě.', 'Diễn đàn kinh tế quốc tế thu hút các chuyên gia học giả từ khắp nơi trên thế giới.'),
  ('蜡烛', '房间停电了，我们点燃了几根蜡烛照明。', 'Fángjiān tíngdiànle, wǒmen diǎnránle jǐ gēn làzhú zhàomíng.', 'Phòng mất điện, chúng tôi đã thắp vài cây nến để chiếu sáng.'),
  ('落成', '新图书馆已经落成，预计下个月正式开放。', 'Xīn túshūguǎn yǐjīng luòchéng, yùjì xià gè yuè zhèngshì kāifàng.', 'Thư viện mới đã khánh thành, dự kiến sẽ mở cửa chính thức vào tháng sau.'),
  ('落实', '政府必须采取措施，确保各项政策得到落实。', 'Zhèngfǔ bìxū cǎiqǔ cuòshī, quèbǎo gè xiàng zhèngcè dédào luòshí.', 'Chính phủ phải thực hiện các biện pháp để đảm bảo các chính sách được đầy đủ chu đáo.'),
  ('良心', '做生意要有良心，不能只图眼前的利益。', 'Zuò shēngyì yào yǒu liángxīn, bùnéng zhǐ tú yǎnqián de lìyì.', 'Làm kinh doanh phải có lương tâm, không thể chỉ chú ý lợi ích trước mắt.'),
  ('联络', '我们通过电子邮件保持联络，及时沟通工作进展。', 'Wǒmen tōngguò diànzǐ yóujiàn bǎochí liánluò, jíshí gōutōng gōngzuò jìnzhǎn.', 'Chúng tôi giữ liên lạc qua email để kịp thời trao đổi tiến độ công việc.'),
  ('联盟', '多个国家成立联盟，共同应对全球气候变化的挑战。', 'Duō gè guójiā chénglì liánméng, gòngtóng yìngduì quánqiú qìhòu biànhuà de tiǎozhàn.', 'Nhiều quốc gia thành lập liên minh để cùng nhau đối phó với thách thức biến đổi khí hậu toàn cầu.'),
  ('联欢', '节日期间，公司举办了联欢晚会，大家一起庆祝。', 'Jiérì qíjiān, gōngsī jǔbànle liánhuān wǎnhuì, dàjiā yīqǐ qìngzhù.', 'Trong dịp lễ, công ty tổ chức buổi liên hoan tối, mọi người cùng nhau chúc mừng.'),
  ('联想', '看到这张照片，我不禁联想到儿时的美好时光。', 'kàn dào zhè zhāng zhào piàn, wǒ bù jīn lián xiǎng dào ér shí de měi hǎo shí guāng.', 'Nhìn bức ảnh này, tôi không khỏi liên tưởng đến những thời gian đẹp đẽ hồi nhỏ.'),
  ('聋哑', '那位聋哑老师用手语教授学生，非常耐心。', 'nà wèi lóng yǎ lǎo shī yòng shǒu yǔ jiào shòu xué shēng, fēi cháng nài xīn.', 'Thầy giáo câm điếc đó dạy học sinh bằng ngôn ngữ cử chỉ, rất kiên nhẫn.'),
  ('络绎不绝', '节日期间，游客们络绎不绝地参观这座古老的寺庙。', 'jié rì qī jiān, yóu kè men luò yì bù jué de cān guān zhè zuò gǔ lǎo de sì miào.', 'Trong dịp lễ, du khách lũ lượt kéo đến tham quan ngôi chùa cổ này.'),
  ('粒', '桌子上有几粒沙子被风吹进了房间。', 'zhuō zi shàng yǒu jǐ lì shā zi bèi fēng chuī jìn le fáng jiān.', 'Trên bàn có vài hạt cát bị gió thổi vào phòng.'),
  ('类似', '他的问题和我之前遇到的情况非常类似。', 'tā de wèn tí hé wǒ zhī qián yù dào de qíng kuàng fēi cháng lèi sì.', 'Vấn đề của anh ấy rất tương tự với tình huống tôi đã gặp trước đây.'),
  ('笼罩', '浓雾笼罩着整个山谷，让人几乎看不到远方。', 'nóng wù lǒng zhào zhe zhěng gè shān gǔ, ràng rén jī hū kàn bú dào yuǎn fāng.', 'Sương mù dày đặc che phủ toàn bộ thung lũng, khiến người ta gần như không nhìn thấy phía xa.'),
  ('立足', '学生们需要在扎实的基础上立足，才能取得更好的成绩。', 'xué shēng men xū yào zài zhā shi de jī chǔ shàng lì zú, cái néng qǔ dé gèng hǎo de chéng jì.', 'Học sinh cần đứng vững trên nền tảng vững chắc mới có thể đạt kết quả tốt hơn.'),
  ('立方', '这个水箱的容量是两立方米，可以储存大量的水。', 'zhè ge shuǐ xiāng de róng liàng shì liǎng lì fāng mǐ, kě yǐ chǔ cún dà liàng de shuǐ.', 'Thể tích bể nước này là hai mét khối, có thể chứa rất nhiều nước.'),
  ('立场', '在讨论问题时，每个人都应该坚持自己的立场。', 'zài tǎo lùn wèn tí shí, měi gè rén dōu yīng gāi jiān chí zì jǐ de lì chǎng.', 'Khi thảo luận vấn đề, mỗi người đều nên giữ lập trường của mình.'),
  ('立体', '这场展览展示了许多立体的艺术作品，令人惊叹。', 'zhè chǎng zhǎn lǎn zhǎn shì le xǔ duō lì tǐ de yì shù zuò pǐn, lìng rén jīng tàn.', 'Buổi triển lãm này trưng bày nhiều tác phẩm nghệ thuật ba chiều, khiến người ta kinh ngạc.'),
  ('立交桥', '城市中建起了多座立交桥，缓解了交通堵塞问题。', 'chéng shì zhōng jiàn qǐ le duō zuò lì jiāo qiáo, huǎn jiě le jiāo tōng dǔ sè wèn tí.', 'Nhiều cầu vượt đã được xây dựng trong thành phố, giảm bớt vấn đề tắc nghẽn giao thông.'),
  ('礼节', '在正式场合，遵守礼节是表现尊重的基本方式。', 'zài zhèng shì chǎng hé, zūn shǒu lǐ jié shì biǎo xiàn zūn zhòng de jī běn fāng shì.', 'Trong các dịp trang trọng, tuân thủ lễ tiết là cách cơ bản để thể hiện sự tôn trọng.'),
  ('礼尚往来', '朋友之间应当礼尚往来，互相帮助才能长久。', 'péng yǒu zhī jiān yīng dāng lǐ shàng wǎng lái, hù xiāng bāng zhù cái néng cháng jiǔ.', 'Giữa bạn bè nên có đi có lại, giúp đỡ nhau mới bền lâu.'),
  ('留神', '过马路时要留神，注意来往的车辆以确保安全。', 'guò mǎ lù shí yào liú shén, zhù yì lái wǎng de chē liàng yǐ què bǎo ān quán.', 'Khi qua đường phải để ý, chú ý các phương tiện qua lại để đảm bảo an toàn.'),
  ('留恋', '分别时大家都留恋地回望那个美丽的校园。', 'fēn bié shí dà jiā dōu liú liàn de huí wàng nà gè měi lì de xiào yuán.', 'Khi chia tay, mọi người đều lưu luyến nhìn lại khuôn viên trường xinh đẹp đó.'),
  ('留念', '他们合影留念，记录下这次难忘的旅行经历。', 'tā men hé yǐng liú niàn, jì lù xià zhè cì nán wàng de lǚ xíng jīng lì.', 'Họ chụp ảnh kỷ niệm, ghi lại chuyến du lịch khó quên này.'),
  ('理睬', '尽管我多次呼喊，他还是没有理睬我。', 'jǐn guǎn wǒ duō cì hū hǎn, tā hái shì méi yǒu lǐ cǎi wǒ.', 'Mặc dù tôi gọi nhiều lần, anh ấy vẫn không để ý đến tôi.'),
  ('理直气壮', '在讲述自己的经历时，他理直气壮地表达了自己的观点。', 'zài jiǎng shù zì jǐ de jīng lì shí, tā lǐ zhí qì zhuàng de biǎo dá le zì jǐ de guān diǎn.', 'Khi kể chuyện trải nghiệm của mình, anh ấy thể hiện quan điểm một cách cây ngay không sợ chết đứng.'),
  ('理智', '面对困难，我们需要保持理智，冷静分析问题。', 'miàn duì kùn nán, wǒ men xū yào bǎo chí lǐ zhì, lěng jìng fēn xī wèn tí.', 'Đối mặt với khó khăn, chúng ta cần giữ lý trí, phân tích vấn đề một cách bình tĩnh.'),
  ('理所当然', '帮助别人不应被视为理所当然，而应心怀感激。', 'bāng zhù bié rén bú yīng bèi shì wéi lǐ suǒ dāng rán, ér yīng xīn huái gǎn jī.', 'Giúp đỡ người khác không nên được xem là lẽ đương nhiên, mà nên biết ơn trong lòng.'),
  ('狼狈', '那次旅行遇到大雨，我们的处境十分狼狈。', 'Nà cì lǚxíng yù dào dàyǔ, wǒmen de chǔjìng shífēn lángbèi.', 'Trong chuyến đi đó gặp mưa to, tình cảnh của chúng tôi rất lang bái (khốn khổ).'),
  ('狼吞虎咽', '他饿极了，狼吞虎咽地吃完了晚饭。', 'Tā è jíle, láng tūn hǔ yàn de chī wánle wǎnfàn.', 'Anh ấy đói đến mức ăn lấy ăn để xong bữa tối.'),
  ('牢骚', '别总是发牢骚，积极面对生活才是关键。', 'Bié zǒng shì fā láosāo, jījí miànduì shēnghuó cái shì guānjiàn.', 'Đừng lúc nào cũng kêu ca, tích cực đối mặt với cuộc sống mới là yếu tố then chốt.'),
  ('牢固', '这栋房子的地基非常牢固，不必担心安全问题。', 'Zhè dòng fángzi de dìjī fēicháng láogù, búbì dānxīn ānquán wèntí.', 'Nền móng của ngôi nhà này rất chắc chắn, không cần lo lắng về vấn đề an toàn.'),
  ('炉灶', '厨房里的炉灶新换了一个，更省能源。', 'Chúfáng lǐ de lúzào xīn huàn le yī gè, gèng shěng néngyuán.', 'Cái bếp nấu trong nhà bếp mới thay một cái, tiết kiệm năng lượng hơn.'),
  ('灵魂', '音乐是他生活中不可或缺的灵魂。', 'Yīnyuè shì tā shēnghuó zhōng bùkě huòquē de línghún.', 'Âm nhạc là linh hồn không thể thiếu trong cuộc sống của anh ấy.'),
  ('灵敏', '这款传感器非常灵敏，能迅速捕捉细微变化。', 'Zhè kuǎn chuángǎnqì fēicháng língmǐn, néng xùnsù bǔzhuō xìwēi biànhuà.', 'Cảm biến này rất nhạy, có thể nhanh chóng bắt được những thay đổi nhỏ nhất.'),
  ('灵感', '艺术家的作品往往来自突如其来的灵感。', 'Yìshùjiā de zuòpǐn wǎngwǎng láizì tūrú qílái de línggǎn.', 'Tác phẩm của nghệ sĩ thường đến từ linh cảm đột ngột.'),
  ('溜', '孩子们在滑冰场上开心地溜冰。', 'Háizimen zài huábīng chǎng shàng kāixīn de liūbīng.', 'Bọn trẻ đang vui vẻ trượt băng trên sân băng.'),
  ('淋', '下雨了，没带伞，被雨水淋得满身湿透。', 'Xiàyǔ le, méi dài sǎn, bèi yǔshuǐ lín de mǎn shēn shī tòu.', 'Trời mưa rồi, không mang dù, bị nước mưa ướt đẫm người.'),
  ('流露', '他的眼神中流露出浓浓的思念之情。', 'Tā de yǎnshén zhōng liúlù chū nóngnòng de sīniàn zhī qíng.', 'Trong ánh mắt anh ấy lộ rõ nỗi nhớ thương sâu sắc.'),
  ('流通', '货币在市场上的流通对经济发展非常重要。', 'Huòbì zài shìchǎng shàng de liútōng duì jīngjì fāzhǎn fēicháng zhòngyào.', 'Tiền tệ lưu thông trên thị trường rất quan trọng đối với phát triển kinh tế.'),
  ('流浪', '那只小狗因为没有主人而在街头流浪。', 'Nà zhī xiǎo gǒu yīnwèi méiyǒu zhǔrén ér zài jiētóu liúlàng.', 'Con chó nhỏ đó vì không có chủ nên lang thang trên phố.'),
  ('流氓', '警方加强了对那些流氓行为的打击力度。', 'Jǐngfāng jiāqiáng le duì nàxiē liúmáng xíngwéi de dǎjī lìdù.', 'Cảnh sát tăng cường đánh mạnh vào những hành vi lưu manh đó.'),
  ('栏目', '这个电视节目有一个专门的科技栏目。', 'Zhège diànshì jiémù yǒu yī gè zhuānmén de kējì lánmù.', 'Chương trình truyền hình này có một chuyên mục công nghệ riêng biệt.'),
  ('来源', '我们的信息来源都经过了严格的核实。', 'Wǒmen de xìnxī láiyuán dōu jīngguò le yángé de héshí.', 'Nguồn thông tin của chúng tôi đều được kiểm chứng nghiêm ngặt.'),
  ('来历', '他所讲的故事来历不明，难以相信。', 'Tā suǒ jiǎng de gùshì láilì bù míng, nányǐ xiāngxìn.', 'Câu chuyện anh ta kể có lai lịch không rõ ràng, khó tin được.'),
  ('晾', '雨停了，妈妈把洗好的衣服拿出去晾晒。', 'Yǔ tíng le, māmā bǎ xǐ hǎo de yīfu ná chūqù liàng shài.', 'Mưa tạnh rồi, mẹ lấy quần áo đã giặt ra phơi.'),
  ('搂', '她紧紧搂住孩子，表达自己深深的爱意。', 'Tā jǐn jǐn lǒu zhù háizi, biǎodá zìjǐ shēnshēn de àiyì.', 'Cô ấy ôm chặt đứa trẻ, bộc lộ tình yêu sâu sắc của mình.'),
  ('掠夺', '历史上的掠夺行为给当地人民带来了苦难。', 'Lìshǐ shàng de lüèduó xíngwéi gěi dāngdì rénmín dàilái le kǔnàn.', 'Hành vi cướp đoạt trong lịch sử đã mang lại đau khổ cho người dân địa phương.'),
  ('捞', '渔民每天早上去河里捞鱼，赚取生活费。', 'Yúmín měitiān zǎoshang qù hé lǐ lāo yú, zhuànqǔ shēnghuófèi.', 'Ngư dân mỗi sáng đều ra sông vớt cá để kiếm tiền sinh sống.'),
  ('懒惰', '他因为懒惰而没有完成老师布置的作业。', 'Tā yīnwèi lǎnduò ér méiyǒu wánchéng lǎoshī bùzhì de zuòyè.', 'Anh ấy vì lười biếng nên không hoàn thành bài tập mà thầy cô giao.'),
  ('愣', '听到这个消息后，她愣在原地，不知所措。', 'Tīng dào zhège xiāoxi hòu, tā lèng zài yuándì, bù zhī suǒ cuò.', 'Nghe được tin này, cô ấy đứng sững tại chỗ, không biết phải làm sao.'),
  ('廉洁', '作为公务员，他一直坚持廉洁自律，赢得尊重。', 'Zuòwéi gōngwùyuán, tā yīzhí jiānchí liánjié zìlǜ, yíngdé zūnzhòng.', 'Là công chức, anh ta luôn giữ gìn liêm khiết tự kỷ luật, được mọi người tôn trọng.'),
  ('履行', '公司承诺的合同义务必须在规定时间内履行。', 'Gōngsī chéngnuò de hétonɡ yìwù bìxū zài ɡuīdìnɡ shíjiān nèi lǚxínɡ.', 'Nghĩa vụ hợp đồng mà công ty cam kết phải thực thi trong thời gian quy định.'),
  ('屡次', '他屡次迟到，已经被经理警告过了。', 'Tā lǚcì chídào, yǐjīng bèi jīnglǐ jǐngɡào ɡuò le.', 'Anh ấy nhiều lần đến muộn, đã bị quản lý cảnh cáo rồi.'),
  ('垄断', '这家大公司垄断了该地区的大部分市场份额。', 'Zhè jiā dà ɡōnɡsī lǒnɡduàn le ɡāi dìqū de dà bùfèn shìchǎnɡ fèné.', 'Công ty lớn này lũng đoạn phần lớn thị trường khu vực đó.'),
  ('喇叭', '小朋友兴奋地吹着红色的喇叭庆祝节日。', 'Xiǎopénɡyǒu xīnɡfèn de chuī zhe hónɡsè de lǎbā qìnɡzhù jiérì.', 'Đứa trẻ háo hức thổi kèn màu đỏ để chúc mừng ngày lễ.'),
  ('啰唆', '她说话啰唆，让人听了感到很烦躁。', 'Tā shuōhuà luōsuo, rànɡ rén tīnɡ le ɡǎndào hěn fánzào.', 'Cô ấy nói chuyện rườm rà làm người khác nghe thấy rất khó chịu.'),
  ('啦', '快点准备好啦，我们马上就要出发了。', 'Kuài diǎn zhǔnbèi hǎo la, wǒmen mǎshàng jiù yào chūfā le.', 'Nhanh chuẩn bị đi nhé, chúng ta sắp khởi hành rồi.'),
  ('唠叨', '妈妈总喜欢唠叨我们要注意身体健康。', 'Māmā zǒnɡ xǐhuān láodao wǒmen yào zhùyì shēntǐ jiànkāng.', 'Mẹ luôn lải nhải rằng chúng ta phải chú ý đến sức khỏe.'),
  ('吝啬', '他太吝啬，甚至不愿意花钱买礼物。', 'Tā tài lìnsè, shènzhì bù yuànyì huā qián mǎi lǐwù.', 'Anh ấy keo kiệt đến mức thậm chí không muốn tiêu tiền mua quà.'),
  ('历来', '我国历来重视教育的发展和改革。', 'Wǒɡuó lìlái zhònɡshì jiàoyù de fāzhǎn hé ɡǎɡé.', 'Nước ta từ trước đến nay luôn coi trọng sự phát triển và cải cách giáo dục.'),
  ('历代', '历代帝王都在这座宫殿中居住过。', 'Lìdài dìwánɡ dōu zài zhè zuò ɡōnɡdiàn zhōnɡ jūzhù ɡuò.', 'Các đời vua chúa đều đã từng cư trú trong cung điện này.'),
  ('力求', '我们力求在下个月完成这个重要项目。', 'Wǒmen lìqiú zài xià ɡè yuè wánchéng zhè ɡe zhònɡyào xiànɡmù.', 'Chúng tôi cố gắng hoàn thành dự án quan trọng này vào tháng tới.'),
  ('力所能及', '遇到需要帮助的人，我们应该尽力所能及地支持。', 'Yù dào xūyào bāngzhù de rén, wǒmen yīnɡɡāi jìn lì suǒ nénɡ jí de zhīchí.', 'Khi gặp người cần giúp đỡ, chúng ta nên làm hết khả năng để hỗ trợ.'),
  ('力争', '他力争在今年获得更多的科研成果。', 'Tā lìzhēng zài jīnnián huòdé ɡènɡ duō de kēyán chénɡguǒ.', 'Anh ấy cố gắng phấn đấu đạt được nhiều thành quả nghiên cứu khoa học hơn trong năm nay.'),
  ('利害', '他的棋艺利害，经常在比赛中获胜。', 'Tā de qíyì lìhài, jīnɡchánɡ zài bǐsài zhōnɡ huòshènɡ.', 'Kỹ thuật cờ của anh ấy rất lợi hại, thường xuyên thắng trong các cuộc thi đấu.'),
  ('列举', '老师列举了几个成功的案例来说明观点。', 'Lǎoshī lièjǔ le jǐ ɡè chénɡɡōnɡ de ànlì lái shuōmínɡ ɡuāndiǎn.', 'Giáo viên nêu ra một vài ví dụ thành công để minh họa quan điểm.'),
  ('凌晨', '他们在凌晨三点才结束了辛苦的工作。', 'Tāmen zài língchén sān diǎn cái jiéshù le xīnkǔ de ɡōnɡzuò.', 'Họ đến tận sáng sớm ba giờ mới kết thúc công việc vất vả.'),
  ('冷酷', '他的冷酷态度让同事们感到难以接近。', 'Tā de lěngkù tàidù ràng tóngshìmen gǎndào nányǐ jiējìn.', 'Thái độ lạnh lùng của anh ta khiến đồng nghiệp cảm thấy khó gần.'),
  ('冷落', '节假日期间这家店显得十分冷落，顾客很少。', 'Jiéjiàrì qījiān zhè jiā diàn xiǎnde shífēn lěngluò, gùkè hěn shǎo.', 'Trong kỳ nghỉ lễ, cửa hàng này trông rất vắng vẻ, khách rất ít.'),
  ('冷却', '机械停止运转后，设备需要一段时间冷却。', 'Jīxiè tíngzhǐ yùnzhuǎn hòu, shèbèi xūyào yí duàn shíjiān lěngquè.', 'Sau khi máy móc dừng hoạt động, thiết bị cần có thời gian để làm lạnh.'),
  ('例外', '在这次考试中，他是唯一的例外，成绩没有及格。', 'Zài zhè cì kǎoshì zhōng, tā shì wéiyī de lìwài, chéngjī méiyǒu jígé.', 'Trong kỳ thi này, anh ấy là ngoại lệ duy nhất, điểm số không đạt.'),
  ('伶俐', '小孩子非常伶俐，能很快学会新知识。', 'Xiǎo háizi fēicháng línglì, néng hěn kuài xuéhuì xīn zhīshì.', 'Đứa trẻ rất lanh lợi, có thể học kiến thức mới rất nhanh.'),
  ('乐趣', '阅读是她生活中最大的乐趣之一。', 'Yuèdú shì tā shēnghuó zhōng zuìdà de lèqù zhī yī.', 'Đọc sách là một trong những niềm vui lớn nhất trong cuộc sống của cô ấy.'),
  ('乐意', '如果你需要帮助，我乐意随时为你效劳。', 'Rúguǒ nǐ xūyào bāngzhù, wǒ lèyì suíshí wèi nǐ xiàoláo.', 'Nếu bạn cần giúp đỡ, tôi cam tâm tình nguyện phục vụ bạn bất cứ lúc nào.'),
  ('临床', '医生在临床实践中积累了丰富的经验。', 'Yīshēng zài línchuáng shíjiàn zhōng jīlěi le fēngfù de jīngyàn.', 'Bác sĩ đã tích lũy được nhiều kinh nghiệm phong phú trong thực hành lâm sàng.'),
  ('默默', '他默默地支持着团队，却很少表现自己。', 'Tā mòmò de zhīchí zhe tuánduì, què hěn shǎo biǎoxiàn zìjǐ.', 'Anh ấy âm thầm ủng hộ đội nhóm, nhưng rất ít khi thể hiện bản thân.'),
  ('麻醉', '手术前，患者接受了全身麻醉。', 'Shǒushù qián, huànzhě jiēshòu le quánshēn mázuì.', 'Trước ca phẫu thuật, bệnh nhân đã được gây tê toàn thân.'),
  ('麻痹', '中风后，他的左手出现了麻痹现象。', 'Zhòngfēng hòu, tā de zuǒ shǒu chūxiàn le mábì xiànxiàng.', 'Sau cơn đột quỵ, tay trái của anh ta bị liệt.'),
  ('麻木', '长时间站立后，我的双脚感到麻木。', 'Cháng shíjiān zhànlì hòu, wǒ de shuāng jiǎo gǎndào mámù.', 'Sau khi đứng lâu, đôi chân tôi cảm thấy tê liệt.'),
  ('魔鬼', '那部电影描绘了一个邪恶的魔鬼形象。', 'Nà bù diànyǐng miáohuì le yí gè xié''è de móguǐ xíngxiàng.', 'Bộ phim đó mô tả hình tượng một con ma quỷ độc ác.'),
  ('魔术', '孩子们都被魔术表演吸引住了。', 'Háizimen dōu bèi móshù biǎoyǎn xīyǐn zhù le.', 'Trẻ em đều bị buổi biểu diễn ảo thuật thu hút.'),
  ('面貌', '随着时间流逝，城市的面貌发生了巨大的变化。', 'Suízhe shíjiān liúshì, chéngshì de miànmào fāshēng le jùdà de biànhuà.', 'Cùng với thời gian trôi qua, diện mạo thành phố đã thay đổi rất lớn.'),
  ('面子', '他为了面子拒绝了朋友的帮助。', 'Tā wèile miànzi jùjué le péngyǒu de bāngzhù.', 'Anh ấy từ chối sự giúp đỡ của bạn bè vì sĩ diện.'),
  ('迷惑', '复杂的信息让她感到迷惑，不知道该如何选择。', 'Fùzá de xìnxī ràng tā gǎndào míhuò, bù zhīdào gāi rúhé xuǎnzé.', 'Thông tin phức tạp khiến cô ấy cảm thấy bối rối, không biết nên chọn như thế nào.'),
  ('迷信', '他对迷信的看法非常理性，从不轻信巫术。', 'Tā duì míxìn de kànfǎ fēicháng lǐxìng, cóng bù qīngxìn wūshù.', 'Anh ấy có quan điểm rất lý tính về mê tín, chưa bao giờ tin vào bùa chú.'),
  ('迷人', '她的笑容非常迷人，让人无法移开目光。', 'Tā de xiàoróng fēicháng mírén, ràng rén wúfǎ yí kāi mùguāng.', 'Nụ cười của cô ấy rất quyến rũ, khiến người ta không thể rời mắt.'),
  ('迈', '在比赛开始时，他迈开了坚定的步伐。', 'Zài bǐsài kāishǐ shí, tā màikāi le jiāndìng de bùfá.', 'Khi cuộc thi bắt đầu, anh ấy bước đi với những bước chân vững chắc.'),
  ('谜语', '这个谜语非常有趣，大家都试着猜看答案。', 'Zhège míyǔ fēicháng yǒuqù, dàjiā dōu shìzhe cāi kàn dá''àn.', 'Câu đố này rất thú vị, mọi người đều cố gắng đoán xem đáp án.'),
  ('谋求', '公司希望通过创新来谋求更好的发展机会。', 'Gōngsī xīwàng tōngguò chuàngxīn lái móuqiú gèng hǎo de fāzhǎn jīhuì.', 'Công ty hy vọng thông qua đổi mới để tìm kiếm cơ hội phát triển tốt hơn.'),
  ('蚂蚁', '春天来临时，蚂蚁开始忙碌地寻找食物。', 'Chūntiān láilín shí, mǎyǐ kāishǐ mánglù de xúnzhǎo shíwù.', 'Khi xuân đến, kiến bắt đầu bận rộn đi tìm thức ăn.'),
  ('藐视', '他对规则的藐视最终导致了严重的后果。', 'Tā duì guīzé de miǎoshì zuìzhōng dǎozhìle yánzhòng de hòuguǒ.', 'Anh ta coi thường quy định đã cuối cùng dẫn đến hậu quả nghiêm trọng.'),
  ('蔓延', '疫情在城市中迅速蔓延，大家都感到很紧张。', 'Yìqíng zài chéngshì zhōng xùnsù mànyán, dàjiā dōu gǎndào hěn jǐnzhāng.', 'Dịch bệnh lây lan nhanh trong thành phố, mọi người đều cảm thấy rất lo lắng.'),
  ('蔑视', '她对待别人的态度充满了蔑视和傲慢。', 'Tā duìdài biérén de tàidù chōngmǎnle mièshì hé àomàn.', 'Cô ấy đối xử với người khác đầy sự miệt thị và kiêu ngạo.'),
  ('萌芽', '经济发展的萌芽开始在农村地区显现出来。', 'Jīngjì fāzhǎn de méngyá kāishǐ zài nóngcūn dìqū xiǎnxiàn chūlái.', 'Mầm non phát triển kinh tế bắt đầu hiện ra ở các vùng nông thôn.'),
  ('莫名其妙', '他突然消失了，让大家感到莫名其妙。', 'Tā tūrán xiāoshī le, ràng dàjiā gǎndào mòríngqímiào.', 'Anh ấy đột nhiên biến mất khiến mọi người cảm thấy không hiểu nổi.'),
  ('茫茫', '茫茫大海中航行需要极强的方向感。', 'Mángmáng dàhǎi zhōng hángxíng xūyào jí qiáng de fāngxiàng gǎn.', 'Đi trên biển mênh mông cần có khả năng định hướng rất tốt.'),
  ('茫然', '听到噩耗后，她整个人显得茫然无措。', 'Tīng dào èhào hòu, tā zhěng gè rén xiǎnde mángrán wú cuò.', 'Sau khi nghe tin xấu, cô ấy trông mơ hồ và bối rối.'),
  ('茂盛', '春天来了，花园里的植物长得非常茂盛。', 'Chūntiān lái le, huāyuán lǐ de zhíwù zhǎng dé fēicháng màoshèng.', 'Mùa xuân đến, cây cối trong khu vườn mọc rất tươi tốt.'),
  ('膜', '医生建议用保护膜覆盖伤口以防感染。', 'Yīshēng jiànyì yòng bǎohù mó fùgài shāngkǒu yǐ fáng gǎnrǎn.', 'Bác sĩ khuyên nên dùng mặt nạ bảo vệ để che vết thương tránh nhiễm trùng.'),
  ('脉搏', '护士正在仔细测量病人的脉搏和血压。', 'Hùshi zhèngzài zǐxì cèliáng bìngrén de màibó hé xuèyā.', 'Y tá đang cẩn thận đo mạch và huyết áp của bệnh nhân.'),
  ('美观', '这座建筑设计既实用又美观，非常受欢迎。', 'Zhè zuò jiànzhú shèjì jì shíyòng yòu měiguān, fēicháng shòu huānyíng.', 'Thiết kế công trình này vừa thực dụng vừa đẹp mắt, rất được ưa chuộng.'),
  ('美满', '他们过着幸福美满的生活，令人羡慕。', 'Tāmen guòzhe xìngfú měimǎn de shēnghuó, lìng rén xiànmù.', 'Họ sống cuộc sống hạnh phúc mỹ mãn khiến người khác ngưỡng mộ.'),
  ('美妙', '音乐会上演奏的乐曲真是美妙动听。', 'Yīnyuè huì shàng yǎnzòu de yuèqǔ zhēn shì měimiào dòngtīng.', 'Bản nhạc được trình diễn ở buổi hòa nhạc thật tuyệt vời và lôi cuốn.'),
  ('磨合', '新员工需要一段时间来磨合适应公司的工作节奏。', 'Xīn yuángōng xūyào yí duàn shíjiān lái móhé shìyìng gōngsī de gōngzuò jiézòu.', 'Nhân viên mới cần một thời gian để chạy thử và thích nghi với nhịp độ làm việc của công ty.'),
  ('码头', '货物已经运到码头，等待装船发往海外。', 'Huòwù yǐjīng yùn dào mǎtóu, děngdài zhuāngchuán fā wǎng hǎiwài.', 'Hàng hóa đã được vận chuyển đến bến tàu, chờ bốc lên tàu để gửi ra nước ngoài.'),
  ('瞄准', '射手认真瞄准目标，准备发射箭矢。', 'Shèshǒu rènzhēn miáozhǔn mùbiāo, zhǔnbèi fāshè jiànshǐ.', 'Xạ thủ tập trung ngắm chuẩn mục tiêu, chuẩn bị bắn tên.'),
  ('眯', '阳光太刺眼了，他不自觉地眯起了眼睛。', 'Yángguāng tài cìyǎn le, tā bù zìjué de mī qǐ le yǎnjing.', 'Ánh nắng quá chói mắt, anh ta không tự chủ được nheo mắt lại.'),
  ('盲目', '盲目的追随可能会导致严重的后果。', 'Mángmù de zhuīsuí kěnéng huì dǎozhì yánzhòng de hòuguǒ.', 'Theo đuổi một cách mù quáng có thể dẫn đến hậu quả nghiêm trọng.'),
  ('目睹', '我亲眼目睹了那场意外的发生。', 'Wǒ qīn yǎn mù dǔ le nà chǎng yìwài de fāshēng.', 'Tôi đã chứng kiến tận mắt sự việc tai nạn đó xảy ra.'),
  ('目光', '他的目光中充满了坚定和自信。', 'Tā de mùguāng zhōng chōngmǎn le jiāndìng hé zìxìn.', 'Ánh mắt của anh ấy tràn đầy sự kiên định và tự tin.'),
  ('猛烈', '风暴猛烈地袭击了沿海地区。', 'Fēngbào měngliè de xíjī le yán hǎi dìqū.', 'Cơn bão dữ dội đã tấn công khu vực ven biển.'),
  ('灭亡', '如果不采取措施，文明可能会灭亡。', 'Rúguǒ bù cǎiqǔ cuòshī, wénmíng kěnéng huì mièwáng.', 'Nếu không có biện pháp, nền văn minh có thể bị diệt vong.'),
  ('漫长', '等待的时间总是感觉格外漫长而煎熬。', 'Děngdài de shíjiān zǒng shì gǎnjué géwài màncháng ér jiānnáo.', 'Thời gian chờ đợi luôn cảm thấy dài đằng đẵng và đau khổ.'),
  ('漫画', '他喜欢通过漫画来表达自己的创意。', 'Tā xǐhuān tōngguò mànhuà lái biǎodá zìjǐ de chuàngyì.', 'Anh ấy thích thể hiện ý tưởng của mình qua truyện tranh.'),
  ('渺小', '在宇宙的面前人类显得十分渺小。', 'Zài yǔzhòu de miànqián rénlèi xiǎnde shífēn miǎoxiǎo.', 'Trước vũ trụ, con người trông thật nhỏ bé.'),
  ('沐浴', '早晨的阳光使整个湖面仿佛沐浴在金色光辉中。', 'Zǎochén de yángguāng shǐ zhěnggè húmiàn fǎngfú mùyù zài jīnsè guānghuī zhōng.', 'Ánh nắng buổi sáng như tắm rửa cả mặt hồ trong ánh sáng vàng.'),
  ('民间', '这些民间故事传承了几百年的文化传统。', 'Zhèxiē mínjiān gùshì chuánchéng le jǐ bǎi nián de wénhuà chuántǒng.', 'Những câu chuyện dân gian này đã truyền lại truyền thống văn hóa hàng trăm năm.'),
  ('民主', '民主制度保证了人民的权利和自由。', 'Mínzhǔ zhìdù bǎozhèng le rénmín de quánlì hé zìyóu.', 'Chế độ dân chủ đảm bảo quyền lợi và tự do của người dân.'),
  ('母语', '学习第二语言时，母语的影响不可忽视。', 'Xuéxí dì èr yǔyán shí, mǔyǔ de yǐngxiǎng bùkě hūshì.', 'Khi học ngôn ngữ thứ hai, ảnh hưởng của tiếng mẹ đẻ không thể xem nhẹ.'),
  ('模范', '他是公司里的模范员工，值得大家学习。', 'Tā shì gōngsī lǐ de mófàn yuángōng, zhídé dàjiā xuéxí.', 'Anh ấy là nhân viên mẫu mực trong công ty, đáng để mọi người học tập.'),
  ('模样', '孩子的模样非常可爱，令人忍不住微笑。', 'Háizi de múyàng fēicháng kě''ài, lìng rén rěnbuzhù wéixiào.', 'Bộ dạng của đứa trẻ rất dễ thương khiến người ta không thể không mỉm cười.'),
  ('模式', '这种教学模式强调学生的主动参与和互动。', 'Zhè zhǒng jiàoxué móshì qiángdiào xuéshēng de zhǔdòng cānyù hé hùdòng.', 'Mô thức giảng dạy này nhấn mạnh sự tham gia chủ động và tương tác của học sinh.'),
  ('模型', '设计师用3D打印技术制作了建筑模型。', 'Shèjìshī yòng 3D dǎyìn jìshù zhìzuò le jiànzhú móxíng.', 'Nhà thiết kế đã sử dụng công nghệ in 3D để làm mô hình kiến trúc.'),
  ('棉花', '这片田地主要种植棉花供纺织业使用。', 'Zhè piàn tiándì zhǔyào zhòngzhí miánhuā gòng fǎngzhī yè shǐyòng.', 'Cánh đồng này chủ yếu trồng bông để phục vụ ngành dệt may.'),
  ('枚', '他从盒子里取出两枚硬币仔细观察。', 'Tā cóng hézi lǐ qǔ chū liǎng méi yìngbì zǐxì guānchá.', 'Anh ấy lấy ra hai cái đồng xu từ trong hộp và quan sát kỹ lưỡng.'),
  ('明智', '在关键时刻做出明智的决定非常重要。', 'Zài guānjiàn shíkè zuò chū míngzhì de juédìng fēicháng zhòngyào.', 'Việc đưa ra quyết định sáng suốt vào thời điểm quan trọng rất cần thiết.'),
  ('明明', '你明明知道规则，却故意不遵守。', 'Nǐ míngmíng zhīdào guīzé, què gùyì bù zūnshǒu.', 'Bạn rõ ràng biết quy tắc nhưng lại cố ý không tuân thủ.'),
  ('敏锐', '他对市场变化有着敏锐的洞察力。', 'Tā duì shìchǎng biànhuà yǒu zhe mǐnruì de dòngchá lì.', 'Anh ấy có khả năng nhận biết sắc sảo về biến động thị trường.'),
  ('敏捷', '她反应敏捷，总能迅速解决问题。', 'Tā fǎnyìng mǐnjié, zǒng néng xùnsù jiějué wèntí.', 'Cô ấy phản ứng nhanh nhạy, luôn có thể giải quyết vấn đề một cách nhanh chóng.'),
  ('摸索', '在黑暗中，他只能摸索前行。', 'Zài hēi''àn zhōng, tā zhǐ néng mōsuǒ qiánxíng.', 'Trong bóng tối, anh ta chỉ có thể lần sờ mà đi về phía trước.'),
  ('摩擦', '两国因为贸易问题产生了严重的摩擦。', 'Liǎng guó yīnwèi màoyì wèntí chǎnshēng le yánzhòng de mócā.', 'Hai quốc gia vì vấn đề thương mại đã phát sinh mâu thuẫn nghiêm trọng.'),
  ('描绘', '画家用细腻的笔触描绘了这幅风景。', 'Huàjiā yòng xìnì de bǐchù miáohuì le zhè fú fēngjǐng.', 'Họa sĩ đã dùng nét vẽ tinh tế để miêu tả bức tranh phong cảnh này.'),
  ('抹杀', '他的努力不能被历史抹杀。', 'Tā de nǔlì bù néng bèi lìshǐ mǒshā.', 'Nỗ lực của anh ấy không thể bị lịch sử bôi nhòa.'),
  ('慢性', '这种疾病是一种慢性病，需要长期治疗。', 'Zhè zhǒng jíbìng shì yī zhǒng mànxìngbìng, xūyào chángqī zhìliáo.', 'Bệnh này là một căn bệnh mãn tính, cần điều trị lâu dài.'),
  ('忙碌', '他为了家庭而忙碌了一整天。', 'Tā wèile jiātíng ér mánglù le yī zhěng tiān.', 'Anh ấy bận rộn cả ngày vì gia đình.'),
  ('弥补', '我们应该努力弥补过去的错误。', 'Wǒmen yīnggāi nǔlì míbǔ guòqù de cuòwù.', 'Chúng ta nên cố gắng để bù đắp những sai lầm trong quá khứ.'),
  ('弥漫', '空气中弥漫着花香，非常令人愉快。', 'Kōngqì zhōng mímàn zhe huāxiāng, fēicháng lìng rén yúkuài.', 'Hương hoa ngào ngạt trong không khí, khiến người ta rất vui thích.'),
  ('密度', '这款材料的密度比普通钢铁更高。', 'Zhè kuǎn cáiliào de mìdù bǐ pǔtōng gāngtiě gèng gāo.', 'Mật độ của loại vật liệu này cao hơn thép thông thường.'),
  ('密封', '请确保瓶盖已经密封好，避免液体漏出。', 'Qǐng quèbǎo píng gài yǐjīng mìfēng hǎo, bìmiǎn yètǐ lòuchū.', 'Xin hãy đảm bảo nắp chai đã được niêm phong tốt để tránh chất lỏng bị rò rỉ.'),
  ('媒介', '电视是现代社会重要的媒介之一。', 'Diànshì shì xiàndài shèhuì zhòngyào de méijiè zhī yī.', 'Truyền hình là một trong những môi giới quan trọng của xã hội hiện đại.'),
  ('墨水儿', '请检查一下笔里的墨水儿够不够用了。', 'Qǐng jiǎnchá yīxià bǐ lǐ de mòshuǐr gòu bù gòu yòng le.', 'Xin hãy kiểm tra xem mực trong bút còn đủ không.'),
  ('埋葬', '村民们为逝去的亲人举行了传统的埋葬仪式。', 'Cūnmín men wèi shìqù de qīnrén jǔxíng le chuántǒng de mái zàng yíshì.', 'Người dân trong làng đã tổ chức tang lễ truyền thống để mai táng người thân đã khuất.'),
  ('埋没', '他的才华被环境埋没，未能被大家发现。', 'Tā de cáihuá bèi huánjìng mái mò, wèinéng bèi dàjiā fāxiàn.', 'Tài năng của anh ấy bị chôn giấu bởi môi trường và không được mọi người phát hiện.'),
  ('埋怨', '她总是不停地埋怨工作压力太大。', 'Tā zǒng shì bù tíng de mányuàn gōngzuò yālì tài dà.', 'Cô ấy luôn liên tục oán trách áp lực công việc quá lớn.'),
  ('埋伏', '士兵们在树林里埋伏，等待敌人出现。', 'Shìbīng men zài shùlín lǐ mái fú, děngdài dírén chūxiàn.', 'Các chiến sĩ mai phục trong rừng, đợi quân địch xuất hiện.'),
  ('嘛', '这件事情很简单，不用太担心嘛！', 'Zhè jiàn shìqíng hěn jiǎndān, bù yòng tài dānxīn ma!', 'Chuyện này rất đơn giản, thôi đừng lo lắng quá mà!'),
  ('命名', '这座新建的公园被命名为和平公园。', 'Zhè zuò xīn jiàn de gōngyuán bèi mìngmíng wèi Hépíng gōngyuán.', 'Công viên mới xây này được đặt tên là Công viên Hòa bình.'),
  ('名额', '这次比赛的名额非常有限，只有十个人能参加。', 'Zhè cì bǐsài de míng''é fēicháng yǒuxiàn, zhǐ yǒu shí gèrén néng cānjiā.', 'Số người tham gia cuộc thi này rất giới hạn, chỉ có mười người được dự thi.'),
  ('名誉', '保护个人的名誉是每个人应尽的责任。', 'Bǎohù gèrén de míngyù shì měi gèrén yīng jìn de zérèn.', 'Bảo vệ danh dự cá nhân là trách nhiệm mỗi người phải làm.'),
  ('名次', '跑步比赛结束后，他获得了第三名的名次。', 'Pǎobù bǐsài jiéshù hòu, tā huòdéle dì sān míng de míngcì.', 'Sau khi cuộc thi chạy kết thúc, anh ấy đoạt thứ hạng ba.'),
  ('名副其实', '他凭借努力成为了名副其实的专家。', 'Tā píngjiè nǔlì chéngwéile míngfùqíshí de zhuānjiā.', 'Anh ấy trở thành chuyên gia đúng như danh xưng nhờ nỗ lực.'),
  ('勉强', '他勉强接受了这份工作，虽然并不喜欢。', 'Tā miǎnqiǎng jiēshòule zhè fèn gōngzuò, suīrán bìng bù xǐhuan.', 'Anh ấy miễn cưỡng nhận công việc này dù không thích.'),
  ('勉励', '老师常常勉励学生努力学习，不断进步。', 'Lǎoshī chángcháng miǎnlì xuéshēng nǔlì xuéxí, bùduàn jìnbù.', 'Giáo viên thường khích lệ học sinh học tập chăm chỉ, không ngừng tiến bộ.'),
  ('冒犯', '他无意中冒犯了长辈，感到非常抱歉。', 'Tā wúyì zhōng màofànle zhǎngbèi, gǎndào fēicháng bàoqiàn.', 'Anh ấy vô tình mạo phạm người lớn và cảm thấy rất xin lỗi.'),
  ('冒充', '骗子冒充银行职员骗取客户信息。', 'Piànzi màochōng yínháng zhíyuán piànqǔ kèhù xìnxī.', 'Kẻ lừa đảo giả mạo nhân viên ngân hàng để lừa lấy thông tin khách hàng.'),
  ('免疫', '疫苗可以帮助人体建立免疫，预防疾病。', 'Yìmiáo kěyǐ bāngzhù réntǐ jiànlì miǎnyì, yùfáng jíbìng.', 'Vắc-xin có thể giúp cơ thể xây dựng miễn dịch, ngăn ngừa bệnh tật.'),
  ('免得', '请早点出发，免得迟到影响考试。', 'Qǐng zǎodiǎn chūfā, miǎndé chídào yǐngxiǎng kǎoshì.', 'Hãy khởi hành sớm để tránh đến muộn ảnh hưởng đến kỳ thi.'),
  ('难能可贵', '他在困境中坚持自己的理想，实属难能可贵。', 'Tā zài kùnjìng zhōng jiānchí zìjǐ de lǐxiǎng, shíshǔ nán néng kě guì.', 'Anh ta kiên trì lý tưởng của mình trong hoàn cảnh khó khăn thật là vô cùng đáng quý.'),
  ('难得', '这次和朋友难得见面，大家都很开心。', 'Zhè cì hé péngyǒu nán dé jiànmiàn, dàjiā dōu hěn kāixīn.', 'Lần này gặp bạn bè rất khó có nên mọi người đều rất vui.'),
  ('难堪', '他在会上发言出错，感到非常难堪。', 'Tā zài huì shàng fāyán chūcuò, gǎndào fēicháng nánkān.', 'Anh ấy phát biểu sai trong buổi họp, cảm thấy rất ngượng ngùng.'),
  ('逆行', '车辆逆行在高速公路上极其危险，必须避免。', 'Chēliàng nìxíng zài gāosù gōnglù shàng jíqí wéixiǎn, bìxū bìmiǎn.', 'Xe cộ đi ngược chiều trên đường cao tốc cực kỳ nguy hiểm, phải tránh.'),
  ('虐待', '任何形式的动物虐待都是法律所禁止的。', 'Rènhé xíngshì de dòngwù nüèdài dōu shì fǎlǜ suǒ jìnzhǐ de.', 'Mọi hình thức ngược đãi động vật đều bị pháp luật cấm.'),
  ('能量', '充足的能量对运动员保持状态很重要。', 'Chōngzú de néngliàng duì yùndòngyuán bǎochí zhuàngtài hěn zhòngyào.', 'Năng lượng đầy đủ rất quan trọng để vận động viên duy trì phong độ.'),
  ('耐用', '这款手机外壳坚固，使用起来非常耐用。', 'Zhè kuǎn shǒujī wàiké jiāngù, shǐyòng qǐlái fēicháng nàiyòng.', 'Vỏ điện thoại này rất chắc chắn, sử dụng rất bền.'),
  ('纽扣儿', '这件衬衫的纽扣儿掉了，需要缝补。', 'Zhè jiàn chènshān de niǔkòur diàole, xūyào féngbǔ.', 'Cái cúc áo của chiếc sơ mi này bị rơi, cần phải khâu lại.'),
  ('纳闷儿', '他看到消息后感到很纳闷儿，不知道发生了什么。', 'Tā kàn dào xiāoxi hòu gǎndào hěn nàmènr, bù zhīdào fāshēngle shénme.', 'Anh ấy sau khi thấy tin tức cảm thấy bồn chồn, không biết đã xảy ra chuyện gì.'),
  ('浓厚', '她对中国文化有浓厚的兴趣，经常参加相关活动。', 'Tā duì Zhōngguó wénhuà yǒu nónghòu de xìngqù, jīngcháng cānjiā xiāngguān huódòng.', 'Cô ấy có hứng thú đậm nét với văn hóa Trung Quốc, thường xuyên tham gia các hoạt động liên quan.'),
  ('捏', '孩子捏着泥巴，玩得很开心。', 'Háizi niē zhe níbā, wán de hěn kāixīn.', 'Đứa trẻ túm lấy bùn, chơi rất vui.'),
  ('挪', '请你把椅子挪一挪，我们好坐下。', 'Qǐng nǐ bǎ yǐzi nuó yí nuó, wǒmen hǎo zuò xià.', 'Xin bạn di chuyển cái ghế một chút, chúng tôi sẽ ngồi vào.'),
  ('拿手', '唱歌是她的拿手好戏，总是赢得掌声。', 'Chànggē shì tā de náshǒu hǎoxì, zǒng shì yíngdé zhǎngshēng.', 'Hát là sở trường của cô ấy, luôn luôn giành được tràng pháo tay.'),
  ('拧', '他用力拧开瓶盖，终于打开了。', 'Tā yòng lì níng kāi pínggài, zhōngyú dǎkāi le.', 'Anh ấy vặn nắp chai thật mạnh, cuối cùng đã mở được.'),
  ('拟定', '会议上我们拟定了明天的工作计划。', 'Huìyì shàng wǒmen nǐdìng le míngtiān de gōngzuò jìhuà.', 'Tại cuộc họp, chúng tôi đã vạch ra kế hoạch công việc ngày mai.'),
  ('扭转', '他想扭转目前的不利局面，需要努力。', 'Tā xiǎng niǔzhuǎn mùqián de bùlì júmiàn, xūyào nǔlì.', 'Anh ấy muốn xoay chuyển tình thế bất lợi hiện tại, cần phải cố gắng.'),
  ('恼火', '他因为迟到而很恼火，大发脾气。', 'Tā yīnwèi chídào ér hěn nǎohuǒ, dà fā píqì.', 'Anh ấy vì đến muộn nên rất nổi cáu, nổi giận.'),
  ('年度', '这份报告总结了公司的年度经营情况。', 'Zhè fèn bàogào zǒngjié le gōngsī de niándù jīngyíng qíngkuàng.', 'Báo cáo này tóm tắt tình hình kinh doanh của công ty trong năm.'),
  ('宁肯', '我宁肯早起，也不想迟到上班。', 'Wǒ nìngkěn zǎoqǐ, yě bù xiǎng chídào shàngbān.', 'Tôi thà thức dậy sớm cũng không muốn đi làm muộn.'),
  ('宁愿', '她宁愿自己承担责任，也不让别人担心。', 'Tā nìngyuàn zìjǐ chéngdān zérèn, yě bù ràng biérén dānxīn.', 'Cô ấy thà tự mình chịu trách nhiệm cũng không muốn làm người khác lo lắng.'),
  ('奴隶', '历史上，很多奴隶为自由而奋争。', 'Lìshǐ shàng, hěn duō núlì wèi zìyóu ér fènzhēng.', 'Trong lịch sử, nhiều nô lệ đã đấu tranh vì tự do.'),
  ('南辕北辙', '如果目标不明确，就会出现南辕北辙的情况。', 'Rúguǒ mùbiāo bù míngquè, jiù huì chūxiàn nányuánběizhé de qíngkuàng.', 'Nếu mục tiêu không rõ ràng, sẽ xảy ra tình trạng nghĩ một đằng làm một nẻo.'),
  ('凝视', '他凝视着远方，似乎在思考人生。', 'Tā níngshì zhe yuǎnfāng, sìhū zài sīkǎo rénshēng.', 'Anh ấy nhìn đăm đăm về phía xa dường như đang suy nghĩ về cuộc đời.'),
  ('凝聚', '大家的努力凝聚成了团队的力量。', 'Dàjiā de nǔlì níngjù chéng le tuánduì de lìliàng.', 'Nỗ lực của mọi người đã hội tụ thành sức mạnh của đội nhóm.'),
  ('凝固', '水遇冷后会凝固成冰。', 'Shuǐ yù lěng hòu huì nínggù chéng bīng.', 'Nước khi gặp lạnh sẽ đông lại thành băng.'),
  ('农历', '春节按照农历日期来庆祝，非常传统。', 'Chūnjié ànzhào nónglì rìqī lái qìngzhù, fēicháng chuántǒng.', 'Tết được ăn mừng theo ngày âm lịch, rất truyền thống.'),
  ('内涵', '这本书的内涵丰富，引人深思。', 'Zhè běn shū de nèihán fēngfù, yǐn rén shēnsī.', 'Nội hàm của cuốn sách này rất phong phú, khiến người ta suy ngẫm sâu sắc.'),
  ('内幕', '他揭露了公司的内幕，引起轩然大波。', 'Tā jiēlù le gōngsī de nèimù, yǐnqǐ xuānrándàbō.', 'Anh ấy đã phơi bày nội tình công ty, gây ra làn sóng lớn.'),
  ('内在', '他的内在品质比外表更重要。', 'Tā de nèizài pǐnzhí bǐ wàibiǎo gèng zhòngyào.', 'Phẩm chất nội tại của anh ấy quan trọng hơn vẻ bề ngoài.'),
  ('殴打', '警方制止了两人的殴打行为，保护了现场秩序。', 'Jǐngfāng zhìzhǐ le liǎng rén de ōudǎ xíngwéi, bǎohù le xiànchǎng zhìxù.', 'Cảnh sát đã ngăn chặn hành vi ẩu đả của hai người, bảo vệ trật tự hiện trường.'),
  ('哦', '他说话的时候，我突然意识到，哦，这就是答案。', 'Tā shuōhuà de shíhòu, wǒ túrán yìshí dào, ó, zhè jiùshì dá''àn.', 'Khi anh ấy nói, tôi đột nhiên nhận ra, ồ, đây chính là câu trả lời.'),
  ('呕吐', '病人因为食物中毒，不断地呕吐无法停止。', 'Bìngrén yīnwèi shíwù zhòngdú, bùduàn de ǒutù wúfǎ tíngzhǐ.', 'Bệnh nhân vì ngộ độc thực phẩm nên nôn mửa liên tục không ngừng.'),
  ('偶像', '她把那位歌手当作自己一生的偶像和榜样。', 'Tā bǎ nà wèi gēshǒu dàng zuò zìjǐ yīshēng de ǒuxiàng hé bǎngyàng.', 'Cô ấy coi ca sĩ đó là thần tượng và hình mẫu của đời mình.'),
  ('魄力', '面对困难，他展现出非凡的魄力和决断能力。', 'Miànduì kùnnan, tā zhǎnxiàn chū fēifán de pòlì hé juéduàn nénglì.', 'Đối mặt với khó khăn, anh ấy thể hiện sự kiên quyết và khả năng quyết đoán phi thường.'),
  ('飘扬', '国旗在风中高高飘扬，象征着国家的尊严。', 'Guóqí zài fēng zhōng gāo gāo piāoyáng, xiàngzhēng zhe guójiā de zūnyán.', 'Quốc kỳ tung bay trong gió, tượng trưng cho sự tôn nghiêm của quốc gia.'),
  ('频繁', '由于天气变化频繁，农民们不得不随时调整种植计划。', 'Yóuyú tiānqì biànhuà pínfán, nóngmín men bùdébù suíshí tiáozhěng zhòngzhí jìhuà.', 'Vì thời tiết thay đổi thường xuyên, nông dân phải thường xuyên điều chỉnh kế hoạch trồng trọt.'),
  ('频率', '这个设备的工作频率必须严格按照说明书调整。', 'Zhège shèbèi de gōngzuò pínlǜ bìxū yángé ànzhào shuōmíngshū tiáozhěng.', 'Tần suất làm việc của thiết bị này phải được điều chỉnh nghiêm ngặt theo hướng dẫn sử dụng.'),
  ('颇', '这部电影的情节设计颇具创意，深受观众喜爱。', 'Zhè bù diànyǐng de qíngjié shèjì pō jù chuàngyì, shēn shòu guānzhòng xǐ''ài.', 'Cốt truyện của bộ phim này khá sáng tạo và được khán giả rất thích.'),
  ('铺', '这条商业街上新开了一家服装铺，生意异常火爆。', 'Zhè tiáo shāngyè jiē shàng xīn kāi le yī jiā fúzhuāng pù, shēngyì yìcháng huǒbào.', 'Trên con phố thương mại này mới mở một cửa hàng quần áo, kinh doanh vô cùng nhộn nhịp.'),
  ('配套', '新小区建设时配套设施非常完善，方便居民生活。', 'Xīn xiǎoqū jiànshè shí pèitào shèshī fēicháng wánshàn, fāngbiàn jūmín shēnghuó.', 'Các cơ sở đồng bộ được hoàn thiện rất tốt khi xây dựng khu dân cư mới, tiện lợi cho sinh hoạt của cư dân.'),
  ('配备', '军队配备了先进的装备以提升整体作战能力。', 'Jūnduì pèibèi le xiānjìn de zhuāngbèi yǐ tíshēng zhěngtǐ zuòzhàn nénglì.', 'Quân đội được phân phối trang bị tiên tiến nhằm nâng cao năng lực tác chiến tổng thể.'),
  ('配偶', '她和配偶已经结婚十年，共同经历了很多风风雨雨。', 'Tā hé pèi''ǒu yǐjīng jiéhūn shí nián, gòngtóng jīnglì le hěn duō fēngfēng yǔyǔ.', 'Cô ấy và vợ/chồng đã kết hôn mười năm, cùng trải qua nhiều thăng trầm.'),
  ('迫害', '历史上许多无辜的人因为信仰不同被迫害。', 'Lìshǐ shàng xǔduō wúgū de rén yīnwèi xìnyǎng bùtóng bèi pòhài.', 'Trong lịch sử, nhiều người vô tội bị bức hại vì tôn giáo khác nhau.'),
  ('迫不及待', '孩子们迫不及待地打开礼物，脸上充满了喜悦。', 'Háizimen pòbùjídài de dǎkāi lǐwù, liǎn shàng chōngmǎn le xǐyuè.', 'Bọn trẻ vội vã mở quà, trên khuôn mặt đầy niềm vui.'),
  ('趴', '小猫趴在窗台上，静静地看着外面的鸟儿。', 'Xiǎo māo pā zài chuāngtái shàng, jìngjìng de kàn zhe wàimiàn de niǎor.', 'Con mèo nhỏ nằm bò trên bậu cửa sổ, yên lặng nhìn những con chim bên ngoài.'),
  ('贫困', '政府出台了多项政策帮助贫困地区改善生活条件。', 'Zhèngfǔ chūtái le duō xiàng zhèngcè bāngzhù pínkùn dìqū gǎishàn shēnghuó tiáojiàn.', 'Chính phủ đã ban hành nhiều chính sách giúp các khu vực nghèo cải thiện điều kiện sống.'),
  ('贫乏', '这本书内容贫乏，缺乏新颖的观点和见解。', 'Zhè běn shū nèiróng pínfá, quēfá xīnyǐng de guāndiǎn hé jiànjiě.', 'Nội dung cuốn sách này nghèo nàn, thiếu những quan điểm và hiểu biết mới mẻ.'),
  ('评论', '专家对该电影的艺术表现提出了深入的评论。', 'Zhuānjiā duì gāi diànyǐng de yìshù biǎoxiàn tíchū le shēnrù de pínglùn.', 'Chuyên gia đã đưa ra những bình luận sâu sắc về biểu hiện nghệ thuật của bộ phim đó.'),
  ('评估', '项目启动前，团队需要对市场环境进行全面评估。', 'Xiàngmù qǐdòng qián, tuánduì xūyào duì shìchǎng huánjìng jìnxíng quánmiàn pínggū.', 'Trước khi khởi động dự án, nhóm cần tiến hành đánh giá toàn diện về môi trường thị trường.'),
  ('譬如', '很多语言都包含了丰富的文化元素，譬如汉语中的成语。', 'Hěn duō yǔyán dōu bāohán le fēngfù de wénhuà yuánsù, pìrú hànyǔ zhōng de chéngyǔ.', 'Nhiều ngôn ngữ đều chứa đựng các yếu tố văn hóa phong phú, ví dụ như thành ngữ trong tiếng Trung.'),
  ('破例', '老师为了鼓励学生，破例允许他们延长作业时间。', 'Lǎoshī wèile gǔlì xuéshēng, pòlì yǔnxǔ tāmen yáncháng zuòyè shíjiān.', 'Giáo viên để khích lệ học sinh, phá lệ cho phép họ kéo dài thời gian làm bài tập.'),
  ('盘旋', '老鹰在山谷上空盘旋，寻找猎物的踪迹。', 'Lǎoyīng zài shāngǔ shàngkōng pánxuán, xúnzhǎo lièyù de zōngjì.', 'Đại bàng bay vòng quanh trên thung lũng, tìm dấu vết con mồi.'),
  ('盆地', '这片盆地四周被高山环绕，气候非常适合农业发展。', 'Zhè piàn pén dì sìzhōu bèi gāoshān huánrào, qìhòu fēicháng shìhé nóngyè fāzhǎn.', 'Vùng thung lũng này được bao quanh bởi núi cao, khí hậu rất thích hợp cho phát triển nông nghiệp.'),
  ('皮革', '这家工厂专门生产高质量的皮革制品出口国外。', 'Zhè jiā gōngchǎng zhuānmén shēngchǎn gāo zhìliàng de pígé zhìpǐn chūkǒu guówài.', 'Nhà máy này chuyên sản xuất các sản phẩm thuộc da chất lượng cao để xuất khẩu ra nước ngoài.'),
  ('疲惫', '连续工作十小时后，他感到身心疲惫，迫切需要休息。', 'Liánxù gōngzuò shí xiǎoshí hòu, tā gǎndào shēnxīn píbèi, pòqiè xūyào xiūxí.', 'Sau khi làm việc liên tục mười tiếng, anh ấy cảm thấy mệt nhọc cả thể xác và tinh thần, rất cần nghỉ ngơi.'),
  ('疲倦', '长时间的学习使她感到疲倦，无法集中注意力。', 'Cháng shíjiān de xuéxí shǐ tā gǎndào píjuàn, wúfǎ jízhōng zhùyìlì.', 'Học tập lâu dài khiến cô ấy cảm thấy thiếu ngủ và không thể tập trung.'),
  ('畔', '太阳缓缓落下，渔民们在湖畔收网准备回家。', 'Tàiyáng huǎnhuǎn luò xià, yúmínmen zài hú pàn shōuwǎng zhǔnbèi huí jiā.', 'Mặt trời từ từ lặn xuống, ngư dân đang thu lưới bên bờ hồ chuẩn bị về nhà.'),
  ('片断', '电影中最感人的片断让观众泪流满面。', 'Diànyǐng zhōng zuì gǎnrén de piànduàn ràng guānzhòng lèiliú mǎnmiàn.', 'Đoạn phim cảm động nhất trong bộ phim khiến khán giả rơi nước mắt.'),
  ('片刻', '这位科学家片刻不停地思考问题，寻求最佳解决方案。', 'Zhè wèi kēxuéjiā piànkè bù tíng de sīkǎo wèntí, xúnqiú zuìjiā jiějué fāng''àn.', 'Nhà khoa học này không ngừng suy nghĩ trong chốc lát, tìm kiếm giải pháp tốt nhất.'),
  ('烹饪', '她在烹饪课上学习了许多传统的地方美食做法。', 'Tā zài pēngrèn kè shàng xuéxíle xǔduō chuántǒng de dìfāng měishí zuòfǎ.', 'Cô ấy đã học nhiều cách làm món ăn địa phương truyền thống trong lớp nấu ăn.'),
  ('瀑布', '游客们站在瀑布前，感受水流倾泻而下的壮观景象。', 'Yóukèmen zhàn zài pùbù qián, gǎnshòu shuǐliú qīngxiè ér xià de zhuàngguān jǐngxiàng.', 'Du khách đứng trước thác nước, cảm nhận cảnh tượng nước chảy đổ xuống hùng vĩ.'),
  ('漂浮', '塑料袋在河面上漂浮，严重污染了水环境。', 'Sùliào dài zài hé miàn shàng piāofú, yánzhòng wūrǎnle shuǐ huánjìng.', 'Túi nhựa trôi nổi trên mặt sông, gây ô nhiễm nghiêm trọng môi trường nước.'),
  ('派遣', '公司派遣技术人员前往现场解决设备故障问题。', 'Gōngsī pàiqiǎn jìshù rényuán qiánwǎng xiànchǎng jiějué shèbèi gùzhàng wèntí.', 'Công ty cử nhân viên kỹ thuật tới hiện trường để giải quyết sự cố thiết bị.'),
  ('派别', '在这场选举中，两个派别的竞争异常激烈。', 'Zài zhè chǎng xuǎnjǔ zhōng, liǎng gè pàibié de jìngzhēng yìcháng jīliè.', 'Trong cuộc bầu cử này, cuộc cạnh tranh giữa hai phe phái rất quyết liệt.'),
  ('泼', '他生气地把水泼到桌子上，表示强烈不满。', 'Tā shēngqì de bǎ shuǐ pō dào zhuōzi shàng, biǎoshì qiángliè bùmǎn.', 'Anh ta tức giận hắt nước lên bàn để biểu thị sự không hài lòng mạnh mẽ.'),
  ('泡沫', '经济泡沫破裂后，许多企业遭受了严重的损失。', 'Jīngjì pàomò pòliè hòu, xǔduō qǐyè zāoshòu le yánzhòng de sǔnshī.', 'Sau khi bong bóng kinh tế vỡ, nhiều doanh nghiệp chịu tổn thất nghiêm trọng.'),
  ('朴素', '她一直保持着朴素的生活方式，不追求奢华。', 'Tā yīzhí bǎochí zhe pǔsù de shēnghuó fāngshì, bù zhuīqiú shēhuá.', 'Cô ấy luôn duy trì lối sống giản dị, không theo đuổi sự xa hoa.'),
  ('朴实', '他的性格朴实真诚，赢得了大家的信任。', 'Tā de xìnggé pǔshí zhēnchéng, yíngdéle dàjiā de xìnrèn.', 'Tính cách của anh ấy thành thật, chất phác, giành được sự tin tưởng của mọi người.'),
  ('普及', '互联网的普及极大地改变了人们的生活方式。', 'Hùliánwǎng de pǔjí jídà de gǎibiànle rénmen de shēnghuó fāngshì.', 'Sự phổ biến của internet đã thay đổi mạnh mẽ cách sống của mọi người.'),
  ('攀登', '登山者克服重重困难，成功攀登到了雪山顶峰。', 'Dēngshān zhě kèfú chóngchóng kùnnán, chénggōng pāndēng dào le xuěshān dǐngfēng.', 'Người leo núi vượt qua nhiều khó khăn và thành công trèo đến đỉnh núi tuyết.'),
  ('撇', '书法家用笔时，轻松地一撇勾勒出优美的线条。', 'Shūfǎ jiā yòng bǐ shí, qīngsōng de yī piě gōulè chū yōuměi de xiàntiáo.', 'Nghệ nhân thư pháp khi cầm bút, nhẹ nhàng phẩy một nét để phác họa đường nét đẹp mắt.'),
  ('排除', '我们需要排除所有干扰，专心完成这个项目。', 'Wǒmen xūyào páichú suǒyǒu gānrǎo, zhuānxīn wánchéng zhège xiàngmù.', 'Chúng ta cần bài trừ mọi phiền nhiễu, tập trung hoàn thành dự án này.'),
  ('排练', '演员们每天晚上都在剧场里排练新剧本。', 'Yǎnyuánmen měitiān wǎnshàng dōu zài jùchǎng lǐ páiliàn xīn jùběn.', 'Diễn viên mỗi tối đều tập kịch bản mới trong nhà hát.'),
  ('排斥', '由于文化差异，有些人对外来思想持排斥态度。', 'Yóuyú wénhuà chāyì, yǒuxiē rén duì wàilái sīxiǎng chí páichì tàidù.', 'Do sự khác biệt văn hóa, một số người có thái độ bài xích tư tưởng ngoại lai.'),
  ('排放', '工厂必须控制废气的排放，保护环境质量。', 'Gōngchǎng bìxū kòngzhì fèiqì de páifàng, bǎohù huánjìng zhìliàng.', 'Nhà máy phải kiểm soát việc thải khí thải, bảo vệ chất lượng môi trường.'),
  ('捧', '她小心翼翼地捧着一杯热腾腾的茶。', 'Tā xiǎoxīn yìyì de pěngzhe yī bēi rè téngténg de chá.', 'Cô ấy cẩn thận bưng một tách trà đang bốc khói.'),
  ('拼搏', '运动员们在赛场上拼搏，争取冠军荣誉。', 'Yùndòngyuánmen zài sàichǎng shàng pīnbó, zhēngqǔ guànjūn róngyù.', 'Các vận động viên đấu tranh trên sân, giành lấy vinh quang chức vô địch.'),
  ('拼命', '为了完成任务，他拼命加班到深夜。', 'Wèile wánchéng rènwù, tā pīnmìng jiābān dào shēnyè.', 'Để hoàn thành nhiệm vụ, anh ấy liều mạng tăng ca đến tận đêm khuya.'),
  ('抛弃', '即使遇到困难，我们也绝不能轻易抛弃梦想。', 'Jíshǐ yùdào kùnnán, wǒmen yě jué bùnéng qīngyì pāoqì mèngxiǎng.', 'Dù gặp khó khăn, chúng ta cũng không thể dễ dàng vứt bỏ ước mơ.'),
  ('批发', '这家市场以批发价格出售各种新鲜水果。', 'Zhè jiā shìchǎng yǐ pīfā jiàgé chūshòu gèzhǒng xīnxiān shuǐguǒ.', 'Chợ này bán buôn nhiều loại trái cây tươi với giá sỉ.'),
  ('批判', '老师严肃地批判了学生的不诚信行为。', 'Lǎoshī yánsù de pīpànle xuéshēng de bù chéngxìn xíngwéi.', 'Giáo viên nghiêm túc phê phán hành vi thiếu trung thực của học sinh.'),
  ('扑', '小狗看到主人回来，兴奋地扑向他。', 'Xiǎogǒu kàn dào zhǔrén huílái, xīngfèn de pū xiàng tā.', 'Chó con thấy chủ về, hớn hở bổ nhào về phía anh ấy.'),
  ('徘徊', '病人在医院走廊里徘徊，等待医生的消息。', 'Bìngrén zài yīyuàn zǒuláng lǐ páihuái, děngdài yīshēng de xiāoxi.', 'Bệnh nhân đi loanh quanh hành lang bệnh viện, chờ tin từ bác sĩ.'),
  ('庞大', '这个公司的庞大数据库包含了数百万条记录。', 'Zhège gōngsī de pángdà shùjùkù bāohánle shù bǎi wàn tiáo jìlù.', 'Cơ sở dữ liệu khổng lồ của công ty này chứa hàng triệu bản ghi.'),
  ('平面', '设计师正在绘制建筑物的平面图。', 'Shèjì shī zhèngzài huìzhì jiànzhù wù de píngmiàn tú.', 'Nhà thiết kế đang vẽ sơ đồ mặt bằng của tòa nhà.'),
  ('平行', '数学课上学习了两条平行线的性质。', 'Shùxué kè shàng xuéxíle liǎng tiáo píngxíng xiàn de xìngzhì.', 'Trong bài toán học tính chất của hai đường thẳng song song.'),
  ('平庸', '他不满意自己平庸的工作表现，决定努力提升技能。', 'Tā bù mǎnyì zìjǐ píngyōng de gōngzuò biǎoxiàn, juédìng nǔlì tíshēng jìnéng.', 'Anh ấy không hài lòng với thành tích công việc tầm thường của mình, quyết định cố gắng nâng cao kỹ năng.'),
  ('平坦', '这条公路非常平坦，适合骑自行车旅行。', 'Zhè tiáo gōnglù fēicháng píngtǎn, shìhé qí zìxíngchē lǚxíng.', 'Con đường này rất bằng phẳng, thích hợp cho việc đi xe đạp du lịch.'),
  ('平原', '这片平原土地肥沃，是重要的农业基地。', 'Zhè piàn píngyuán tǔdì féiwò, shì zhòngyào de nóngyè jīdì.', 'Vùng đồng bằng này đất đai màu mỡ, là cơ sở nông nghiệp quan trọng.'),
  ('平凡', '虽然生活平凡，他却过得很满足和快乐。', 'Suīrán shēnghuó píngfán, tā què guò dé hěn mǎnzú hé kuàilè.', 'Dù cuộc sống bình thường, anh ấy vẫn sống rất mãn nguyện và vui vẻ.'),
  ('屏障', '森林像一道天然的屏障，保护着村庄不受风沙侵袭。', 'Sēnlín xiàng yī dào tiānrán de píngzhàng, bǎohù zhe cūnzhuāng bù shòu fēngshā qīnxí.', 'Rừng như một rào chắn tự nhiên bảo vệ làng khỏi bị cát gió tấn công.'),
  ('屏幕', '他的新手机屏幕非常清晰，可以显示高质量的视频。', 'Tā de xīn shǒujī píngmù fēicháng qīngxī, kěyǐ xiǎnshì gāo zhìliàng de shìpín.', 'Màn hình điện thoại mới của anh ấy rất sắc nét, có thể hiển thị video chất lượng cao.'),
  ('屁股', '小猫咪静静地躺在沙发上，用屁股抵着主人的脚。', 'Xiǎo māomī jìngjìng de tǎng zài shāfā shàng, yòng pìgu dǐ zhe zhǔrén de jiǎo.', 'Con mèo nhỏ nằm yên trên sofa, dùng mông tựa vào chân chủ nhân.'),
  ('培育', '这个研究项目旨在培育更多适合高原环境的作物。', 'Zhège yánjiū xiàngmù zhǐ zài péiyù gèng duō shìhé gāoyuán huánjìng de zuòwù.', 'Dự án nghiên cứu này nhằm bồi dưỡng nhiều loại cây trồng thích hợp với môi trường cao nguyên hơn.'),
  ('坡', '我们沿着陡峭的山坡艰难地攀爬，终于到达了山顶。', 'Wǒmen yánzhe dǒuqiào de shānpō jiānnán de pān pá, zhōngyú dàodále shāndǐng.', 'Chúng tôi khó nhọc trèo theo sườn dốc đứng, cuối cùng đã tới được đỉnh núi.'),
  ('品质', '这家公司的产品以高品质和良好的售后服务闻名。', 'Zhè jiā gōngsī de chǎnpǐn yǐ gāo pǐnzhì hé liánghǎo de shòuhòu fúwù wénmíng.', 'Sản phẩm của công ty này nổi tiếng với phẩm chất cao và dịch vụ hậu mãi tốt.'),
  ('品种', '农场引进了多种新的品种，以提高农业产量和质量。', 'Nóngchǎng yǐnjìnle duō zhǒng xīn de pǐnzhǒng, yǐ tígāo nóng yè chǎn liàng hé zhìliàng.', 'Nông trại đã nhập khẩu nhiều giống mới để nâng cao sản lượng và chất lượng nông nghiệp.'),
  ('品德', '教师不仅要传授知识，还要注重学生的品德教育。', 'Jiàoshī bùjǐn yào chuánshòu zhīshì, hái yào zhùzhòng xuéshēng de pǐndé jiàoyù.', 'Giáo viên không chỉ truyền dạy kiến thức mà còn chú trọng giáo dục phẩm đức cho học sinh.'),
  ('品尝', '在旅行中，我们有机会品尝到各种地道的地方美食。', 'Zài lǚxíng zhōng, wǒmen yǒu jīhuì pǐncháng dào gè zhǒng dìdào de dìfāng měishí.', 'Trong chuyến du lịch, chúng tôi có cơ hội nếm thử nhiều món ngon đặc trưng địa phương.'),
  ('劈', '他用斧头劈开了大块的木材，为冬天准备了足够的燃料。', 'Tā yòng fǔtóu pī kāi le dà kuài de mùcái, wèi dōngtiān zhǔnbèi le zúgòu de ránliào.', 'Anh ấy dùng rìu bổ tách những khúc gỗ lớn, chuẩn bị đủ nhiên liệu cho mùa đông.'),
  ('判决', '法庭经过仔细审理，最终作出了公正的判决。', 'Fǎtíng jīngguò zǐxì shěnlǐ, zuìzhōng zuòchūle gōngzhèng de pànjué.', 'Toà án sau khi xem xét kỹ lưỡng đã đưa ra phán quyết công bằng.'),
  ('偏见', '我们应该摒弃对陌生文化的偏见，努力增进理解。', 'Wǒmen yīnggāi bìngqì duì mòshēng wénhuà de piānjiàn, nǔlì zēngjìn lǐjiě.', 'Chúng ta nên loại bỏ thành kiến đối với văn hóa lạ, cố gắng tăng cường sự hiểu biết.'),
  ('偏差', '实验数据出现了偏差，需要重新校准仪器。', 'Shíyàn shùjù chūxiàn le piānchā, xūyào chóngxīn jiàozhǔn yíqì.', 'Dữ liệu thí nghiệm xuất hiện sai lệch, cần phải hiệu chuẩn lại thiết bị.'),
  ('偏僻', '他们住在一个偏僻的山区村落，交通非常不便。', 'Tāmen zhù zài yīgè piānpì de shānqū cūnluò, jiāotōng fēicháng bù biàn.', 'Họ sống ở một ngôi làng hẻo lánh trên núi, giao thông rất bất tiện.'),
  ('偏偏', '我明明告诉他不要去，偏偏他还是坚持自己的决定。', 'Wǒ míngmíng gàosu tā bùyào qù, piānpiān tā háishì jiānchí zìjǐ de juédìng.', 'Tôi rõ ràng bảo anh ấy đừng đi, nhưng anh ấy lại cố ý vẫn giữ quyết định của mình.'),
  ('齐心协力', '只有齐心协力，我们才能克服困难，实现目标。', 'Zhǐyǒu qíxīn xiélì, wǒmen cáinéng kèfú kùnnán, shíxiàn mùbiāo.', 'Chỉ khi đồng tâm hiệp lực, chúng ta mới có thể vượt qua khó khăn và đạt được mục tiêu.'),
  ('齐全', '这家超市的商品种类齐全，什么都可以买到。', 'Zhè jiā chāoshì de shāngpǐn zhǒnglèi qíquán, shénme dōu kěyǐ mǎidào.', 'Siêu thị này có đầy đủ các loại hàng hóa, cái gì cũng có thể mua được.'),
  ('驱逐', '政府决定驱逐所有非法居留的外国人。', 'Zhèngfǔ juédìng qūzhú suǒyǒu fēifǎ jūliú de wàiguó rén.', 'Chính phủ quyết định trục xuất tất cả người nước ngoài ở lại bất hợp pháp.'),
  ('锲而不舍', '他在学习上锲而不舍，最终取得了优异的成绩。', 'Tā zài xuéxí shàng qiè ér bù shě, zuìzhōng qǔdé le yōuyì de chéngjì.', 'Anh ấy kiên trì không bỏ cuộc trong học tập, cuối cùng đạt được kết quả xuất sắc.'),
  ('钦佩', '我非常钦佩她面对困难时的坚强和勇气。', 'Wǒ fēicháng qīnpèi tā miàn duì kùnnán shí de jiānqiáng hé yǒngqì.', 'Tôi rất khâm phục sự mạnh mẽ và dũng cảm của cô ấy khi đối mặt với khó khăn.'),
  ('迄今为止', '这部电影迄今为止取得了巨大的票房成功。', 'Zhè bù diànyǐng qìjīn wéizhǐ qǔdéle jùdà de piàofáng chénggōng.', 'Bộ phim này đến nay đã đạt được thành công phòng vé lớn.'),
  ('迁徙', '候鸟每年都会进行长距离的迁徙以避寒。', 'Hòuniǎo měi nián dōu huì jìnxíng cháng jùlí de qiānxǐ yǐ bì hán.', 'Chim di cư mỗi năm đều thực hiện di chuyển đường dài để tránh rét.'),
  ('迁就', '他总是迁就别人的意见，导致自己不开心。', 'Tā zǒng shì qiānjiù biérén de yìjiàn, dǎozhì zìjǐ bù kāixīn.', 'Anh ấy luôn chiều theo ý kiến người khác, dẫn đến bản thân không vui.'),
  ('趣味', '她对古典音乐有浓厚的趣味，经常去听演奏会。', 'Tā duì gǔdiǎn yīnyuè yǒu nónghòu de qùwèi, jīngcháng qù tīng yǎnzòuhuì.', 'Cô ấy có hứng thú mạnh với nhạc cổ điển, thường xuyên đi nghe hòa nhạc.'),
  ('起草', '这份合同由律师负责起草并与客户沟通。', 'Zhè fèn hétóng yóu lǜshī fùzé qǐcǎo bìng yǔ kèhù gōutōng.', 'Hợp đồng này do luật sư chịu trách nhiệm viết bản thảo và trao đổi với khách hàng.'),
  ('起码', '完成这个任务，起码需要三天的时间准备。', 'Wánchéng zhège rènwu, qǐmǎ xūyào sān tiān de shíjiān zhǔnbèi.', 'Để hoàn thành nhiệm vụ này, chí ít cần ba ngày để chuẩn bị.'),
  ('起源', '汉字的起源可以追溯到几千年前的甲骨文。', 'Hànzì de qǐyuán kěyǐ zhuīsù dào jǐ qiān nián qián de jiǎgǔwén.', 'Nguồn gốc của chữ Hán có thể truy trở về hàng nghìn năm trước với chữ giáp cốt.'),
  ('起哄', '他在老师讲课时突然大叫，引起同学们的起哄。', 'Tā zài lǎoshī jiǎngkè shí tūrán dà jiào, yǐnqǐ tóngxuémen de qǐhòng.', 'Anh ta khi giáo viên đang giảng bài thì bất ngờ la lớn, khiến các bạn học sinh đùa giỡn ầm ĩ.'),
  ('起初', '起初我不理解他的决定，后来慢慢明白了他的苦衷。', 'Qǐchū wǒ bù lǐjiě tā de juédìng, hòulái màn man míngbáile tā de kǔzhōng.', 'Lúc đầu tôi không hiểu quyết định của anh ấy, sau đó dần dần hiểu được khó khăn của anh ta.'),
  ('起伏', '海面的起伏让船只显得格外摇摆不定。', 'Hǎimiàn de qǐfú ràng chuánzhī xiǎnde géwài yáobǎi bù dìng.', 'Sóng biển gợn sóng khiến con tàu lắc lư không ngừng.'),
  ('谴责', '国际社会纷纷谴责这种违反人权的行为。', 'Guójì shèhuì fēnfēn qiǎnzé zhè zhǒng wéifǎn rénquán de xíngwéi.', 'Cộng đồng quốc tế đồng loạt lên án hành vi vi phạm nhân quyền này.'),
  ('谦逊', '他虽然成绩优异，但总是表现得很谦逊。', 'Tā suīrán chéngjī yōuyì, dàn zǒng shì biǎoxiàn de hěn qiānxùn.', 'Mặc dù thành tích xuất sắc, anh ấy luôn thể hiện rất khiêm tốn.'),
  ('请示', '项目进展出现问题，经理马上向上级请示处理方案。', 'Xiàngmù jìnzhǎn chūxiàn wèntí, jīnglǐ mǎshàng xiàng shàngjí qǐngshì chǔlǐ fāng''àn.', 'Dự án gặp vấn đề, quản lý lập tức xin ý kiến cấp trên về phương án xử lý.'),
  ('请柬', '他们寄出了婚礼的请柬给所有亲朋好友。', 'Tāmen jì chūle hūnlǐ de qǐngjiǎn gěi suǒyǒu qīnpéng hǎoyǒu.', 'Họ đã gửi thiệp mời đám cưới cho tất cả bạn bè thân thiết.'),
  ('请教', '遇到不会的问题时，不要害怕向老师请教。', 'Yù dào bù huì de wèntí shí, bú yào hàipà xiàng lǎoshī qǐngjiào.', 'Khi gặp vấn đề không biết, đừng ngại hỏi thầy cô thỉnh giáo.'),
  ('请帖', '他们设计了精美的请帖邀请宾客参加晚宴。', 'Tāmen shèjìle jīngměi de qǐngtiě yāoqǐng bīnkè cānjiā wǎnyàn.', 'Họ thiết kế thiệp mời tinh tế để mời khách tham dự tiệc tối.'),
  ('翘', '小猫用爪子翘起了一片落叶，显得很可爱。', 'Xiǎo māo yòng zhuǎzi qiào qǐle yī piàn luò yè, xiǎnde hěn kě''ài.', 'Chú mèo con dùng móng tay vểnh một chiếc lá rụng, trông rất dễ thương.'),
  ('群众', '领导亲切地向群众发表了讲话，赢得了掌声。', 'Lǐngdǎo qīnqiè de xiàng qúnzhòng fābiǎole jiǎnghuà, yíngdéle zhǎngshēng.', 'Lãnh đạo thân mật phát biểu với quần chúng, giành được tràng pháo tay.'),
  ('缺陷', '这个产品存在设计上的缺陷，需要及时改进。', 'Zhège chǎnpǐn cúnzài shèjì shàng de quēxiàn, xūyào jíshí gǎijìn.', 'Sản phẩm này tồn tại khiếm khuyết về thiết kế, cần được cải tiến kịp thời.'),
  ('缺席', '因为身体不适，他连续三次缺席重要会议。', 'Yīnwèi shēntǐ bùshì, tā liánxù sān cì quēxí zhòngyào huìyì.', 'Vì sức khỏe không tốt, anh ấy liên tiếp vắng mặt ba cuộc họp quan trọng.'),
  ('缺口', '这堵墙上的缺口让冷风吹了进来，房间变得很冷。', 'Zhè dǔ qiáng shàng de quēkǒu ràng lěngfēng chuī le jìnlái, fángjiān biàn dé hěn lěng.', 'Chỗ hổng trên bức tường này khiến gió lạnh thổi vào, phòng trở nên rất lạnh.'),
  ('签署', '所有参与人员在合同上签署了自己的名字以示同意。', 'Suǒyǒu cānyù rényuán zài hétong shàng qiānshǔ le zìjǐ de míngzì yǐ shì tóngyì.', 'Tất cả những người tham gia đã ký tên của mình trên hợp đồng để biểu thị sự đồng ý.'),
  ('窍门', '他掌握了学习汉语的窍门，所以进步很快。', 'Tā zhǎngwò le xuéxí hànyǔ de qiàomén, suǒyǐ jìnbù hěn kuài.', 'Anh ấy đã nắm được bí quyết học tiếng Trung, nên tiến bộ rất nhanh.'),
  ('确立', '公司已确立新的管理制度以提高工作效率。', 'Gōngsī yǐ quèlì xīn de guǎnlǐ zhìdù yǐ tígāo gōngzuò xiàolǜ.', 'Công ty đã thiết lập hệ thống quản lý mới nhằm nâng cao hiệu quả công việc.'),
  ('确切', '请提供确切的时间和地点，以便我们安排会议。', 'Qǐng tígōng quèqiè de shíjiān hé dìdiǎn, yǐbiàn wǒmen ānpái huìyì.', 'Xin cung cấp thời gian và địa điểm chính xác để chúng tôi sắp xếp cuộc họp.'),
  ('确信', '我确信他会按时完成这个重要的任务。', 'Wǒ quèxìn tā huì ànshí wánchéng zhège zhòngyào de rènwù.', 'Tôi tin chắc rằng anh ta sẽ hoàn thành nhiệm vụ quan trọng này đúng hạn.'),
  ('确保', '为了确保安全，大家必须遵守所有规定。', 'Wèi le quèbǎo ānquán, dàjiā bìxū zūnshǒu suǒyǒu guīdìng.', 'Để đảm bảo an toàn, mọi người phải tuân thủ tất cả các quy định.'),
  ('瘸', '这个老人因为腿部受伤，走路时有些瘸。', 'Zhège lǎorén yīnwèi tuǐbù shòushāng, zǒulù shí yǒuxiē qué.', 'Ông lão này vì chấn thương chân nên khi đi lại hơi què.'),
  ('犬', '这种犬种非常适合家庭养护，性格温顺。', 'Zhè zhǒng quǎn zhǒng fēicháng shìhé jiātíng yǎnghù, xìnggé wēnshùn.', 'Loại chó này rất thích hợp để nuôi trong gia đình, tính cách hiền lành.'),
  ('牵扯', '这件事牵扯到很多部门，处理起来比较复杂。', 'Zhè jiàn shì qiānchě dào hěn duō bùmén, chǔlǐ qǐlái bǐjiào fùzá.', 'Việc này liên lụy đến nhiều phòng ban, xử lý khá phức tạp.'),
  ('牵制', '敌军被我方部队成功牵制，无法继续前进。', 'Dí jūn bèi wǒ fāng bùduì chénggōng qiānzhì, wúfǎ jìxù qiánjìn.', 'Quân địch bị đội của phía ta giữ chân thành công, không thể tiếp tục tiến lên.'),
  ('牵', '她牵着孩子的手，小心翼翼地过马路。', 'Tā qiān zhe háizi de shǒu, xiǎoxīn yìyì de guò mǎlù.', 'Cô ấy nắm tay đứa trẻ, cẩn thận băng qua đường.'),
  ('潜移默化', '良好的教育环境对学生的品德潜移默化地影响很大。', 'Liánghǎo de jiàoyù huánjìng duì xuéshēng de pǐndé qiányí mòhuà de yǐngxiǎng hěn dà.', 'Môi trường giáo dục tốt ảnh hưởng dần dần đến phẩm chất của học sinh.'),
  ('潜水', '他利用假期去海边潜水，体验海底世界的美丽。', 'Tā lìyòng jiàqī qù hǎibiān qiánshuǐ, tǐyàn hǎidǐ shìjiè de měilì.', 'Anh ấy tận dụng kỳ nghỉ để đi lặn biển, trải nghiệm vẻ đẹp dưới đáy biển.'),
  ('潜力', '这位年轻运动员展示出了巨大的潜力，未来可期。', 'Zhè wèi niánqīng yùndòngyuán zhǎnshì chū le jùdà de qiánlì, wèilái kěqī.', 'Vận động viên trẻ này thể hiện tiềm lực to lớn, tương lai đầy hứa hẹn.'),
  ('渠道', '公司开辟了新的销售渠道，以拓展市场份额。', 'Gōngsī kāipì le xīn de xiāoshòu qúdào, yǐ tuòzhǎn shìchǎng fèn''é.', 'Công ty mở rộng kênh bán hàng mới để mở rộng thị phần.'),
  ('清除', '工人们正在清除建筑工地上的垃圾和杂物。', 'Gōngrén men zhèngzài qīngchú jiànzhù gōngdì shàng de lājī hé záwù.', 'Công nhân đang quét sạch rác và đồ vật lộn xộn trên công trường xây dựng.'),
  ('清醒', '喝完咖啡后，他终于清醒过来，专心工作。', 'Hē wán kāfēi hòu, tā zhōngyú qīngxǐng guòlái, zhuānxīn gōngzuò.', 'Sau khi uống cà phê, anh ấy cuối cùng tỉnh táo trở lại, tập trung làm việc.'),
  ('清真', '这家餐厅专门提供清真食品，符合穆斯林的饮食习惯。', 'Zhè jiā cāntīng zhuānmén tígōng qīngzhēn shípǐn, fúhé mùsīlín de yǐnshí xíguàn.', 'Nhà hàng này chuyên cung cấp đồ ăn halal, phù hợp với thói quen ăn uống của người Hồi giáo.'),
  ('清理', '他们花了一整天时间清理仓库，整理存货。', 'Tāmen huā le yī zhěng tiān shíjiān qīnglǐ cāngkù, zhěnglǐ cún huò.', 'Họ đã dành cả ngày để dọn dẹp kho hàng và sắp xếp hàng tồn kho.'),
  ('清澈', '湖水清澈见底，吸引了许多游客来观赏。', 'Hú shuǐ qīngchè jiàn dǐ, xīyǐn le xǔduō yóukè lái guānshǎng.', 'Nước hồ trong veo tận đáy, thu hút nhiều du khách đến tham quan.'),
  ('清洁', '我们应该保持房间清洁，避免细菌滋生。', 'Wǒmen yīnggāi bǎochí fángjiān qīngjié, bìmiǎn xìjūn zīshēng.', 'Chúng ta nên giữ phòng sạch sẽ, tránh vi khuẩn sinh sôi.'),
  ('清晰', '老师讲解的问题非常清晰，学生们都能理解。', 'Lǎoshī jiǎngjiě de wèntí fēicháng qīngxī, xuéshēngmen dōu néng lǐjiě.', 'Vấn đề giáo viên giải thích rất rõ ràng, học sinh đều có thể hiểu.'),
  ('清晨', '清晨的空气很新鲜，适合晨跑锻炼身体。', 'Qīngchén de kōngqì hěn xīnxiān, shìhé chén pǎo duànliàn shēntǐ.', 'Không khí sáng sớm rất trong lành, thích hợp để chạy bộ buổi sáng tập thể dục.'),
  ('洽谈', '双方代表在会议室认真洽谈合作细节。', 'Shuāngfāng dàibiǎo zài huìyì shì rènzhēn qiàtán hézuò xìjié.', 'Đại diện hai bên đang thương thảo chi tiết hợp tác trong phòng họp.'),
  ('气魄', '他的演讲充满气魄，鼓舞了在场的每个人。', 'Tā de yǎnjiǎng chōngmǎn qìpò, gǔwǔ le zài chǎng de měi gèrén.', 'Bài phát biểu của anh ấy đầy khí phách, cổ vũ tất cả mọi người có mặt.'),
  ('气质', '她天生气质优雅，给人留下深刻印象。', 'Tā tiānshēng qìzhì yōuyǎ, gěi rén liú xià shēnkè yìnxiàng.', 'Cô ấy có khí chất bẩm sinh thanh lịch, để lại ấn tượng sâu sắc cho người khác.'),
  ('气象', '气象专家预测明天将有大风和降雨。', 'Qìxiàng zhuānjiā yùcè míngtiān jiāng yǒu dà fēng hé jiàng yǔ.', 'Chuyên gia khí tượng dự báo ngày mai sẽ có gió lớn và mưa.'),
  ('气色', '她最近工作辛苦，但气色看起来还是很好。', 'Tā zuìjìn gōngzuò xīnku, dàn qìsè kàn qǐlái háishì hěn hǎo.', 'Cô ấy dạo này làm việc vất vả, nhưng khí sắc vẫn trông rất tốt.'),
  ('气概', '面对困难，他表现出非凡的气概和勇气。', 'Miànduì kùnnán, tā biǎoxiàn chū fēifán de qìgài hé yǒngqì.', 'Đối mặt với khó khăn, anh ấy thể hiện khí chất và sự dũng cảm phi thường.'),
  ('气味', '厨房里飘着诱人的饭菜气味，让人垂涎三尺。', 'Chúfáng lǐ piāozhe yòurén de fàncài qìwèi, ràng rén chuíxián sān chǐ.', 'Trong bếp lan tỏa mùi thức ăn hấp dẫn khiến người ta thèm thuồng.'),
  ('气压', '高原地区的气压较低，游客需适应环境变化。', 'Gāoyuán dìqū de qìyā jiào dī, yóukè xū shìyìng huánjìng biànhuà.', 'Áp suất khí quyển ở vùng cao nguyên thấp hơn, du khách cần thích nghi với thay đổi môi trường.'),
  ('气势', '比赛开始时，运动员们展现出强大的气势和决心。', 'Bǐsài kāishǐ shí, yùndòngyuánmen zhǎnxiàn chū qiángdà de qìshì hé juéxīn.', 'Khi trận đấu bắt đầu, các vận động viên thể hiện khí thế và quyết tâm mạnh mẽ.'),
  ('气功', '他每天坚持练习气功，以增强身体健康和精神状态。', 'Tā měitiān jiānchí liànxí qìgōng, yǐ zēngqiáng shēntǐ jiànkāng hé jīngshén zhuàngtài.', 'Anh ấy kiên trì luyện khí công mỗi ngày để tăng cường sức khỏe và tinh thần.'),
  ('歧视', '公司禁止任何形式的种族歧视，提倡平等对待。', 'Gōngsī jìnzhǐ rènhé xíngshì de zhǒngzú qíshì, tíchàng píngděng duìdài.', 'Công ty nghiêm cấm bất kỳ hình thức phân biệt chủng tộc nào, đề cao đối xử bình đẳng.'),
  ('欺骗', '网络诈骗利用虚假信息欺骗了许多用户。', 'Wǎngluò zhàpiàn lìyòng xūjiǎ xìnxī qīpiàn le xǔduō yònghù.', 'Lừa đảo mạng sử dụng thông tin giả mạo để lừa gạt nhiều người dùng.'),
  ('欺负', '学校严厉打击欺负同学的行为，保护学生权益。', 'Xuéxiào yánlì dǎjī qīfù tóngxué de xíngwéi, bǎohù xuéshēng quányì.', 'Trường học nghiêm khắc xử lý hành vi bắt nạt bạn học, bảo vệ quyền lợi học sinh.'),
  ('桥梁', '这座桥梁连接了两岸的交通，方便了人们出行。', 'Zhè zuò qiáoliáng liánjiē le liǎng àn de jiāotōng, fāngbiàn le rénmen chūxíng.', 'Cây cầu này nối liền giao thông hai bờ, thuận tiện cho mọi người đi lại.'),
  ('权衡', '在做决定时，他仔细权衡了利弊和各种因素。', 'Zài zuò juédìng shí, tā zǐxì quánhéng le lìbì hé gè zhǒng yīnsù.', 'Khi đưa ra quyết định, anh ấy cân nhắc kỹ lưỡng lợi hại và các yếu tố khác nhau.'),
  ('权威', '这本教材由教育权威专家编写，内容权威且准确。', 'Zhè běn jiàocái yóu jiàoyù quánwēi zhuānjiā biānxiě, nèiróng quánwēi qiě zhǔnquè.', 'Cuốn giáo trình này được các chuyên gia giáo dục có uy tín biên soạn, nội dung có quyền uy và chính xác.'),
  ('期限', '这个项目的完成期限定在今年十二月底。', 'Zhè ge xiàng mù de wán chéng qī xiàn dìng zài jīn nián shí èr yuè dǐ.', 'Kì hạn hoàn thành dự án này được định vào cuối tháng 12 năm nay.'),
  ('期望', '我对他的期望很高，希望他能取得好成绩。', 'Wǒ duì tā de qī wàng hěn gāo, xī wàng tā néng qǔ dé hǎo chéng jì.', 'Tôi có kỳ vọng rất lớn vào anh ấy, hy vọng anh ấy có thể đạt được thành tích tốt.'),
  ('曲折', '旅途经历了许多曲折，但最终我们还是到了目的地。', 'Lǚ tú jīng lì le xǔ duō qū zhé, dàn zuì zhōng wǒ men hái shì dào le mù dì dì.', 'Chuyến đi trải qua nhiều khúc khuỷu, nhưng cuối cùng chúng tôi vẫn đến được đích.'),
  ('曲子', '这首曲子旋律优美，令人陶醉。', 'Zhè shǒu qǔ zi xuán lǜ yōu měi, lìng rén táo zuì.', 'Bản nhạc này giai điệu du dương, khiến người ta say mê.'),
  ('晴朗', '今天的天气非常晴朗，适合户外运动。', 'Jīn tiān de tiān qì fēi cháng qíng lǎng, shì hé hù wài yùn dòng.', 'Thời tiết hôm nay rất trong xanh, thích hợp cho hoạt động ngoài trời.'),
  ('旗袍', '她穿着一件漂亮的旗袍参加晚会。', 'Tā chuān zhe yī jiàn piào liang de qí páo cān jiā wǎn huì.', 'Cô ấy mặc một chiếc áo sườn xám đẹp tham dự buổi tiệc tối.'),
  ('旗帜', '他们高举旗帜，表达对理想的追求。', 'Tā men gāo jǔ qí zhì, biǎo dá duì lǐ xiǎng de zhuī qiú.', 'Họ giương cao cờ quạt, thể hiện sự theo đuổi lý tưởng.'),
  ('掐', '孩子们玩耍时不小心被同伴掐了。', 'Hái zi men wán shuǎ shí bù xiǎo xīn bèi tóng bàn qiā le.', 'Lúc chơi đùa, trẻ con không cẩn thận bị bạn bè véo.'),
  ('拳头', '他握紧拳头，准备迎接挑战。', 'Tā wò jǐn quán tóu, zhǔn bèi yíng jiē tiǎo zhàn.', 'Anh ấy nắm chặt nắm đấm, chuẩn bị đón nhận thử thách.'),
  ('抢救', '医生们正在紧急抢救受伤的患者。', 'Yī shēng men zhèng zài jǐn jí qiǎng jiù shòu shāng de huàn zhě.', 'Các bác sĩ đang cấp cứu gấp bệnh nhân bị thương.'),
  ('抢劫', '那晚街上发生了一起抢劫事件。', 'Nà wǎn jiē shàng fā shēng le yī qǐ qiǎng jié shì jiàn.', 'Tối hôm đó xảy ra một vụ cướp trên đường phố.'),
  ('情节', '这部小说的情节跌宕起伏，十分吸引人。', 'Zhè bù xiǎo shuō de qíng jié diē dàng qǐ fú, shí fēn xī yǐn rén.', 'Tình tiết của cuốn tiểu thuyết này rất biến hóa, cực kỳ thu hút người đọc.'),
  ('情理', '你的要求合乎情理，我会尽量满足。', 'Nǐ de yāo qiú hé hū qíng lǐ, wǒ huì jǐn liàng mǎn zú.', 'Yêu cầu của bạn hợp lý, tôi sẽ cố gắng đáp ứng.'),
  ('情报', '军队收集了敌方的重要情报。', 'Jūn duì shōu jí le dí fāng de zhòng yào qíng bào.', 'Quân đội thu thập được những thông tin tình báo quan trọng của địch.'),
  ('情形', '由于突发的情形，活动被迫延期。', 'Yóu yú tū fā de qíng xíng, huó dòng bèi pò yán qī.', 'Do tình hình phát sinh đột ngột, sự kiện bị buộc phải hoãn lại.'),
  ('恰当', '请用恰当的词语表达你的意思。', 'Qǐng yòng qià dàng de cí yǔ biǎo dá nǐ de yì si.', 'Hãy dùng từ ngữ phù hợp để diễn đạt ý của bạn.'),
  ('恰巧', '我恰巧遇到了多年未见的老朋友。', 'Wǒ qià qiǎo yù dào le duō nián wèi jiàn de lǎo péng you.', 'Tôi vừa khéo gặp được người bạn cũ lâu năm không gặp.'),
  ('恰到好处', '她的表演恰到好处，赢得了满堂喝彩。', 'Tā de biǎo yǎn qià dào hǎo chù, yíng dé le mǎn táng hè cǎi.', 'Màn trình diễn của cô ấy vừa đúng lúc, nhận được tràng pháo tay liên tiếp.'),
  ('强迫', '没人有权强迫你做不愿意的事情。', 'Méi rén yǒu quán qiǎng pò nǐ zuò bù yuàn yì de shì qing.', 'Không ai có quyền ép buộc bạn làm những việc bạn không muốn.'),
  ('强制', '政府对违法行为实行强制措施。', 'Zhèng fǔ duì wéi fǎ xíng wéi shí xíng qiáng zhì cuò shī.', 'Chính phủ thực hiện các biện pháp cưỡng chế đối với hành vi vi phạm pháp luật.'),
  ('岂有此理', '他居然撒谎，岂有此理，令人难以接受。', 'Tā jūrán sāhuǎng, qǐ yǒu cǐ lǐ, lìngrén nányǐ jiēshòu.', 'Anh ấy lại nói dối, lẽ nào lại như vậy, khiến người ta khó chấp nhận.'),
  ('屈服', '经过激烈的抵抗，他们最终不得不屈服。', 'Jīngguò jīliè de dǐkàng, tāmen zuìzhōng bùdébù qūfú.', 'Sau một cuộc kháng cự quyết liệt, cuối cùng họ đành phải khuất phục.'),
  ('奇妙', '大自然的变化真是奇妙，让人充满惊喜。', 'Dà zìrán de biànhuà zhēn shì qímiào, ràng rén chōngmǎn jīngxǐ.', 'Sự thay đổi của thiên nhiên thật kỳ diệu, làm người ta đầy bất ngờ.'),
  ('圈套', '他不小心掉进了对方精心设计的圈套。', 'Tā bù xiǎoxīn diàojìnle duìfāng jīngxīn shèjì de quāntào.', 'Anh ấy bất cẩn đã rơi vào cái bẫy do đối phương tinh tế tạo ra.'),
  ('器材', '运动场上的健身器材种类繁多，满足各种需求。', 'Yùndòng chǎng shàng de jiànshēn qìcái zhǒnglèi fánduō, mǎnzú gèzhǒng xūqiú.', 'Các loại dụng cụ thể dục trên sân vận động rất đa dạng, đáp ứng mọi nhu cầu.'),
  ('器官', '人体的每个器官都有其独特的重要功能。', 'Réntǐ de měi gè qìguān dōu yǒu qí dútè de zhòngyào gōngnéng.', 'Mỗi cơ quan trong cơ thể người đều có chức năng quan trọng riêng biệt.'),
  ('启蒙', '父母在孩子成长过程中起到了启蒙的重要作用。', 'Fùmǔ zài háizi chéngzhǎng guòchéng zhōng qǐdàole qǐméng de zhòngyào zuòyòng.', 'Cha mẹ đóng vai trò quan trọng trong việc vỡ lòng của trẻ.'),
  ('启程', '我们计划明天早上启程前往目的地。', 'Wǒmen jìhuà míngtiān zǎoshang qǐchéng qiánwǎng mùdì dì.', 'Chúng tôi dự định sáng mai khởi hành đến địa điểm.'),
  ('启示', '这本书给了我很多人生的启示和思考。', 'Zhè běn shū gěile wǒ hěn duō rénshēng de qǐshì hé sīkǎo.', 'Cuốn sách này đã mang đến cho tôi nhiều gợi mở và suy nghĩ về cuộc đời.'),
  ('启事', '公告栏上贴着一张寻找走失宠物的启事。', 'Gōnggàolán shàng tiēzhe yī zhāng xúnzhǎo zǒushī chǒngwù de qǐshì.', 'Trên bảng thông báo có dán thông báo tìm thú cưng bị thất lạc.'),
  ('取缔', '政府决定取缔所有非法经营的摊点。', 'Zhèngfǔ juédìng qǔdì suǒyǒu fēifǎ jīngyíng de tāndiǎn.', 'Chính phủ quyết định cấm chỉ tất cả các sạp kinh doanh bất hợp pháp.'),
  ('千方百计', '为了完成任务，他千方百计地寻找解决方案。', 'Wèile wánchéng rènwù, tā qiānfāngbǎijì de xúnzhǎo jiějué fāng''àn.', 'Để hoàn thành nhiệm vụ, anh ấy trăm phương nghìn kế tìm cách giải quyết.'),
  ('区域', '这个区域禁止汽车通行，以保护环境。', 'Zhège qūyù jìnzhǐ qìchē tōngxíng, yǐ bǎohù huánjìng.', 'Khu vực này cấm xe ô tô đi lại để bảo vệ môi trường.'),
  ('区分', '学生们需要学会区分不同类型的文学作品。', 'Xuéshēngmen xūyào xuéhui qūfēn bùtóng lèixíng de wénxué zuòpǐn.', 'Học sinh cần học cách phân biệt các loại tác phẩm văn học khác nhau.'),
  ('勤劳', '勤劳的农民每天早出晚归，种植庄稼。', 'Qínláo de nóngmín měitiān zǎo chū wǎn guī, zhòngzhí zhuāngjià.', 'Người nông dân chịu thương chịu khó đi làm đồng từ sáng sớm tới tối muộn.'),
  ('勤俭', '勤俭节约是中华民族的传统美德。', 'Qínjiǎn jiéyuē shì Zhōnghuá mínzú de chuántǒng měidé.', 'Cần cù tiết kiệm là truyền thống đạo đức tốt đẹp của dân tộc Trung Hoa.'),
  ('前景', '这项新技术的发展前景非常广阔。', 'Zhè xiàng xīn jìshù de fāzhǎn qiánjǐng fēicháng guǎngkuò.', 'Triển vọng phát triển của công nghệ mới này rất rộng lớn.'),
  ('前提', '合作的前提是双方必须互相信任和支持。', 'Hézuò de qiántí shì shuāngfāng bìxū hùxiāng xìnrèn hé zhīchí.', 'Tiền đề của sự hợp tác là hai bên phải tin tưởng và hỗ trợ lẫn nhau.'),
  ('切实', '我们需要采取切实的措施解决环境污染问题。', 'Wǒmen xūyào cǎiqǔ qièshí de cuòshī jiějué huánjìng wūrǎn wèntí.', 'Chúng ta cần thực hiện các biện pháp thiết thực để giải quyết ô nhiễm môi trường.'),
  ('凄凉', '秋天的黄昏显得格外凄凉和孤独。', 'Qiūtiān de huánghūn xiǎndé géwài qīliáng hé gūdú.', 'Hoàng hôn mùa thu trông thật lạnh lẽo và cô độc.'),
  ('全局', '我们必须从全局的角度来考虑这个问题。', 'Wǒmen bìxū cóng quánjú de jiǎodù lái kǎolǜ zhège wèntí.', 'Chúng ta phải xem xét vấn đề này từ góc độ toàn cục.'),
  ('全力以赴', '运动员们在比赛中全力以赴，争取冠军。', 'Yùndòngyuánmen zài bǐsài zhōng quánlì yǐfù, zhēngqǔ guànjūn.', 'Các vận động viên dốc hết sức lực trong trận đấu để giành chức vô địch.'),
  ('倾斜', '大楼因为地基不稳而开始倾斜。', 'Dàlóu yīnwèi dìjī bù wěn ér kāishǐ qīngxié.', 'Tòa nhà bắt đầu nghiêng vì móng không vững.'),
  ('倾听', '老师耐心地倾听学生们的意见。', 'Lǎoshī nàixīn de qīngtīng xuéshengmen de yìjiàn.', 'Giáo viên kiên nhẫn lắng nghe ý kiến của học sinh.'),
  ('倾向', '专家们倾向于支持这个新的解决方案。', 'Zhuānjiāmen qīngxiàng yú zhīchí zhège xīn de jiějuéfāng''àn.', 'Các chuyên gia có xu hướng ủng hộ phương án giải quyết mới này.'),
  ('侵略', '历史上许多国家曾遭受过外国的侵略。', 'Lìshǐ shàng xǔduō guójiā céng zāoshòuguò wàiguó de qīnlüè.', 'Nhiều quốc gia trong lịch sử từng bị xâm lược bởi nước ngoài.'),
  ('侵犯', '未经允许，任何人不得侵犯他人的隐私。', 'Wèijīng yǔnxǔ, rènhé rén bùdé qīnfàn tārén de yǐnsī.', 'Chưa được phép, bất cứ ai cũng không được xâm phạm quyền riêng tư của người khác.'),
  ('企图', '他企图通过作弊来获得高分，但最终失败了。', 'Tā qǐtú tōngguò zuòbì lái huòdé gāofēn, dàn zuìzhōng shībàile.', 'Anh ta mưu đồ gian lận để đạt điểm cao, nhưng cuối cùng thất bại.'),
  ('亲热', '他们关系亲热，经常一起出去玩。', 'Tāmen guānxi qīnrè, jīngcháng yīqǐ chūqù wán.', 'Mối quan hệ của họ rất thân mật, thường đi chơi cùng nhau.'),
  ('亲密', '这些年来，他们保持着非常亲密的友谊。', 'Zhèxiē nián lái, tāmen bǎochí zhe fēicháng qīnmì de yǒuyì.', 'Những năm qua, họ duy trì tình bạn rất thân thiết.'),
  ('乞丐', '城市的街头常能看到乞丐向路人乞讨。', 'Chéngshì de jiētóu cháng néng kàn dào qǐgài xiàng lùrén qǐtǎo.', 'Trên phố thành phố thường thấy người ăn mày xin tiền người đi đường.'),
  ('丘陵', '这片丘陵地带风景秀丽，适合旅游。', 'Zhè piàn qiūlíng dìdài fēngjǐng xiùlì, shìhé lǚyóu.', 'Khu vực đồi núi này phong cảnh tươi đẹp, thích hợp để du lịch.'),
  ('饶恕', '她选择饶恕过去的错误，重新开始生活。', 'Tā xuǎnzé ráoshù guòqù de cuòwù, chóngxīn kāishǐ shēnghuó.', 'Cô ấy chọn tha thứ cho những sai lầm trong quá khứ và bắt đầu lại cuộc sống.'),
  ('让步', '双方经过长时间谈判，终于达成让步协议。', 'Shuāngfāng jīngguò cháng shíjiān tánpàn, zhōngyú dáchéng ràngbù xiéyì.', 'Hai bên sau cuộc đàm phán lâu dài cuối cùng đã đạt được thỏa thuận nhượng bộ.'),
  ('认定', '警方认定嫌疑人就是这起案件的主犯。', 'Jǐngfāng rèndìng xiányí rén jiùshì zhè qǐ ànjiàn de zhǔfàn.', 'Cảnh sát nhận định nghi phạm chính là thủ phạm của vụ án này.'),
  ('认可', '公司领导认可了这项创新方案的价值。', 'Gōngsī lǐngdǎo rènkěle zhè xiàng chuàngxīn fāng''àn de jiàzhí.', 'Lãnh đạo công ty đã công nhận giá trị của kế hoạch đổi mới này.'),
  ('融洽', '团队成员之间的关系非常融洽，工作效率高。', 'Tuánduì chéngyuán zhījiān de guānxì fēicháng róngqià, gōngzuò xiàolǜ gāo.', 'Mối quan hệ giữa các thành viên trong nhóm rất hòa hợp, hiệu quả công việc cao.'),
  ('融化', '春天来了，雪开始渐渐融化。', 'Chūntiān láile, xuě kāishǐ jiànjiàn rónghuà.', 'Mùa xuân đã đến, tuyết bắt đầu tan chảy dần.'),
  ('荣誉', '获得这项国际奖项是他的莫大荣誉。', 'Huòdé zhè xiàng guójì jiǎngxiàng shì tā de mòdà róngyù.', 'Giành được giải thưởng quốc tế này là niềm vinh dự to lớn của anh ấy.'),
  ('荣幸', '能够参加这次会议，我感到非常荣幸。', 'Nénggòu cānjiā zhè cì huìyì, wǒ gǎndào fēicháng róngxìng.', 'Tôi cảm thấy rất vinh hạnh khi được tham dự cuộc họp này.'),
  ('若干', '他手里拿着若干文件，准备开始会议。', 'Tā shǒu lǐ názhe ruògān wénjiàn, zhǔnbèi kāishǐ huìyì.', 'Anh ấy đang cầm một vài tài liệu trên tay, chuẩn bị bắt đầu cuộc họp.'),
  ('热门', '这部电影最近非常热门，吸引了大量观众。', 'Zhè bù diànyǐng zuìjìn fēicháng rèmén, xīyǐn le dàliàng guānzhòng.', 'Bộ phim này gần đây rất sốt, thu hút được rất nhiều khán giả.'),
  ('热泪盈眶', '听到儿子的成功消息，母亲热泪盈眶，感动不已。', 'Tīngdào érzi de chénggōng xiāoxi, mǔqīn rè lèi yíng kuàng, gǎndòng bù yǐ.', 'Nghe tin con trai thành công, người mẹ nước mắt lưng tròng, rất cảm động.'),
  ('溶解', '盐在水中迅速溶解，形成咸味的溶液。', 'Yán zài shuǐ zhōng xùnsù róngjiě, xíngchéng xiánwèi de róngyè.', 'Muối nhanh chóng hòa tan trong nước, tạo thành dung dịch mặn.'),
  ('柔和', '她的声音很柔和，让人感到非常舒服。', 'Tā de shēngyīn hěn róuhé, ràng rén gǎndào fēicháng shūfú.', 'Giọng của cô ấy rất dịu dàng, khiến người ta cảm thấy rất dễ chịu.'),
  ('染', '工厂废水排放不当，导致河流被严重染污染。', 'Gōngchǎng fèishuǐ páifàng bùdàng, dǎozhì héliú bèi yánzhòng rǎn wūrǎn.', 'Việc xả thải nước thải của nhà máy không đúng cách đã khiến dòng sông bị nghiêm trọng nhiễm bẩn.'),
  ('日益', '随着科技发展，人们的生活水平日益提高。', 'Suízhe kējì fāzhǎn, rénmen de shēnghuó shuǐpíng rìyì tígāo.', 'Cùng với sự phát triển của công nghệ, mức sống của con người ngày càng được nâng cao.'),
  ('日新月异', '这座城市的发展日新月异，变化令人惊叹。', 'Zhè zuò chéngshì de fāzhǎn rìxīn yuèyì, biànhuà lìng rén jīngtàn.', 'Sự phát triển của thành phố này biến chuyển từng ngày, khiến người ta ngạc nhiên.'),
  ('揉', '按摩师用力揉我的背部，缓解了肌肉疲劳。', 'Ànmó shī yònglì róu wǒ de bèibù, huǎnjiě le jīròu píláo.', 'Nhân viên massage đã dùng lực nhào lưng tôi, giảm bớt mệt mỏi cơ bắp.'),
  ('扰乱', '非法集会扰乱了正常的交通秩序。', 'Fēifǎ jíhuì rǎoluàn le zhèngcháng de jiāotōng zhìxù.', 'Cuộc tập hợp trái phép đã gây hỗn loạn trật tự giao thông bình thường.'),
  ('惹祸', '他不小心惹祸，错过了重要会议。', 'Tā bù xiǎoxīn rě huò, cuòguò le zhòngyào huìyì.', 'Anh ta không cẩn thận gây rước họa, bỏ lỡ cuộc họp quan trọng.'),
  ('忍耐', '面对困难，她展现出极强的忍耐力。', 'Miànduì kùnnán, tā zhǎnxiàn chū jí qiáng de rěnnài lì.', 'Đối mặt với khó khăn, cô ấy thể hiện sức chịu đựng rất mạnh mẽ.'),
  ('忍受', '他无法忍受连续几天的高强度工作。', 'Tā wúfǎ rěnshòu liánxù jǐ tiān de gāo qiángdù gōngzuò.', 'Anh ấy không thể nhẫn nhịn công việc cường độ cao liên tục vài ngày.'),
  ('弱点', '每个人都有自己的弱点，要学会克服。', 'Měi gèrén dōu yǒu zìjǐ de ruòdiǎn, yào xuéhuì kèfú.', 'Mỗi người đều có điểm yếu của bản thân, cần học cách khắc phục.'),
  ('容貌', '她因美丽的容貌被许多人称赞。', 'Tā yīn měilì de róngmào bèi xǔduō rén chēngzàn.', 'Cô ấy được nhiều người khen ngợi vì dung mạo xinh đẹp.'),
  ('容纳', '这个会议室可以容纳一百多人同时开会。', 'Zhège huìyìshì kěyǐ róngnà yìbǎi duō rén tóngshí kāihuì.', 'Phòng họp này có thể chứa hơn một trăm người cùng một lúc.'),
  ('容忍', '他选择容忍别人的错误，保持良好关系。', 'Tā xuǎnzé róngrěn biérén de cuòwù, bǎochí liánghǎo guānxì.', 'Anh ấy chọn tha thứ lỗi lầm của người khác để duy trì quan hệ tốt.'),
  ('容器', '请把食物放进密封容器里保存。', 'Qǐng bǎ shíwù fàng jìn mìfēng róngqì lǐ bǎocún.', 'Xin hãy cho thức ăn vào thùng chứa kín để bảo quản.'),
  ('嚷', '孩子们在操场上嚷嚷，玩得很开心。', 'Háizimen zài cāochǎng shàng rāngrāng, wán de hěn kāixīn.', 'Bọn trẻ đang gào lên ở sân chơi, chơi rất vui vẻ.'),
  ('儒家', '儒家思想强调仁爱和礼仪的重要性。', 'Rújiā sīxiǎng qiángdiào rén''ài hé lǐyí de zhòngyàoxìng.', 'Tư tưởng Nho gia nhấn mạnh tầm quan trọng của nhân ái và lễ nghi.'),
  ('任重道远', '这项工程任重道远，需要我们长期坚持才能完成。', 'Zhè xiàng gōngchéng rèn zhòng dào yuǎn, xūyào wǒmen chángqī jiānchí cáinéng wánchéng.', 'Dự án này gánh nặng đường xa, chúng ta cần kiên trì lâu dài mới hoàn thành được.'),
  ('任意', '请不要任意丢弃垃圾，保持环境整洁。', 'Qǐng bùyào rèn yì diūqì lājī, bǎochí huánjìng zhěngjié.', 'Xin đừng tự ý vứt rác, giữ gìn môi trường sạch sẽ.'),
  ('任性', '孩子任性地哭闹，父母也只能耐心劝导。', 'Háizi rèn xìng de kūnào, fùmǔ yě zhǐ néng nàixīn quàndǎo.', 'Đứa trẻ tùy hứng khóc nhè, cha mẹ chỉ có thể kiên nhẫn khuyên bảo.'),
  ('任命', '公司决定任命李经理为新的销售总监。', 'Gōngsī juédìng rènmìng Lǐ jīnglǐ wèi xīn de xiāoshòu zǒngjiān.', 'Công ty quyết định bổ nhiệm quản lý Lý làm giám đốc kinh doanh mới.'),
  ('仍旧', '尽管时光流逝，他的热情仍旧不减。', 'Jǐnguǎn shíguāng liúshì, tā de rèqíng réngjiù bù jiǎn.', 'Dù thời gian trôi qua, nhiệt huyết của anh ấy vẫn như xưa không giảm.'),
  ('仁慈', '这位医生以仁慈的态度对待每一位病人。', 'Zhè wèi yīshēng yǐ réncí de tàidù duìdài měi yī wèi bìngrén.', 'Vị bác sĩ này đối xử với từng bệnh nhân bằng thái độ nhân từ.'),
  ('人间', '佛教教导我们要关心人间的苦难。', 'Fójiào jiàodǎo wǒmen yào guānxīn rénjiān de kǔnàn.', 'Phật giáo dạy chúng ta phải quan tâm tới những khổ đau của nhân gian.'),
  ('人道', '灾区需要得到更多的人道援助和支持。', 'Zāiqū xūyào dédào gèng duō de réndào yuánzhù hé zhīchí.', 'Vùng bị thiên tai cần nhận được nhiều sự cứu trợ và hỗ trợ nhân đạo hơn.'),
  ('人质', '劫匪挟持多人作为人质，警方正在谈判。', 'Jiéfěi xiéchí duō rén zuòwéi rénzhì, jǐngfāng zhèngzài tánpàn.', 'Bọn cướp bắt giữ nhiều người làm con tin, cảnh sát đang đàm phán.'),
  ('人格', '诚信是建立良好人格的重要基础之一。', 'Chéngxìn shì jiànlì liánghǎo réngé de zhòngyào jīchǔ zhī yī.', 'Chính trực là một trong những nền tảng quan trọng để xây dựng nhân cách tốt.'),
  ('人性', '小说深入探讨了人性的复杂与矛盾。', 'Xiǎoshuō shēnrù tàntǎo le rénxìng de fùzá yǔ máodùn.', 'Tiểu thuyết đi sâu khám phá sự phức tạp và mâu thuẫn của nhân tính.'),
  ('人工', '这座桥梁采用了最新的人工智能技术建造。', 'Zhè zuò qiáoliáng cǎiyòng le zuìxīn de réngōng zhìnéng jìshù jiànzào.', 'Cây cầu này được xây dựng bằng công nghệ trí tuệ nhân tạo mới nhất.'),
  ('人家', '人家都说他是个勤奋努力的人。', 'Rénjiā dōu shuō tā shì gè qínfèn nǔlì de rén.', 'Người ta đều nói anh ấy là người chăm chỉ nỗ lực.'),
  ('人士', '这次会议邀请了多位经济领域的人士参加。', 'Zhè cì huìyì yāoqǐng le duō wèi jīngjì lǐngyù de rénshì cānjiā.', 'Cuộc họp lần này đã mời nhiều nhân sĩ trong lĩnh vực kinh tế tham gia.'),
  ('人为', '洪水的发生部分是由于人为破坏环境造成的。', 'Hóngshuǐ de fāshēng bùfèn shì yóuyú rénwéi pòhuài huánjìng zàochéng de.', 'Việc xảy ra lũ lụt phần nào là do con người phá hoại môi trường gây ra.'),
  ('骚扰', '她因为收到骚扰电话感到非常困扰。', 'Tā yīnwèi shōudào sāorǎo diànhuà gǎndào fēicháng kùnrǎo.', 'Cô ấy vì nhận được điện thoại quấy rối nên cảm thấy rất phiền muộn.'),
  ('首饰', '这款首饰设计精美，非常适合送礼。', 'Zhè kuǎn shǒushì shèjì jīngměi, fēicháng shìhé sòng lǐ.', 'Mẫu trang sức này thiết kế tinh xảo, rất thích hợp để làm quà tặng.'),
  ('首要', '完成这项任务是我们当前的首要目标。', 'Wánchéng zhè xiàng rènwù shì wǒmen dāngqián de shǒuyào mùbiāo.', 'Hoàn thành nhiệm vụ này là mục tiêu hàng đầu của chúng ta hiện tại.'),
  ('闪烁', '夜空中的星星不停地闪烁，十分美丽。', 'Yèkōng zhōng de xīngxing bùtíng de shǎnshuò, shífēn měilì.', 'Những vì sao trên bầu trời đêm nhấp nháy không ngừng, rất đẹp.'),
  ('释放', '警方在收集证据后决定释放这名嫌疑人。', 'Jǐngfāng zài shōují zhèngjù hòu juédìng shìfàng zhè míng xiányírén.', 'Cảnh sát sau khi thu thập chứng cứ đã quyết định phóng thích nghi phạm này.'),
  ('逝世', '那位著名作家已于去年逝世，令人深感惋惜。', 'Nà wèi zhùmíng zuòjiā yǐ yú qùnián shìshì, lìngrén shēn gǎn wǎnxī.', 'Nhà văn nổi tiếng đó đã tạ thế vào năm ngoái, khiến mọi người rất tiếc nuối.'),
  ('适宜', '这种植物只在气候适宜的地区才能正常生长。', 'Zhè zhǒng zhíwù zhǐ zài qìhòu shìyí de dìqū cáinéng zhèngcháng shēngzhǎng.', 'Loại cây này chỉ có thể phát triển bình thường ở khu vực có khí hậu thích hợp.'),
  ('试验', '科学家们计划下个月进行新药的临床试验。', 'Kēxuéjiāmen jìhuà xià gè yuè jìnxíng xīn yào de línchuáng shìyàn.', 'Các nhà khoa học dự định tiến hành thí nghiệm lâm sàng thuốc mới vào tháng tới.'),
  ('试图', '他试图通过加班来完成所有的工作任务。', 'Tā shìtú tōngguò jiābān lái wánchéng suǒyǒu de gōngzuò rènwù.', 'Anh ấy định thử hoàn thành tất cả nhiệm vụ công việc bằng cách làm thêm giờ.'),
  ('识别', '新技术能够快速识别不同类型的图片内容。', 'Xīn jìshù nénggòu kuàisù shíbié bùtóng lèixíng de túpiàn nèiróng.', 'Công nghệ mới có thể nhận biết nhanh chóng nội dung của các loại hình ảnh khác nhau.'),
  ('设置', '请按照说明书的步骤来设置无线网络连接。', 'Qǐng ànzhào shuōmíngshū de bùzhòu lái shèzhì wúxiàn wǎngluò liánjiē.', 'Vui lòng theo các bước trong hướng dẫn để lắp đặt kết nối mạng không dây.'),
  ('设立', '学校近日设立了一个新的国际交流中心。', 'Xuéxiào jìnrì shèlìle yīgè xīn de guójì jiāoliú zhōngxīn.', 'Trường học gần đây đã thiết lập một trung tâm giao lưu quốc tế mới.'),
  ('设想', '我们设想未来的生活会更加便利和智能化。', 'Wǒmen shèxiǎng wèilái de shēnghuó huì gèngjiā biànlì hé zhìnéng huà.', 'Chúng tôi tưởng tượng cuộc sống trong tương lai sẽ thuận tiện và thông minh hơn.'),
  ('视频', '他上传了一个介绍旅游景点的视频到社交平台。', 'Tā shàngchuánle yīgè jièshào lǚyóu jǐngdiǎn de shìpín dào shèjiāo píngtái.', 'Anh ấy đã tải lên một đoạn clip giới thiệu điểm du lịch lên nền tảng xã hội.'),
  ('视野', '高楼的顶层拥有开阔的视野和美丽的城市景观。', 'Gāolóu de dǐngcéng yǒngyǒu kāikuò de shìyě hé měilì de chéngshì jǐngguān.', 'Tầng cao nhất của tòa nhà có tầm nhìn rộng mở và cảnh thành phố đẹp.'),
  ('视线', '走廊拐角处安装了镜子以便扩大视线范围。', 'Zǒuláng guǎijiǎo chù ānzhuāngle jìngzi yǐbiàn kuòdà shìxiàn fànwéi.', 'Góc hành lang được lắp gương để mở rộng tầm mắt quan sát.'),
  ('视力', '长时间使用电子产品可能会影响青少年的视力。', 'Cháng shíjiān shǐyòng diànzǐ chǎnpǐn kěnéng huì yǐngxiǎng qīngshàonián de shìlì.', 'Sử dụng thiết bị điện tử lâu dài có thể ảnh hưởng tới thị lực của thanh thiếu niên.'),
  ('衰退', '随着年龄增长，人体的免疫功能逐渐衰退。', 'Suízhe niánlíng zēngzhǎng, réntǐ de miǎnyì gōngnéng zhújiàn shuāituì.', 'Cùng với việc tăng tuổi, chức năng miễn dịch của cơ thể dần thoái hóa.'),
  ('衰老', '保持健康的生活方式可以延缓身体的衰老过程。', 'Bǎochí jiànkāng de shēnghuó fāngshì kěyǐ yánhuǎn shēntǐ de shuāilǎo guòchéng.', 'Duy trì lối sống lành mạnh có thể làm chậm quá trình lão hóa của cơ thể.'),
  ('舒畅', '听着优美的音乐，她感到身心十分舒畅。', 'Tīngzhe yōuměi de yīnyuè, tā gǎndào shēnxīn shífēn shūchàng.', 'Nghe nhạc du dương, cô cảm thấy trong người rất khoan khoái.'),
  ('舌头', '吃辣椒时，我的舌头感觉非常辣和麻。', 'Chī làjiāo shí, wǒ de shétou gǎnjué fēicháng là hé má.', 'Khi ăn ớt, lưỡi tôi cảm thấy rất cay và tê.'),
  ('胜负', '比赛的胜负悬念一直保留到最后一分钟。', 'Bǐsài de shèngfù xuánniàn yīzhí bǎoliú dào zuìhòu yī fēnzhōng.', 'Thắng thua của trận đấu luôn được giữ đến phút cuối cùng.'),
  ('耍', '孩子们喜欢在公园里耍各种玩具和游戏。', 'Háizimen xǐhuān zài gōngyuán lǐ shuǎ gè zhǒng wánjù hé yóuxì.', 'Bọn trẻ thích chơi đủ loại đồ chơi và trò chơi trong công viên.'),
  ('绅士', '他总是彬彬有礼，举止像个真正的绅士。', 'Tā zǒng shì bīnbīn yǒu lǐ, jǔzhǐ xiàng gè zhēnzhèng de shēnshì.', 'Anh ấy luôn lịch thiệp, cư xử như một quý ông đích thực.'),
  ('筛选', '招聘过程中，公司会对简历进行严格的筛选。', 'Zhāopìn guòchéng zhōng, gōngsī huì duì jiǎnlì jìnxíng yángé de shāixuǎn.', 'Trong quá trình tuyển dụng, công ty sẽ sàng lọc hồ sơ rất nghiêm ngặt.'),
  ('竖', '那棵大树直直地竖立在河边，非常壮观。', 'Nà kē dà shù zhí zhí de shù lì zài hé biān, fēi cháng zhuàng guān.', 'Cây đại thụ đó mọc thẳng đứng bên bờ sông, rất hùng vĩ.'),
  ('私自', '他私自进入了公司机密资料库，行为非常不当。', 'Tā sī zì jìn rù le gōng sī jī mì zī liào kù, xíng wéi fēi cháng bù dàng.', 'Anh ta lén lút vào kho dữ liệu bí mật của công ty, hành vi rất không đúng.'),
  ('神经', '他的神经紧张，一直无法平静下来。', 'Tā de shén jīng jǐn zhāng, yī zhí wú fǎ píng jìng xià lái.', 'Thần kinh của anh ấy căng thẳng, không thể bình tĩnh lại.'),
  ('神气', '他赢得比赛后，神气十足地走出赛场。', 'Tā yíng dé bǐ sài hòu, shén qì shí zú de zǒu chū sài chǎng.', 'Anh ấy sau khi thắng trận, bước ra sân với thần sắc đầy tự tin.'),
  ('神态', '她听到这个消息时，神态非常激动且难以掩饰。', 'Tā tīng dào zhè ge xiāo xi shí, shén tài fēi cháng jī dòng qiě nán yǐ yǎn shì.', 'Cô ấy khi nghe tin này, thần thái rất xúc động và khó che giấu.'),
  ('神奇', '这本书讲述了一个神奇的魔法世界，吸引了很多读者。', 'Zhè běn shū jiǎng shù le yī gè shén qí de mó fǎ shì jiè, xī yǐn le hěn duō dú zhě.', 'Cuốn sách này kể về một thế giới phép thuật thần kỳ, thu hút nhiều độc giả.'),
  ('神圣', '每个人都应该尊重生命的神圣，不得随意伤害。', 'Měi gè rén dōu yīng gāi zūn zhòng shēng mìng de shén shèng, bù dé suí yì shāng hài.', 'Mỗi người đều nên tôn trọng sự thần thánh của sự sống, không được tùy tiện làm tổn thương.'),
  ('神仙', '传说中，山上住着神仙，能赐予人们幸福和长寿。', 'Chuán shuō zhōng, shān shàng zhù zhe shén xiān, néng cì yǔ rén men xìng fú hé cháng shòu.', 'Theo truyền thuyết, trên núi có thần tiên sống, có thể ban phúc và trường thọ cho con người.'),
  ('社区', '他积极参与社区活动，努力改善居民生活环境。', 'Tā jī jí cān yù shè qū huó dòng, nǔ lì gǎi shàn jū mín shēng huó huán jìng.', 'Anh ấy tích cực tham gia hoạt động cộng đồng, cố gắng cải thiện môi trường sống của cư dân.'),
  ('示范', '老师在黑板上示范了这道题的解法，大家都明白了。', 'Lǎo shī zài hēi bǎn shàng shì fàn le zhè dào tí de jiě fǎ, dà jiā dōu míng bai le.', 'Giáo viên đã làm mẫu cách giải bài tập này trên bảng, mọi người đều hiểu.'),
  ('示意', '他轻轻点头，示意同伴跟他一起走。', 'Tā qīng qīng diǎn tóu, shì yì tóng bàn gēn tā yī qǐ zǒu.', 'Anh ấy gật đầu nhẹ, ra hiệu cho bạn cùng đi với mình.'),
  ('示威', '市民们自发组织示威，表达对政策的不满情绪。', 'Shì mín men zì fā zǔ zhī shì wēi, biǎo dá duì zhèng cè de bù mǎn qíng xù.', 'Người dân tự phát tổ chức biểu tình để bày tỏ sự không hài lòng với chính sách.'),
  ('石油', '该地区丰富的石油资源对国家经济发展至关重要。', 'Gāi dì qū fēng fù de shí yóu zī yuán duì guó jiā jīng jì fā zhǎn zhì guān zhòng yào.', 'Nguồn dầu mỏ phong phú ở khu vực này rất quan trọng đối với sự phát triển kinh tế quốc gia.'),
  ('瞬间', '他在瞬间做出了决定，没有丝毫犹豫。', 'Tā zài shùn jiān zuò chū le jué dìng, méi yǒu sī háo yóu yù.', 'Anh ấy đã đưa ra quyết định trong nháy mắt, không hề do dự.'),
  ('省会', '长沙是湖南省的省会，也是当地的重要经济中心。', 'Cháng shā shì Húnán shěng de shěng huì, yě shì dāng dì de zhòng yào jīng jì zhōng xīn.', 'Trường Sa là thủ phủ tỉnh Hồ Nam, cũng là trung tâm kinh tế quan trọng địa phương.'),
  ('盛行', '近年来，电动汽车在城市中越来越盛行。', 'Jìn nián lái, diàn dòng qì chē zài chéng shì zhōng yuè lái yuè shèng xíng.', 'Gần đây, xe điện ngày càng thịnh hành ở các thành phố.'),
  ('盛情', '感谢您的盛情邀请，我一定会准时参加晚会。', 'Gǎn xiè nín de shèng qíng yāo qǐng, wǒ yī dìng huì zhǔn shí cān jiā wǎn huì.', 'Cảm ơn lời mời nhiệt tình của anh/chị, tôi nhất định sẽ đến dự buổi tiệc đúng giờ.'),
  ('盛开', '春天来了，公园里的樱花盛开，美不胜收。', 'Chūn tiān lái le, gōng yuán lǐ de yīng huā shèng kāi, měi bù shèng shōu.', 'Mùa xuân đến, hoa anh đào trong công viên nở rộ, đẹp không thể tả.'),
  ('盛产', '这个地区盛产水果，尤其以苹果最为著名。', 'Zhè ge dì qū shèng chǎn shuǐ guǒ, yóu qí yǐ píng guǒ zuì wéi zhù míng.', 'Khu vực này sản xuất nhiều hoa quả, đặc biệt nổi tiếng với táo.'),
  ('疏远', '多年不见，昔日好友变得陌生而疏远。', 'Duō nián bù jiàn, xī rì hǎo yǒu biàn de mò shēng ér shū yuǎn.', 'Nhiều năm không gặp, bạn thân ngày xưa trở nên xa lạ và xa cách.'),
  ('疏忽', '他的疏忽导致了公司的严重损失。', 'Tā de shū hū dǎo zhì le gōng sī de yán zhòng sǔn shī.', 'Sự sơ suất của anh ấy đã gây ra tổn thất nghiêm trọng cho công ty.'),
  ('申报', '请您如实申报所有的收入和支出。', 'Qǐng nín rú shí shēn bào suǒ yǒu de shōu rù hé zhī chū.', 'Xin bạn hãy trình báo trung thực tất cả thu nhập và chi tiêu.'),
  ('生锈', '如果铁器长时间暴露在空气中，就会生锈。', 'Rú guǒ tiě qì cháng shí jiān bào lù zài kōng qì zhōng, jiù huì shēng xiù.', 'Nếu đồ sắt để ngoài không khí lâu dài sẽ bị rỉ sét.'),
  ('生育', '政府出台了新的政策鼓励适龄夫妻生育。', 'Zhèng fǔ chū tái le xīn de zhèng cè gǔ lì shì líng fū qī shēng yù.', 'Chính phủ đã ban hành chính sách mới khuyến khích các cặp vợ chồng trong độ tuổi sinh đẻ.'),
  ('生肖', '你的生肖属什么？我属兔。', 'Nǐ de shēng xiào shǔ shén me? Wǒ shǔ tù.', 'Con giáp của bạn là gì? Tôi thuộc con Thỏ.'),
  ('生疏', '时间久了，他对这项技能变得有些生疏。', 'Shí jiān jiǔ le, tā duì zhè xiàng jì néng biàn dé yǒu xiē shēng shū.', 'Sau một thời gian dài, anh ấy đã trở nên hơi mới lạ với kỹ năng này.'),
  ('生理', '女性的生理周期会影响情绪变化。', 'Nǚ xìng de shēng lǐ zhōu qī huì yǐng xiǎng qíng xù biàn huà.', 'Chu kỳ sinh lý của phụ nữ sẽ ảnh hưởng đến sự thay đổi cảm xúc.'),
  ('生物', '这片森林中生活着丰富多样的生物。', 'Zhè piàn sēn lín zhōng shēng huó zhe fēng fù duō yàng de shēng wù.', 'Trong khu rừng này có sinh vật phong phú và đa dạng sinh sống.'),
  ('生机', '春天的到来给大地带来了新的生机。', 'Chūn tiān de dào lái gěi dà dì dài lái le xīn de shēng jī.', 'Sự đến của mùa xuân mang lại sức sống mới cho đất đai.'),
  ('生效', '这项合同将在签署后立即生效。', 'Zhè xiàng hé tóng jiàng zài qiān shǔ hòu lì jí shēng xiào.', 'Hợp đồng này sẽ có hiệu lực ngay sau khi ký kết.'),
  ('生态', '保护生态环境是每个人的责任。', 'Bǎo hù shēng tài huán jìng shì měi gè rén de zé rèn.', 'Bảo vệ môi trường sinh thái là trách nhiệm của mỗi người.'),
  ('生存', '动物们为了生存不断适应环境的变化。', 'Dòng wù men wèi le shēng cún bù duàn shì yìng huán jìng de biàn huà.', 'Động vật không ngừng thích nghi với sự thay đổi môi trường để sinh tồn.'),
  ('率领', '将军率领部队参加了重要的战役。', 'Jiāng jūn shuài lǐng bù duì cān jiā le zhòng yào de zhàn yì.', 'Tướng lĩnh dẫn đầu quân đội tham gia trận đánh quan trọng.'),
  ('牲畜', '农村的牲畜包括牛、羊和猪等。', 'Nóng cūn de shēng chù bāo kuò niú, yáng hé zhū děng.', 'Gia súc ở nông thôn gồm có bò, cừu và heo.'),
  ('爽快', '他的回答十分爽快，让人感到舒服。', 'Tā de huí dá shí fēn shuǎng kuài, ràng rén gǎn dào shū fu.', 'Câu trả lời của anh ấy rất sảng khoái khiến người ta thấy dễ chịu.'),
  ('渗透', '水分已经渗透进了墙壁内部。', 'Shuǐ fèn yǐ jīng shèn tòu jìn le qiáng bì nèi bù.', 'Nước đã thẩm thấu vào bên trong bức tường.'),
  ('深沉', '他的声音低沉而深沉，表达了内心的坚定。', 'Tā de shēng yīn dī chén ér shēn chén, biǎo dá le nèi xīn de jiān dìng.', 'Giọng anh ta trầm và sâu lắng, thể hiện sự kiên định trong lòng.'),
  ('深情厚谊', '他们之间有着深情厚谊，难以割舍。', 'Tā men zhī jiān yǒu zhe shēn qíng hòu yì, nán yǐ gē shě.', 'Tình nghĩa sâu đậm giữa họ thật khó mà rời bỏ.'),
  ('深奥', '这本哲学书内容深奥，需要仔细研读。', 'Zhè běn zhé xué shū nèi róng shēn ào, xū yào zǐ xì yán dú.', 'Cuốn sách triết học này có nội dung cao siêu, cần đọc kỹ lưỡng.'),
  ('涮火锅', '冬天和朋友们一起涮火锅特别开心。', 'Dōng tiān hé péng yǒu men yī qǐ shuàn huǒ guō tè bié kāi xīn.', 'Mùa đông đi nhúng lẩu cùng bạn bè rất vui.'),
  ('涉及', '这本书涉及许多历史事件的分析和解读。', 'Zhè běn shū shèjí xǔduō lìshǐ shìjiàn de fēnxī hé jiědú.', 'Cuốn sách này đề cập đến phân tích và giải thích nhiều sự kiện lịch sử.'),
  ('水龙头', '请把水龙头关掉，避免浪费水资源。', 'Qǐng bǎ shuǐlóngtóu guāndiào, bìmiǎn làngfèi shuǐ zīyuán.', 'Xin hãy khóa vòi nước lại để tránh lãng phí tài nguyên nước.'),
  ('水泥', '工地上工人们正在用水泥修补墙壁。', 'Gōngdì shàng gōngrénmen zhèngzài yòng shuǐní xiūbǔ qiángbì.', 'Các công nhân trên công trường đang dùng bùn đất để sửa tường.'),
  ('水利', '政府投资建设了多个水利工程，改善灌溉条件。', 'Zhèngfǔ tóuzī jiànshèle duō gè shuǐlì gōngchéng, gǎishàn guàngài tiáojiàn.', 'Chính phủ đầu tư xây dựng nhiều công trình thủy lợi để cải thiện điều kiện tưới tiêu.'),
  ('死亡', '事故导致多人死亡，令人深感痛心。', 'Shìgù dǎozhì duō rén sǐwáng, lìng rén shēn gǎn tòngxīn.', 'Tai nạn dẫn đến nhiều người tử vong, khiến người ta rất đau lòng.'),
  ('梢', '树梢上停着一只美丽的鸟儿。', 'Shù shāo shàng tíngzhe yī zhī měilì de niǎor.', 'Trên ngọn cây có một con chim xinh đẹp đậu.'),
  ('树立', '他通过努力树立了良好的个人形象。', 'Tā tōngguò nǔlì shùlìle liánghǎo de gèrén xíngxiàng.', 'Anh ấy đã xây dựng được hình tượng cá nhân tốt thông qua nỗ lực.'),
  ('束缚', '传统观念束缚了年轻人的思想自由。', 'Chuántǒng guānniàn shùfùle niánqīng rén de sīxiǎng zìyóu.', 'Quan niệm truyền thống đã trói buộc sự tự do tư tưởng của giới trẻ.'),
  ('束', '他递给我一束鲜花，表达谢意。', 'Tā dì gěi wǒ yī shù xiānhuā, biǎodá xièyì.', 'Anh ấy trao cho tôi một bó hoa tươi để bày tỏ lời cảm ơn.'),
  ('是非', '不要总是被别人的是非影响自己的心情。', 'Bùyào zǒng shì bèi biérén de shìfēi yǐngxiǎng zìjǐ de xīnqíng.', 'Đừng luôn bị thị phi của người khác ảnh hưởng đến tâm trạng của mình.'),
  ('时而', '天气时而晴朗，时而下雨，变化无常。', 'Tiānqì shí ér qínglǎng, shí ér xiàyǔ, biànhuà wúcháng.', 'Thời tiết đôi khi trời trong, đôi khi mưa, thay đổi thất thường.'),
  ('时机', '成功需要抓住合适的时机并付诸行动。', 'Chénggōng xūyào zhuāzhù héshì de shíjī bìng fùzhū xíngdòng.', 'Thành công cần nắm bắt thời cơ thích hợp và hành động.'),
  ('时常', '她时常关心朋友的生活状况。', 'Tā shícháng guānxīn péngyǒu de shēnghuó zhuàngkuàng.', 'Cô ấy thường xuyên quan tâm đến tình hình cuộc sống của bạn bè.'),
  ('时光', '美好的时光总是在不经意间流逝。', 'Měihǎo de shíguāng zǒng shì zài bù jīngyì jiān liúshì.', 'Những thời khắc đẹp đẽ luôn trôi qua một cách bất ngờ.'),
  ('时事', '学生们积极讨论最新的时事新闻。', 'Xuéshēngmen jījí tǎolùn zuìxīn de shíshì xīnwén.', 'Các học sinh tích cực thảo luận về tin tức thời sự mới nhất.'),
  ('施展', '他在比赛中施展了出色的篮球技巧。', 'Tā zài bǐsài zhōng shīzhǎnle chūsè de lánqiú jìqiǎo.', 'Anh ấy đã thể hiện kỹ năng bóng rổ xuất sắc trong trận đấu.'),
  ('施加', '压力施加在员工身上，影响工作效率。', 'Yālì shījiā zài yuángōng shēnshang, yǐngxiǎng gōngzuò xiàolǜ.', 'Áp lực được tạo ra lên nhân viên, ảnh hưởng tới hiệu quả công việc.'),
  ('斯文', '他是一个斯文有礼的绅士。', 'Tā shì yī gè sīwén yǒu lǐ de shēnshì.', 'Anh ấy là một quý ông lịch sự và nho nhã.'),
  ('数额', '捐款的数额远远超过了预期。', 'Juānkuǎn de shù’é yuǎn yuǎn chāoguòle yùqī.', 'Số tiền quyên góp vượt xa mong đợi.'),
  ('散文', '她喜欢阅读各种不同风格的散文作品。', 'Tā xǐhuān yuèdú gè zhǒng bùtóng fēnggé de sǎnwén zuòpǐn.', 'Cô ấy thích đọc các tác phẩm tản văn với nhiều phong cách khác nhau.'),
  ('散布', '有人在社区散布不实的谣言，造成了恐慌。', 'Yǒurén zài shèqū sànbù bù shí de yáoyán, zàochéngle kǒnghuāng.', 'Có người trong cộng đồng phát tán tin đồn không đúng sự thật, gây ra hoang mang.'),
  ('散发', '花园里散发着淡淡的花香，让人心旷神怡。', 'Huāyuán lǐ sànfā zhe dàndàn de huāxiāng, ràng rén xīn kuàng shén yí.', 'Trong vườn tỏa ra hương thơm nhẹ nhàng của hoa, khiến người ta cảm thấy sảng khoái.'),
  ('收音机', '早上我习惯打开收音机听新闻和音乐。', 'Zǎoshang wǒ xíguàn dǎkāi shōuyīnjī tīng xīnwén hé yīnyuè.', 'Buổi sáng tôi có thói quen bật đài nghe tin tức và nhạc.'),
  ('收藏', '她喜欢收藏各种古董，家里摆满了珍贵的艺术品。', 'Tā xǐhuān shōucáng gè zhǒng gǔdǒng, jiālǐ bǎi mǎnle zhēnguì de yìshùpǐn.', 'Cô ấy thích sưu tầm các loại cổ vật, trong nhà chất đầy đồ nghệ thuật quý giá.'),
  ('收缩', '寒冷时血管会收缩，导致手脚发冷。', 'Hánlěng shí xuèguǎn huì shōusuō, dǎozhì shǒujiǎo fā lěng.', 'Khi lạnh, mạch máu sẽ co lại, làm tay chân bị lạnh.'),
  ('收益', '经过努力投资，这个项目的收益远远超过预期。', 'Jīngguò nǔlì tóuzī, zhège xiàngmù de shōuyì yuǎn yuǎn chāoguò yùqī.', 'Sau khi đầu tư nỗ lực, lợi nhuận của dự án này vượt xa dự kiến.'),
  ('擅长', '他擅长解决复杂的数学问题，经常帮助同学。', 'Tā shàncháng jiějué fùzá de shùxué wèntí, jīngcháng bāngzhù tóngxué.', 'Anh ấy giỏi giải quyết các bài toán phức tạp và thường giúp đỡ bạn học.'),
  ('擅自', '未经允许，你不能擅自进入实验室操作设备。', 'Wèijīng yǔnxǔ, nǐ bù néng shànzì jìnrù shíyànshì cāozuò shèbèi.', 'Chưa được phép, bạn không được tự ý vào phòng thí nghiệm vận hành thiết bị.'),
  ('撒谎', '孩子因为怕挨罚，所以对父母撒谎了。', 'Háizi yīnwèi pà ái fá, suǒyǐ duì fùmǔ sāhuǎng le.', 'Đứa trẻ vì sợ bị phạt nên đã nói dối cha mẹ.'),
  ('摄氏度', '明天的气温预计将达到三十五摄氏度，非常炎热。', 'Míngtiān de qìwēn yùjì jiāng dádào sānshíwǔ shèshìdù, fēicháng yánrè.', 'Nhiệt độ ngày mai dự kiến sẽ lên đến 35 độ C, rất nóng.'),
  ('授予', '学校授予他优秀学生的荣誉称号，以表彰他的努力。', 'Xuéxiào shòuyǔ tā yōuxiù xuéshēng de róngyù chēnghào, yǐ biǎozhāng tā de nǔlì.', 'Trường đã trao tặng cho anh ấy danh hiệu học sinh xuất sắc để ghi nhận sự nỗ lực.'),
  ('捎', '请你帮我捎一封信给远方的朋友好吗？', 'Qǐng nǐ bāng wǒ shāo yī fēng xìn gěi yuǎnfāng de péngyǒu hǎo ma?', 'Bạn giúp tôi mang hộ một bức thư cho người bạn ở xa được không?'),
  ('拾', '公园里有人在拾垃圾，保持环境的清洁。', 'Gōngyuán lǐ yǒu rén zài shí lājī, bǎochí huánjìng de qīngjié.', 'Có người trong công viên đang nhặt rác để giữ vệ sinh môi trường.'),
  ('手艺', '这位师傅的手艺非常精湛，制作的家具非常耐用。', 'Zhè wèi shīfù de shǒuyì fēicháng jīngzhàn, zhìzuò de jiājù fēicháng nàiyòng.', 'Thợ này có tay nghề rất điêu luyện, đồ nội thất làm ra rất bền.'),
  ('手法', '他的绘画手法独特，作品充满了个人风格。', 'Tā de huìhuà shǒufǎ dútè, zuòpǐn chōngmǎn le gèrén fēnggé.', 'Phương pháp vẽ của anh ấy rất độc đáo, tác phẩm đầy phong cách cá nhân.'),
  ('手势', '老师用手势指引学生们排队进入教室。', 'Lǎoshī yòng shǒushì zhǐyǐn xuéshēngmen páiduì jìnrù jiàoshì.', 'Giáo viên dùng cử chỉ hướng dẫn học sinh xếp hàng vào lớp.'),
  ('慎重', '签合同前一定要慎重考虑所有条款，避免纠纷。', 'Qiān hétóng qián yīdìng yào shènzhòng kǎolǜ suǒyǒu tiáokuǎn, bìmiǎn jiūfēn.', 'Trước khi ký hợp đồng nhất định phải xem xét cẩn thận các điều khoản để tránh tranh chấp.'),
  ('思维', '创新需要灵活的思维和开放的态度。', 'Chuàngxīn xūyào línghuó de sīwéi hé kāifàng de tàidù.', 'Sáng tạo cần tư duy linh hoạt và thái độ cởi mở.'),
  ('思索', '他静静地思索着人生的意义，没有发出声音。', 'Tā jìngjìng de sīsuǒ zhe rénshēng de yìyì, méiyǒu fāchū shēngyīn.', 'Anh ấy lặng lẽ suy nghĩ về ý nghĩa cuộc đời mà không phát ra âm thanh.'),
  ('思念', '归国后，她常常思念远方的家人和朋友。', 'Guīguó hòu, tā chángcháng sīniàn yuǎnfāng de jiārén hé péngyǒu.', 'Sau khi trở về nước, cô thường nhớ nhung gia đình và bạn bè ở xa.'),
  ('师范', '他毕业于著名的师范大学，成为一名教师。', 'Tā bì yè yú zhù míng de shī fàn dà xué, chéng wéi yì míng jiào shī.', 'Anh ấy tốt nghiệp từ trường đại học sư phạm nổi tiếng và trở thành một giáo viên.'),
  ('山脉', '这条山脉绵延数百公里，风景非常壮观。', 'Zhè tiáo shān mài mián yán shù bǎi gōng lǐ, fēng jǐng fēi cháng zhuàng guān.', 'Dãy núi này kéo dài hàng trăm cây số, cảnh sắc rất hùng vĩ.'),
  ('尸体', '警方在森林中发现了一具被掩埋的尸体。', 'Jǐng fāng zài sēn lín zhōng fā xiàn le yī jù bèi yǎn mái de shī tǐ.', 'Cảnh sát phát hiện một thi thể bị chôn trong rừng.'),
  ('尚且', '即使他自己都有困难，尚且帮助了别人。', 'Jí shǐ tā zì jǐ dōu yǒu kùn nán, shàng qiě bāng zhù le bié rén.', 'Ngay cả khi bản thân gặp khó khăn, anh ấy vẫn giúp đỡ người khác.'),
  ('审美', '他的审美观念非常独特，喜欢现代艺术。', 'Tā de shěn měi guān niàn fēi cháng dú tè, xǐ huān xiàn dài yì shù.', 'Quan niệm thẩm mỹ của anh ấy rất độc đáo, thích nghệ thuật hiện đại.'),
  ('审理', '法院将于下周开始审理这起经济纠纷案件。', 'Fǎ yuàn jiāng yú xià zhōu kāi shǐ shěn lǐ zhè qǐ jīng jì jiū fēn àn jiàn.', 'Tòa án sẽ bắt đầu thẩm lý vụ án tranh chấp kinh tế vào tuần tới.'),
  ('审查', '政府对所有进口商品进行严格审查。', 'Zhèng fǔ duì suǒ yǒu jìn kǒu shāng pǐn jìn xíng yán gé shěn chá.', 'Chính phủ tiến hành thẩm tra nghiêm ngặt tất cả hàng nhập khẩu.'),
  ('审判', '法官公正地审判了这起刑事案件。', 'Fǎ guān gōng zhèng de shěn pàn le zhè qǐ xíng shì àn jiàn.', 'Thẩm phán đã xét xử công bằng vụ án hình sự này.'),
  ('实质', '他的言论的实质是希望获得更多支持。', 'Tā de yán lùn de shí zhì shì xī wàng huò dé gèng duō zhī chí.', 'Thực chất lời phát biểu của anh ấy là hy vọng nhận được nhiều sự ủng hộ hơn.'),
  ('实行', '政府决定从明年开始实行新的教育政策。', 'Zhèng fǔ jué dìng cóng míng nián kāi shǐ shí xíng xīn de jiào yù zhèng cè.', 'Chính phủ quyết định bắt đầu thực thi chính sách giáo dục mới từ năm sau.'),
  ('实施', '为了保护环境，市政府将实施垃圾分类制度。', 'Wèi le bǎo hù huán jìng, shì zhèng fǔ jiāng shí shī lā jī fēn lèi zhì dù.', 'Để bảo vệ môi trường, chính quyền thành phố sẽ thi hành hệ thống phân loại rác thải.'),
  ('实惠', '这家超市的促销活动非常实惠，吸引了很多顾客。', 'Zhè jiā chāo shì de cù xiāo huó dòng fēi cháng shí huì, xī yǐn le hěn duō gù kè.', 'Chương trình khuyến mãi của siêu thị này rất ưu đãi, thu hút nhiều khách hàng.'),
  ('实力', '这家公司在市场上的实力不断增强，竞争力很强。', 'Zhè jiā gōng sī zài shì chǎng shàng de shí lì bù duàn zēng qiáng, jìng zhēng lì hěn qiáng.', 'Thực lực của công ty này trên thị trường ngày càng mạnh, sức cạnh tranh rất lớn.'),
  ('实事求是', '他做事一直秉持实事求是的态度，非常值得信赖。', 'Tā zuò shì yī zhí bǐng chí shí shì qiú shì de tài dù, fēi cháng zhí dé xìn lài.', 'Anh ấy làm việc luôn giữ thái độ tinh thần cầu thị, rất đáng tin cậy.'),
  ('守护', '父母用尽心力守护孩子的成长和安全。', 'Fù mǔ yòng jǐn xīn lì shǒu hù hái zi de chéng zhǎng hé ān quán.', 'Cha mẹ hết lòng bảo vệ sự trưởng thành và an toàn của con cái.'),
  ('嫂子', '我的嫂子做了一桌丰盛的晚餐招待我们。', 'Wǒ de sǎo zi zuò le yī zhuō fēng shèng de wǎn cān zhāo dài wǒ men.', 'Chị dâu của tôi đã nấu một mâm cơm tối thịnh soạn tiếp đãi chúng tôi.'),
  ('奢侈', '他喜欢奢侈的生活方式，经常购买名牌商品。', 'Tā xǐ huān shē chǐ de shēng huó fāng shì, jīng cháng gòu mǎi míng pái shāng pǐn.', 'Anh ấy thích lối sống xa hoa, thường xuyên mua hàng hiệu.'),
  ('失踪', '那名游客在山区失踪，救援队正在搜寻。', 'Nà míng yóu kè zài shān qū shī zōng, jiù yuán duì zhèng zài sōu xún.', 'Du khách đó bị mất tích trong khu vực núi, đội cứu hộ đang tìm kiếm.'),
  ('失误', '球员在比赛中出现了关键的失误，导致失败。', 'Qiú yuán zài bǐ sài zhōng chū xiàn le guān jiàn de shī wù, dǎo zhì shī bài.', 'Cầu thủ đã mắc sai lầm quan trọng trong trận đấu dẫn đến thất bại.'),
  ('失事', '那架飞机在起飞后不久失事，事故原因正在调查。', 'Nà jià fēi jī zài qǐ fēi hòu bù jiǔ shī shì, shì gù yuán yīn zhèng zài diào chá.', 'Chiếc máy bay đó bị sự cố sau khi cất cánh, nguyên nhân đang được điều tra.'),
  ('声誉', '这家公司的声誉因为优质服务而大大提升。', 'Zhè jiā gōngsī de shēngyù yīnwèi yōuzhì fúwù ér dàdà tíshēng.', 'Danh tiếng của công ty này đã được nâng cao rất nhiều nhờ dịch vụ chất lượng.'),
  ('声明', '政府针对网络谣言发布了正式声明。', 'Zhèngfǔ zhēnduì wǎngluò yáoyán fābùle zhèngshì shēngmíng.', 'Chính phủ đã phát hành tuyên bố chính thức về các tin đồn trên mạng.'),
  ('声势', '这场抗议活动的声势空前，吸引了大量媒体关注。', 'Zhè chǎng kàngyì huódòng de shēngshì kōngqián, xīyǐn le dàliàng méitǐ guānzhù.', 'Phong trào biểu tình này có thanh thế chưa từng có, thu hút sự chú ý lớn từ truyền thông.'),
  ('啥', '你到底想说啥，别拐弯抹角了。', 'Nǐ dàodǐ xiǎng shuō shá, bié guǎiwān mǒjiǎo le.', 'Cuối cùng bạn muốn nói cái gì, đừng vòng vo nữa.'),
  ('商标', '这个品牌的商标设计非常独特，易于识别。', 'Zhège pǐnpái de shāngbiāo shèjì fēicháng dútè, yìyú shíbié.', 'Nhãn hiệu của thương hiệu này được thiết kế rất độc đáo, dễ nhận biết.'),
  ('哨', '士兵们轮流在哨所值夜班，确保安全。', 'Shìbīngmen lúnliú zài shàosuǒ zhí yèbān, quèbǎo ānquán.', 'Các binh sĩ thay phiên nhau trực đêm tại trạm gác để đảm bảo an toàn.'),
  ('呻吟', '病人在手术后不断呻吟，显得非常痛苦。', 'Bìngrén zài shǒushù hòu bùduàn shēnyín, xiǎnde fēicháng tòngkǔ.', 'Bệnh nhân cứ rên rỉ sau ca phẫu thuật, trông rất đau đớn.'),
  ('司法', '司法部门必须保障法律的公平与正义。', 'Sīfǎ bùmén bìxū bǎozhàng fǎlǜ de gōngpíng yǔ zhèngyì.', 'Bộ phận tư pháp phải đảm bảo sự công bằng và công lý của pháp luật.'),
  ('司令', '司令下达了重要的军事命令，要求全军戒备。', 'Sīlìng xiàdále zhòngyào de jūnshì mìnglìng, yāoqiú quán jūn jièbèi.', 'Tư lệnh đã ra lệnh quân sự quan trọng, yêu cầu toàn quân cảnh giác.'),
  ('受罪', '他虽然受罪很多，但始终没有放弃努力。', 'Tā suīrán shòuzuì hěn duō, dàn shǐzhōng méiyǒu fàngqì nǔlì.', 'Anh ấy tuy chịu nhiều khổ cực nhưng luôn không từ bỏ nỗ lực.'),
  ('双胞胎', '我的妹妹生了一对健康可爱的双胞胎。', 'Wǒ de mèimei shēng le yī duì jiànkāng kě''ài de shuāngbāotāi.', 'Em gái tôi sinh một cặp sinh đôi khỏe mạnh và dễ thương.'),
  ('十足', '他表现出十足的自信，赢得了大家的认可。', 'Tā biǎoxiàn chū shízú de zìxìn, yíngdéle dàjiā de rènkě.', 'Anh ấy thể hiện đầy đủ sự tự tin, nhận được sự công nhận của mọi người.'),
  ('势必', '如果不采取措施，问题势必会变得更加严重。', 'Rúguǒ bù cǎiqǔ cuòshī, wèntí shìbì huì biàn de gèngjiā yánzhòng.', 'Nếu không có biện pháp, sự việc tất phải trở nên nghiêm trọng hơn.'),
  ('势力', '那个家族在当地拥有很大的势力和影响力。', 'Nàgè jiāzú zài dāngdì yōngyǒu hěn dà de shìlì hé yǐngxiǎnglì.', 'Gia tộc đó có thế lực lớn và ảnh hưởng tại địa phương.'),
  ('刹车', '司机在看到红灯时立即刹车，避免了事故发生。', 'Sījī zài kàn dào hóngdēng shí lìjí shāchē, bìmiǎnle shìgù fāshēng.', 'Tài xế ngay lập tức phanh xe khi thấy đèn đỏ, tránh được tai nạn.'),
  ('使命', '作为教师，我的使命是培养学生的全面发展。', 'Zuòwéi jiàoshī, wǒ de shǐmìng shì péiyǎng xuéshēng de quánmiàn fāzhǎn.', 'Là giáo viên, sứ mệnh của tôi là đào tạo sự phát triển toàn diện của học sinh.'),
  ('伤脑筋', '这个复杂的问题让我们感到十分伤脑筋。', 'Zhège fùzá de wèntí ràng wǒmen gǎndào shífēn shāng nǎojīn.', 'Vấn đề phức tạp này khiến chúng tôi cảm thấy rất đau đầu.'),
  ('事项', '会议安排了多个重要事项需要及时讨论和解决。', 'Huìyì ānpáile duō gè zhòngyào shìxiàng xūyào jíshí tǎolùn hé jiějué.', 'Cuộc họp đã sắp xếp nhiều hạng mục công việc quan trọng cần thảo luận và giải quyết kịp thời.'),
  ('事迹', '他在抗灾救援中的感人事迹被广泛传颂。', 'Tā zài kàng zāi jiùyuán zhōng de gǎnrén shìjì bèi guǎngfàn chuánsòng.', 'Câu chuyện lịch sử cảm động của anh ấy trong cứu trợ thiên tai được lan truyền rộng rãi.'),
  ('事故', '上周工厂发生了一起严重的安全事故，引起了关注。', 'Shàng zhōu gōngchǎng fāshēngle yī qǐ yánzhòng de ānquán shìgù, yǐnqǐle guānzhù.', 'Tuần trước, nhà máy đã xảy ra một tai nạn an toàn nghiêm trọng, gây chú ý.'),
  ('事态', '当前的事态发展令人非常关注。', 'dāng qián de shì tài fā zhǎn lìng rén fēi cháng guān zhù.', 'Tình hình hiện tại đang phát triển khiến mọi người rất quan tâm.'),
  ('事务', '他每天都忙于处理各种公司事务。', 'tā měi tiān dōu máng yú chǔ lǐ gè zhǒng gōng sī shì wù.', 'Anh ấy mỗi ngày đều bận xử lý đủ các loại công việc công ty.'),
  ('事件', '这起事件引起了社会的广泛关注。', 'zhè qǐ shì jiàn yǐn qǐ le shè huì de guǎng fàn guān zhù.', 'Sự việc này đã thu hút sự quan tâm rộng rãi của xã hội.'),
  ('事业', '她立志投身教育事业帮助更多学生。', 'tā lì zhì tóu shēn jiào yù shì yè bāng zhù gèng duō xué shēng.', 'Cô ấy quyết tâm đầu tư vào sự nghiệp giáo dục để giúp đỡ nhiều học sinh hơn.'),
  ('书面', '请将申请材料以书面形式提交。', 'qǐng jiāng shēn qǐng cái liào yǐ shū miàn xíng shì tí jiāo.', 'Vui lòng nộp tài liệu xin bằng hình thức văn bản.'),
  ('书记', '他被任命为党委书记，负责组织工作。', 'tā bèi rèn mìng wèi dǎng wěi shū jì, fù zé zǔ zhī gōng zuò.', 'Anh ta được bổ nhiệm làm bí thư đảng ủy, phụ trách công tác tổ chức.'),
  ('书籍', '图书馆里收藏了大量珍贵的书籍。', 'tú shū guǎn lǐ shōu cáng le dà liàng zhēn guì de shū jí.', 'Thư viện lưu giữ một lượng lớn sách quý giá.'),
  ('书法', '他的书法作品在比赛中获得了第一名。', 'tā de shū fǎ zuò pǐn zài bǐ sài zhōng huò dé le dì yī míng.', 'Tác phẩm thư pháp của anh ấy đã giành giải nhất trong cuộc thi.'),
  ('丧失', '他因为疏忽而丧失了这次宝贵的机会。', 'tā yīn wèi shū hū ér sàng shī le zhè cì bǎo guì de jī huì.', 'Anh ấy vì sơ suất mà mất đi cơ hội quý giá lần này.'),
  ('世代', '这个村庄的手艺世代相传，十分珍贵。', 'zhè gè cūn zhuāng de shǒu yì shì dài xiāng chuán, shí fēn zhēn guì.', 'Nghề thủ công của ngôi làng này được truyền lại qua các thế hệ, rất quý giá.'),
  ('上进', '他是个非常上进的学生，总是努力学习。', 'tā shì gè fēi cháng shàng jìn de xué shēng, zǒng shì nǔ lì xué xí.', 'Anh ấy là một học sinh rất tiến bộ, luôn nỗ lực học tập.'),
  ('上级', '员工应及时向上级汇报工作进展情况。', 'yuán gōng yīng jí shí xiàng shàng jí huì bào gōng zuò jìn zhǎn qíng kuàng.', 'Nhân viên nên kịp thời báo cáo tiến độ công việc cho cấp trên.'),
  ('上瘾', '他因为玩游戏上瘾，学习成绩下降了。', 'tā yīn wèi wán yóu xì shàng yǐn, xué xí chéng jì xià jiàng le.', 'Anh ấy vì nghiện chơi game nên thành tích học tập giảm sút.'),
  ('上游', '污染物从上游排放，影响了下游水质。', 'wū rǎn wù cóng shàng yóu pái fàng, yǐng xiǎng le xià yóu shuǐ zhì.', 'Chất ô nhiễm thải ra từ thượng du đã ảnh hưởng đến chất lượng nước ở hạ du.'),
  ('上任', '他将于下个月正式上任新的经理职位。', 'tā jiāng yú xià gè yuè zhèng shì shàng rèn xīn de jīng lǐ zhí wèi.', 'Anh ấy sẽ chính thức nhậm chức vị trí giám đốc mới vào tháng sau.'),
  ('饲养', '农民在田边饲养了许多家禽和牲畜。', 'nóng mín zài tián biān sì yǎng le xǔ duō jiā qín hé shēng chù.', 'Người nông dân nuôi rất nhiều gia cầm và gia súc bên đồng ruộng.'),
  ('隧道', '新建的隧道大大缩短了通勤时间。', 'xīn jiàn de suì dào dà dà suō duǎn le tōng qín shí jiān.', 'Đường hầm mới xây đã rút ngắn đáng kể thời gian đi lại.'),
  ('随意', '请不要随意丢弃垃圾，保持环境整洁。', 'qǐng bù yào suí yì diū qì lā jī, bǎo chí huán jìng zhěng jié.', 'Xin đừng tùy tiện vứt rác, giữ môi trường sạch sẽ.'),
  ('随即', '他解释完，随即离开了会议现场。', 'tā jiě shì wán, suí jí lí kāi le huì yì xiàn chǎng.', 'Anh ấy giải thích xong, ngay lập tức rời khỏi hiện trường cuộc họp.'),
  ('诉讼', '双方因合同纠纷提起了诉讼程序。', 'shuāng fāng yīn hé tóng jiū fēn tí qǐ le sù sòng chéng xù.', 'Hai bên đã khởi kiện trong quá trình tố tụng vì tranh chấp hợp đồng.'),
  ('苏醒', '经过一夜的休息，他终于从昏迷中苏醒过来。', 'Jīngguò yī yè de xiūxí, tā zhōngyú cóng hūnmí zhōng sūxǐng guòlái.', 'Sau một đêm nghỉ ngơi, cuối cùng anh ấy tỉnh lại sau khi mê man.'),
  ('艘', '港口停靠着三艘巨大的货轮，十分壮观。', 'Gǎngkǒu tíngkào zhe sān sōu jùdà de huòlún, shífēn zhuàngguān.', 'Ở cảng có ba chiếc tàu hàng lớn đậu, rất hùng vĩ.'),
  ('肆无忌惮', '他在公众场合肆无忌惮地发表激烈言论，引起争议。', 'Tā zài gōngzhòng chǎnghé sìwújìdàn de fābiǎo jīliè yánlùn, yǐnqǐ zhēngyì.', 'Anh ta phát biểu lời lẽ gay gắt một cách không kiêng nể nơi công cộng, gây ra tranh cãi.'),
  ('耸', '高楼大厦在晨曦中耸立，显得格外雄伟。', 'Gāolóu dàshà zài chénxī zhōng sǒnglì, xiǎnde géwài xióngwěi.', 'Các toà nhà chọc trời đứng thẳng trong ánh sớm, trông vô cùng hùng vĩ.'),
  ('索性', '既然计划失败了，我们索性重新开始吧。', 'Jìrán jìhuà shībài le, wǒmen suǒxìng chóngxīn kāishǐ ba.', 'Vì kế hoạch thất bại, chúng ta dứt khoát bắt đầu lại đi.'),
  ('索取', '他不应该无理地索取别人的劳动成果。', 'Tā bù yīnggāi wúlǐ de suǒqǔ biérén de láodòng chéngguǒ.', 'Anh ta không nên đòi lại thành quả lao động của người khác một cách vô lý.'),
  ('素食', '越来越多的人选择健康的素食生活方式。', 'Yuè lái yuè duō de rén xuǎnzé jiànkāng de sùshí shēnghuó fāngshì.', 'Ngày càng nhiều người chọn lối sống ăn chay khỏe mạnh.'),
  ('素质', '良好的教育能够提升学生的综合素质。', 'Liánghǎo de jiàoyù nénggòu tíshēng xuéshēng de zōnghé sùzhì.', 'Giáo dục tốt có thể nâng cao tố chất toàn diện của học sinh.'),
  ('算数', '他说到做到，绝对算数，从不轻易改变主意。', 'Tā shuō dào zuò dào, juéduì suànshù, cóng bù qīngyì gǎibiàn zhǔyì.', 'Anh ấy nói được làm được, tuyệt đối giữ lời hứa, không bao giờ dễ dàng thay đổi ý định.'),
  ('损坏', '这次地震造成了许多建筑物的严重损坏。', 'Zhè cì dìzhèn zàochéng le xǔduō jiànzhùwù de yánzhòng sǔnhuài.', 'Trận động đất lần này đã gây tổn thất nghiêm trọng cho nhiều tòa nhà.'),
  ('岁月', '岁月如梭，转眼间我们已经毕业十年了。', 'Suìyuè rú suō, zhuǎnyǎn jiān wǒmen yǐjīng bìyè shí nián le.', 'Thời gian trôi nhanh như thoi đưa, thoáng chốc chúng ta đã tốt nghiệp được mười năm.'),
  ('寺庙', '每年春节，很多游客都会去寺庙祈福。', 'Měi nián chūnjié, hěn duō yóukè dōu huì qù sìmiào qífú.', 'Mỗi năm vào dịp Tết Nguyên Đán, nhiều du khách đều đến đền chùa để cầu phúc.'),
  ('塑造', '这部电影成功地塑造了一个复杂的人物形象。', 'Zhè bù diànyǐng chénggōng de sùzào le yī gè fùzá de rénwù xíngxiàng.', 'Bộ phim này đã xây dựng thành công hình tượng nhân vật phức tạp.'),
  ('四肢', '运动员的四肢都经过专业的训练，非常灵活。', 'Yùndòngyuán de sìzhī dōu jīngguò zhuānyè de xùnliàn, fēicháng línghuó.', 'Tứ chi của vận động viên đều được huấn luyện chuyên nghiệp, rất linh hoạt.'),
  ('俗话', '俗话说，早起的鸟儿有虫吃，这是生活的道理。', 'Súhuà shuō, zǎoqǐ de niǎo ér yǒu chóng chī, zhè shì shēnghuó de dàolǐ.', 'Tục ngữ có câu, chim dậy sớm thì bắt được sâu, đó là quy luật cuộc sống.'),
  ('题材', '这部小说的题材非常新颖，吸引了大量读者。', 'Zhè bù xiǎoshuō de tícái fēicháng xīnyǐng, xīyǐn le dàliàng dúzhě.', 'Đề tài của cuốn tiểu thuyết này rất mới lạ, thu hút nhiều độc giả.'),
  ('陶醉', '她陶醉在美妙的音乐中，忘记了一切烦恼。', 'Tā táozuì zài měimiào de yīnyuè zhōng, wàngjì le yīqiè fánnǎo.', 'Cô ấy ngất ngây trong âm nhạc tuyệt vời, quên hết mọi phiền muộn.'),
  ('陶瓷', '这家工厂主要生产高品质的陶瓷产品。', 'Zhè jiā gōngchǎng zhǔyào shēngchǎn gāo pǐnzhì de táocí chǎnpǐn.', 'Nhà máy này chủ yếu sản xuất các sản phẩm gốm sứ chất lượng cao.'),
  ('铜', '这座雕塑是用纯铜铸造的，历经百年依然光亮。', 'Zhè zuò diāosù shì yòng chún tóng zhùzào de, lìjīng bǎinián yīrán guāngliàng.', 'Bức tượng này được đúc bằng đồng nguyên chất, trải qua trăm năm vẫn sáng bóng.'),
  ('通货膨胀', '近年来，通货膨胀导致生活成本大幅上升。', 'Jìnnián lái, tōnghuò péngzhàng dǎozhì shēnghuó chéngběn dàfú shàngshēng.', 'Gần đây, lạm phát đã dẫn đến chi phí sinh hoạt tăng mạnh.'),
  ('通讯', '他的工作主要是负责国际通讯的传输与管理。', 'Tā de gōngzuò zhǔyào shì fùzé guójì tōngxùn de chuánshū yǔ guǎnlǐ.', 'Công việc của anh ấy chủ yếu là phụ trách truyền tải và quản lý thông tấn quốc tế.'),
  ('通缉', '警方已经发布通缉令，寻找这名逃犯。', 'Jǐngfāng yǐjīng fābù tōngjī lìng, xúnzhǎo zhè míng táofàn.', 'Cảnh sát đã phát lệnh truy nã để tìm kiếm tên tội phạm bỏ trốn này.'),
  ('通用', '这种软件在不同操作系统中都能够通用。', 'Zhè zhǒng ruǎnjiàn zài bùtóng cāozuò xìtǒng zhōng dōu nénggòu tōngyòng.', 'Phần mềm này có thể thông dụng trên các hệ điều hành khác nhau.'),
  ('通俗', '这本书采用通俗易懂的语言讲解复杂的理论。', 'Zhè běn shū cǎiyòng tōngsú yì dǒng de yǔyán jiǎngjiě fùzá de lǐlùn.', 'Cuốn sách này giải thích các lý thuyết phức tạp bằng ngôn ngữ thông thường dễ hiểu.'),
  ('途径', '学习一门新语言的途径有很多种，包括听说读写。', 'Xuéxí yī mén xīn yǔyán de tújìng yǒu hěn duō zhǒng, bāokuò tīng shuō dú xiě.', 'Có nhiều con đường để học một ngôn ngữ mới, bao gồm nghe, nói, đọc, viết.'),
  ('透露', '他无意中透露了公司的商业秘密。', 'Tā wúyì zhōng tòulù le gōngsī de shāngyè mìmì.', 'Anh ấy vô tình tiết lộ bí mật thương mại của công ty.'),
  ('踏实', '你只要踏实努力，就一定能取得好成绩。', 'Nǐ zhǐyào tāshí nǔlì, jiù yīdìng néng qǔdé hǎo chéngjī.', 'Chỉ cần bạn làm việc thiết thực và chăm chỉ thì nhất định sẽ đạt được kết quả tốt.'),
  ('跳跃', '孩子们在草地上欢快地跳跃玩耍。', 'Háizimen zài cǎodì shàng huānkuài de tiàoyuè wánshuǎ.', 'Bọn trẻ đang nhảy vọt vui vẻ trên bãi cỏ.'),
  ('贪污', '政府正在严厉打击各种形式的贪污行为。', 'Zhèngfǔ zhèngzài yánlì dǎjí gè zhǒng xíngshì de tānwū xíngwéi.', 'Chính phủ đang nghiêm khắc trấn áp mọi hình thức tham ô.'),
  ('贪婪', '他的贪婪让他忽视了道德和法律的底线。', 'Tā de tānlán ràng tā hūshì le dàodé hé fǎlǜ de dǐxiàn.', 'Sự tham lam của anh ta khiến anh ta bỏ qua giới hạn đạo đức và pháp luật.'),
  ('调解', '法院要求双方通过调解来解决纠纷。', 'Fǎyuàn yāoqiú shuāngfāng tōngguò tiáojiě lái jiějué jiūfēn.', 'Tòa án yêu cầu hai bên hòa giải để giải quyết tranh chấp.'),
  ('调节', '为了保持身体健康，要合理调节饮食。', 'Wèile bǎochí shēntǐ jiànkāng, yào hélǐ tiáojié yǐnshí.', 'Để giữ gìn sức khỏe, phải điều chỉnh chế độ ăn uống hợp lý.'),
  ('调料', '这道菜的独特风味来源于各种调料的配合。', 'Zhè dào cài de dútè fēngwèi láiyuán yú gè zhǒng tiáoliào de pèihé.', 'Hương vị đặc biệt của món ăn này đến từ sự phối hợp của các loại gia vị.'),
  ('调和', '艺术家的作品调和了传统与现代元素。', 'Yìshùjiā de zuòpǐn tiáohé le chuántǒng yǔ xiàndài yuánsù.', 'Tác phẩm của nghệ sĩ hòa giải các yếu tố truyền thống và hiện đại.'),
  ('调剂', '他通过运动调剂了繁忙的工作压力。', 'Tā tōngguò yùndòng tiáojì le fánmáng de gōngzuò yālì.', 'Anh ấy điều tiết căng thẳng công việc bận rộn bằng cách vận động.'),
  ('讨好', '他总是试图讨好老板以获得升职机会。', 'Tā zǒng shì shìtú tǎohǎo lǎobǎn yǐ huòdé shēngzhí jīhuì.', 'Anh ta luôn cố gắng nịnh bợ sếp để có cơ hội thăng chức.'),
  ('舔', '小狗用舌头舔主人的手表示亲热。', 'Xiǎo gǒu yòng shétou tiǎn zhǔrén de shǒu biǎoshì qīnrè.', 'Chú chó nhỏ dùng lưỡi liếm tay chủ nhân để thể hiện sự thân thiết.'),
  ('脱离', '他努力工作，想脱离贫困的生活状态。', 'Tā nǔlì gōngzuò, xiǎng tuōlí pínkùn de shēnghuó zhuàngtài.', 'Anh ấy làm việc chăm chỉ, muốn tách rời khỏi tình trạng sống nghèo khó.'),
  ('统计', '我们需要统计今年的销售数据来分析市场趋势。', 'Wǒmen xūyào tǒngjì jīnnián de xiāoshòu shùjù lái fēnxī shìchǎng qūshì.', 'Chúng tôi cần thống kê dữ liệu bán hàng năm nay để phân tích xu hướng thị trường.'),
  ('统统', '老师说乱扔垃圾的人统统要接受处罚。', 'Lǎoshī shuō luàn rēng lājī de rén tǒngtǒng yào jiēshòu chǔfá.', 'Giáo viên nói những người vứt rác bừa bãi tất cả đều phải bị phạt.'),
  ('统筹兼顾', '这个项目需要统筹兼顾各种资源和时间安排。', 'Zhège xiàngmù xūyào tǒng chóu jiān gù gè zhǒng zīyuán hé shíjiān ānpái.', 'Dự án này cần tính toán mọi bề các nguồn lực và lịch trình thời gian.'),
  ('统治', '这个国家由一个强大的帝国统治了几个世纪。', 'Zhège guójiā yóu yīgè qiángdà de dìguó tǒng zhì le jǐ gè shìjì.', 'Quốc gia này đã bị một đế quốc hùng mạnh thống trị suốt vài thế kỷ.'),
  ('童话', '孩子们喜欢听奶奶讲各种有趣的童话故事。', 'Háizimen xǐhuān tīng nǎinai jiǎng gè zhǒng yǒuqù de tóng huà gùshì.', 'Bọn trẻ thích nghe bà kể các câu chuyện cổ tích thú vị.'),
  ('突破', '科学家在癌症研究中取得了重大突破。', 'Kēxuéjiā zài áizhèng yánjiū zhōng qǔdé le zhòngdà tū pò.', 'Các nhà khoa học đã đạt được đột phá lớn trong nghiên cứu ung thư.'),
  ('秃', '他年纪轻轻就开始秃顶，显得很特别。', 'Tā niánjì qīngqīng jiù kāishǐ tū dǐng, xiǎnde hěn tèbié.', 'Anh ấy còn trẻ tuổi mà đầu đã hói, trông rất đặc biệt.'),
  ('瘫痪', '事故使他的腿部瘫痪，不能再走路了。', 'Shìgù shǐ tā de tuǐbù tān huàn, bùnéng zài zǒulù le.', 'Tai nạn khiến chân anh ta bị bại liệt, không thể đi lại nữa.'),
  ('田野', '春天到了，田野里开满了各种美丽的花朵。', 'Chūntiān dào le, tiányě lǐ kāi mǎn le gè zhǒng měilì de huāduǒ.', 'Mùa xuân đến, đồng ruộng đầy hoa đẹp mọi nơi.'),
  ('田径', '他从小学开始就对田径运动非常感兴趣。', 'Tā cóng xiǎoxué kāishǐ jiù duì tián jìng yùndòng fēicháng gǎn xìngqù.', 'Từ tiểu học anh ấy đã rất quan tâm đến điền kinh.'),
  ('特长', '她的特长是绘画，作品多次获奖。', 'Tā de tè cháng shì huìhuà, zuòpǐn duō cì huò jiǎng.', 'Sở trường của cô ấy là hội họa, tác phẩm đã nhiều lần đoạt giải.'),
  ('特意', '他特意从外地赶来参加我们的聚会。', 'Tā tè yì cóng wàidì gǎnlái cānjiā wǒmen de jùhuì.', 'Anh ấy đặc biệt từ nơi khác vội vàng đến dự buổi họp mặt của chúng tôi.'),
  ('特定', '这批物资是专门为特定地区准备的。', 'Zhè pī wùzī shì zhuānmén wèi tè dìng dìqū zhǔnbèi de.', 'Lô vật资 này được chỉ định chuẩn bị riêng cho vùng đặc thù.'),
  ('滔滔不绝', '他对自己的经历滔滔不绝地讲了整整一个晚上。', 'Tā duì zìjǐ de jīnglì tāo tāo bù jué de jiǎng le zhěngzhěng yīgè wǎnshàng.', 'Anh ấy kể về kinh nghiệm của mình thao thao bất tuyệt suốt cả tối.'),
  ('淘汰', '这个比赛中，表现差的选手会被淘汰出局。', 'Zhège bǐsài zhōng, biǎoxiàn chà de xuǎnshǒu huì bèi táotài chūjú.', 'Trong cuộc thi này, các thí sinh có thành tích kém sẽ bị loại.'),
  ('涂抹', '医生嘱咐病人每天涂抹药膏三次。', 'Yīshēng zhǔfù bìngrén měitiān túmǒ yàogāo sān cì.', 'Bác sĩ dặn bệnh nhân mỗi ngày bôi thuốc mỡ ba lần.'),
  ('泰斗', '他被誉为文学界的泰斗，影响深远。', 'Tā bèi yù wéi wénxué jiè de tài dǒu, yǐngxiǎng shēnyuǎn.', 'Ông được ca ngợi là bậc thầy trong giới văn học, ảnh hưởng sâu rộng.'),
  ('椭圆', '运动场的跑道设计成椭圆形，方便运动员训练。', 'Yùndòng chǎng de pǎodào shèjì chéng tuǒ yuán xíng, fāngbiàn yùndòngyuán xùnliàn.', 'Đường chạy của sân vận động được thiết kế hình bầu dục, tiện cho vận động viên tập luyện.'),
  ('条约', '两国签署了一项和平条约，结束了长期冲突。', 'Liǎng guó qiānshǔ le yī xiàng hépíng tiáoyuē, jiéshù le chángqí chōngtū.', 'Hai nước đã ký một hiệp ước hòa bình, chấm dứt xung đột lâu dài.'),
  ('条理', '他讲课思路清晰，条理非常分明。', 'Tā jiǎngkè sīlù qīngxī, tiáolǐ fēicháng fēnmíng.', 'Anh ấy giảng bài có suy nghĩ rõ ràng, trật tự rất mạch lạc.'),
  ('条款', '合同中的条款必须仔细阅读，避免纠纷。', 'Hétóng zhōng de tiáokuǎn bìxū zǐxì yuèdú, bìmiǎn jiūfēn.', 'Các điều khoản trong hợp đồng phải đọc kỹ để tránh tranh chấp.'),
  ('摊', '周末市场上有很多小贩摆着各种各样的摊位。', 'Zhōumò shìchǎng shàng yǒu hěnduō xiǎofàn bǎi zhe gè zhǒng gè yàng de tānwèi.', 'Chợ cuối tuần có nhiều người bán hàng bày các loại sạp khác nhau.'),
  ('提议', '会议上他提出了一个建设性的提议，获得大家认可。', 'Huìyì shàng tā tíchūle yīgè jiànshèxìng de tíyì, huòdé dàjiā rènkě.', 'Trong cuộc họp, anh ấy đã đề nghị một đề xuất xây dựng và được mọi người đồng ý.'),
  ('提示', '系统自动提示用户更新软件以提高安全性。', 'Xìtǒng zìdòng tíshì yònghù gēngxīn ruǎnjiàn yǐ tígāo ānquán xìng.', 'Hệ thống tự động đưa ra lời nhắc người dùng cập nhật phần mềm để tăng tính bảo mật.'),
  ('提炼', '这座工厂主要负责从原油中提炼高品质的汽油。', 'Zhè zuò gōngchǎng zhǔyào fùzé cóng yuányóu zhōng tíliàn gāo pǐnzhí de qìyóu.', 'Nhà máy này chủ yếu phụ trách lọc xăng chất lượng cao từ dầu thô.'),
  ('提拔', '公司决定提拔表现优秀的员工担任管理职位。', 'Gōngsī juédìng tíbá biǎoxiàn yōuxiù de yuángōng dānrèn guǎnlǐ zhíwèi.', 'Công ty quyết định đề bạt những nhân viên có thành tích xuất sắc giữ vị trí quản lý.'),
  ('推销', '他每天都会去不同的商店推销自家的产品。', 'Tā měitiān dūhuì qù bùtóng de shāngdiàn tuīxiāo zìjiā de chǎnpǐn.', 'Hàng ngày anh ta đều đến các cửa hàng khác nhau để bán sản phẩm của gia đình.'),
  ('推论', '根据现有的数据，我们可以推论出市场将会增长。', 'Gēnjù xiàn yǒu de shùjù, wǒmen kěyǐ tuīlùn chū shìchǎng jiāng huì zēngzhǎng.', 'Dựa trên dữ liệu hiện có, chúng ta có thể suy luận thị trường sẽ tăng trưởng.'),
  ('推翻', '这项新证据足以推翻之前的结论。', 'Zhè xiàng xīn zhèngjù zúyǐ tuīfān zhīqián de jiélùn.', 'Bằng chứng mới này đủ để lật đổ kết luận trước đó.'),
  ('推理', '侦探通过细致的推理找到了真正的罪犯。', 'Zhēntàn tōngguò xìzhì de tuīlǐ zhǎodàole zhēnzhèng de zuìfàn.', 'Thám tử đã tìm ra tội phạm thật sự thông qua suy lý tỉ mỉ.'),
  ('推测', '我们可以推测天气明天会更加寒冷。', 'Wǒmen kěyǐ tuīcè tiānqì míngtiān huì gèngjiā hánlěng.', 'Chúng ta có thể suy đoán thời tiết ngày mai sẽ lạnh hơn.'),
  ('探讨', '专家们正在探讨环境保护的新方法。', 'Zhuānjiāmen zhèngzài tàntǎo huánjìng bǎohù de xīn fāngfǎ.', 'Các chuyên gia đang thảo luận về phương pháp mới bảo vệ môi trường.'),
  ('探索', '科学家不断探索宇宙的奥秘。', 'Kēxuéjiā bùduàn tànsuǒ yǔzhòu de àomì.', 'Các nhà khoa học không ngừng khám phá bí mật của vũ trụ.'),
  ('探测', '卫星可以探测地球表面的温度变化。', 'Wèixīng kěyǐ tàncè dìqiú biǎomiàn de wēndù biànhuà.', 'Vệ tinh có thể thăm dò sự thay đổi nhiệt độ bề mặt Trái Đất.'),
  ('探望', '节日期间他特地去医院探望了生病的祖母。', 'Jiérì qījiān tā tèdì qù yīyuàn tànwàngle shēngbìng de zǔmǔ.', 'Trong dịp lễ, anh ấy đặc biệt đi thăm bà bệnh viện.'),
  ('掏', '他从口袋里掏出手机给我看。', 'Tā cóng kǒudài lǐ tāo chū shǒujī gěi wǒ kàn.', 'Anh ấy móc điện thoại ra từ túi để cho tôi xem.'),
  ('挺拔', '这里的松树高大挺拔，风景非常美丽。', 'Zhèlǐ de sōngshù gāodà tǐngbá, fēngjǐng fēicháng měilì.', 'Những cây thông ở đây cao lớn và thẳng tắp, cảnh quan rất đẹp.'),
  ('挑衅', '他故意挑衅对手，导致了激烈的争吵。', 'Tā gùyì tiǎoxìn duìshǒu, dǎozhìle jīliè de zhēngchǎo.', 'Anh ta cố ý khiêu khích đối thủ dẫn đến cuộc cãi cọ dữ dội.'),
  ('挑拨', '不要相信他们的谣言，以免被挑拨离间。', 'Bùyào xiāngxìn tāmen de yáoyán, yǐmiǎn bèi tiāobō líjiàn.', 'Đừng tin tin đồn của họ để tránh bị chọc phá gây chia rẽ.'),
  ('挑剔', '他对食物非常挑剔，总是不满意。', 'Tā duì shíwù fēicháng tiāotì, zǒng shì bù mǎnyì.', 'Anh ấy rất kén ăn, luôn luôn không hài lòng với thức ăn.'),
  ('拖延', '因为不断拖延，项目最终没能按时完成。', 'Yīnwèi bùduàn tuōyán, xiàngmù zuìzhōng méi néng ànshí wánchéng.', 'Bởi vì liên tục kéo dài, dự án cuối cùng không thể hoàn thành đúng hạn.'),
  ('投降', '面对强大的敌人，士兵们最终选择了投降。', 'Miànduì qiángdà de dírén, shìbīngmen zuìzhōng xuǎnzéle tóuxiáng.', 'Đối mặt với kẻ thù mạnh mẽ, các binh lính cuối cùng đã chọn đầu hàng.'),
  ('投诉', '如果服务不满意，客户可以提出投诉来维护自己的权益。', 'Rúguǒ fúwù bù mǎnyì, kèhù kěyǐ tíchū tóusù lái wéihù zìjǐ de quányì.', 'Nếu dịch vụ không hài lòng, khách hàng có thể khiếu nại để bảo vệ quyền lợi của mình.'),
  ('投票', '所有公民都有权利参加选举并投票决定领导人。', 'Suǒyǒu gōngmín dōu yǒu quánlì cānjiā xuǎnjǔ bìng tóupiào juédìng lǐngdǎo rén.', 'Tất cả công dân đều có quyền tham gia bầu cử và bỏ phiếu quyết định lãnh đạo.'),
  ('投机', '他们两个在生意上很投机，合作非常愉快。', 'Tāmen liǎng gè zài shēngyì shàng hěn tóujī, hézuò fēicháng yúkuài.', 'Hai người họ rất hiểu nhau trong kinh doanh, hợp tác rất vui vẻ.'),
  ('投掷', '运动员投掷标枪时需要注意姿势和力量的平衡。', 'Yùndòngyuán tóuzhì biāoqiāng shí xūyào zhùyì zīshì hé lìliàng de pínghéng.', 'Vận động viên ném giáo khi thi đấu cần chú ý tư thế và sự cân bằng lực.'),
  ('托运', '我在机场将行李托运到目的地，方便出行。', 'Wǒ zài jīchǎng jiāng xínglǐ tuōyùn dào mùdì dì, fāngbiàn chūxíng.', 'Tôi đã ủy thác vận chuyển hành lý đến nơi đến tại sân bay để tiện cho việc đi lại.'),
  ('徒弟', '师傅耐心教导徒弟掌握烹饪的技巧和经验。', 'Shīfù nàixīn jiàodǎo túdì zhǎngwò pēngrèn de jìqiǎo hé jīngyàn.', 'Thầy cẩn thận dạy đồ đệ thành thạo kỹ năng và kinh nghiệm nấu nướng.'),
  ('弹性', '这种材料具有很好的弹性，可以反复拉伸而不断裂。', 'Zhè zhǒng cáiliào jùyǒu hěn hǎo de tánxìng, kěyǐ fǎnfù lāshēn ér bù duànliè.', 'Loại vật liệu này có tính đàn hồi rất tốt, có thể kéo giãn nhiều lần mà không bị đứt.'),
  ('妥当', '为了保障安全，我们必须制定妥当的应急预案。', 'Wèile bǎozhàng ānquán, wǒmen bìxū zhìdìng tuǒdàng de yìngjí yù''àn.', 'Để đảm bảo an toàn, chúng ta phải đưa ra phương án ứng phó thỏa đáng.'),
  ('妥善', '请妥善保管好个人身份证件，避免丢失带来麻烦。', 'Qǐng tuǒshàn bǎoguǎn hǎo gèrén shēnfèn zhèngjiàn, bìmiǎn diūshī dàilái máfan.', 'Xin vui lòng giữ gìn giấy tờ tùy thân một cách ổn thỏa để tránh rắc rối do mất mát.'),
  ('妥协', '双方经过多次磋商，终于达成了妥协协议。', 'Shuāngfāng jīngguò duō cì cuōshāng, zhōngyú dáchéngle tuǒxié xiéyì.', 'Hai bên sau nhiều lần thương lượng cuối cùng đã đi đến thỏa hiệp.'),
  ('太空', '人类探索太空的历史已经超过半个世纪。', 'Rénlèi tànsuǒ tàikōng de lìshǐ yǐjīng chāoguò bàn gè shìjì.', 'Lịch sử con người khám phá vũ trụ đã vượt quá nửa thế kỷ.'),
  ('天赋', '她从小就展现了音乐方面的天赋。', 'Tā cóng xiǎo jiù zhǎnxiànle yīnyuè fāngmiàn de tiānfù.', 'Cô ấy từ nhỏ đã thể hiện năng khiếu về âm nhạc.'),
  ('天生', '他天生具有领导才能，在团队中很受尊重。', 'Tā tiānshēng jùyǒu lǐngdǎo cáinéng, zài tuánduì zhōng hěn shòu zūnzhòng.', 'Anh ta bẩm sinh có tài năng lãnh đạo, rất được tôn trọng trong đội nhóm.'),
  ('天然气', '我国正在大力开发和利用天然气资源。', 'Wǒguó zhèngzài dàlì kāifā hé lìyòng tiānránqì zīyuán.', 'Nước ta đang mạnh mẽ khai thác và sử dụng nguồn khí đốt tự nhiên.'),
  ('天文', '天文学家通过望远镜观测星体的运动轨迹。', 'Tiānwén xuéjiā tōngguò wàngyuǎnjìng guāncè xīngtǐ de yùndòng guǐjì.', 'Các nhà thiên văn học quan sát quỹ đạo chuyển động của thiên thể qua kính viễn vọng.'),
  ('天才', '他被誉为数学天才，解决了很多复杂的问题。', 'Tā bèi yùwéi shùxué tiāncái, jiějuéle hěn duō fùzá de wèntí.', 'Anh ta được ca ngợi là thiên tài toán học, đã giải quyết nhiều vấn đề phức tạp.'),
  ('天堂', '很多人相信去世后灵魂会进入天堂安息。', 'Hěn duō rén xiāngxìn qùshì hòu línghún huì jìnrù tiāntáng ānxī.', 'Nhiều người tin rằng linh hồn sẽ vào thiên đường an nghỉ sau khi mất.'),
  ('天伦之乐', '节假日期间，大家享受着天伦之乐，团聚一堂。', 'Jiéjiàrì qījiān, dàjiā xiǎngshòu zhe tiānlún zhī lè, tuánjù yītáng.', 'Trong kỳ nghỉ lễ, mọi người tận hưởng hạnh phúc gia đình, sum họp cùng nhau.'),
  ('塔', '这座古老的塔见证了城市的发展和变迁。', 'Zhè zuò gǔlǎo de tǎ jiànzhèngle chéngshì de fāzhǎn hé biànqiān.', 'Ngọn tháp cổ này chứng kiến sự phát triển và thay đổi của thành phố.'),
  ('塌', '由于地震，部分建筑物出现了塌陷的情况。', 'Yóuyú dìzhèn, bùfèn jiànzhùwù chūxiànle tāxiàn de qíngkuàng.', 'Do động đất, một số công trình xây dựng đã bị sập đổ.'),
  ('坦白', '我决定向他坦白所有的事实真相。', 'Wǒ juédìng xiàng tā tǎnbái suǒyǒu de shìshí zhēnxiàng.', 'Tôi quyết định thẳng thắn nói với anh ấy mọi sự thật.'),
  ('土壤', '这里的土壤非常肥沃，适合种植水果。', 'Zhèlǐ de tǔrǎng fēicháng féiwò, shìhé zhòngzhí shuǐguǒ.', 'Đất ở đây rất màu mỡ, thích hợp để trồng trái cây.'),
  ('图案', '这件衣服的图案设计得很精致独特。', 'Zhè jiàn yīfu de tú''àn shèjì dé hěn jīngzhì dútè.', 'Hình vẽ trên chiếc áo này được thiết kế rất tinh xảo và độc đáo.'),
  ('团结', '只有大家团结一致，才能克服所有困难。', 'Zhǐyǒu dàjiā tuánjié yīzhì, cáinéng kèfú suǒyǒu kùnnán.', 'Chỉ có mọi người đoàn kết nhất trí, mới có thể vượt qua mọi khó khăn.'),
  ('团圆', '春节是家人团圆的最重要节日。', 'Chūnjié shì jiārén tuányuán de zuì zhòngyào jiérì.', 'Tết Nguyên Đán là ngày lễ quan trọng nhất để gia đình đoàn viên.'),
  ('团体', '这个团体专注于环保事业的发展。', 'Zhège tuántǐ zhuānzhù yú huánbǎo shìyè de fāzhǎn.', 'Đoàn thể này chuyên chú vào sự phát triển của công việc bảo vệ môi trường.'),
  ('唾弃', '他因为欺骗被朋友们唾弃。', 'Tā yīnwèi qīpiàn bèi péngyǒumen tuòqì.', 'Anh ta bị bạn bè nhổ vào mặt vì đã lừa dối.'),
  ('吞吞吐吐', '面对重要问题，他总是吞吞吐吐说不清。', 'Miànduì zhòngyào wèntí, tā zǒng shì tūn tūn tǔ tǔ shuō bù qīng.', 'Đối mặt với vấn đề quan trọng, anh ấy lúc nào cũng lắp bắp nói không rõ.'),
  ('同胞', '在国外，我们都应该互相关怀同胞。', 'Zài guówài, wǒmen dōu yīnggāi hùxiāng guānhuái tóngbāo.', 'Ở nước ngoài, chúng ta đều nên quan tâm lẫn nhau, đồng bào cùng chung một tổ quốc.'),
  ('同志', '革命时期，同志之间的信任至关重要。', 'Gémìng shíqī, tóngzhì zhī jiān de xìnrèn zhìguān zhòngyào.', 'Thời kỳ cách mạng, sự tin tưởng giữa các đồng chí vô cùng quan trọng.'),
  ('叹气', '听到坏消息，他忍不住长长地叹气。', 'Tīngdào huài xiāoxi, tā rěn bù zhù cháng cháng de tànqì.', 'Nghe tin xấu, anh ấy không nhịn được thở dài dài.'),
  ('台风', '预报说明天将有强台风登陆沿海地区。', 'Yùbào shuō míngtiān jiāng yǒu qiáng táifēng dēnglù yánhǎi dìqū.', 'Bản tin dự báo ngày mai sẽ có một cơn bão mạnh đổ bộ vào vùng ven biển.'),
  ('停顿', '他说话中间有一点停顿，显得很犹豫。', 'Tā shuōhuà zhōngjiān yǒu yīdiǎn tíngdùn, xiǎnde hěn yóuyù.', 'Anh ấy nói chuyện giữa chừng có chút ngừng lại, trông rất do dự.'),
  ('停滞', '经济发展因为政策问题出现了明显停滞。', 'Jīngjì fāzhǎn yīnwèi zhèngcè wèntí chūxiànle míngxiǎn tíngzhì.', 'Phát triển kinh tế đã出现明显的停滞 do vấn đề chính sách.'),
  ('停泊', '这艘船停泊在港口已经三天了。', 'Zhè sōu chuán tíngbó zài gǎngkǒu yǐjīng sān tiān le.', 'Con tàu này đã cập bến cảng ba ngày rồi.'),
  ('倘若', '倘若明天下雨，比赛将会推迟进行。', 'Tǎngruò míngtiān xiàyǔ, bǐsài jiāng huì tuīchí jìnxíng.', 'Nếu ngày mai mưa, trận đấu sẽ bị hoãn lại.'),
  ('体面', '他为家里争了很多体面的荣誉。', 'Tā wèi jiālǐ zhēng le hěn duō tǐmiàn de róngyù.', 'Anh ấy đã giành được nhiều vinh dự thể diện cho gia đình.'),
  ('体谅', '希望你能体谅我的难处，给我一些时间。', 'Xīwàng nǐ néng tǐliàng wǒ de nánchù, gěi wǒ yīxiē shíjiān.', 'Hy vọng bạn có thể lượng thứ cho khó khăn của tôi, cho tôi thêm chút thời gian.'),
  ('体裁', '这篇文章的体裁属于现代散文类型。', 'Zhè piān wénzhāng de tǐcái shǔyú xiàndài sǎnwén lèixíng.', 'Thể loại của bài văn này thuộc loại văn xuôi hiện đại.'),
  ('体系', '教育体系的改革需要长期的努力和投资。', 'Jiàoyù tǐxì de gǎigé xūyào chángqī de nǔlì hé tóuzī.', 'Cải cách hệ thống giáo dục cần phải có sự nỗ lực và đầu tư lâu dài.'),
  ('体积', '这个箱子的体积比那个大很多，装得更多。', 'Zhè ge xiāngzi de tǐjī bǐ nà ge dà hěn duō, zhuāng de gèng duō.', 'Thể tích của chiếc hộp này lớn hơn rất nhiều so với cái kia, chứa được nhiều hơn.'),
  ('亭子', '公园中间有一个漂亮的亭子，供人们避雨休息。', 'Gōng yuán zhōng jiān yǒu yí ge piàoliang de tíngzi, gōng rénmen bì yǔ xiūxí.', 'Ở giữa công viên có một cái đình đẹp để mọi người trú mưa và nghỉ ngơi.'),
  ('顽强', '他在比赛中表现出非常顽强的精神，最终赢得了胜利。', 'Tā zài bǐ sài zhōng biǎo xiàn chū fēicháng wán qiáng de jīng shén, zuìzhōng yíngdé le shènglì.', 'Anh ấy thể hiện tinh thần vô cùng ngoan cường trong trận đấu và cuối cùng giành chiến thắng.'),
  ('顽固', '他对改变自己的意见非常顽固，几乎听不进去别人的建议。', 'Tā duì gǎi biàn zìjǐ de yìjiàn fēicháng wángù, jīhū tīng bù jìnqù biérén de jiànyì.', 'Anh ấy rất ngoan cố đối với việc thay đổi ý kiến của mình, gần như không nghe lời khuyên của người khác.'),
  ('问世', '这本新书将在下个月正式问世，期待读者的反响。', 'Zhè běn xīn shū jiāng zài xià ge yuè zhèngshì wènshì, qídài dúzhě de fǎnxiǎng.', 'Cuốn sách mới này sẽ chính thức ra mắt vào tháng tới, mong đợi phản ứng của độc giả.'),
  ('违背', '他的行为违背了公司的规定，必须接受相应的处罚。', 'Tā de xíngwéi wéi bèi le gōngsī de guīdìng, bìxū jiēshòu xiāngyìng de chǔfá.', 'Hành vi của anh ta vi phạm quy định của công ty, phải chịu hình phạt tương ứng.'),
  ('误解', '沟通不畅常常导致误解，影响人际关系。', 'Gōutōng bù chàng chángcháng dǎozhì wùjiě, yǐngxiǎng rénjì guānxì.', 'Giao tiếp không thông suốt thường dẫn đến hiểu lầm, ảnh hưởng đến mối quan hệ giữa người với người.'),
  ('误差', '测量结果存在一定的误差，需要进行校正。', 'Cèliáng jiéguǒ cúnzài yí dìng de wùchā, xūyào jìnxíng jiàozhèng.', 'Kết quả đo có một sai số nhất định, cần phải hiệu chỉnh.'),
  ('诬陷', '他被老板诬陷犯了错误，实际上是无辜的。', 'Tā bèi lǎobǎn wūxiàn fàn le cuòwù, shíjì shàng shì wúgū de.', 'Anh ta bị sếp hãm hại phạm sai lầm, thực tế anh ta vô tội.'),
  ('蔚蓝', '海面在阳光下显得格外蔚蓝，非常美丽。', 'Hǎimiàn zài yángguāng xià xiǎnde géwài wèilán, fēicháng měilì.', 'Mặt biển dưới ánh nắng trông rất xanh da trời, rất đẹp.'),
  ('舞蹈', '她从小学习舞蹈，动作优雅且充满力量。', 'Tā cóng xiǎo xuéxí wǔdǎo, dòngzuò yōuyǎ qiě chōngmǎn lìliàng.', 'Cô ấy học múa từ nhỏ, động tác vừa uyển chuyển vừa mạnh mẽ.'),
  ('维生素', '水果和蔬菜是维生素的重要来源，必须合理摄取。', 'Shuǐguǒ hé shūcài shì wéishēngsù de zhòngyào láiyuán, bìxū hélǐ shèqǔ.', 'Trái cây và rau củ là nguồn cung cấp vitamin quan trọng, phải hấp thụ hợp lý.'),
  ('维持', '为了健康，我们需要维持良好的生活习惯。', 'Wèile jiànkāng, wǒmen xūyào wéichí liánghǎo de shēnghuó xíguàn.', 'Để khỏe mạnh, chúng ta cần duy trì thói quen sinh hoạt tốt.'),
  ('维护', '政府应当采取措施维护社会的公平和正义。', 'Zhèngfǔ yīngdāng cǎiqǔ cuòshī wéihù shèhuì de gōngpíng hé zhèngyì.', 'Chính phủ nên có biện pháp bảo vệ công bằng và công lý xã hội.'),
  ('窝', '小鸟飞回了它温暖的窝里，安心休息。', 'Xiǎo niǎo fēi huí le tā wēnnuǎn de wō lǐ, ānxīn xiūxí.', 'Chú chim nhỏ bay về tổ ấm của nó và nghỉ ngơi yên tâm.'),
  ('畏惧', '面对困难，他从不畏惧，总是勇敢前行。', 'Miànduì kùnnan, tā cóng bù wèijù, zǒng shì yǒnggǎn qiánxíng.', 'Đối mặt với khó khăn, anh ấy không bao giờ sợ hãi, luôn tiến về phía trước dũng cảm.'),
  ('瓦解', '由于内部矛盾严重，团队最终瓦解了。', 'Yóuyú nèibù máodùn yánzhòng, tuánduì zuìzhōng wǎjiě le.', 'Do mâu thuẫn nội bộ nghiêm trọng, nhóm cuối cùng tan rã.'),
  ('玩意儿', '这是一种新型的电子玩意儿，功能非常强大。', 'Zhè shì yì zhǒng xīnxíng de diànzǐ wányìr, gōngnéng fēicháng qiángdà.', 'Đây là một thứ đồ chơi điện tử kiểu mới, chức năng rất mạnh mẽ.'),
  ('玩弄', '他喜欢玩弄文字技巧，让文章更生动有趣。', 'Tā xǐhuan wánnòng wénzì jìqiǎo, ràng wénzhāng gèng shēngdòng yǒuqù.', 'Anh ấy thích chơi đùa với kỹ thuật chữ nghĩa làm cho bài viết sinh động và thú vị hơn.'),
  ('物资', '灾区急需各种救援物资，包括食物和药品。', 'Zāiqū jíxū gè zhǒng jiùyuán wùzī, bāokuò shíwù hé yàopǐn.', 'Khu vực thiên tai rất cần các vật tư cứu trợ đa dạng, bao gồm thực phẩm và thuốc men.'),
  ('物美价廉', '这家商店的商品物美价廉，深受顾客喜爱。', 'Zhè jiā shāngdiàn de shāngpǐn wù měi jià lián, shēn shòu gùkè xǐ''ài.', 'Hàng hóa ở cửa hàng này hàng đẹp giá rẻ, được khách hàng rất yêu thích.'),
  ('物业', '我们小区的物业管理服务非常专业又细致。', 'Wǒmen xiǎoqū de wùyè guǎnlǐ fúwù fēicháng zhuānyè yòu xìzhì.', 'Dịch vụ quản lý sản nghiệp của khu dân cư chúng tôi rất chuyên nghiệp và tỉ mỉ.'),
  ('温带', '温带气候适合各种水果和蔬菜的生长。', 'Wēndài qìhòu shìhé gè zhǒng shuǐguǒ hé shūcài de shēngzhǎng.', 'Khí hậu ôn đới thích hợp cho sự phát triển của nhiều loại trái cây và rau củ.'),
  ('温和', '老师的性格温和，让学生们感到很亲切。', 'Lǎoshī de xìnggé wēnhé, ràng xuéshēng men gǎndào hěn qīnqiè.', 'Tính cách của thầy giáo rất ôn hòa, khiến học sinh cảm thấy rất thân thiện.'),
  ('污蔑', '他被人污蔑成贪污犯，但他坚决否认指控。', 'Tā bèi rén wūmiè chéng tānwūfàn, dàn tā jiānjué fǒurèn zhǐkòng.', 'Anh ta bị người ta phỉ báng thành kẻ tham nhũng, nhưng anh ta kiên quyết phủ nhận cáo buộc.'),
  ('歪曲', '媒体不能歪曲事实，必须保持客观公正。', 'Méitǐ bùnéng wāiqū shìshí, bìxū bǎochí kèguān gōngzhèng.', 'Truyền thông không thể xuyên tạc sự thật, phải giữ thái độ khách quan và công bằng.'),
  ('武装', '军队不断武装自己，准备应对各种挑战。', 'Jūn duì bùduàn wǔzhuāng zìjǐ, zhǔnbèi yìngduì gè zhǒng tiǎozhàn.', 'Quân đội không ngừng vũ trang bản thân, chuẩn bị đối phó với các thử thách.'),
  ('武器', '禁止非法携带武器进入公共场所是法律规定。', 'Jìnzhǐ fēifǎ xiédài wǔqì jìnrù gōnggòng chǎngsuǒ shì fǎlǜ guīdìng.', 'Pháp luật quy định nghiêm cấm mang vũ khí trái phép vào nơi công cộng.'),
  ('武侠', '他很喜欢阅读武侠小说，对其中的江湖世界充满向往。', 'Tā hěn xǐhuān yuèdú wǔxiá xiǎoshuō, duì qízhōng de jiānghú shìjiè chōngmǎn xiàngwǎng.', 'Anh ấy rất thích đọc tiểu thuyết võ hiệp, đầy mong mỏi về thế giới giang hồ trong đó.'),
  ('未免', '你这样说话未免有些太过分了，需要注意分寸。', 'Nǐ zhèyàng shuōhuà wèimiǎn yǒuxiē tài guòfèn le, xūyào zhùyì fēncùn.', 'Bạn nói như vậy thì tránh khỏi quá đáng rồi, cần chú ý giới hạn.'),
  ('无非', '他的观点无非是希望大家共同努力，改善环境。', 'Tā de guāndiǎn wúfēi shì xīwàng dàjiā gòngtóng nǔlì, gǎishàn huánjìng.', 'Quan điểm của anh ta chẳng qua là hy vọng mọi người cùng nỗ lực cải thiện môi trường.'),
  ('无辜', '那些无辜的平民不应该成为战争的牺牲品。', 'Nàxiē wúgū de píngmín bù yīnggāi chéngwéi zhànzhēng de xīshēngpǐn.', 'Những thường dân vô tội không nên trở thành vật hy sinh của chiến tranh.'),
  ('无赖', '他经常耍无赖，欺负弱小，让人讨厌。', 'Tā jīngcháng shuǎ wúlài, qīfù ruòxiǎo, ràng rén tǎoyàn.', 'Anh ta thường xuyên làm trò vô lại, bắt nạt kẻ yếu, khiến người khác khó chịu.'),
  ('无能为力', '面对自然灾害，我们有时感到无能为力，只能祈祷平安。', 'Miànduì zìrán zāihài, wǒmen yǒushí gǎndào wúnéngwéilì, zhǐ néng qídǎo píng''ān.', 'Đối mặt với thiên tai, đôi khi chúng ta cảm thấy bất lực, chỉ biết cầu mong bình an.'),
  ('无耻', '这种无耻的行为破坏了社会的道德底线。', 'Zhè zhǒng wúchǐ de xíngwéi pòhuài le shèhuì de dàodé dǐxiàn.', 'Hành vi vô liêm sỉ này đã phá hoại chuẩn mực đạo đức xã hội.'),
  ('无精打采', '他最近因为生病，整天看起来无精打采。', 'Tā zuìjìn yīnwèi shēngbìng, zhěng tiān kàn qǐlái wú jīng dǎ cǎi.', 'Gần đây anh ấy vì bệnh nên cả ngày trông mặt mày ủ rũ.'),
  ('无穷无尽', '宇宙的奥秘似乎无穷无尽，等待人类去探索。', 'Yǔzhòu de àomì sìhū wúqióng wújìn, děngdài rénlèi qù tànsuǒ.', 'Thần bí của vũ trụ dường như vô cùng vô tận, chờ con người khám phá.'),
  ('无知', '对历史无知的人容易被错误的观点误导。', 'Duì lìshǐ wúzhī de rén róngyì bèi cuòwù de guāndiǎn wùdǎo.', 'Người không biết về lịch sử dễ bị dẫn dắt bởi những quan điểm sai lầm.'),
  ('无理取闹', '他经常因为一点小事无理取闹，大家都不愿意理他。', 'Tā jīngcháng yīnwèi yī diǎn xiǎoshì wúlǐ qǔ nào, dàjiā dōu bù yuànyì lǐ tā.', 'Anh ấy thường vô cớ gây sự vì chút việc nhỏ, mọi người đều không muốn để ý.'),
  ('无比', '母亲对孩子的爱是无比深厚和无私的。', 'Mǔqīn duì háizi de ài shì wúbǐ shēnhòu hé wúsī de.', 'Tình yêu của mẹ dành cho con là vô cùng sâu sắc và cao thượng.'),
  ('无忧无虑', '小孩子在花园里快乐地玩耍，显得无忧无虑。', 'Xiǎo háizi zài huāyuán lǐ kuàilè de wánshuǎ, xiǎnde wú yōu wú lǜ.', 'Đứa trẻ vui vẻ chơi đùa trong vườn hoa, trông thật vô lo vô nghĩ.'),
  ('无微不至', '她对爷爷奶奶的照顾无微不至，令人感动。', 'Tā duì yéyé nǎinai de zhàogù wú wēi bù zhì, lìng rén gǎndòng.', 'Cô ấy chăm sóc ông bà chu đáo tỉ mỉ khiến mọi người cảm động.'),
  ('无动于衷', '面对朋友的困难，他竟然无动于衷，毫无帮助。', 'Miànduì péngyǒu de kùnnán, tā jìngrán wú dòng yú zhōng, háo wú bāngzhù.', 'Đối mặt với khó khăn của bạn, anh ta thờ ơ, không chút giúp đỡ.'),
  ('无偿', '他无偿为社区居民提供法律咨询服务。', 'Tā wú cháng wèi shèqū jūmín tígōng fǎlǜ zīxún fúwù.', 'Anh ấy cung cấp dịch vụ tư vấn pháp luật cho cư dân cộng đồng mà không hoàn lại.'),
  ('文雅', '她的言谈举止非常文雅，给人好印象。', 'Tā de yántán jǔzhǐ fēicháng wényǎ, gěi rén hǎo yìnxiàng.', 'Lời nói và cử chỉ của cô ấy rất nho nhã, để lại ấn tượng tốt cho mọi người.'),
  ('文艺', '学校每年都会举办一次大型的文艺演出。', 'Xuéxiào měi nián dōu huì jǔbàn yīcì dàxíng de wényì yǎnchū.', 'Trường học mỗi năm đều tổ chức một buổi biểu diễn văn nghệ lớn.'),
  ('文献', '为了写论文，他查阅了大量的历史文献。', 'Wèile xiě lùnwén, tā cháyuèle dàliàng de lìshǐ wénxiàn.', 'Để viết luận văn, anh ấy đã tra cứu rất nhiều tài liệu lịch sử.'),
  ('文物', '博物馆里收藏了许多珍贵的文物。', 'Bówùguǎn lǐ shōucángle xǔduō zhēnguì de wénwù.', 'Bảo tàng lưu giữ nhiều văn vật quý giá.'),
  ('文凭', '他通过努力考取了名牌大学的学士文凭。', 'Tā tōngguò nǔlì kǎoqǔle míngpái dàxué de xuéshì wénpíng.', 'Anh ấy đã nỗ lực để lấy được văn bằng cử nhân của trường đại học danh tiếng.'),
  ('挽救', '医生们尽力挽救了许多危重病人的生命。', 'Yīshēngmen jìnlì wǎnjiùle xǔduō wēizhòng bìngrén de shēngmìng.', 'Các bác sĩ đã cố gắng cứu vớt sinh mạng của nhiều bệnh nhân nguy kịch.'),
  ('挽回', '他努力挽回破裂的友谊，关系逐渐改善。', 'Tā nǔlì wǎnhuí pòliè de yǒuyì, guānxì zhújiàn gǎishàn.', 'Anh ấy cố gắng cứu vãn tình bạn đổ vỡ, mối quan hệ dần được cải thiện.'),
  ('挖掘', '考古学家在古墓中挖掘出许多珍贵的文物。', 'Kǎogǔ xuéjiā zài gǔ mù zhōng wājué chū xǔduō zhēnguì de wénwù.', 'Nhà khảo cổ học đã khai quật ra nhiều văn vật quý giá trong ngôi mộ cổ.'),
  ('慰问', '节日期间，公司派代表去医院慰问病人。', 'Jiérì qíjiān, gōngsī pài dàibiǎo qù yīyuàn wèiwèn bìngrén.', 'Trong dịp lễ, công ty cử đại diện đến bệnh viện thăm hỏi bệnh nhân.'),
  ('惋惜', '大家都惋惜这位优秀老师的离开。', 'Dàjiā dōu wǎnxī zhè wèi yōuxiù lǎoshī de líkāi.', 'Mọi người đều thương tiếc sự ra đi của thầy giáo xuất sắc này.'),
  ('微观', '科学家通过显微镜观察细胞的微观结构。', 'Kēxuéjiā tōngguò xiǎnwēijìng guānchá xìbāo de wēiguān jiégòu.', 'Các nhà khoa học quan sát cấu trúc vi mô của tế bào qua kính hiển vi.'),
  ('微不足道', '他所犯的错误其实微不足道，不必太在意。', 'Tā suǒ fàn de cuòwù qíshí wēi bù zú dào, bùbì tài zàiyì.', 'Những lỗi anh ta phạm ra thực ra không đáng để nhắc tới, không cần phải bận tâm quá.'),
  ('往常', '这家店的生意往常非常好，今年却有所下降。', 'Zhè jiā diàn de shēngyì wǎngcháng fēicháng hǎo, jīnnián què yǒu suǒ xiàjiàng.', 'Kinh doanh cửa hàng này mọi khi rất tốt, nhưng năm nay lại có phần giảm sút.'),
  ('往事', '他常常回忆起童年的往事，感慨万分。', 'Tā chángcháng huíyì qǐ tóngnián de wǎngshì, gǎnkǎi wànfēn.', 'Anh ấy thường nghĩ về chuyện trước kia của thời thơ ấu, cảm xúc dâng trào.'),
  ('完毕', '会议已经完毕，大家可以自由离开。', 'Huìyì yǐjīng wánbì, dàjiā kěyǐ zìyóu líkāi.', 'Cuộc họp đã hoàn tất, mọi người có thể tự do ra về.'),
  ('完备', '项目资料必须完备，才能顺利通过审批。', 'Xiàngmù zīliào bìxū wánbèi, cáinéng shùnlì tōngguò shěnpī.', 'Tài liệu dự án phải chuẩn bị đầy đủ mới có thể thuận lợi thông qua phê duyệt.'),
  ('娃娃', '她给孩子买了一个漂亮的娃娃作为生日礼物。', 'Tā gěi háizi mǎi le yí gè piàoliang de wáwa zuòwéi shēngrì lǐwù.', 'Cô ấy mua cho đứa trẻ một con búp bê xinh đẹp làm quà sinh nhật.'),
  ('威风', '他帅气的样子显得非常威风，让人敬畏。', 'Tā shuàiqì de yàngzi xiǎnde fēicháng wēifēng, ràng rén jìngwèi.', 'Dáng vẻ điển trai của anh ấy trông rất uy phong, làm người ta kính nể.'),
  ('威望', '这位教授在学术界享有极高的威望。', 'Zhè wèi jiàoshòu zài xuéshù jiè xiǎngyǒu jí gāo de wēiwàng.', 'Giáo sư này có danh vọng rất cao trong giới học thuật.'),
  ('威力', '这款新型导弹具有强大的威力，威胁国家安全。', 'Zhè kuǎn xīnxíng dǎodàn jùyǒu qiángdà de wēilì, wēixié guójiā ānquán.', 'Loại tên lửa mới này có uy lực mạnh, đe dọa an ninh quốc gia.'),
  ('威信', '领导人必须保持自己的威信，才能有效管理团队。', 'Lǐngdǎorén bìxū bǎochí zìjǐ de wēixìn, cáinéng yǒuxiào guǎnlǐ tuánduì.', 'Lãnh đạo phải giữ uy tín của mình thì mới quản lý đội nhóm hiệu quả.'),
  ('委托', '他委托律师处理公司的法律事务。', 'Tā wěituō lǜshī chǔlǐ gōngsī de fǎlǜ shìwù.', 'Anh ấy ủy thác luật sư xử lý các công việc pháp lý của công ty.'),
  ('委员', '他被选为委员会的委员，参与重要决策。', 'Tā bèi xuǎn wèi wěiyuán huì de wěiyuán, cānyù zhòngyào juécè.', 'Anh ấy được bầu làm ủy viên ủy ban, tham gia các quyết định quan trọng.'),
  ('妄想', '别抱有妄想，成功需要努力和时间。', 'Bié bàoyǒu wàngxiǎng, chénggōng xūyào nǔlì hé shíjiān.', 'Đừng có mơ tưởng viển vông, thành công cần cố gắng và thời gian.'),
  ('外表', '虽然他的外表普通，但内心非常聪明。', 'Suīrán tā de wàibiǎo pǔtōng, dàn nèixīn fēicháng cōngmíng.', 'Mặc dù bề ngoài bình thường, nhưng trong lòng anh ấy rất thông minh.'),
  ('外行', '在这个领域，我只是个外行，很多知识不了解。', 'Zài zhège lǐngyù, wǒ zhǐshì gè wàiháng, hěn duō zhīshi bù liǎojiě.', 'Trong lĩnh vực này, tôi chỉ là người ngoài ngành, không biết nhiều kiến thức.'),
  ('外界', '外界的压力让他感到非常焦虑和不安。', 'Wàijiè de yālì ràng tā gǎndào fēicháng jiāolǜ hé bù''ān.', 'Áp lực từ bên ngoài khiến anh ta cảm thấy rất lo lắng và bất an.'),
  ('外向', '她性格外向，喜欢和别人交流和分享。', 'Tā xìnggé wàixiàng, xǐhuan hé biérén jiāoliú hé fēnxiǎng.', 'Cô ấy tính cách hướng ngoại, thích giao tiếp và chia sẻ với người khác.'),
  ('喂', '喂，你好！请问现在是几点了？', 'Wèi, nǐ hǎo! Qǐngwèn xiànzài shì jǐ diǎn le?', 'A lô, bạn khỏe không! Xin hỏi bây giờ là mấy giờ rồi?'),
  ('唯独', '大家都同意这个计划，唯独他表示反对。', 'Dàjiā dōu tóngyì zhège jìhuà, wéidú tā biǎoshì fǎnduì.', 'Mọi người đều đồng ý với kế hoạch này, độc nhất anh ta phản đối.'),
  ('哇', '哇，这个风景真美，让人流连忘返。', 'Wā, zhège fēngjǐng zhēn měi, ràng rén liúlián wàngfǎn.', 'Oa oa, cảnh sắc này thật đẹp, khiến người ta lưu luyến không muốn rời.'),
  ('危机', '公司在经济危机中面临巨大的挑战。', 'Gōngsī zài jīngjì wēijī zhōng miànlín jùdà de tiǎozhàn.', 'Công ty đang đối mặt với thử thách lớn trong khủng hoảng kinh tế.'),
  ('卫星', '人造卫星被发射到太空，用于科学研究。', 'Rénzào wèixīng bèi fāshè dào tàikōng, yòngyú kēxué yánjiū.', 'Vệ tinh nhân tạo được phóng lên không gian để phục vụ nghiên cứu khoa học.'),
  ('务必', '请务必准时参加明天的重要会议。', 'Qǐng wùbì zhǔnshí cānjiā míngtiān de zhòngyào huìyì.', 'Xin nhất thiết phải tham dự đúng giờ cuộc họp quan trọng ngày mai.'),
  ('侮辱', '他的言语侮辱了别人，令人非常不满。', 'Tā de yányǔ wǔrǔ le biérén, lìng rén fēicháng bùmǎn.', 'Lời nói của anh ta đã sỉ nhục người khác, khiến mọi người rất bất mãn.'),
  ('伪造', '警方发现有人伪造证件试图进入会场。', 'Jǐngfāng fāxiàn yǒurén wěizào zhèngjiàn shìtú jìnrù huìchǎng.', 'Cảnh sát phát hiện có người giả mạo giấy tờ để cố gắng vào hội trường.'),
  ('乌黑', '他的头发乌黑发亮，看起来非常健康。', 'Tā de tóufǎ wūhēi fā liàng, kàn qǐlái fēicháng jiànkāng.', 'Tóc của anh ấy đen kịt và bóng mượt, trông rất khỏe mạnh.'),
  ('为难', '我不想为难你，但这件事真的很棘手。', 'Wǒ bù xiǎng wéi nán nǐ, dàn zhè jiàn shì zhēnde hěn jíshǒu.', 'Tôi không muốn làm khó bạn, nhưng việc này thực sự rất nan giải.'),
  ('为期', '这次会议为期三天，期间会讨论多个议题。', 'Zhè cì huìyì wéi qī sān tiān, qījiān huì tǎolùn duō gè yìtí.', 'Hội nghị lần này có kỳ hạn ba ngày, trong thời gian đó sẽ thảo luận nhiều chủ đề.'),
  ('丸', '医生开了几丸药，要求按时服用。', 'Yīshēng kāi le jǐ wán yào, yāoqiú àn shí fúyòng.', 'Bác sĩ đã kê vài viên thuốc, yêu cầu uống đúng giờ.'),
  ('万分', '我对你的帮助表示万分感谢，真心感激。', 'Wǒ duì nǐ de bāngzhù biǎoshì wànfēn gǎnxiè, zhēnxīn gǎnjī.', 'Tôi vô cùng cảm ơn sự giúp đỡ của bạn, thật lòng biết ơn.'),
  ('鲜明', '这幅画色彩鲜明，表现出浓烈的情感。', 'Zhè fú huà sècǎi xiānmíng, biǎoxiàn chū nóngliè de qínggǎn.', 'Bức tranh này có màu sắc tươi sáng, thể hiện cảm xúc mạnh mẽ.'),
  ('馅儿', '这家店的包子馅儿很丰富，口味多样。', 'Zhè jiā diàn de bāozi xiànr hěn fēngfù, kǒuwèi duōyàng.', 'Nhân bánh bao ở cửa hàng này rất phong phú, hương vị đa dạng.'),
  ('须知', '参加考试前，请仔细阅读考场须知，注意规定。', 'Cānjiā kǎoshì qián, qǐng zǐxì yuèdú kǎochǎng xūzhī, zhùyì guīdìng.', 'Trước khi tham dự kỳ thi, vui lòng đọc kỹ những điều cần biết về phòng thi và chú ý quy định.'),
  ('霞', '夕阳映照下，天空出现了美丽的彩霞。', 'Xīyáng yìngzhào xià, tiānkōng chūxiàn le měilì de cǎixiá.', 'Dưới ánh hoàng hôn, bầu trời xuất hiện ráng mây tuyệt đẹp.'),
  ('需求', '市场对高质量产品的需求日益增长。', 'Shìchǎng duì gāo zhìliàng chǎnpǐn de xūqiú rìyì zēngzhǎng.', 'Nhu cầu về sản phẩm chất lượng cao trên thị trường ngày càng tăng.'),
  ('雪上加霜', '这场意外让他的经济状况雪上加霜，陷入困境。', 'Zhè chǎng yìwài ràng tā de jīngjì zhuàngkuàng xuě shàng jiā shuāng, xiànrù kùnjìng.', 'Tai nạn này đã khiến tình hình tài chính của anh ta thêm phần khó khăn, rơi vào cảnh bế tắc.'),
  ('雄厚', '这家公司拥有雄厚的资金支持和技术力量。', 'Zhè jiā gōngsī yōngyǒu xiónghòu de zījīn zhīchí hé jìshù lìliang.', 'Công ty này có sự hỗ trợ tài chính và lực lượng kỹ thuật hùng hậu.'),
  ('雄伟', '长城雄伟壮观，是中国的象征之一。', 'Chángchéng xióngwěi zhuàngguān, shì Zhōngguó de xiàngzhēng zhī yī.', 'Vạn Lý Trường Thành hùng vĩ tráng lệ, là một trong những biểu tượng của Trung Quốc.'),
  ('陷阱', '在野外行走时要小心，避免落入野兽设置的陷阱。', 'Zài yěwài xíngzǒu shí yào xiǎoxīn, bìmiǎn luò rù yěshòu shèzhì de xiànjǐng.', 'Khi đi bộ ngoài trời, phải cẩn thận tránh rơi vào cạm bẫy do thú dữ giăng ra.'),
  ('陷害', '他被人陷害，被错误地指控犯了罪行。', 'Tā bèi rén xiànhài, bèi cuòwù de zhǐkòng fàn le zuìxíng.', 'Anh ta bị người khác hãm hại, bị cáo buộc sai trái về tội phạm.'),
  ('陷入', '公司因资金短缺陷入了严重的经营困难。', 'Gōngsī yīn zījīn duǎnquē xiànrù le yánzhòng de jīngyíng kùnnan.', 'Công ty do thiếu vốn đã rơi vào khó khăn nghiêm trọng trong kinh doanh.'),
  ('闲话', '流言和闲话严重影响了她的名誉。', 'Liúyán hé xiánhuà yánzhòng yǐngxiǎng le tā de míngyù.', 'Lời đồn thổi và lời đàm tiếu đã ảnh hưởng nghiêm trọng đến danh tiếng của cô ấy.'),
  ('镶嵌', '这件珠宝上镶嵌着许多珍贵的宝石。', 'Zhè jiàn zhūbǎo shàng xiāngqiàn zhe xǔduō zhēnguì de bǎoshí.', 'Viên trang sức này được khảm nhiều đá quý quý giá.'),
  ('销毁', '公司决定销毁过期的产品，确保质量安全。', 'Gōngsī juédìng xiāohuǐ guòqī de chǎnpǐn, quèbǎo zhìliàng ānquán.', 'Công ty quyết định tiêu hủy sản phẩm hết hạn để đảm bảo an toàn chất lượng.'),
  ('酗酒', '酗酒不仅伤害身体，也影响家庭和睦。', 'Xù jiǔ bùjǐn shānghài shēntǐ, yě yǐngxiǎng jiātíng hémù.', 'Nghiện rượu không những làm tổn hại cơ thể mà còn ảnh hưởng đến sự hòa thuận của gia đình.'),
  ('选拔', '这次比赛是为了选拔优秀的运动员参加全国比赛。', 'Zhè cì bǐ sài shì wèi le xuǎn bá yōu xiù de yùn dòng yuán cān jiā quán guó bǐ sài.', 'Cuộc thi lần này nhằm tuyển chọn những vận động viên xuất sắc tham dự cuộc thi cấp quốc gia.'),
  ('选手', '每个选手都经过严格训练才能站上赛场。', 'Měi gè xuǎn shǒu dōu jīng guò yán gé xùn liàn cái néng zhàn shàng sài chǎng.', 'Mỗi tuyển thủ đều phải trải qua huấn luyện nghiêm ngặt mới có thể đứng trên sân thi đấu.'),
  ('选举', '市民们将于下个月进行市长的选举投票。', 'Shì mín men jiāng yú xià gè yuè jìn xíng shì zhǎng de xuǎn jǔ tóu piào.', 'Cư dân thành phố sẽ tiến hành bỏ phiếu bầu cử thị trưởng vào tháng tới.'),
  ('辛勤', '老师们辛勤工作，为学生们创造良好的学习环境。', 'Lǎo shī men xīn qín gōng zuò, wèi xué shēng men chuàng zào liáng hǎo de xué xí huán jìng.', 'Các thầy cô giáo siêng năng làm việc để tạo ra môi trường học tập tốt cho học sinh.'),
  ('贤惠', '她不仅美丽，而且非常贤惠，照顾家人无微不至。', 'Tā bù jǐn měi lì, ér qiě fēi cháng xián huì, zhào gù jiā rén wú wēi bù zhì.', 'Cô ấy không những xinh đẹp mà còn rất hiền thục, chăm sóc gia đình từng li từng tí.'),
  ('谢绝', '为保持安静，图书馆谢绝携带食物进入。', 'Wèi bǎo chí ān jìng, tú shū guǎn xiè jué xié dài shí wù jìn rù.', 'Để giữ yên tĩnh, thư viện từ chối mang thức ăn vào.'),
  ('许可', '未经许可，任何人不得进入实验室。', 'Wèi jīng xǔ kě, rèn hé rén bù dé jìn rù shí yàn shì.', 'Chưa được phép, bất kỳ ai đều không được vào phòng thí nghiệm.'),
  ('袭击', '敌军突然袭击了边境的哨所，造成严重损失。', 'Dí jūn tū rán xí jī le biān jìng de shào suǒ, zào chéng yán zhòng sǔn shī.', 'Quân địch bất ngờ tập kích chốt biên giới, gây thiệt hại nặng nề.'),
  ('衔接', '新旧系统的衔接需要技术人员仔细协调处理。', 'Xīn jiù xì tǒng de xián jiē xū yào jì shù rén yuán zǐ xì xié tiáo chù lǐ.', 'Việc nối tiếp giữa hệ thống mới và cũ cần nhân viên kỹ thuật phối hợp kỹ càng.'),
  ('行政', '政府部门负责城市的行政管理和公共服务。', 'Zhèng fǔ bù mén fù zé chéng shì de xíng zhèng guǎn lǐ hé gōng gòng fú wù.', 'Các cơ quan chính phủ chịu trách nhiệm quản lý hành chính và dịch vụ công cộng của thành phố.'),
  ('血压', '医生建议我每天测量血压，保持身体健康。', 'Yī shēng jiàn yì wǒ měi tiān cè liáng xuè yā, bǎo chí shēn tǐ jiàn kāng.', 'Bác sĩ khuyên tôi nên đo huyết áp hàng ngày để giữ sức khỏe.'),
  ('虚荣', '他过于追求虚荣，常常炫耀自己的财富。', 'Tā guò yú zhuī qiú xū róng, cháng cháng xuàn yào zì jǐ de cáifù.', 'Anh ấy quá chú trọng hư vinh, thường khoe khoang tài sản của mình.'),
  ('虚假', '网络上充斥着许多虚假信息，需要仔细辨别。', 'Wǎng luò shàng chōng chì zhe xǔ duō xū jiǎ xìn xī, xū yào zǐ xì biàn bié.', 'Trên mạng tràn ngập nhiều thông tin giả dối, cần phải phân biệt kỹ.'),
  ('虚伪', '他的笑容看起来很虚伪，让人无法相信。', 'Tā de xiào róng kàn qǐ lái hěn xū wěi, ràng rén wú fǎ xiāng xìn.', 'Nụ cười của anh ta trông rất giả tạo, khiến người khác không thể tin được.'),
  ('薪水', '公司每个月按时发放员工的薪水和奖金。', 'Gōng sī měi gè yuè àn shí fā fàng yuán gōng de xīn shuǐ hé jiǎng jīn.', 'Công ty trả lương và thưởng cho nhân viên đúng hạn mỗi tháng.'),
  ('膝盖', '运动时要注意保护膝盖，避免受伤。', 'Yùn dòng shí yào zhù yì bǎo hù xī gài, bì miǎn shòu shāng.', 'Khi vận động cần chú ý bảo vệ đầu gối để tránh bị thương.'),
  ('腥', '这道海鲜菜的味道有些腥，不太适合口味清淡的人。', 'Zhè dào hǎi xiān cài de wèi dào yǒu xiē xīng, bù tài shì hé kǒu wèi qīng dàn de rén.', 'Món hải sản này có mùi tanh, không hợp với người ăn nhạt.'),
  ('胸膛', '他的胸膛因长期锻炼而非常结实有力。', 'Tā de xiōng táng yīn cháng qī duàn liàn ér fēi cháng jié shi yǒu lì.', 'Lồng ngực của anh ấy rất săn chắc và khỏe mạnh do luyện tập lâu dài.'),
  ('胸怀', '她胸怀宽广，能够包容不同的意见和观点。', 'Tā xiōng huái kuān guǎng, néng gòu bāo róng bù tóng de yì jiàn hé guān diǎn.', 'Cô ấy có tấm lòng rộng lớn, có thể bao dung các ý kiến và quan điểm khác nhau.'),
  ('肖像', '这幅肖像画描绘了她细腻的表情和神态。', 'Zhè fú xiào xiàng huà miáo huì le tā xì nì de biǎo qíng hé shén tài.', 'Bức chân dung này miêu tả biểu cảm và thần thái tinh tế của cô ấy.'),
  ('羞耻', '他感到羞耻，因为没有完成自己的承诺。', 'Tā gǎn dào xiū chǐ, yīn wèi méi yǒu wán chéng zì jǐ de chéng nuò.', 'Anh ấy cảm thấy xấu hổ vì không hoàn thành lời hứa của mình.'),
  ('绣', '奶奶喜欢在布料上绣各种精美的图案。', 'Nǎinai xǐ huān zài bù liào shàng xiù gè zhǒng jīng měi de tú àn.', 'Bà thích thêu các họa tiết tinh xảo trên vải.'),
  ('细菌', '保持卫生可以有效地减少细菌的传播。', 'Bǎo chí wèi shēng kě yǐ yǒu xiào de jiǎn shǎo xì jūn de chuán bō.', 'Giữ vệ sinh có thể giảm hiệu quả sự lây lan của vi khuẩn.'),
  ('细致', '他的工作态度非常细致，得到了大家的认可。', 'Tā de gōng zuò tài dù fēi cháng xì zhì, dé dào le dà jiā de rèn kě.', 'Thái độ làm việc của anh ấy rất tỉ mỉ, được mọi người đánh giá cao.'),
  ('细胞', '科学家们发现细胞的结构比想象中更复杂。', 'Kē xué jiā men fā xiàn xì bāo de jié gòu bǐ xiǎng xiàng zhōng gèng fù zá.', 'Các nhà khoa học phát hiện cấu trúc tế bào phức tạp hơn tưởng tượng.'),
  ('线索', '警方通过线索找到了失踪多日的人员。', 'Jǐng fāng tōng guò xiàn suǒ zhǎo dào le shī zōng duō rì de rén yuán.', 'Cảnh sát tìm ra manh mối và tìm được người mất tích nhiều ngày.'),
  ('纤维', '富含纤维的食物有助于促进消化系统健康。', 'Fù hán xiān wéi de shí wù yǒu zhù yú cù jìn xiāo huà xì tǒng jiàn kāng.', 'Thức ăn giàu chất xơ giúp cải thiện sức khỏe hệ tiêu hóa.'),
  ('系列', '这部电视剧属于一系列悬疑题材的作品。', 'Zhè bù diàn shì jù shǔ yú yī xì liè xuán yí tí cái de zuò pǐn.', 'Bộ phim truyền hình này thuộc một loạt tác phẩm thể loại trinh thám.'),
  ('相辅相成', '理论与实践相辅相成，缺一不可。', 'Lǐ lùn yǔ shí jiàn xiāng fǔ xiāng chéng, quē yī bù kě.', 'Lý thuyết và thực hành bổ trợ cho nhau, không thể thiếu một trong hai.'),
  ('相等', '比赛中双方的实力几乎相等，结果难以预测。', 'Bǐ sài zhōng shuāng fāng de shí lì jī hū xiāng děng, jié guǒ nán yǐ yù cè.', 'Lực lượng hai bên trong trận đấu gần như ngang bằng, kết quả khó đoán định.'),
  ('相应', '企业的发展需要相应的政策支持。', 'Qǐ yè de fā zhǎn xū yào xiāng yìng de zhèng cè zhī chí.', 'Sự phát triển của doanh nghiệp cần sự hỗ trợ chính sách tương ứng.'),
  ('相差', '这两款手机的价格相差不大，但是功能不一样。', 'Zhè liǎng kuǎn shǒu jī de jià gé xiāng chà bù dà, dàn shì gōng néng bù yī yàng.', 'Giá của hai mẫu điện thoại này chênh lệch không nhiều, nhưng chức năng khác nhau.'),
  ('相声', '我们昨晚去剧场观看了一场精彩的相声表演。', 'Wǒ men zuó wǎn qù jù chǎng guān kàn le yī chǎng jīng cǎi de xiàng shēng biǎo yǎn.', 'Tối qua chúng tôi đến rạp xem một buổi biểu diễn xiangsheng đầy ấn tượng.'),
  ('畜牧', '畜牧业的发展对农村经济起到了积极的推动作用。', 'Xù mù yè de fā zhǎn duì nóng cūn jīng jì qǐ dào le jī jí de tuī dòng zuò yòng.', 'Phát triển ngành chăn nuôi đã tạo nên động lực tích cực cho kinh tế nông thôn.'),
  ('现状', '政府正在努力改善城市的交通现状。', 'Zhèng fǔ zhèng zài nǔ lì gǎi shàn chéng shì de jiāo tōng xiàn zhuàng.', 'Chính phủ đang cố gắng cải thiện hiện trạng giao thông thành phố.'),
  ('现成', '这些现成的材料可以用来快速完成项目。', 'Zhè xiē xiàn chéng de cái liào kě yǐ yòng lái kuài sù wán chéng xiàng mù.', 'Những vật liệu có sẵn này có thể dùng để hoàn thành dự án nhanh chóng.'),
  ('现场', '记者第一时间赶到事故现场进行报道。', 'Jì zhě dì yī shí jiān gǎn dào shì gù xiàn chǎng jìn xíng bào dào.', 'Phóng viên đã có mặt tại hiện trường vụ tai nạn để đưa tin kịp thời.'),
  ('狭隘', '狭隘的观念限制了她的发展。', 'Xiá ài de guān niàn xiàn zhì le tā de fā zhǎn.', 'Quan niệm hẹp hòi đã hạn chế sự phát triển của cô ấy.'),
  ('狭窄', '这条狭窄的小路只允许单车通过。', 'Zhè tiáo xiá zhǎi de xiǎo lù zhǐ yǔn xǔ dān chē tōng guò.', 'Con đường nhỏ hẹp này chỉ cho phép xe đạp đi qua.'),
  ('牺牲', '为了国家利益，他愿意牺牲个人的幸福。', 'Wèi le guó jiā lì yì, tā yuàn yì xī shēng gè rén de xìng fú.', 'Vì lợi ích quốc gia, anh ấy sẵn sàng hy sinh hạnh phúc cá nhân.'),
  ('熏陶', '他的艺术熏陶使他对绘画产生浓厚兴趣。', 'Tā de yìshù xūntáo shǐ tā duì huìhuà chǎnshēng nónghòu xìngqù.', 'Sự hun đúc nghệ thuật của anh ấy khiến anh ta có hứng thú mạnh mẽ với hội họa.'),
  ('熄灭', '风吹得很大，火焰很快就被熄灭了。', 'Fēng chuī dé hěn dà, huǒyàn hěn kuài jiù bèi xīmiè le.', 'Gió thổi rất mạnh, ngọn lửa nhanh chóng bị dập tắt.'),
  ('炫耀', '他喜欢用名牌包来炫耀自己的财富。', 'Tā xǐhuān yòng míngpái bāo lái xuànyào zìjǐ de cáifù.', 'Anh ấy thích dùng túi hiệu để khoe khoang sự giàu có của mình.'),
  ('潇洒', '他举止潇洒，给人留下深刻印象。', 'Tā jǔzhǐ xiāosǎ, gěi rén liú xià shēnkè yìnxiàng.', 'Cử chỉ của anh ấy rất thoải mái, để lại ấn tượng sâu sắc với người khác.'),
  ('溪', '清晨我们沿着小溪散步，感受大自然的美妙。', 'Qīngchén wǒmen yánzhe xiǎoxī sànbù, gǎnshòu dà zìrán de měimiào.', 'Sáng sớm chúng tôi dạo bộ dọc theo con suối nhỏ, cảm nhận vẻ đẹp của thiên nhiên.'),
  ('消除', '科学技术的发展有助于消除贫困和疾病。', 'Kēxué jìshù de fāzhǎn yǒu zhù yú xiāochú pínkùn hé jíbìng.', 'Sự phát triển của khoa học kỹ thuật giúp loại bỏ đói nghèo và bệnh tật.'),
  ('消防', '消防部门迅速赶到现场扑灭火灾，保证安全。', 'Xiāofáng bùmén xùnsù gǎndào xiànchǎng pūmiè huǒzāi, bǎozhèng ānquán.', 'Bộ phận chữa cháy nhanh chóng có mặt tại hiện trường để dập tắt đám cháy, đảm bảo an toàn.'),
  ('消耗', '这台机器在运行过程中消耗大量能源。', 'Zhè tái jīqì zài yùnxíng guòchéng zhōng xiāohào dàliàng néngyuán.', 'Chiếc máy này tiêu hao một lượng lớn năng lượng trong quá trình vận hành.'),
  ('消灭', '政府制定法律以消灭非法行为，保障社会秩序。', 'Zhèngfǔ zhìdìng fǎlǜ yǐ xiāomiè fēifǎ xíngwéi, bǎozhàng shèhuì zhìxù.', 'Chính phủ ban hành pháp luật để tiêu diệt hành vi phạm pháp, bảo đảm trật tự xã hội.'),
  ('消毒', '餐具必须经过高温消毒才能使用，确保卫生安全。', 'Cānjù bìxū jīngguò gāowēn xiāodú cáinéng shǐyòng, quèbǎo wèishēng ānquán.', 'Bộ đồ ăn phải được khử độc bằng nhiệt độ cao mới được sử dụng, đảm bảo vệ sinh an toàn.'),
  ('泄露', '企业要加强保密，防止重要信息泄露。', 'Qǐyè yào jiāqiáng bǎomì, fángzhǐ zhòngyào xìnxī xièlòu.', 'Doanh nghiệp cần tăng cường bảo mật để ngăn chặn rò rỉ thông tin quan trọng.'),
  ('泄气', '遇到挫折时他没有泄气，反而更加努力。', 'Yù dào cuòzhé shí tā méiyǒu xièqì, fǎn''ér gèng jiā nǔlì.', 'Khi gặp thất bại anh ấy không nản lòng mà ngược lại càng cố gắng hơn.'),
  ('汹涌', '海浪汹涌澎湃，展现大海的威力和壮观。', 'Hǎilàng xiōngyǒng péngpài, zhǎnxiàn dàhǎi de wēilì hé zhuànguān.', 'Sóng biển cuồn cuộn dâng trào, thể hiện sức mạnh và vẻ hùng vĩ của đại dương.'),
  ('欣欣向荣', '春天来了，花草树木欣欣向荣，充满生机。', 'Chūntiān lái le, huācǎo shùmù xīnxīn xiàng róng, chōngmǎn shēngjī.', 'Mùa xuân đến, cây cỏ hoa lá phát triển thịnh vượng, tràn đầy sức sống.'),
  ('欣慰', '看到孩子们健康成长，父母感到十分欣慰。', 'Kàn dào háizimen jiànkāng chéngzhǎng, fùmǔ gǎndào shífēn xīnwèi.', 'Nhìn thấy con cái lớn lên khỏe mạnh, cha mẹ cảm thấy rất mừng vui thanh thản.'),
  ('显著', '这项技术的进步带来了显著的经济效益。', 'Zhè xiàng jìshù de jìnbù dài lái le xiǎnzhù de jīngjì xiàoyì.', 'Tiến bộ của công nghệ này mang lại hiệu quả kinh tế nổi bật.'),
  ('昔日', '昔日的老街区如今已经焕然一新。', 'Xīrì de lǎo jiēqū rújīn yǐjīng huànrán yī xīn.', 'Khu phố cũ trước kia giờ đã hoàn toàn đổi mới.'),
  ('旋转', '风车在风中缓缓旋转，景象十分美丽。', 'Fēngchē zài fēng zhōng huǎnhuǎn xuánzhuǎn, jǐngxiàng shífēn měilì.', 'Cối xay gió trong gió quay tròn chậm rãi, cảnh tượng rất đẹp.'),
  ('旋律', '这首歌的旋律优美动听，深受大家喜爱。', 'Zhè shǒu gē de xuánlǜ yōuměi dòngtīng, shēnshòu dàjiā xǐ''ài.', 'Giai điệu của bài hát này du dương dễ nghe, được mọi người yêu thích.'),
  ('新颖', '她设计的方案非常新颖，赢得了专家的认可。', 'Tā shèjì de fāng''àn fēicháng xīnyǐng, yíngdé le zhuānjiā de rènkě.', 'Bản thiết kế của cô ấy rất mới lạ, được các chuyên gia công nhận.'),
  ('新陈代谢', '人的新陈代谢速度会随着年龄的增长而减慢。', 'Rén de xīnchén dàixiè sùdù huì suízhe niánlíng de zēngzhǎng ér jiǎnmàn.', 'Tốc độ đổi mới của cơ thể người sẽ chậm lại theo độ tuổi tăng lên.'),
  ('新郎', '在婚礼上，新郎穿着传统的中式礼服显得非常帅气。', 'Zài hūnlǐ shàng, xīnláng chuānzhe chuántǒng de zhōngshì lǐfú xiǎnde fēicháng shuàiqì.', 'Trong đám cưới, chú rể mặc bộ lễ phục kiểu Trung truyền thống trông rất phong độ.'),
  ('新娘', '新娘披着洁白的婚纱，脸上洋溢着幸福的笑容。', 'Xīnniáng pīzhe jiébái de hūnshā, liǎn shàng yángyìzhe xìngfú de xiàoróng.', 'Cô dâu mặc chiếc váy cưới trắng tinh, trên mặt toát lên nụ cười hạnh phúc.'),
  ('效益', '这家企业实行新政策后，公司的效益明显提升。', 'Zhè jiā qǐyè shíxíng xīn zhèngcè hòu, gōngsī de xiàoyì míngxiǎn tíshēng.', 'Sau khi công ty thực hiện chính sách mới, hiệu quả hoạt động rõ ràng được cải thiện.'),
  ('携带', '旅途中请务必携带有效身份证件以备检查。', 'Lǚtú zhōng qǐng wùbì xiédài yǒuxiào shēnfèn zhèngjiàn yǐ bèi jiǎnchá.', 'Trong chuyến đi, vui lòng mang theo giấy tờ tùy thân hợp lệ để kiểm tra.'),
  ('掀起', '春风掀起了湖面上的波浪，景色十分迷人。', 'Chūnfēng xiānqǐle húmiàn shàng de bōlàng, jǐngsè shífēn mírén.', 'Gió xuân làm dạt lên những gợn sóng trên mặt hồ, cảnh sắc rất quyến rũ.'),
  ('想方设法', '为了完成任务，他想方设法克服了种种困难。', 'Wèile wánchéng rènwù, tā xiǎng fāng shè fǎ kèfúle zhǒng zhǒng kùnnán.', 'Để hoàn thành nhiệm vụ, anh ta trăm phương ngàn kế vượt qua mọi khó khăn.'),
  ('悬殊', '两队实力悬殊，比赛结果令人意外。', 'Liǎng duì shílì xuánshū, bǐsài jiéguǒ lìng rén yìwài.', 'Sức mạnh giữa hai đội có sự cách biệt lớn, kết quả trận đấu gây bất ngờ.'),
  ('悬挂', '节日期间，街道上悬挂着各式各样的彩灯装饰。', 'Jiérì qījiān, jiēdào shàng xuánguàzhe gè shì gè yàng de cǎidēng zhuāngshì.', 'Trong dịp lễ, trên phố treo đầy các loại đèn màu trang trí.'),
  ('悬念', '电影的结局充满悬念，让观众期待下一部作品。', 'Diànyǐng de jiéjú chōngmǎn xuánniàn, ràng guānzhòng qídài xià yī bù zuòpǐn.', 'Kết thúc bộ phim đầy hồi hộp, khiến khán giả mong đợi phần tiếp theo.'),
  ('悬崖峭壁', '登山者在悬崖峭壁上小心翼翼地攀爬。', 'Dēng shān zhě zài xuányá qiàobì shàng xiǎoxīn yìyì de pānpá.', 'Người leo núi đang cẩn thận leo trên vách núi cheo leo.'),
  ('性能', '这款手机性能强大，适合玩大型游戏。', 'Zhè kuǎn shǒujī xìngnéng qiángdà, shìhé wán dàxíng yóuxì.', 'Chiếc điện thoại này có tính năng mạnh mẽ, thích hợp chơi game nặng.'),
  ('性感', '她穿着那件礼服显得非常性感迷人。', 'Tā chuānzhe nà jiàn lǐfú xiǎnde fēicháng xìnggǎn mírén.', 'Cô ấy mặc bộ váy đó trông rất gợi cảm và quyến rũ.'),
  ('性命', '在救援行动中，大家奋力保护每一个人的性命。', 'Zài jiùyuán xíngdòng zhōng, dàjiā fènlì bǎohù měi yí gè rén de xìngmìng.', 'Trong hoạt động cứu hộ, mọi người cố gắng bảo vệ tính mạng từng người.'),
  ('心血', '这件作品凝聚了艺术家的全部心血和努力。', 'Zhè jiàn zuòpǐn níngjùle yìshùjiā de quánbù xīnxuè hé nǔlì.', 'Tác phẩm này hàm chứa toàn bộ tâm huyết và nỗ lực của nghệ sĩ.'),
  ('心眼儿', '他虽然不善言辞，但心眼儿很好，值得信赖。', 'Tā suīrán bù shàn yáncí, dàn xīnyǎnr hěn hǎo, zhídé xìnlài.', 'Anh ấy dù không giỏi ăn nói nhưng trong lòng rất tốt, đáng tin cậy.'),
  ('心疼', '看到孩子受伤，母亲感到非常心疼和难过。', 'Kàn dào háizi shòushāng, mǔqīn gǎndào fēicháng xīnténg hé nánguò.', 'Nhìn thấy con bị thương, mẹ cảm thấy rất đau lòng và buồn bã.'),
  ('心甘情愿', '他心甘情愿地承担这份责任，从不抱怨。', 'Tā xīngān qíngyuàn de chéngdān zhè fèn zérèn, cóng bù bàoyuàn.', 'Anh ấy cam tâm tình nguyện nhận trách nhiệm này, chưa từng phàn nàn.'),
  ('心灵', '音乐有治愈心灵的力量，可以带来内心的平静。', 'Yīnyuè yǒu zhìyù xīnlíng de lìliàng, kěyǐ dàilái nèixīn de píngjìng.', 'Âm nhạc có sức chữa lành tâm hồn, mang lại sự bình yên trong lòng.'),
  ('心态', '保持积极的心态有助于克服生活中的困难。', 'Bǎochí jījí de xīntài yǒuzhù yú kèfú shēnghuó zhōng de kùnnán.', 'Giữ thái độ tích cực giúp vượt qua những khó khăn trong cuộc sống.'),
  ('心得', '读完这本书后，我有很多心得想要分享。', 'Dú wán zhè běn shū hòu, wǒ yǒu hěn duō xīn dé xiǎng yào fēn xiǎng.', 'Sau khi đọc xong cuốn sách này, tôi có nhiều tâm đắc muốn chia sẻ.'),
  ('循环', '地球上的水不断循环，维持生态平衡。', 'Dìqiú shàng de shuǐ bùduàn xún huán, wéichí shēngtài pínghéng.', 'Nước trên Trái Đất không ngừng tuần hoàn để duy trì cân bằng sinh thái.'),
  ('循序渐进', '学习语言需要循序渐进，不能急于求成。', 'Xuéxí yǔyán xūyào xún xù jiàn jìn, bùnéng jí yú qiú chéng.', 'Học ngôn ngữ cần phải lần lượt từng bước, không thể nóng vội đạt thành công.'),
  ('形态', '不同生物的形态适应了各自的环境。', 'Bùtóng shēngwù de xíngtài shìyìng le gèzì de huánjìng.', 'Hình thái của các sinh vật khác nhau thích nghi với môi trường của chúng.'),
  ('弦', '这把古琴的弦需要定期更换。', 'Zhè bǎ gǔqín de xián xūyào dìngqī gēnghuàn.', 'Dây đàn cổ này cần được thay định kỳ.'),
  ('序言', '书的序言部分介绍了作者的写作背景。', 'Shū de xù yán bùfen jièshào le zuòzhě de xiězuò bèijǐng.', 'Phần lời nói đầu của sách giới thiệu bối cảnh viết của tác giả.'),
  ('巷', '他家住在城市的一个安静的巷子里。', 'Tā jiā zhù zài chéngshì de yí gè ānjìng de xiàngzi lǐ.', 'Nhà anh ấy ở trong một ngõ yên tĩnh của thành phố.'),
  ('巡逻', '警察每天晚上都会在街上巡逻。', 'Jǐngchá měi tiān wǎnshàng dōu huì zài jiē shàng xúnluó.', 'Cảnh sát đều tuần tra trên đường mỗi buổi tối.'),
  ('峡谷', '峡谷两边的悬崖峭壁令人惊叹。', 'Xiágǔ liǎng biān de xuányá qiàobì lìng rén jīngtàn.', 'Hai bên hẻm núi là những vách đá cheo leo khiến người ta kinh ngạc.'),
  ('屑', '桌子上的木屑需要及时清理。', 'Zhuōzi shàng de mùxiè xūyào jíshí qīnglǐ.', 'Vụn gỗ trên bàn cần được dọn dẹp kịp thời.'),
  ('小心翼翼', '他小心翼翼地打开那只精致的盒子。', 'Tā xiǎoxīn yì yì de dǎkāi nà zhī jīngzhì de hézi.', 'Anh ấy cẩn thận từng li mở chiếc hộp tinh xảo đó.'),
  ('寻觅', '她在市场上寻觅特别的礼物给朋友。', 'Tā zài shìchǎng shàng xúnmì tèbié de lǐwù gěi péngyǒu.', 'Cô ấy đang tìm kiếm món quà đặc biệt cho bạn ở chợ.'),
  ('宪法', '宪法保障公民的基本权利和自由。', 'Xiànfǎ bǎozhàng gōngmín de jīběn quánlì hé zìyóu.', 'Hiến pháp bảo đảm quyền lợi và tự do cơ bản của công dân.'),
  ('宣誓', '新官员在大会上庄严宣誓就职。', 'Xīn guānyuán zài dàhuì shàng zhuāngyán xuānshì jiùzhí.', 'Viên chức mới tuyên thệ nhậm chức một cách trang nghiêm tại đại hội.'),
  ('宣扬', '学校积极宣扬环保的重要性。', 'Xuéxiào jījí xuānyáng huánbǎo de zhòngyào xìng.', 'Trường học tích cực tuyên truyền tầm quan trọng của bảo vệ môi trường.'),
  ('学说', '这个学说影响了整个现代哲学的发展。', 'Zhège xuéshuō yǐngxiǎng le zhěnggè xiàndài zhéxué de fāzhǎn.', 'Học thuyết này ảnh hưởng đến sự phát triển của toàn bộ triết học hiện đại.'),
  ('学位', '他获得了博士学位，成为该领域的专家。', 'Tā huòdé le bóshì xuéwèi, chéngwéi gāi lǐngyù de zhuānjiā.', 'Anh ấy đã nhận học vị tiến sĩ và trở thành chuyên gia trong lĩnh vực đó.'),
  ('嫌疑', '警方逮捕了几名有盗窃嫌疑的嫌犯。', 'Jǐngfāng dàibǔ le jǐ míng yǒu dàoqiè xiányí de xiánfàn.', 'Cảnh sát bắt giữ vài tên nghi phạm có nghi ngờ trộm cắp.'),
  ('嫌', '他总是嫌别人做事不够认真。', 'Tā zǒng shì xián biérén zuò shì bù gòu rènzhēn.', 'Anh ta luôn chê bai người khác làm việc không đủ nghiêm túc.'),
  ('媳妇', '那位善良的媳妇深受婆婆的喜爱。', 'Nà wèi shànliáng de xífù shēn shòu pópo de xǐ''ài.', 'Người con dâu hiền lành đó rất được mẹ chồng yêu mến.'),
  ('夕阳', '夕阳西下，整个天空被染成了橘红色。', 'Xīyáng xī xià, zhěnggè tiānkōng bèi rǎn chéngle júhóng sè.', 'Mặt trời lặn về phía tây, cả bầu trời nhuộm màu cam đỏ.'),
  ('嗅觉', '他的嗅觉异常灵敏，能够闻出各种香料的味道。', 'Tā de xiùjué yìcháng língmǐn, nénggòu wén chū gè zhǒng xiāngliào de wèidào.', 'Khứu giác của anh ấy rất nhạy, có thể ngửi ra mùi của nhiều loại gia vị khác nhau.'),
  ('喧哗', '图书馆里不允许喧哗，大家要保持安静。', 'Túshūguǎn lǐ bù yǔnxǔ xuānhuá, dàjiā yào bǎochí ānjìng.', 'Trong thư viện không được phép to mồm, mọi người phải giữ yên lặng.'),
  ('喜闻乐见', '这个节目内容丰富，深受观众喜闻乐见。', 'Zhège jiémù nèiróng fēngfù, shēn shòu guānzhòng xǐ wén lè jiàn.', 'Chương trình này có nội dung phong phú, được khán giả yêu thích và dễ xem.'),
  ('喜悦', '他听到升职的消息，脸上充满了喜悦的笑容。', 'Tā tīng dào shēngzhí de xiāoxi, liǎn shàng chōngmǎnle xǐyuè de xiàoróng.', 'Anh ấy nghe tin thăng chức, trên mặt tràn đầy nụ cười vui mừng.'),
  ('响应', '全校师生积极响应环保活动，纷纷参加植树。', 'Quán xiào shīshēng jījí xiǎngyìng huánbǎo huódòng, fēnfēn cānjiā zhíshù.', 'Toàn thể giáo viên và học sinh trường tích cực đáp ứng hoạt động bảo vệ môi trường, lần lượt tham gia trồng cây.'),
  ('响亮', '他的声音响亮清晰，能够传到教室的每一个角落。', 'Tā de shēngyīn xiǎngliàng qīngxī, nénggòu chuán dào jiàoshì de měi yī gè jiǎoluò.', 'Giọng nói của anh ấy vang dội và rõ ràng, có thể truyền đến mọi góc của lớp học.'),
  ('向来', '他向来注重时间管理，从不拖延工作进度。', 'Tā xiànglái zhùzhòng shíjiān guǎnlǐ, cóng bù tuōyán gōngzuò jìndù.', 'Anh ấy từ trước đến nay rất chú trọng quản lý thời gian, chưa từng trì hoãn tiến độ công việc.'),
  ('向往', '许多人向往自由自在的生活方式，渴望远离城市喧嚣。', 'Xǔduō rén xiàngwǎng zìyóu zìzài de shēnghuó fāngshì, kěwàng yuǎnlí chéngshì xuānxiāo.', 'Nhiều người hướng về lối sống tự do thoải mái, khát khao rời xa sự ồn ào của thành phố.'),
  ('向导', '我们请了一位经验丰富的向导带队，保障登山安全。', 'Wǒmen qǐngle yī wèi jīngyàn fēngfù de xiàngdǎo dàiduì, bǎozhàng dēngshān ānquán.', 'Chúng tôi đã mời một hướng dẫn viên giàu kinh nghiệm dẫn đoàn, đảm bảo an toàn khi leo núi.'),
  ('协调', '各部门需要密切协调，才能完成此次大型项目。', 'Gè bùmén xūyào mìqiè xiétiáo, cáinéng wánchéng cǐ cì dàxíng xiàngmù.', 'Các phòng ban cần phối hợp chặt chẽ mới có thể hoàn thành dự án lớn lần này.'),
  ('协议', '双方经过多次谈判，最终达成了友好的协议。', 'Shuāngfāng jīngguò duō cì tánpàn, zuìzhōng dáchéngle yǒuhǎo de xiéyì.', 'Hai bên sau nhiều lần đàm phán cuối cùng đã đạt được thỏa thuận hữu nghị.'),
  ('协商', '公司和员工就薪资问题进行了充分协商。', 'Gōngsī hé yuángōng jiù xīn zī wèntí jìnxíngle chōngfèn xiéshāng.', 'Công ty và nhân viên đã tiến hành hiệp thương đầy đủ về vấn đề lương bổng.'),
  ('协助', '警方请求公众协助提供犯罪线索，促进案件侦破。', 'Jǐngfāng qǐngqiú gōngzhòng xiézhù tígōng fànzuì xiànsuǒ, cùjìn ànjiàn zhēnpò.', 'Cảnh sát yêu cầu công chúng trợ giúp cung cấp manh mối tội phạm để thúc đẩy phá án.'),
  ('协会', '这个协会致力于推广传统文化，组织各种相关活动。', 'Zhège xiéhuì zhìlì yú tuīguǎng chuántǒng wénhuà, zǔzhī gè zhǒng xiāngguān huódòng.', 'Hiệp hội này chuyên tâm quảng bá văn hóa truyền thống, tổ chức nhiều hoạt động liên quan.'),
  ('削弱', '长期的战争削弱了国家的经济实力和社会稳定。', 'Chángqī de zhànzhēng xuēruòle guójiā de jīngjì shílì hé shèhuì wěndìng.', 'Chiến tranh kéo dài đã làm suy yếu sức mạnh kinh tế và sự ổn định xã hội của quốc gia.'),
  ('削', '请用刀子把苹果削成薄片，这样更容易入味。', 'Qǐng yòng dāozi bǎ píngguǒ xiāo chéng báo piàn, zhèyàng gèng róngyì rù wèi.', 'Làm ơn dùng dao cắt táo thành lát mỏng, như thế sẽ dễ ngấm vị hơn.'),
  ('刑事', '警方正在调查这起刑事案件，寻找嫌疑人。', 'Jǐngfāng zhèngzài diàochá zhè qǐ xíngshì ànjiàn, xúnzhǎo xiányí rén.', 'Cảnh sát đang điều tra vụ án hình sự này để tìm nghi phạm.'),
  ('凶手', '警方最终锁定了案件的凶手并将其逮捕。', 'Jǐngfāng zuìzhōng suǒdìngle ànjiàn de xiōngshǒu bìng jiāng qí dàibǔ.', 'Cảnh sát cuối cùng đã xác định được hung thủ của vụ án và bắt giữ hắn.'),
  ('凶恶', '他犯下的凶恶罪行震惊了整个社会。', 'Tā fànxià de xiōng''è zuìxíng zhènjīngle zhěnggè shèhuì.', 'Tội ác hung ác mà hắn phạm phải đã làm chấn động toàn xã hội.'),
  ('兴高采烈', '孩子们兴高采烈地跑进教室，准备开始新的学习。', 'Háizimen xìng gāo cǎi liè de pǎo jìn jiàoshì, zhǔnbèi kāishǐ xīn de xuéxí.', 'Các em nhỏ vui vẻ hào hứng chạy vào lớp học, chuẩn bị bắt đầu học tập mới.'),
  ('兴隆', '这家店生意兴隆，每天都有很多顾客光顾。', 'Zhè jiā diàn shēngyì xīnglóng, měitiān dōu yǒu hěnduō gùkè guānggù.', 'Cửa hàng này kinh doanh hưng thịnh, mỗi ngày đều có nhiều khách hàng tới.'),
  ('兴致勃勃', '他兴致勃勃地分享旅行中的见闻，让大家听得入迷。', 'Tā xìngzhì bóbó de fēnxiǎng lǚxíng zhōng de jiànwén, ràng dàjiā tīng de rùmí.', 'Anh ấy cực kỳ cao hứng chia sẻ những trải nghiệm trong chuyến du lịch, khiến mọi người nghe say mê.'),
  ('兴旺', '春节期间，市场上的生意特别兴旺，人们购物非常积极。', 'Chūnjié qījiān, shìchǎng shàng de shēngyì tèbié xīngwàng, rénmen gòuwù fēicháng jījí.', 'Trong dịp Tết, các cửa hàng trên thị trường hết sức hưng vượng, mọi người mua sắm rất tích cực.'),
  ('先进', '我们公司的设备技术非常先进，提高了生产效率。', 'Wǒmen gōngsī de shèbèi jìshù fēicháng xiānjìn, tígāo le shēngchǎn xiàolǜ.', 'Thiết bị kỹ thuật của công ty chúng tôi rất tiên tiến, nâng cao hiệu quả sản xuất.'),
  ('先前', '老师在先前的讲座中介绍了这部分内容的重点。', 'Lǎoshī zài xiānqián de jiǎngzuò zhōng jièshào le zhè bùfen nèiróng de zhòngdiǎn.', 'Giáo viên đã giới thiệu những điểm chính của phần này trong bài giảng trước kia.'),
  ('修建', '政府计划在公园旁边修建一座新的体育馆。', 'Zhèngfǔ jìhuà zài gōngyuán pángbiān xiūjiàn yī zuò xīn de tǐyùguǎn.', 'Chính phủ dự định xây dựng một nhà thi đấu thể thao mới bên cạnh công viên.'),
  ('修复', '古老的寺庙经过多年努力终于得到了修复。', 'Gǔlǎo de sìmiào jīngguò duōnián nǔlì zhōngyú dédào le xiūfù.', 'Ngôi chùa cổ đã được sửa chữa sau nhiều năm nỗ lực.'),
  ('修养', '良好的修养能让人在社交场合表现得更加得体。', 'Liánghǎo de xiūyǎng néng ràng rén zài shèjiāo chǎnghé biǎoxiàn de gèngjiā détǐ.', 'Tu dưỡng tốt giúp người ta thể hiện đàng hoàng hơn trong các buổi giao tiếp xã hội.'),
  ('信赖', '客户对我们的产品表示了高度信赖和满意。', 'Kèhù duì wǒmen de chǎnpǐn biǎoshì le gāodù xìnlài hé mǎnyì.', 'Khách hàng bày tỏ sự tin cậy và hài lòng cao đối với sản phẩm của chúng tôi.'),
  ('信誉', '这家公司的信誉很好，所以吸引了很多投资者。', 'Zhè jiā gōngsī de xìnyù hěn hǎo, suǒyǐ xīyǐn le hěnduō tóuzī zhě.', 'Uy tín của công ty này rất tốt, vì thế thu hút nhiều nhà đầu tư.'),
  ('信念', '无论遇到什么困难，他始终坚持自己的信念。', 'Wúlùn yù dào shénme kùnnan, tā shǐzhōng jiānchí zìjǐ de xìnniàn.', 'Dù gặp khó khăn gì, anh ấy luôn kiên định với tâm niệm của mình.'),
  ('信仰', '宗教信仰对他的生活起到了重要的指导作用。', 'Zōngjiào xìnyǎng duì tā de shēnghuó qǐ dào le zhòngyào de zhǐdǎo zuòyòng.', 'Tín ngưỡng tôn giáo đóng vai trò hướng dẫn quan trọng trong cuộc sống của anh ấy.'),
  ('乡镇', '乡镇的发展带动了周边农村的经济增长。', 'Xiāngzhèn de fāzhǎn dàidòng le zhōubiān nóngcūn de jīngjì zēngzhǎng.', 'Sự phát triển của các làng mạc đã thúc đẩy tăng trưởng kinh tế ở vùng nông thôn lân cận.'),
  ('习俗', '了解当地的习俗有助于更好地融入社区生活。', 'Liǎojiě dāngdì de xísú yǒuzhù yú gèng hǎo de róngrù shèqū shēnghuó.', 'Hiểu biết về tập tục địa phương giúp hòa nhập tốt hơn vào đời sống cộng đồng.'),
  ('下属', '经理要求下属按时完成所有的工作任务。', 'Jīnglǐ yāoqiú xiàshǔ ànshí wánchéng suǒyǒu de gōngzuò rènwù.', 'Quản lý yêu cầu cấp dưới hoàn thành mọi nhiệm vụ công việc đúng hạn.'),
  ('鸦雀无声', '听了这个消息，整个会议室顿时鸦雀无声。', 'Tīng le zhège xiāoxi, zhěnggè huìyì shì dùnshí yāquè wú shēng.', 'Nghe tin này, cả phòng họp lập tức lặng im không nói.'),
  ('验证', '科学家们通过实验验证了假设的正确性。', 'Kēxuéjiā men tōngguò shíyàn yànzhèng le jiǎshè de zhèngquè xìng.', 'Các nhà khoa học đã nghiệm chứng tính đúng đắn của giả thuyết qua thí nghiệm.'),
  ('验收', '工程完工后，相关部门对项目进行了严格验收。', 'Gōngchéng wángōng hòu, xiāngguān bùmén duì xiàngmù jìnxíng le yángé yànshōu.', 'Sau khi dự án hoàn thành, các phòng ban liên quan đã tiến hành nghiệm thu nghiêm ngặt.'),
  ('饮食', '健康的饮食习惯对保持良好体质非常重要。', 'Jiànkāng de yǐnshí xíguàn duì bǎochí liánghǎo tǐzhì fēicháng zhòngyào.', 'Thói quen ăn uống lành mạnh rất quan trọng để duy trì sức khỏe tốt.'),
  ('预言', '他曾经预言这场暴风雨将会造成严重的破坏。', 'Tā céngjīng yùyán zhè chǎng bàofēngyǔ jiāng huì zàochéng yánzhòng de pòhuài.', 'Anh ấy từng tiên tri rằng cơn bão này sẽ gây ra thiệt hại nghiêm trọng.'),
  ('预算', '我们需要提前做好明年的公司运营预算。', 'Wǒmen xūyào tíqián zuò hǎo míngnián de gōngsī yùnxíng yùsuàn.', 'Chúng ta cần làm dự toán vận hành công ty cho năm tới từ trước.'),
  ('预期', '销售额已经超过了最初的预期目标。', 'Xiāoshòu''é yǐjīng chāoguòle zuìchū de yùqī mùbiāo.', 'Doanh số đã vượt qua mục tiêu dự kiến ban đầu.'),
  ('预料', '他没有预料到竞争对手会这么强大。', 'Tā méiyǒu yùliào dào jìngzhēng duìshǒu huì zhème qiángdà.', 'Anh ấy không dự liệu được đối thủ cạnh tranh lại mạnh đến vậy.'),
  ('预先', '请您预先支付订金以确保预订成功。', 'Qǐng nín yùxiān zhīfù dìngjīn yǐ quèbǎo yùdìng chénggōng.', 'Xin bạn thanh toán trước tiền đặt cọc để đảm bảo đặt chỗ thành công.'),
  ('预兆', '黑云密布是暴雨来临的预兆。', 'Hēi yún mì bù shì bàoyǔ láilín de yùzhào.', 'Mây đen dày đặc là điềm báo của cơn mưa lớn sắp đến.'),
  ('音响', '音响设备的质量直接影响演唱会的效果。', 'Yīnxiǎng shèbèi de zhìliàng zhíjiē yǐngxiǎng yǎnchànghuì de xiàoguǒ.', 'Chất lượng thiết bị loa ảnh hưởng trực tiếp đến hiệu quả buổi hòa nhạc.'),
  ('隐蔽', '士兵们在森林中寻找一个隐蔽的地方休息。', 'Shìbīngmen zài sēnlín zhōng xúnzhǎo yīgè yǐnbì de dìfang xiūxí.', 'Các binh sĩ đang tìm một nơi giấu kín trong rừng để nghỉ ngơi.'),
  ('隐约', '我隐约听到远处传来音乐声。', 'Wǒ yǐnyuē tīngdào yuǎn chù chuán lái yīnyuè shēng.', 'Tôi lờ mờ nghe thấy tiếng nhạc từ xa vọng lại.'),
  ('隐私', '尊重别人的隐私是基本的社交礼仪。', 'Zūnzhòng biérén de yǐnsī shì jīběn de shèjiāo lǐyí.', 'Tôn trọng chuyện riêng tư của người khác là phép lịch sự cơ bản.'),
  ('隐瞒', '他试图隐瞒自己犯错的事实，但最终被发现了。', 'Tā shìtú yǐnmán zìjǐ fàncuò de shìshí, dàn zuìzhōng bèi fāxiàn le.', 'Anh ta cố che giấu sự thật mình đã phạm lỗi, nhưng cuối cùng bị phát hiện.'),
  ('隐患', '这栋建筑存在严重的安全隐患，需要立即整改。', 'Zhè dòng jiànzhù cúnzài yánzhòng de ānquán yǐnhuàn, xūyào lìjí zhěnggǎi.', 'Tòa nhà này có hiểm họa an toàn nghiêm trọng, cần phải sửa chữa ngay.'),
  ('阴谋', '警方成功揭露了恐怖分子的阴谋计划。', 'Jǐngfāng chénggōng jiēlùle kǒngbù fènzǐ de yīn móu jìhuà.', 'Cảnh sát đã thành công làm sáng tỏ âm mưu của những kẻ khủng bố.'),
  ('野蛮', '这种行为被认为是野蛮而不可接受的。', 'Zhè zhǒng xíngwéi bèi rènwéi shì yěmán ér bùkě jiēshòu de.', 'Hành vi này được xem là man rợ và không thể chấp nhận được.'),
  ('野心', '他有着称霸业界的野心，不断努力提升自己。', 'Tā yǒuzhe chēng bà yè jiè de yěxīn, bùduàn nǔlì tíshēng zìjǐ.', 'Anh ấy có dã tâm thống trị ngành, không ngừng nỗ lực nâng cao bản thân.'),
  ('酝酿', '这次会议的成功是经过长时间酝酿的结果。', 'Zhè cì huìyì de chénggōng shì jīngguò cháng shíjiān yùnniàng de jiéguǒ.', 'Thành công của cuộc họp này là kết quả của quá trình lên men kéo dài.'),
  ('遥远', '他们计划到遥远的外国去旅行探索文化。', 'Tāmen jìhuà dào yáoyuǎn de wàiguó qù lǚxíng tànsuǒ wénhuà.', 'Họ dự định đi du lịch đến những nước xa xôi để khám phá văn hóa.'),
  ('遥控', '这台电视可以通过遥控器轻松操作。', 'Zhè tái diànshì kěyǐ tōngguò yáokòngqì qīngsōng cāozuò.', 'Chiếc tivi này có thể dễ dàng điều khiển bằng remote.'),
  ('遗留', '这个古老的建筑遗留了丰富的历史文化遗产。', 'Zhège gǔlǎo de jiànzhù yíliúle fēngfù de lìshǐ wénhuà yíchǎn.', 'Tòa nhà cổ này để lại một di sản văn hóa lịch sử phong phú.'),
  ('遗失', '他不小心遗失了重要的护照，十分着急。', 'Tā bù xiǎoxīn yíshī le zhòngyào de hùzhào, shífēn zhāojí.', 'Anh ấy vô tình làm mất hộ chiếu quan trọng, rất lo lắng.'),
  ('遗传', '这种疾病主要是通过基因遗传给下一代的。', 'Zhè zhǒng jíbìng zhǔyào shì tōngguò jīyīn yíchuán gěi xià yīdài de.', 'Bệnh này chủ yếu được di truyền cho thế hệ sau qua gen.'),
  ('遗产', '他继承了祖父留下的丰厚遗产，包括房产和存款。', 'Tā jìchéng le zǔfù liú xià de fēnghòu yíchǎn, bāokuò fángchǎn hé cúnkǔn.', 'Anh ấy thừa kế di sản hậu hĩnh ông nội để lại, bao gồm bất động sản và tiền gửi.'),
  ('运行', '这台机器连续运行了三天，没有出现任何故障。', 'Zhè tái jīqì liánxù yùnxíng le sān tiān, méiyǒu chūxiàn rènhé gùzhàng.', 'Chiếc máy này đã vận hành liên tục trong ba ngày, không xảy ra sự cố nào.'),
  ('运算', '计算机能够快速完成复杂的数学运算任务。', 'Jìsuànjī nénggòu kuàisù wánchéng fùzá de shùxué yùnsuàn rènwù.', 'Máy tính có thể hoàn thành nhanh các tác vụ tính toán toán học phức tạp.'),
  ('迎面', '他迎面走来，脸上露出温暖的笑容。', 'Tā yíngmiàn zǒu lái, liǎn shàng lù chū wēnnuǎn de xiàoróng.', 'Anh ấy đang đi về phía đối diện, trên mặt lộ ra nụ cười ấm áp.'),
  ('踊跃', '学生们踊跃参加校园的各种文艺活动。', 'Xuéshēngmen yǒngyuè cānjiā xiàoyuán de gèzhǒng wényì huódòng.', 'Các học sinh nhiệt tình tham gia các hoạt động văn nghệ trong trường.'),
  ('谣言', '网络上流传的谣言很快被事实驳斥了。', 'Wǎngluò shàng liúchuán de yáoyán hěn kuài bèi shìshí bóchì le.', 'Lời đồn trên mạng đã nhanh chóng bị sự thật bác bỏ.'),
  ('诱惑', '面对巨大的利益诱惑，他仍然坚守自己的原则。', 'Miànduì jùdà de lìyì yòuhuò, tā réngrán jiānshǒu zìjǐ de yuánzé.', 'Trước sự mê hoặc lợi ích lớn, anh ta vẫn giữ vững nguyên tắc của mình.'),
  ('言论', '在公共场合发表言论时应注意礼貌和尊重他人。', 'Zài gōnggòng chǎnghé fābiǎo yánlùn shí yīng zhùyì lǐmào hé zūnzhòng tārén.', 'Khi phát biểu ngôn luận nơi công cộng cần chú ý lịch sự và tôn trọng người khác.'),
  ('要素', '团队合作是成功项目的关键要素之一。', 'Tuánduì hézuò shì chénggōng xiàngmù de guānjiàn yàosù zhī yī.', 'Hợp tác nhóm là một trong những yếu tố then chốt của dự án thành công.'),
  ('要点', '这篇文章的要点已经在开头部分清晰说明。', 'Zhè piān wénzhāng de yàodiǎn yǐjīng zài kāitóu bùfèn qīngxī shuōmíng.', 'Điểm chính của bài viết này đã được giải thích rõ ràng ở phần mở đầu.'),
  ('要命', '夏天的高温让人感觉热得要命。', 'Xiàtiān de gāowēn ràng rén gǎnjué rè dé yàomìng.', 'Nhiệt độ cao của mùa hè làm người ta cảm thấy nóng đến chết đi được.'),
  ('衣裳', '她穿着一件漂亮的红色衣裳，显得格外迷人。', 'Tā chuānzhuó yī jiàn piàoliang de hóngsè yīshang, xiǎnde géwài mírén.', 'Cô ấy mặc một chiếc áo đỏ đẹp, trông cực kỳ quyến rũ.'),
  ('蕴藏', '这片土地蕴藏着丰富的矿产资源。', 'Zhè piàn tǔdì yùncáng zhe fēngfù de kuàngchǎn zīyuán.', 'Mảnh đất này chứa đựng nhiều tài nguyên khoáng sản phong phú.'),
  ('英明', '国王以英明的决策带领国家走向繁荣。', 'Guówáng yǐ yīngmíng de juécè dàilǐng guójiā zǒuxiàng fánróng.', 'Nhà vua dẫn dắt quốc gia đi tới thịnh vượng bằng những quyết định anh minh.'),
  ('英勇', '士兵们英勇地冲锋在前，保卫国家安全。', 'Shìbīngmen yīngyǒng de chōngfēng zài qián, bǎowèi guójiā ānquán.', 'Các binh sĩ anh dũng tiến lên phía trước để bảo vệ an ninh quốc gia.'),
  ('舆论', '这场事件引起了广泛的舆论关注。', 'Zhè chǎng shìjiàn yǐnqǐ le guǎngfàn de yúlùn guānzhù.', 'Vụ việc này đã thu hút sự quan tâm rộng rãi của dư luận.'),
  ('耀眼', '阳光照在湖面上，反射出耀眼的光芒。', 'Yángguāng zhào zài húmiàn shàng, fǎnshè chū yàoyǎn de guāngmáng.', 'Ánh nắng chiếu trên mặt hồ, phản chiếu ra ánh sáng chói mắt.'),
  ('翼', '鸟儿展翅飞翔，展开了美丽的翼。', 'Niǎo er zhǎn chì fēixiáng, zhǎnkāi le měilì de yì.', 'Chim giang cánh bay lượn, mở rộng đôi cánh đẹp đẽ.'),
  ('羽绒服', '冬天穿上一件厚实的羽绒服，可以有效抵御严寒。', 'Dōngtiān chuān shàng yī jiàn hòushí de yǔróngfú, kěyǐ yǒuxiào dǐyù yánhán.', 'Mùa đông mặc một chiếc áo lông vũ dày dặn có thể chống lạnh hiệu quả.'),
  ('缘故', '他迟到的缘故是因为交通堵塞。', 'Tā chí dào de yuán gù shì yīn wèi jiāo tōng dǔ sè.', 'Lý do anh ấy đến muộn là vì tắc đường.'),
  ('约束', '公司的规章制度对员工行为有严格的约束。', 'Gōng sī de guī zhāng zhì dù duì yuán gōng xíng wéi yǒu yán gé de yuē shù.', 'Quy chế công ty có sự ràng buộc nghiêm ngặt đối với hành vi nhân viên.'),
  ('眼色', '他一看到领导的眼色就知道该怎么做了。', 'Tā yī kàn dào lǐng dǎo de yǎn sè jiù zhī dào gāi zěn me zuò le.', 'Anh ấy chỉ cần nhìn sắc mặt của lãnh đạo là biết phải làm thế nào.'),
  ('眼神', '她用温柔的眼神看着孩子，充满爱意。', 'Tā yòng wēn róu de yǎn shén kàn zhe hái zi, chōng mǎn ài yì.', 'Cô ấy nhìn đứa trẻ bằng ánh mắt dịu dàng, tràn đầy yêu thương.'),
  ('眼光', '他的眼光非常独到，能发现别人忽略的问题。', 'Tā de yǎn guāng fēi cháng dú dào, néng fā xiàn bié rén hū lüè de wèn tí.', 'Cách nhìn của anh ấy rất độc đáo, có thể phát hiện ra vấn đề mà người khác bỏ qua.'),
  ('盈利', '这家企业连续三年实现了稳定的盈利增长。', 'Zhè jiā qǐ yè lián xù sān nián shí xiàn le wěn dìng de yíng lì zēng zhǎng.', 'Doanh nghiệp này đã đạt được tăng trưởng lợi nhuận ổn định trong ba năm liên tiếp.'),
  ('疑惑', '他对这个计划的可行性表示了疑惑。', 'Tā duì zhè ge jì huà de kě xíng xìng biǎo shì le yí huò.', 'Anh ấy bày tỏ sự nghi ngờ về tính khả thi của kế hoạch này.'),
  ('用户', '我们的产品设计始终以用户需求为中心。', 'Wǒ men de chǎn pǐn shè jì shǐ zhōng yǐ yòng hù xū qiú wéi zhōng xīn.', 'Thiết kế sản phẩm của chúng tôi luôn lấy nhu cầu người dùng làm trung tâm.'),
  ('玉', '这块玉石的颜色非常纯净，价值很高。', 'Zhè kuài yù shí de yán sè fēi cháng chún jìng, jià zhí hěn gāo.', 'Viên ngọc này có màu sắc rất trong, giá trị rất cao.'),
  ('犹如', '她的笑容犹如春天里的阳光，温暖人心。', 'Tā de xiào róng yóu rú chūn tiān lǐ de yáng guāng, wēn nuǎn rén xīn.', 'Nụ cười của cô ấy như ánh nắng mùa xuân, sưởi ấm trái tim người.'),
  ('烟花爆竹', '春节晚上，人们点燃烟花爆竹庆祝新年。', 'Chūn jié wǎn shàng, rén men diǎn rán yān huā bào zhú qìng zhù xīn nián.', 'Tối Tết Nguyên Đán, mọi người đốt pháo hoa pháo nổ để chúc mừng năm mới.'),
  ('炎热', '夏天的中午特别炎热，让人难以忍受。', 'Xià tiān de zhōng wǔ tè bié yán rè, ràng rén nán yǐ rěn shòu.', 'Buổi trưa mùa hè đặc biệt nóng bức khiến người ta khó chịu.'),
  ('演绎', '他能用逻辑推理演绎出复杂的结论。', 'Tā néng yòng luó jí tuī lǐ yǎn yì chū fù zá de jié lùn.', 'Anh ấy có thể dùng suy luận logic để diễn dịch ra kết luận phức tạp.'),
  ('演奏', '小提琴家在音乐会上精彩地演奏了多首曲子。', 'Xiǎo tí qín jiā zài yīn yuè huì shàng jīng cǎi de yǎn zòu le duō shǒu qǔ zi.', 'Nghệ sĩ violin đã biểu diễn nhiều bản nhạc tuyệt vời tại buổi hòa nhạc.'),
  ('演变', '社会的发展演变反映了人们生活方式的改变。', 'Shè huì de fā zhǎn yǎn biàn fǎn yìng le rén men shēng huó fāng shì de gǎi biàn.', 'Sự diễn biến phát triển xã hội phản ánh sự thay đổi cách sống của mọi người.'),
  ('演习', '军队每年都会组织规模庞大的实战演习。', 'Jūn duì měi nián dōu huì zǔ zhī guī mó páng dà de shí zhàn yǎn xí.', 'Quân đội mỗi năm đều tổ chức diễn tập thực chiến quy mô lớn.'),
  ('源泉', '知识是创新的源泉，推动社会进步。', 'Zhī shì shì chuàng xīn de yuán quán, tuī dòng shè huì jìn bù.', 'Kiến thức là nguồn cội của sự sáng tạo, thúc đẩy tiến bộ xã hội.'),
  ('渔民', '渔民们清晨出海捕鱼，生活非常辛苦。', 'Yú mín men qīng chén chū hǎi bǔ yú, shēng huó fēi cháng xīn kǔ.', 'Ngư dân ra biển đánh cá vào sáng sớm, cuộc sống rất vất vả.'),
  ('淹没', '洪水将农田淹没，农作物损失严重。', 'Hóng shuǐ jiāng nóng tián yān mò, nóng zuò wù sǔn shī yán zhòng.', 'Lũ lụt đã nhấn chìm ruộng đồng, thiệt hại cây trồng rất nghiêm trọng.'),
  ('液体', '水是一种无色无味的液体，生命必需。', 'Shuǐ shì yī zhǒng wú sè wú wèi de yè tǐ, shēng mìng bì xū.', 'Nước là một loại chất lỏng không màu, không mùi, cần thiết cho sự sống.'),
  ('涌现', '近年来，许多新的科技公司在市场上涌现出来，引起广泛关注。', 'Jìnnián lái, xǔduō xīn de kējì gōngsī zài shìchǎng shàng yǒngxiàn chūlái, yǐnqǐ guǎngfàn guānzhù.', 'Những năm gần đây, nhiều công ty công nghệ mới liên tục trào dâng trên thị trường, thu hút sự chú ý rộng rãi.'),
  ('沿海', '中国沿海地区由于气候温暖，适合发展渔业和旅游业。', 'Zhōngguó yánhǎi dìqū yóuyú qìhòu wēnnuǎn, shìhé fāzhǎn yúyè hé lǚyóu yè.', 'Các vùng duyên hải Trung Quốc do khí hậu ấm áp nên thích hợp phát triển ngành đánh bắt cá và du lịch.'),
  ('油腻', '这道菜味道很丰富，但吃起来有点油腻，适合夏天少吃。', 'Zhè dào cài wèidào hěn fēngfù, dàn chī qǐlái yǒudiǎn yóunì, shìhé xiàtiān shǎo chī.', 'Món ăn này hương vị rất phong phú, nhưng khi ăn có chút ngấy, thích hợp nên ăn ít vào mùa hè.'),
  ('油漆', '工人们正在给房子外墙刷油漆，使其看起来焕然一新。', 'Gōngrénmen zhèngzài gěi fángzi wàiqiáng shuā yóuqī, shǐ qí kàn qǐlái huànrán yī xīn.', 'Công nhân đang sơn dầu ngoại thất ngôi nhà, khiến nó trông mới mẻ hoàn toàn.'),
  ('永恒', '他们的友谊像星空一样永恒，不会随着时间消逝。', 'Tāmen de yǒuyì xiàng xīngkōng yíyàng yǒnghéng, bù huì suízhe shíjiān xiāoshì.', 'Tình bạn của họ giống như bầu trời sao vĩnh hằng, không phai mờ theo thời gian.'),
  ('氧气', '高山上的氧气稀薄，登山者需要携带氧气瓶。', 'Gāoshān shàng de yǎngqì xībó, dēngshān zhě xūyào xiédài yǎngqì píng.', 'Oxy trên núi cao rất loãng, người leo núi cần mang bình oxy theo.'),
  ('毅然', '面对困难，他毅然决定坚持到底，不轻言放弃。', 'Miànduì kùnnan, tā yìrán juédìng jiānchí dàodǐ, bù qīngyán fàngqì.', 'Đối mặt với khó khăn, anh ấy kiên quyết quyết định kiên trì đến cùng, không dễ dàng từ bỏ.'),
  ('毅力', '成功需要天赋，更需要持久的毅力和努力。', 'Chénggōng xūyào tiānfù, gèng xūyào chíjiǔ de yìlì hé nǔlì.', 'Thành công cần tài năng, nhưng còn cần nghị lực và nỗ lực bền bỉ.'),
  ('欲望', '人的欲望如果无法控制，可能会带来负面影响。', 'Rén de yùwàng rúguǒ wúfǎ kòngzhì, kěnéng huì dàilái fùmiàn yǐngxiǎng.', 'Dục vọng của con người nếu không kiểm soát được thì có thể gây ra tác động tiêu cực.'),
  ('样品', '客户对产品样品提出了修改意见，希望能更符合市场需求。', 'Kèhù duì chǎnpǐn yàngpǐn tíchūle xiūgǎi yìjiàn, xīwàng néng gèng fúhé shìchǎng xūqiú.', 'Khách hàng đã đưa ra ý kiến chỉnh sửa đối với sản phẩm mẫu, mong muốn nó phù hợp hơn với nhu cầu thị trường.'),
  ('有条不紊', '他工作时总是有条不紊，效率很高，深受领导认可。', 'Tā gōngzuò shí zǒng shì yǒutiáo bùwěn, xiàolǜ hěn gāo, shēn shòu lǐngdǎo rènkě.', 'Anh ấy làm việc lúc nào cũng có thứ tự chặt chẽ, hiệu quả rất cao, được lãnh đạo đánh giá cao.'),
  ('摇滚', '去年夏天，我去参加了一场激动人心的摇滚音乐会。', 'Qùnián xiàtiān, wǒ qù cānjiāle yī chǎng jīdòng rénxīn de yáogǔn yīnyuè huì.', 'Mùa hè năm ngoái, tôi đã tham dự một buổi hòa nhạc nhạc rock đầy sôi động.'),
  ('摇摆', '秋风吹过，树枝轻轻地摇摆，显得生机勃勃。', 'Qiūfēng chuīguò, shùzhī qīngqīng de yáobǎi, xiǎnde shēngjī bóbó.', 'Gió thu thổi qua, cành cây nhẹ nhàng lắc lư, trông rất sinh động.'),
  ('掩饰', '他试图用笑容来掩饰内心的紧张和不安。', 'Tā shìtú yòng xiàoróng lái yǎnshì nèixīn de jǐnzhāng hé bù''ān.', 'Anh ấy cố gắng dùng nụ cười để che giấu sự căng thẳng và bất an trong lòng.'),
  ('掩盖', '无法用谎言掩盖事实真相，迟早会被揭穿。', 'Wúfǎ yòng huǎngyán yǎngài shìshí zhēnxiàng, chízǎo huì bèi jiēchuān.', 'Không thể dùng lời nói dối để che lấp sự thật, sớm hay muộn cũng bị vạch trần.'),
  ('掩护', '士兵们在掩护队友撤退时表现出了极大的勇气。', 'Shìbīngmen zài yǎnhù duìyǒu chètuì shí biǎoxiàn chūle jídà de yǒngqì.', 'Các binh sĩ thể hiện lòng dũng cảm lớn khi bảo vệ đồng đội rút lui.'),
  ('拥有', '一个人要想成功，必须拥有坚定的信念和不断学习的态度。', 'Yīgè rén yào xiǎng chénggōng, bìxū yōngyǒu jiāndìng de xìnniàn hé bùduàn xuéxí de tàidù.', 'Muốn thành công, một người phải có niềm tin kiên định và thái độ học hỏi liên tục.'),
  ('拥护', '人民群众一致拥护政府的新政策，期待社会更加繁荣。', 'Rénmín qúnzhòng yīzhì yōnghù zhèngfǔ de xīn zhèngcè, qīdài shèhuì gèngjiā fánróng.', 'Nhân dân nhất trí bảo vệ chính sách mới của chính phủ, mong xã hội ngày càng thịnh vượng.'),
  ('愚蠢', '犯下这样的错误实在太愚蠢了，需要认真反思。', 'Fànxià zhèyàng de cuòwù shízài tài yúchǔn le, xūyào rènzhēn fǎnsī.', 'Phạm phải sai lầm như vậy thật quá ngu xuẩn, cần phải suy ngẫm nghiêm túc.'),
  ('愚昧', '科学知识的普及有助于消除社会中的愚昧现象。', 'Kēxué zhīshì de pǔjí yǒuzhù yú xiāochú shèhuì zhōng de yúmèi xiànxiàng.', 'Việc phổ cập kiến thức khoa học giúp loại bỏ hiện tượng ngu muội trong xã hội.'),
  ('意识', '他突然意识到自己犯了一个很大的错误。', 'Tā tūrán yìshí dào zìjǐ fàn le yí gè hěn dà de cuòwù.', 'Anh ấy đột nhiên nhận thức được mình đã phạm phải một sai lầm rất lớn.'),
  ('意料', '这次比赛的结果超出了所有人的意料。', 'Zhè cì bǐsài de jiéguǒ chāo chū le suǒyǒu rén de yìliào.', 'Kết quả của trận đấu lần này vượt qua dự liệu của tất cả mọi người.'),
  ('意志', '只有坚强的意志才能克服困难取得成功。', 'Zhǐ yǒu jiānqiáng de yìzhì cáinéng kèfú kùnnan qǔdé chénggōng.', 'Chỉ có ý chí kiên cường mới có thể vượt qua khó khăn để đạt được thành công.'),
  ('意图', '他的言行表现出明显的恶意和不良意图。', 'Tā de yánxíng biǎoxiàn chū míngxiǎn de èyì hé bùliáng yìtú.', 'Lời nói và hành động của anh ta thể hiện rõ ý đồ xấu và ác ý.'),
  ('意味着', '这场胜利意味着球队进入了总决赛阶段。', 'Zhè chǎng shènglì yìwèizhe qiúduì jìnrù le zǒng juésài jiēduàn.', 'Chiến thắng này có nghĩa là đội bóng đã vào vòng chung kết.'),
  ('意向', '他表达了对合作项目的浓厚意向。', 'Tā biǎodá le duì hézuò xiàngmù de nónghòu yìxiàng.', 'Anh ấy bày tỏ ý đồ mạnh mẽ về dự án hợp tác.'),
  ('愈', '随着时间的推移，伤口渐渐愈合了。', 'Suízhe shíjiān de tuīyí, shāngkǒu jiànjiàn yùhé le.', 'Theo thời gian, vết thương dần dần khỏi bệnh.'),
  ('忧郁', '她因为失恋而变得忧郁寡欢，久久不能释怀。', 'Tā yīnwèi shīliàn ér biàn de yōuyù guǎhuān, jiǔjiǔ bùnéng shìhuái.', 'Cô ấy trở nên sầu muộn, u sầu vì thất tình, mãi không thể quên đi.'),
  ('引用', '在论文中正确引用权威资料非常重要。', 'Zài lùnwén zhōng zhèngquè yǐnyòng quánwēi zīliào fēicháng zhòngyào.', 'Việc trích dẫn tài liệu uy tín một cách chính xác trong luận văn rất quan trọng.'),
  ('引擎', '这辆汽车的引擎性能强劲，能耗却很低。', 'Zhè liàng qìchē de yǐnqíng xìngnéng qiángjìng, néng hào què hěn dī.', 'Động cơ của chiếc ô tô này có hiệu suất mạnh mẽ, nhưng mức tiêu thụ nhiên liệu lại rất thấp.'),
  ('引导', '老师耐心引导学生掌握复杂的语法规则。', 'Lǎoshī nàixīn yǐndǎo xuéshēng zhǎngwò fùzá de yǔfǎ guīzé.', 'Giáo viên kiên nhẫn hướng dẫn học sinh nắm vững các quy tắc ngữ pháp phức tạp.'),
  ('异常', '系统检测到异常活动，立即启动了安全措施。', 'Xìtǒng jiǎncè dào yìcháng huódòng, lìjí qǐdòng le ānquán cuòshī.', 'Hệ thống phát hiện hoạt động bất thường và lập tức kích hoạt các biện pháp an toàn.'),
  ('延续', '这项传统活动已经延续了几百年，深受欢迎。', 'Zhè xiàng chuántǒng huódòng yǐjīng yánxù le jǐ bǎi nián, shēn shòu huānyíng.', 'Hoạt động truyền thống này đã được duy trì liên tục hàng trăm năm và rất được yêu thích.'),
  ('延期', '比赛因天气恶劣宣布延期举行。', 'Bǐsài yīn tiānqì èliè xuānbù yánqī jǔxíng.', 'Trận đấu được thông báo kéo dài thời hạn vì thời tiết xấu.'),
  ('延伸', '河流从山脉延伸到平原，滋养着沿途的土地。', 'Héliú cóng shānmài yánshēn dào píngyuán, zīyǎng zhe yántú de tǔdì.', 'Dòng sông vươn ra từ dãy núi đến đồng bằng, nuôi dưỡng đất dọc theo đường đi.'),
  ('庸俗', '这部电影的情节庸俗，缺乏深度和创意。', 'Zhè bù diànyǐng de qíngjié yōngsú, quēfá shēndù hé chuàngyì.', 'Tình tiết của bộ phim này rất dung tục, thiếu chiều sâu và sáng tạo.'),
  ('应酬', '他花了很多时间参加各种社交应酬活动。', 'Tā huā le hěn duō shíjiān cānjiā gè zhǒng shèjiāo yìngchou huódòng.', 'Anh ấy dành nhiều thời gian tham gia các buổi tiệc xã giao khác nhau.'),
  ('应邀', '她应邀出席了国际学术会议并发表演讲。', 'Tā yìngyāo chūxí le guójì xuéshù huìyì bìng fābiǎo yǎnjiǎng.', 'Cô ấy nhận lời mời tham dự hội nghị khoa học quốc tế và phát biểu.'),
  ('幼稚', '他的想法有点幼稚，需要更加成熟和理智。', 'Tā de xiǎngfǎ yǒudiǎn yòuzhì, xūyào gèngjiā chéngshú hé lǐzhì.', 'Ý nghĩ của anh ấy hơi ngây thơ, cần phải trưởng thành và lý trí hơn.'),
  ('岳母', '我非常尊敬岳母，她对我们的帮助很多。', 'Wǒ fēicháng zūnjìng yuèmǔ, tā duì wǒmen de bāngzhù hěn duō.', 'Tôi rất kính trọng mẹ vợ, bà đã giúp đỡ chúng tôi rất nhiều.'),
  ('岩石', '这座山上的岩石经历了数百万年的风化。', 'Zhè zuò shān shàng de yánshí jīnglìle shù bǎi wàn nián de fēnghuà.', 'Những tảng nham thạch trên ngọn núi này đã trải qua vô vàn năm phong hóa.'),
  ('寓言', '寓言故事往往通过动物角色传递人生哲理。', 'Yùyán gùshì wǎngwǎng tōngguò dòngwù juésè chuándì rénshēng zhélǐ.', 'Truyện ngụ ngôn thường truyền đạt triết lý cuộc sống thông qua các nhân vật động vật.'),
  ('宇宙', '宇宙的奥秘吸引了无数科学家的探索热情。', 'Yǔzhòu de àomì xīyǐnle wúshù kēxuéjiā de tànsuǒ rèqíng.', 'Bí ẩn của vũ trụ thu hút sự nhiệt huyết khám phá của vô số nhà khoa học.'),
  ('孕育', '春天是万物孕育新生命的季节。', 'Chūntiān shì wànwù yùnyù xīn shēngmìng de jìjié.', 'Mùa xuân là mùa mang thai của muôn loài sinh mệnh mới.'),
  ('婴儿', '护士细心照顾刚出生的婴儿。', 'Hùshì xìxīn zhàogù gāng chūshēng de yīng''ér.', 'Y tá chăm sóc cẩn thận em bé mới sinh.'),
  ('圆满', '他们的婚礼举办得非常圆满和成功。', 'Tāmen de hūnlǐ jǔbàn de fēicháng yuánmǎn hé chénggōng.', 'Lễ cưới của họ được tổ chức rất viên mãn và thành công.'),
  ('园林', '苏州的园林以其精致的设计闻名世界。', 'Sūzhōu de yuánlín yǐ qí jīngzhì de shèjì wénmíng shìjiè.', 'Lâm viên ở Tô Châu nổi tiếng thế giới bởi thiết kế tinh tế.'),
  ('原理', '这台机器的工作原理并不复杂。', 'Zhè tái jīqì de gōngzuò yuánlǐ bìng bù fùzá.', 'Nguyên lý hoạt động của máy này không phức tạp.'),
  ('原始', '我们参观了保存完好的原始森林。', 'Wǒmen cānguānle bǎocún wánhǎo de yuánshǐ sēnlín.', 'Chúng tôi đã tham quan khu rừng nguyên thủy được bảo tồn nguyên vẹn.'),
  ('原告', '原告在法庭上陈述了自己的诉求。', 'Yuángào zài fǎtíng shàng chénshùle zìjǐ de sùqiú.', 'Nguyên cáo đã trình bày yêu cầu của mình tại tòa án.'),
  ('原先', '原先计划的行程因为天气变化有所调整。', 'Yuánxiān jìhuà de xíngchéng yīnwèi tiānqì biànhuà yǒu suǒ tiáozhěng.', 'Lịch trình ban đầu đã được điều chỉnh vì thời tiết thay đổi.'),
  ('厌恶', '他对说谎的人怀有强烈的厌恶情绪。', 'Tā duì shuōhuǎng de rén huáiyǒu qiángliè de yànwù qíngxù.', 'Anh ta có cảm giác ghét bỏ mạnh mẽ đối với người nói dối.'),
  ('压迫', '那个国家的人民一直生活在压迫之下。', 'Nàgè guójiā de rénmín yīzhí shēnghuó zài yāpò zhī xià.', 'Nhân dân của đất nước đó luôn sống trong sự áp bức.'),
  ('压缩', '文件太大了，需要进行压缩才能发送。', 'Wénjiàn tài dà le, xūyào jìnxíng yāsuō cáinéng fāsòng.', 'Tập tin quá lớn, cần nén lại mới có thể gửi đi.'),
  ('压榨', '资本家常常压榨工人的劳动成果。', 'Zīběnjiā chángcháng yāzhà gōngrén de láodòng chéngguǒ.', 'Tư bản chủ nghĩa thường xuyên đàn áp thành quả lao động của công nhân.'),
  ('压抑', '长时间的压抑让他感到身心俱疲。', 'Cháng shíjiān de yāyì ràng tā gǎndào shēnxīn jù pí.', 'Sự đè nén kéo dài khiến anh ta cảm thấy cả tâm hồn lẫn thể xác đều mệt mỏi.'),
  ('压岁钱', '春节期间，孩子们都期待收到长辈的压岁钱。', 'Chūnjié qījiān, háizimen dōu qīdài shōudào zhǎngbèi de yāsuìqián.', 'Trong dịp Tết, các em nhỏ đều mong nhận được tiền mừng tuổi từ người lớn.'),
  ('压制', '警方采取武力压制示威者引发争议。', 'Jǐngfāng cǎiqǔ wǔlì yāzhì shìwēizhě yǐnfā zhēngyì.', 'Cảnh sát sử dụng vũ lực để trấn áp người biểu tình gây tranh cãi.'),
  ('勇于', '他勇于面对生活中的各种挑战。', 'Tā yǒngyú miànduì shēnghuó zhōng de gèzhǒng tiǎozhàn.', 'Anh ta dám đối mặt với mọi thử thách trong cuộc sống.'),
  ('冤枉', '他被误解而感到非常冤枉。', 'Tā bèi wùjiě ér gǎndào fēicháng yuānwang.', 'Anh ta cảm thấy rất oan uổng vì bị hiểu lầm.'),
  ('元首', '各国元首在峰会上表达了共同的合作意愿。', 'Gèguó yuánshǒu zài fēnghuì shàng biǎodále gòngtóng de hézuò yìyuàn.', 'Nguyên thủ các nước đã bày tỏ nguyện vọng hợp tác chung tại hội nghị thượng đỉnh.'),
  ('元素', '水是生命不可缺少的基本元素之一。', 'Shuǐ shì shēngmìng bùkě quēshǎo de jīběn yuánsù zhī yī.', 'Nước là một trong những nguyên tố cơ bản không thể thiếu của sự sống.'),
  ('元宵节', '我们一家人在元宵节那天一起吃汤圆庆祝。', 'Wǒmen yījiā rén zài Yuánxiāo Jié nà tiān yīqǐ chī tāngyuán qìngzhù.', 'Gia đình chúng tôi cùng ăn bánh trôi trong ngày Tết Nguyên tiêu để mừng.'),
  ('依靠', '年轻人在成长过程中需要依靠家人的支持和关爱。', 'Niánqīng rén zài chéngzhǎng guòchéng zhōng xūyào yīkào jiārén de zhīchí hé guān''ài.', 'Người trẻ trong quá trình trưởng thành cần có chỗ dựa là sự ủng hộ và quan tâm của gia đình.'),
  ('依赖', '孩子们不应该过度依赖电子产品，要学会独立思考。', 'Háizimen bù yīnggāi guòdù yīlài diànzǐ chǎnpǐn, yào xuéhuì dúlì sīkǎo.', 'Trẻ em không nên quá dựa dẫm vào thiết bị điện tử, phải học cách suy nghĩ độc lập.'),
  ('依旧', '虽然时间过去多年，他的笑容依旧那么温暖。', 'Suīrán shíjiān guòqù duōnián, tā de xiàoróng yījiù nàme wēnnuǎn.', 'Dù đã nhiều năm trôi qua, nụ cười của anh ấy vẫn ấm áp như xưa.'),
  ('依据', '法院的判决必须严格依据法律条款。', 'Fǎyuàn de pànjué bìxū yángé yījù fǎlǜ tiáokuǎn.', 'Phán quyết của tòa án phải dựa trên các điều khoản pháp luật một cách nghiêm ngặt.'),
  ('依托', '这家公司依托先进的技术迅速发展起来。', 'Zhè jiā gōngsī yītuō xiānjìn de jìshù xùnsù fāzhǎn qǐlái.', 'Công ty này dựa vào công nghệ tiên tiến để phát triển nhanh chóng.'),
  ('优越', '他凭借优越的条件获得了这次比赛的冠军。', 'Tā píngjiè yōuyuè de tiáojiàn huòdéle zhè cì bǐsài de guànjūn.', 'Anh ấy nhờ điều kiện ưu việt đã giành được chức vô địch trong cuộc thi này.'),
  ('优胜劣汰', '在激烈的市场竞争中，优胜劣汰是常态。', 'Zài jīliè de shìchǎng jìngzhēng zhōng, yōushèng liètāi shì chángtài.', 'Trong cạnh tranh thị trường khốc liệt, mạnh được yếu thua là điều bình thường.'),
  ('优异', '他在学术研究方面取得了优异的成绩。', 'Tā zài xuéshù yánjiū fāngmiàn qǔdéle yōuyì de chéngjī.', 'Anh ấy đã đạt được thành tích xuất sắc trong lĩnh vực nghiên cứu học thuật.'),
  ('优先', '紧急情况下，伤者必须被优先救治。', 'Jǐnjí qíngkuàng xià, shāngzhě bìxū bèi yōuxiān jiùzhì.', 'Trong tình huống khẩn cấp, những người bị thương phải được cứu chữa ưu tiên.'),
  ('仪式', '毕业典礼的仪式非常庄重隆重，令人难忘。', 'Bìyè diǎnlǐ de yíshì fēicháng zhuāngzhòng lóngzhòng, lìng rén nánwàng.', 'Nghi thức lễ tốt nghiệp rất trang trọng và long trọng, gây ấn tượng khó quên.'),
  ('仪器', '科学家使用精密仪器进行实验数据的测量。', 'Kēxuéjiā shǐyòng jīngmì yíqì jìnxíng shíyàn shùjù de cèliáng.', 'Các nhà khoa học sử dụng thiết bị máy đo tinh vi để đo dữ liệu thí nghiệm.'),
  ('以致', '他的错误决定以致公司遭受了严重损失。', 'Tā de cuòwù juédìng yǐzhì gōngsī zāoshòule yánzhòng sǔnshī.', 'Quyết định sai lầm của anh ta dẫn đến công ty chịu tổn thất nghiêm trọng.'),
  ('以至', '天气持续寒冷，以至于很多居民都感冒了。', 'Tiānqì chíxù hánlěng, yǐzhì yú hěn duō jūmín dōu gǎnmào le.', 'Thời tiết liên tục lạnh đến mức nhiều cư dân đều bị cảm.'),
  ('以往', '以往这里是一个热闹的市场，现在已经变得安静了。', 'Yǐwǎng zhèlǐ shì yīgè rènào de shìchǎng, xiànzài yǐjīng biàndé ānjìng le.', 'Trước kia nơi đây là một khu chợ nhộn nhịp, bây giờ đã trở nên yên tĩnh.'),
  ('以免', '请提前通知对方，以免发生误会。', 'Qǐng tíqián tōngzhī duìfāng, yǐmiǎn fāshēng wùhuì.', 'Xin hãy thông báo trước cho đối phương để tránh xảy ra hiểu lầm.'),
  ('以便', '我提前准备资料，以便开会时使用。', 'Wǒ tíqián zhǔnbèi zīliào, yǐbiàn kāihuì shí shǐyòng.', 'Tôi chuẩn bị tài liệu trước để tiện sử dụng trong buổi họp.'),
  ('亦', '他不仅是一名优秀的老师，亦是一位出色的作家。', 'Tā bùjǐn shì yī míng yōuxiù de lǎoshī, yì shì yī wèi chūsè de zuòjiā.', 'Anh ấy không chỉ là một giáo viên xuất sắc mà còn là một nhà văn tài năng.'),
  ('亚军', '这次比赛他获得了亚军，表现非常出色。', 'Zhè cì bǐ sài tā huò dé le yà jūn, biǎo xiàn fēi cháng chū sè.', 'Trong cuộc thi này, anh ấy đã giành á quân, thể hiện rất xuất sắc.'),
  ('乐谱', '钢琴老师给我发了一份新的乐谱，让我练习。', 'Gāng qín lǎo shī gěi wǒ fā le yī fèn xīn de yuè pǔ, ràng wǒ liàn xí.', 'Thầy dạy đàn piano đã gửi cho tôi một bản nhạc mới để luyện tập.'),
  ('严禁', '这里严禁吸烟，违者将被罚款。', 'Zhè lǐ yán jìn xī yān, wéi zhě jiāng bèi fá kuǎn.', 'Ở đây nghiêm cấm hút thuốc, vi phạm sẽ bị phạt tiền.'),
  ('严峻', '面对严峻的考验，我们必须坚持不懈。', 'Miàn duì yán jùn de kǎo yàn, wǒ men bì xū jiān chí bù xiè.', 'Đối mặt với những thử thách cam go, chúng ta phải kiên trì không ngừng.'),
  ('严寒', '北方的严寒使得农作物难以生长。', 'Běi fāng de yán hán shǐ dé nóng zuò wù nán yǐ shēng zhǎng.', 'Thời tiết lạnh khắc nghiệt ở miền Bắc khiến cây trồng khó phát triển.'),
  ('严密', '警方对案发现场进行了严密的调查。', 'Jǐng fāng duì àn fā xiàn chǎng jìn xíng le yán mì de diào chá.', 'Cảnh sát đã tiến hành điều tra nghiêm ngặt hiện trường vụ án.'),
  ('严厉', '老师对学生的纪律要求非常严厉。', 'Lǎo shī duì xué shēng de jì lǜ yāo qiú fēi cháng yán lì.', 'Giáo viên yêu cầu kỷ luật với học sinh rất nghiêm khắc.'),
  ('与日俱增', '他的工作压力与日俱增，需要及时调整心态。', 'Tā de gōng zuò yā lì yǔ rì jù zēng, xū yào jí shí tiáo zhěng xīn tài.', 'Áp lực công việc của anh ấy tăng lên từng ngày, cần phải điều chỉnh tâm trạng kịp thời.'),
  ('一贯', '他一贯保持乐观的态度，很少抱怨。', 'Tā yī guàn bǎo chí lè guān de tài dù, hěn shǎo bào yuàn.', 'Anh ấy luôn giữ thái độ lạc quan và rất ít phàn nàn.'),
  ('一目了然', '这张地图结构清晰，一目了然。', 'Zhè zhāng dì tú jié gòu qīng xī, yī mù liǎo rán.', 'Bản đồ này có cấu trúc rõ ràng, nhìn là hiểu.'),
  ('一流', '她是一流的医生，技术非常高超。', 'Tā shì yī liú de yī shēng, jì shù fēi cháng gāo chāo.', 'Cô ấy là bác sĩ hàng đầu, kỹ thuật rất xuất sắc.'),
  ('一度', '这部电影一度成为票房冠军，受到了广泛好评。', 'Zhè bù diàn yǐng yī dù chéng wéi piào fáng guàn jūn, shòu dào le guǎng fàn hǎo píng.', 'Bộ phim này từng một lần trở thành quán quân phòng vé và nhận được nhiều đánh giá tốt.'),
  ('一帆风顺', '祝你未来的事业一帆风顺，取得更大成就。', 'Zhù nǐ wèi lái de shì yè yī fān fēng shùn, qǔ dé gèng dà chéng jiù.', 'Chúc bạn sự nghiệp tương lai thuận buồm xuôi gió, đạt được thành tựu lớn hơn.'),
  ('一如既往', '他对工作的态度一如既往地认真负责。', 'Tā duì gōng zuò de tài dù yī rú jì wǎng de rèn zhēn fù zé.', 'Anh ấy luôn nghiêm túc và có trách nhiệm với công việc như trước giờ.'),
  ('一向', '他一向喜欢早起锻炼身体，从不懈怠。', 'Tā yī xiàng xǐ huān zǎo qǐ duàn liàn shēn tǐ, cóng bù xiè dài.', 'Anh ấy luôn thích dậy sớm tập thể dục và chưa bao giờ lười biếng.'),
  ('一举两得', '参加这个培训既能提升技能，又能认识新朋友，真是一举两得。', 'Cān jiā zhè ge péi xùn jì néng tí shēng jì néng, yòu néng rèn shi xīn péng yǒu, zhēn shì yī jǔ liǎng dé.', 'Tham gia khóa đào tạo này vừa nâng cao kỹ năng lại vừa kết bạn mới thật là nhất cử lưỡng tiện.'),
  ('一丝不苟', '他做事一丝不苟，从不马虎。', 'Tā zuò shì yī sī bù gǒu, cóng bù mǎ hǔ.', 'Anh ấy làm việc rất cẩn thận, chưa bao giờ qua loa.'),
  ('熨', '妈妈教我怎么用熨斗熨平衣服上的皱纹。', 'Mā mā jiāo wǒ zěn me yòng yùn dǒu yùn píng yī fu shàng de zhòu wén.', 'Mẹ dạy tôi cách dùng bàn là để là phẳng các nếp nhăn trên quần áo.'),
  ('驻扎', '军队在边境地区驻扎，以确保安全。', 'Jūn duì zài biān jìng dì qū zhù zhā, yǐ què bǎo ān quán.', 'Quân đội đóng quân ở khu vực biên giới để đảm bảo an ninh.'),
  ('震撼', '这部电影的剧情非常震撼，让人难以忘怀。', 'Zhè bù diàn yǐng de jù qíng fēi cháng zhèn hàn, ràng rén nán yǐ wàng huái.', 'Cốt truyện của bộ phim này rất gây ấn tượng mạnh, khiến người ta khó quên.'),
  ('震惊', '这则新闻的内容让整个社会感到震惊。', 'Zhè zé xīnwén de nèiróng ràng zhěnggè shèhuì gǎndào zhènjīng.', 'Nội dung tin tức này khiến cả xã hội cảm thấy chấn động.'),
  ('障碍', '语言障碍是我们交流时遇到的主要问题。', 'Yǔyán zhàng''ài shì wǒmen jiāoliú shí yù dào de zhǔyào wèntí.', 'Trở ngại ngôn ngữ là vấn đề chính khi chúng ta giao tiếp.'),
  ('阻碍', '缺乏资金严重阻碍了项目的顺利进行。', 'Quēfá zījīn yánzhòng zǔ''ài le xiàngmù de shùnlì jìnxíng.', 'Thiếu vốn nghiêm trọng cản trở tiến độ suôn sẻ của dự án.'),
  ('阻挠', '敌人的策略不断阻挠我们的计划实施。', 'Dírén de cèlüè bùduàn zǔnáo wǒmen de jìhuà shíshī.', 'Chiến lược của địch liên tục ngăn chặn việc thực hiện kế hoạch của chúng ta.'),
  ('阻拦', '警察成功阻拦了那些试图逃跑的罪犯。', 'Jǐngchá chénggōng zǔlán le nàxiē shìtú táopǎo de zuìfàn.', 'Cảnh sát đã thành công ngăn cản những tội phạm cố gắng bỏ chạy.'),
  ('阵容', '这次比赛的队伍阵容比以往更加强大。', 'Zhè cì bǐsài de duìwǔ zhènróng bǐ yǐwǎng gèng jiā qiángdà.', 'Đội hình của đội trong trận đấu lần này mạnh hơn mọi khi.'),
  ('阵地', '士兵们坚守在前线阵地上抵御敌人进攻。', 'Shìbīngmen jiānshǒu zài qiánxiàn zhèndì shàng dǐyù dírén jìngōng.', 'Binh lính kiên cường giữ vững trận địa tiền tuyến để chống lại địch.'),
  ('镇静', '面对突发状况，他始终保持镇静和冷静。', 'Miànduì túfā zhuàngkuàng, tā shǐzhōng bǎochí zhènjìng hé lěngjìng.', 'Đối mặt với tình huống bất ngờ, anh ấy luôn giữ bình tĩnh và điềm đạm.'),
  ('镇定', '她镇定地处理了紧急事件，避免了更大损失。', 'Tā zhèndìng de chǔlǐ le jǐnjí shìjiàn, bìmiǎn le gèng dà sǔnshī.', 'Cô ấy xử lý sự cố khẩn cấp một cách chấn tĩnh, tránh được thiệt hại lớn hơn.'),
  ('铸造', '这家工厂专门铸造高质量的金属零件。', 'Zhè jiā gōngchǎng zhuānmén zhùzào gāo zhìliàng de jīnshǔ língjiàn.', 'Nhà máy này chuyên đúc các bộ phận kim loại chất lượng cao.'),
  ('钻研', '他花了多年时间深入钻研人工智能技术。', 'Tā huā le duō nián shíjiān shēnrù zuānyán réngōng zhìnéng jìshù.', 'Anh ấy đã dành nhiều năm nghiên cứu chuyên sâu về công nghệ trí tuệ nhân tạo.'),
  ('钻石', '这枚戒指上镶嵌了一颗罕见的钻石。', 'Zhè méi jièzhi shàng xiāngqiàn le yī kē hǎnjiàn de zuànshí.', 'Chiếc nhẫn này đính một viên kim cương hiếm có.'),
  ('重心', '在进行这项工作时，应把重心放在质量控制上。', 'Zài jìnxíng zhè xiàng gōngzuò shí, yīng bǎ zhòngxīn fàng zài zhìliàng kòngzhì shàng.', 'Khi thực hiện công việc này, nên đặt trọng tâm vào kiểm soát chất lượng.'),
  ('郑重', '他在公开场合郑重承诺会兑现诺言。', 'Tā zài gōngkāi chǎnghé zhèngzhòng chéngnuò huì duìxiàn nuòyán.', 'Anh ấy đã trịnh trọng hứa sẽ giữ lời hứa trước công chúng.'),
  ('遵循', '所有员工必须遵循公司的规章制度才能保证秩序。', 'Suǒyǒu yuángōng bìxū zūnxún gōngsī de guīzhāng zhìdù cáinéng bǎozhèng zhìxù.', 'Tất cả nhân viên phải tuân theo quy định của công ty để đảm bảo trật tự.'),
  ('遮挡', '高楼遮挡了阳光，导致花园里光线不足。', 'Gāolóu zhēdǎng le yángguāng, dǎozhì huāyuán lǐ guāngxiàn bùzú.', 'Những tòa nhà cao đã che khuất ánh sáng, khiến vườn hoa thiếu sáng.'),
  ('遭遇', '他在旅行中遭遇了一场突如其来的暴风雨。', 'Tā zài lǚxíng zhōng zāoyù le yī chǎng túrúqílái de bàofēngyǔ.', 'Anh ấy đã gặp phải một trận bão bất ngờ trong chuyến du lịch.'),
  ('遭殃', '污染问题让附近的居民都遭殃了。', 'Wūrǎn wèntí ràng fùjìn de jūmín dōu zāoyāng le.', 'Vấn đề ô nhiễm đã khiến cư dân quanh khu vực gặp tai ương.'),
  ('遭受', '这个公司近年来遭受了严重的经济损失。', 'Zhège gōngsī jìnnián lái zāoshòu le yánzhòng de jīngjì sǔnshī.', 'Công ty này trong những năm gần đây đã chịu tổn thất kinh tế nghiêm trọng.'),
  ('造型', '这座雕塑的造型独特，吸引了众多游客。', 'Zhè zuò diāosù de zàoxíng dútè, xīyǐn le zhòngduō yóukè.', 'Tác phẩm điêu khắc này có tạo hình độc đáo, thu hút nhiều du khách.'),
  ('逐年', '公司的收入逐年增长，发展非常迅速。', 'Gōngsī de shōurù zhú nián zēngzhǎng, fāzhǎn fēicháng xùnsù.', 'Thu nhập của công ty tăng lên từng năm, phát triển rất nhanh.'),
  ('追究', '警方决定追究这起事故的全部责任。', 'Jǐngfāng juédìng zhuījiū zhè qǐ shìgù de quánbù zérèn.', 'Cảnh sát quyết định truy cứu toàn bộ trách nhiệm của vụ tai nạn này.'),
  ('追悼', '全校师生在礼堂举行追悼会，悼念逝去的老师。', 'Quán xiào shīshēng zài lǐtáng jǔxíng zhuīdào huì, dàoniàn shìqù de lǎoshī.', 'Toàn thể giáo viên và học sinh trong trường tổ chức lễ truy điệu tại đại sảnh tưởng nhớ thầy đã mất.'),
  ('转达', '请把我的感谢之情转达给所有帮助过我们的人。', 'Qǐng bǎ wǒ de gǎnxiè zhī qíng zhuǎndá gěi suǒyǒu bāngzhù guò wǒmen de rén.', 'Xin hãy chuyển lời cảm ơn của tôi đến tất cả những người đã giúp đỡ chúng tôi.'),
  ('转让', '他决定将公司股份全部转让给合伙人。', 'Tā juédìng jiāng gōngsī gǔfèn quánbù zhuǎnràng gěi héhuǒrén.', 'Anh ấy quyết định chuyển nhượng toàn bộ cổ phần công ty cho đối tác.'),
  ('转移', '由于安全问题，工厂的生产设备被转移到郊区。', 'Yóuyú ānquán wèntí, gōngchǎng de shēngchǎn shèbèi bèi zhuǎnyí dào jiāoqū.', 'Do vấn đề an toàn, thiết bị sản xuất của nhà máy đã được dịch chuyển đến ngoại ô.'),
  ('转折', '故事的发展出现了意想不到的转折，让人震惊。', 'Gùshì de fāzhǎn chūxiàn le yìxiǎng bùdào de zhuǎnzhé, ràng rén zhènjīng.', 'Diễn biến câu chuyện xuất hiện bước ngoặt bất ngờ khiến người ta choáng váng.'),
  ('踪迹', '搜救队在森林里找到了失踪者的踪迹。', 'Sōujiù duì zài sēnlín lǐ zhǎodào le shīzōng zhě de zōngjì.', 'Đội cứu hộ đã tìm thấy dấu tích của người mất tích trong khu rừng.'),
  ('足以', '他的努力足以让他获得这次比赛的冠军。', 'Tā de nǔlì zúyǐ ràng tā huòdé zhè cì bǐsài de guànjūn.', 'Nỗ lực của anh ấy đủ để giúp anh giành chức vô địch trong cuộc thi này.'),
  ('走私', '海关发现了一起大型走私货物案件。', 'Hǎiguān fāxiàn le yī qǐ dàxíng zǒusī huòwù ànjiàn.', 'Hải quan phát hiện một vụ buôn lậu hàng hoá lớn.'),
  ('走漏', '内部机密信息被员工意外走漏出去。', 'Nèibù jīmì xìnxī bèi yuángōng yìwài zǒulòu chūqù.', 'Thông tin bí mật nội bộ đã bị nhân viên vô tình tiết lộ ra ngoài.'),
  ('走廊', '学生们在教学楼的走廊里排队等候。', 'Xuéshēngmen zài jiàoxué lóu de zǒuláng lǐ páiduì děnghòu.', 'Học sinh đang xếp hàng chờ đợi ở hành lang tòa nhà học tập.'),
  ('赠送', '商店购买指定商品即可赠送精美礼品。', 'Shāngdiàn gòumǎi zhǐdìng shāngpǐn jí kě zèngsòng jīngměi lǐpǐn.', 'Cửa hàng mua hàng hoá chỉ định sẽ được tặng quà tặng tinh tế.'),
  ('赞叹', '观众们对艺术家的表演赞叹不已。', 'Guānzhòngmen duì yìshùjiā de biǎoyǎn zàntàn bù yǐ.', 'Khán giả không ngừng khen ngợi màn trình diễn của nghệ sĩ.'),
  ('赞助', '这场活动得到了多家企业的赞助支持。', 'Zhè chǎng huódòng dédàole duō jiā qǐyè de zànzhù zhīchí.', 'Sự kiện này đã nhận được tài trợ hỗ trợ từ nhiều doanh nghiệp.'),
  ('资深', '他是一名资深记者，报道经验丰富。', 'Tā shì yī míng zīshēn jìzhě, bàodào jīngyàn fēngfù.', 'Anh ấy là một nhà báo thâm niên, có kinh nghiệm đưa tin phong phú.'),
  ('资本', '创业需要充足的资本支持才能成功。', 'Chuàngyè xūyào chōngzú de zīběn zhīchí cáinéng chénggōng.', 'Khởi nghiệp cần có sự hỗ trợ tư bản đầy đủ mới có thể thành công.'),
  ('资助', '政府提供资金资助贫困学生完成学业。', 'Zhèngfǔ tígōng zījīn zīzhù pínkùn xuéshēng wánchéng xuéyè.', 'Chính phủ cung cấp nguồn vốn viện trợ cho học sinh nghèo hoàn thành học tập.'),
  ('资产', '他管理着公司的全部资产，责任重大。', 'Tā guǎnlǐ zhe gōngsī de quánbù zīchǎn, zérèn zhòngdà.', 'Anh ấy quản lý toàn bộ tài sản của công ty, trách nhiệm vô cùng lớn.'),
  ('贼', '小区发生了一起贼偷盗事件，居民很担心。', 'Xiǎoqū fāshēng le yī qǐ zéi tōudào shìjiàn, jūmín hěn dānxīn.', 'Khu dân cư xảy ra một vụ kẻ trộm, cư dân rất lo lắng.'),
  ('责怪', '不要因为小失误而责怪自己，保持积极心态很重要。', 'Bù yào yīnwèi xiǎo shīwù ér zéguài zìjǐ, bǎochí jījí xīntài hěn zhòngyào.', 'Đừng vì một sai lầm nhỏ mà trách móc bản thân, giữ thái độ tích cực rất quan trọng.'),
  ('诸位', '诸位同学请注意，明天有重要的考试，请做好准备。', 'Zhūwèi tóngxué qǐng zhùyì, míngtiān yǒu zhòngyào de kǎoshì, qǐng zuò hǎo zhǔnbèi.', 'Các bạn học sinh chú ý, ngày mai có kỳ thi quan trọng, hãy chuẩn bị thật tốt.'),
  ('诈骗', '警方提醒大家，提高警惕，防止电话诈骗事件发生。', 'Jǐngfāng tíxǐng dàjiā, tígāo jǐngtì, fángzhǐ diànhuà zhàpiàn shìjiàn fāshēng.', 'Cảnh sát nhắc nhở mọi người nâng cao cảnh giác, phòng tránh các vụ lừa gạt qua điện thoại.'),
  ('证实', '科学研究已经证实这种药物对治疗疾病有效。', 'Kēxué yánjiū yǐjīng zhèngshí zhè zhǒng yàowù duì zhìliáo jíbìng yǒuxiào.', 'Nghiên cứu khoa học đã chứng minh loại thuốc này hiệu quả trong điều trị bệnh.'),
  ('证书', '他通过了考试，获得了英语等级证书，感到非常自豪。', 'Tā tōngguò le kǎoshì, huòdé le Yīngyǔ děngjí zhèngshū, gǎndào fēicháng zìháo.', 'Anh ấy đã vượt qua kỳ thi và nhận được giấy chứng nhận trình độ tiếng Anh, cảm thấy rất tự hào.'),
  ('装备', '这次远足我们必须准备好全部的装备，包括帐篷和食物。', 'Zhè cì yuǎnzú wǒmen bìxū zhǔnbèi hǎo quánbù de zhuāngbèi, bāokuò zhàngpéng hé shíwù.', 'Chuyến leo núi lần này chúng ta phải chuẩn bị đầy đủ trang bị, bao gồm lều trại và thức ăn.'),
  ('装卸', '工人们正在码头有序地进行货物的装卸工作。', 'Gōngrénmen zhèngzài mǎtóu yǒuxù de jìnxíng huòwù de zhuāngxiè gōngzuò.', 'Công nhân đang tiến hành công việc bốc xếp hàng hóa một cách có trật tự ở bến cảng.'),
  ('衷心', '我衷心感谢所有支持和帮助过我的朋友们。', 'Wǒ zhōngxīn gǎnxiè suǒyǒu zhīchí hé bāngzhù guò wǒ de péngyǒumen.', 'Tôi chân thành cảm ơn tất cả bạn bè đã ủng hộ và giúp đỡ tôi.'),
  ('蒸发', '烈日当空，水面上的水分迅速蒸发，天气变得干燥。', 'Lièrì dāngkōng, shuǐmiàn shàng de shuǐfèn xùnsù zhēngfā, tiānqì biàn dé gānzào.', 'Dưới nắng gắt, nước trên mặt hồ nhanh chóng bốc hơi, thời tiết trở nên khô hanh.'),
  ('著作', '这位作家的著作在国际上享有很高的声誉。', 'Zhè wèi zuòjiā de zhùzuò zài guójì shàng xiǎng yǒu hěn gāo de shēngyù.', 'Các tác phẩm của nhà văn này được quốc tế rất tôn trọng.'),
  ('舟', '小舟缓缓地驶过宁静的湖面，风景美得如画。', 'Xiǎo zhōu huǎnhuǎn de shǐ guò níngjìng de húmiàn, fēngjǐng měi de rú huà.', 'Chiếc thuyền nhỏ lững lờ trôi trên mặt hồ yên tĩnh, cảnh đẹp như tranh vẽ.'),
  ('致辞', '董事长在开幕式上发表了热情洋溢的致辞。', 'Dǒngshì zhǎng zài kāimù shì shàng fābiǎo le rèqíng yángyì de zhìcí.', 'Chủ tịch hội đồng quản trị đã đọc bài diễn văn đầy nhiệt huyết tại lễ khai mạc.'),
  ('致力', '公司致力于开发环保产品，保护我们的地球环境。', 'Gōngsī zhìlì yú kāifā huánbǎo chǎnpǐn, bǎohù wǒmen de dìqiú huánjìng.', 'Công ty dốc sức phát triển sản phẩm thân thiện với môi trường để bảo vệ trái đất của chúng ta.'),
  ('致使', '他的疏忽大意致使项目延期，影响了整体进度。', 'Tā de shūhū dàyì zhìshǐ xiàngmù yánqī, yǐngxiǎng le zhěngtǐ jìndù.', 'Sự cẩu thả của anh ta khiến dự án bị trì hoãn, ảnh hưởng đến tiến độ chung.'),
  ('自满', '取得一点成绩后不能自满，要继续努力追求更高目标。', 'Qǔdé yīdiǎn chéngjì hòu bùnéng zìmǎn, yào jìxù nǔlì zhuīqiú gèng gāo mùbiāo.', 'Sau khi đạt được một chút thành tích không được tự mãn, phải tiếp tục cố gắng theo đuổi mục tiêu cao hơn.'),
  ('自发', '大家自发地组织了清理社区环境的活动，非常有意义。', 'Dàjiā zìfā de zǔzhī le qīnglǐ shèqū huánjìng de huódòng, fēicháng yǒu yìyì.', 'Mọi người tự phát tổ chức hoạt động dọn dẹp môi trường khu dân cư, rất có ý nghĩa.'),
  ('自卑', '他因为外表和能力的原因常常感到自卑，需要更多鼓励。', 'Tā yīnwèi wàibiǎo hé nénglì de yuányīn chángcháng gǎndào zìbēi, xūyào gèng duō gǔlì.', 'Anh ấy thường cảm thấy tự ti vì ngoại hình và năng lực, cần thêm nhiều sự khích lệ.'),
  ('自力更生', '在困难面前，我们应坚持自力更生，努力克服挑战。', 'Zài kùnnán miànqián, wǒmen yīng jiānchí zìlì gēngshēng, nǔlì kèfú tiǎozhàn.', 'Trước khó khăn, chúng ta nên kiên trì tự lực cánh sinh, cố gắng vượt qua thử thách.'),
  ('自主', '年轻人应当培养自主意识，独立解决生活中的问题。', 'Niánqīng rén yīngdāng péiyǎng zìzhǔ yìshí, dúlì jiějué shēnghuó zhōng de wèntí.', 'Thanh niên nên phát triển ý thức tự chủ, độc lập giải quyết các vấn đề trong cuộc sống.'),
  ('脂肪', '为了健康，应该控制摄入过多的脂肪，保持合理饮食。', 'Wèile jiànkāng, yīnggāi kòngzhì shèrù guòduō de zhīfáng, bǎochí hélǐ yǐnshí.', 'Để khỏe mạnh, nên kiểm soát lượng mỡ nạp vào cơ thể, duy trì chế độ ăn hợp lý.'),
  ('肿瘤', '医生检查后发现他体内有一个肿瘤，需要尽快治疗。', 'Yīshēng jiǎnchá hòu fāxiàn tā tǐnèi yǒu yīgè zhǒngliú, xūyào jǐnkuài zhìliáo.', 'Bác sĩ kiểm tra sau đó phát hiện trong cơ thể anh ta có một cái khối u, cần phải điều trị càng sớm càng tốt.'),
  ('职能', '公司的不同部门有各自的职能和职责分工。', 'Gōngsī de bùtóng bùmén yǒu gèzì de zhínéng hé zhízé fēngōng.', 'Các phòng ban khác nhau của công ty có các chức năng và phân công nhiệm vụ riêng.'),
  ('职务', '他因为工作表现优秀，被提升到更高的职务。', 'Tā yīnwèi gōngzuò biǎoxiàn yōuxiù, bèi tíshēng dào gèng gāo de zhíwù.', 'Anh ấy vì thể hiện công việc xuất sắc nên được thăng chức vụ cao hơn.'),
  ('职位', '这家公司的管理职位竞争非常激烈。', 'Zhè jiā gōngsī de guǎnlǐ zhíwèi jìngzhēng fēicháng jīliè.', 'Chức vị quản lý trong công ty này cạnh tranh rất gay gắt.'),
  ('罪犯', '警方成功抓捕了这名逃跑的罪犯。', 'Jǐngfāng chénggōng zhuābǔ le zhè míng táopǎo de zuìfàn.', 'Cảnh sát đã thành công bắt giữ tên tội phạm bỏ trốn này.'),
  ('终身', '他决定为社会服务，做一名终身志愿者。', 'Tā juédìng wèi shèhuì fúwù, zuò yī míng zhōngshēn zhìyuànzhě.', 'Anh ấy quyết định phục vụ xã hội, trở thành tình nguyện viên suốt đời.'),
  ('终究', '努力学习终究会带来成功和回报。', 'Nǔlì xuéxí zhōngjiū huì dàilái chénggōng hé huíbào.', 'Cố gắng học tập cuối cùng sẽ mang lại thành công và phần thưởng.'),
  ('终点', '马拉松比赛的终点设在市中心的广场上。', 'Mǎlāsōng bǐsài de zhōngdiǎn shè zài shì zhōngxīn de guǎngchǎng shàng.', 'Điểm kết thúc cuộc thi marathon được đặt tại quảng trường trung tâm thành phố.'),
  ('终止', '由于协议未达成，双方决定终止谈判。', 'Yóuyú xiéyì wèi dáchéng, shuāngfāng juédìng zhōngzhǐ tánpàn.', 'Do thỏa thuận không đạt được, hai bên quyết định chấm dứt đàm phán.'),
  ('纵横', '这张地图上道路和河流纵横交错，非常复杂。', 'Zhè zhāng dìtú shàng dàolù hé héliú zònghéng jiāocuò, fēicháng fùzá.', 'Trên bản đồ này các con đường và dòng sông dọc ngang đan xen nhau rất phức tạp.'),
  ('糟蹋', '我们不应该糟蹋食物，要珍惜每一粒米。', 'Wǒmen bù yīnggāi zāotà shíwù, yào zhēnxī měi yī lì mǐ.', 'Chúng ta không nên lãng phí thức ăn, phải trân trọng từng hạt gạo.'),
  ('粥', '早餐他喜欢喝一碗热腾腾的稀粥。', 'Zǎocān tā xǐhuān hē yī wǎn rè téngténg de xī zhōu.', 'Bữa sáng anh ấy thích uống một bát cháo nóng hổi.'),
  ('章程', '公司章程明确规定了员工的权利和义务。', 'Gōngsī zhāngchéng míngquè guīdìng le yuángōng de quánlì hé yìwù.', 'Điều lệ công ty quy định rõ quyền lợi và nghĩa vụ của nhân viên.'),
  ('租赁', '他们与房东签订了为期一年的租赁合同。', 'Tāmen yǔ fángdōng qiāndìng le wéiqí yī nián de zūlìn hétóng.', 'Họ đã ký hợp đồng cho thuê nhà với chủ nhà trong vòng một năm.'),
  ('种植', '这片农田主要用于种植水稻和小麦。', 'Zhè piàn nóngtián zhǔyào yòng yú zhòngzhí shuǐdào hé xiǎomài.', 'Mảnh ruộng này chủ yếu được sử dụng để trồng lúa và lúa mì.'),
  ('种族', '种族之间的和平共处是社会稳定的基础。', 'Zhǒngzú zhījiān de hépíng gòngchǔ shì shèhuì wěndìng de jīchǔ.', 'Sự hòa bình chung sống giữa các chủng tộc là nền tảng của xã hội ổn định.'),
  ('种子', '农民们把种子均匀地撒在田地里。', 'Nóngmín men bǎ zhǒngzi jūnyún de sā zài tiándì lǐ.', 'Những người nông dân rải đều hạt giống trên cánh đồng.'),
  ('祖父', '每当我有困难，祖父总是耐心地教导我。', 'Měi dāng wǒ yǒu kùnnán, zǔfù zǒng shì nàixīn de jiàodǎo wǒ.', 'Mỗi khi tôi gặp khó khăn, ông nội luôn kiên nhẫn dạy dỗ tôi.'),
  ('祖国', '我们应当尽自己最大的努力来建设美丽的祖国。', 'Wǒmen yīngdāng jǐn zìjǐ zuìdà de nǔlì lái jiànshè měilì de zǔguó.', 'Chúng ta nên nỗ lực hết mình để xây dựng một tổ quốc tươi đẹp.'),
  ('祖先', '尊重祖先的传统文化有助于增强民族认同感。', 'Zūnzhòng zǔxiān de chuántǒng wénhuà yǒuzhù yú zēngqiáng mínzú rèntóng gǎn.', 'Tôn trọng văn hóa truyền thống của tổ tiên giúp tăng cường sự nhận thức dân tộc.'),
  ('砸', '他用锤子狠狠地砸碎了那块玻璃。', 'Tā yòng chuízi hěn hěn de zá suì le nà kuài bōlí.', 'Anh ấy dùng búa đập tan vỡ mảnh kính đó một cách mạnh mẽ.'),
  ('砖', '工人正在把一块块砖砌成坚固的墙壁。', 'Gōngrén zhèngzài bǎ yī kuài kuài zhuān qì chéng jiāngù de qiángbì.', 'Công nhân đang xây tường kiên cố bằng từng viên gạch.'),
  ('知足常乐', '虽然生活不富裕，但他始终相信知足常乐的道理。', 'Suīrán shēnghuó bù fùyù, dàn tā shǐzhōng xiāngxìn zhīzú cháng lè de dàolǐ.', 'Mặc dù cuộc sống không giàu có, nhưng anh ấy luôn tin vào đạo lý biết đủ thường vui.'),
  ('知觉', '寒冷的气温让他的知觉逐渐变得迟钝。', 'Hánlěng de qìwēn ràng tā de zhījué zhújiàn biàn dé chídùn.', 'Nhiệt độ lạnh khiến tri giác của anh ta dần trở nên chậm chạp.'),
  ('瞻仰', '游客们虔诚地瞻仰着这座历史悠久的古庙。', 'Yóukèmen qiánchéng de zhānyǎng zhe zhè zuò lìshǐ yōujiǔ de gǔ miào.', 'Du khách thành kính chiêm ngưỡng ngôi đền cổ có lịch sử lâu đời này.'),
  ('着重', '会议中他特别着重强调了团队合作的重要性。', 'Huìyì zhōng tā tèbié zhuózhòng qiángdiào le tuánduì hézuò de zhòngyào xìng.', 'Trong cuộc họp, anh ấy đặc biệt nhấn mạnh tầm quan trọng của hợp tác nhóm.'),
  ('着迷', '她对绘画艺术深深着迷，几乎每天都在练习。', 'Tā duì huìhuà yìshù shēn shēn zháomí, jīhū měitiān dōu zài liànxí.', 'Cô ấy say sưa với nghệ thuật hội họa đến mức gần như ngày nào cũng luyện tập.'),
  ('着手', '项目经理决定马上着手准备下个月的展览活动。', 'Xiàngmù jīnglǐ juédìng mǎshàng zhuóshǒu zhǔnbèi xià gè yuè de zhǎnlǎn huódòng.', 'Quản lý dự án quyết định lập tức bắt tay vào chuẩn bị sự kiện triển lãm tháng sau.'),
  ('着想', '他总是为家人的未来着想，努力工作赚钱。', 'Tā zǒng shì wèi jiārén de wèilái zhuóxiǎng, nǔlì gōngzuò zhuànqián.', 'Anh ấy luôn lo nghĩ cho tương lai của gia đình và làm việc chăm chỉ để kiếm tiền.'),
  ('眨', '孩子们开心地眨着眼睛，期待着惊喜的到来。', 'Háizimen kāixīn de zhǎ zhe yǎnjīng, qīdài zhe jīngxǐ de dàolái.', 'Các đứa trẻ vui vẻ nháy mắt mong chờ điều bất ngờ đến.'),
  ('真相', '警方经过调查，终于揭露了事件的真相。', 'Jǐngfāng jīngguò diàochá, zhōngyú jiēlù le shìjiàn de zhēnxiàng.', 'Cảnh sát sau khi điều tra đã cuối cùng làm sáng tỏ chân tướng sự việc.'),
  ('真理', '科学家们不断探索，希望发现自然界的真理。', 'Kēxuéjiā men bùduàn tànsuǒ, xīwàng fāxiàn zìrán jiè de zhēnlǐ.', 'Các nhà khoa học không ngừng khám phá với hy vọng tìm ra chân lý của thiên nhiên.'),
  ('真挚', '他用真挚的感情写了一封动人的信给朋友。', 'Tā yòng zhēnzhì de gǎnqíng xiě le yī fēng dòngrén de xìn gěi péngyǒu.', 'Anh ấy dùng tình cảm chân thành viết một bức thư cảm động gửi bạn bè.'),
  ('直播', '明星通过直播平台与粉丝互动，分享日常生活。', 'Míngxīng tōngguò zhí bō píngtái yǔ fěnsī hùdòng, fēnxiǎng rìcháng shēnghuó.', 'Ngôi sao tương tác với người hâm mộ và chia sẻ cuộc sống hàng ngày qua nền tảng truyền hình trực tiếp.'),
  ('直径', '这个圆形游泳池的直径大约有二十米。', 'Zhège yuánxíng yóuyǒngchí de zhíjìng dàyuē yǒu èrshí mǐ.', 'Đường kính của bể bơi hình tròn này khoảng hai mươi mét.'),
  ('皱纹', '她的脸上细细的皱纹显示了岁月的痕迹。', 'Tā de liǎn shàng xì xì de zhòuwén xiǎnshì le suìyuè de hénjì.', 'Những nếp nhăn mảnh trên khuôn mặt cô ấy thể hiện dấu vết của thời gian.'),
  ('症状', '发烧和咳嗽是感冒常见的症状之一。', 'Fāshāo hé késou shì gǎnmào chángjiàn de zhèngzhuàng zhī yī.', 'Sốt và ho là một trong những triệu chứng phổ biến của cảm lạnh.'),
  ('琢磨', '他反复琢磨这个问题，终于找到了解决方法。', 'Tā fǎnfù zhuómó zhège wèntí, zhōngyú zhǎodào le jiějué fāngfǎ.', 'Anh ấy nghiền ngẫm vấn đề này nhiều lần cuối cùng tìm ra cách giải quyết.'),
  ('珍贵', '这块古董手镯对家族来说非常珍贵。', 'Zhè kuài gǔdǒng shǒuzhuó duì jiāzú lái shuō fēicháng zhēnguì.', 'Chiếc vòng tay cổ này rất quý báu đối với gia đình.'),
  ('珍稀', '森林里生活着许多珍稀的动植物，必须保护好环境。', 'Sēnlín lǐ shēnghuó zhe xǔduō zhēnxī de dòng zhíwù, bìxū bǎohù hǎo huánjìng.', 'Trong rừng có rất nhiều động thực vật quý hiếm, cần phải bảo vệ môi trường tốt.'),
  ('珍珠', '她戴着一条由珍珠组成的项链，非常漂亮。', 'Tā dài zhe yī tiáo yóu zhēnzhū zǔchéng de xiàngliàn, fēicháng piàoliang.', 'Cô ấy đeo một chiếc vòng cổ làm từ ngọc trai, rất đẹp.'),
  ('照耀', '阳光照耀着大地，万物都显得生机勃勃。', 'Yángguāng zhàoyào zhe dàdì, wànwù dōu xiǎnde shēngjī bóbó.', 'Ánh nắng chiếu sáng mặt đất, mọi vật đều trở nên đầy sức sống.'),
  ('照样', '虽然下雨了，他还是照样去跑步，没有改变计划。', 'Suīrán xià yǔ le, tā háishì zhàoyàng qù pǎobù, méiyǒu gǎibiàn jìhuà.', 'Mặc dù trời mưa, anh ấy vẫn như thường lệ đi chạy bộ, không thay đổi kế hoạch.'),
  ('灾难', '地震带来了严重的灾难，许多房屋被毁坏。', 'Dìzhèn dàilái le yánzhòng de zāinàn, xǔduō fángwū bèi huǐhuài.', 'Động đất đã mang đến thảm họa nghiêm trọng, nhiều nhà cửa bị phá hủy.'),
  ('滞留', '由于大雪封路，车辆不得不滞留在高速公路上。', 'Yóuyú dàxuě fēng lù, chēliàng bùdébù zhìliú zài gāosù gōnglù shàng.', 'Vì tuyết rơi dày làm tắc đường, xe phải dừng lại trên đường cao tốc.'),
  ('滋润', '这款面霜能有效滋润皮肤，防止干燥。', 'Zhè kuǎn miànshuāng néng yǒuxiào zīrùn pífū, fángzhǐ gānzào.', 'Loại kem dưỡng này có thể làm ẩm da hiệu quả, ngăn ngừa khô ráp.'),
  ('滋味', '妈妈做的饭菜有一种特殊的滋味，让人回味无穷。', 'Māmā zuò de fàncài yǒu yī zhǒng tèshū de zīwèi, ràng rén huíwèi wúqióng.', 'Món ăn mẹ nấu có một hương vị đặc biệt, khiến người ta nhớ mãi không quên.'),
  ('渣', '这杯咖啡里有一些渣，需要过滤一下。', 'Zhè bēi kāfēi lǐ yǒu yīxiē zhā, xūyào guòlǜ yīxià.', 'Trong cốc cà phê này có một ít cặn, cần phải lọc một chút.'),
  ('注重', '公司非常注重员工的培训和发展，投入了大量资源。', 'Gōngsī fēicháng zhùzhòng yuángōng de péixùn hé fāzhǎn, tóurù le dàliàng zīyuán.', 'Công ty rất chú trọng đào tạo và phát triển nhân viên, đầu tư nhiều nguồn lực.'),
  ('注释', '请在文章后面加上详细的注释以方便读者理解。', 'Qǐng zài wénzhāng hòumiàn jiā shàng xiángxì de zhùshì yǐ fāngbiàn dúzhě lǐjiě.', 'Xin hãy thêm phần chú thích chi tiết ở cuối bài viết để giúp độc giả hiểu.'),
  ('注视', '他一直注视着远方的山峰，思索着未来的计划。', 'Tā yīzhí zhùshì zhe yuǎnfāng de shānfēng, sīsuǒ zhe wèilái de jìhuà.', 'Anh ấy luôn nhìn chằm chằm vào ngọn núi xa xăm, suy nghĩ về kế hoạch tương lai.'),
  ('注射', '医生建议他注射疫苗以提高免疫力。', 'Yīshēng jiànyì tā zhùshè yìmiáo yǐ tígāo miǎnyìlì.', 'Bác sĩ khuyên anh nên tiêm vaccine để tăng cường miễn dịch.'),
  ('沾光', '他因为朋友的帮助而沾光，才顺利拿到这份工作。', 'Tā yīnwèi péngyǒu de bāngzhù ér zhān guāng, cái shùnlì ná dào zhè fèn gōngzuò.', 'Anh ta nhờ sự giúp đỡ của bạn mà được thơm lây, mới nhận được công việc này.'),
  ('沼泽', '湿地沼泽是许多珍稀动植物的重要栖息地。', 'Shīdì zhǎozé shì xǔduō zhēnxī dòngzhíwù de zhòngyào qīxīdì.', 'Đầm lầy vùng đất ngập nước là nơi cư trú quan trọng của nhiều loài động thực vật quý hiếm.'),
  ('治理', '政府采取了一系列措施来治理城市的污染问题。', 'Zhèngfǔ cǎiqǔ le yī xìliè cuòshī lái zhìlǐ chéngshì de wūrǎn wèntí.', 'Chính phủ đã thực hiện một loạt biện pháp để quản lý vấn đề ô nhiễm thành phố.'),
  ('治安', '社区的治安状况明显改善，居民感到更加安全。', 'Shèqū de zhì''ān zhuàngkuàng míngxiǎn gǎishàn, jūmín gǎndào gèngjiā ānquán.', 'Tình hình trị an ở khu dân cư đã được cải thiện rõ rệt, người dân cảm thấy an toàn hơn.'),
  ('殖民地', '历史上很多国家曾经建立过殖民地，扩大了领土。', 'Lìshǐ shàng hěnduō guójiā céngjīng jiànlì guò zhímíndì, kuòdà le lǐngtǔ.', 'Trong lịch sử, nhiều quốc gia đã từng thành lập thuộc địa và mở rộng lãnh thổ.'),
  ('正负', '电池的正负极必须正确连接才能正常工作。', 'Diànchí de zhèng fù jí bìxū zhèngquè liánjiē cáinéng zhèngcháng gōngzuò.', 'Cực dương và cực âm của pin phải được kết nối đúng cách mới hoạt động bình thường.'),
  ('正规', '他毕业于一所正规大学，学历受到了认可。', 'Tā bìyè yú yī suǒ zhèngguī dàxué, xuélì shòudào le rènkě.', 'Anh ấy tốt nghiệp từ một trường đại học chính quy, bằng cấp được công nhận.'),
  ('正经', '他是个正经人，做事非常认真负责。', 'Tā shì gè zhèngjīng rén, zuòshì fēicháng rènzhēn fùzé.', 'Anh ấy là người nghiêm túc, làm việc rất cẩn thận và có trách nhiệm.'),
  ('正气', '保持社会的正气能够促进人民的幸福和安宁。', 'bǎo chí shè huì de zhèng qì néng gòu cù jìn rén mín de xìng fú hé ān níng.', 'Giữ gìn nếp sống lành mạnh của xã hội có thể thúc đẩy hạnh phúc và bình yên của nhân dân.'),
  ('正月', '春节通常在农历正月初一庆祝家人团聚。', 'chūn jié tōng cháng zài nóng lì zhēng yuè chū yī qìng zhù jiā rén tuán jù.', 'Tết Nguyên đán thường được đón mừng vào ngày mùng một tháng giêng âm lịch để gia đình sum họp.'),
  ('正当', '他提出的理由非常正当，大家都表示理解和支持。', 'tā tí chū de lǐ yóu fēi cháng zhèng dàng, dà jiā dōu biǎo shì lǐ jiě hé zhī chí.', 'Lý do anh ấy đưa ra rất chính đáng, mọi người đều thể hiện sự hiểu và ủng hộ.'),
  ('正宗', '这家餐厅的川菜味道非常正宗，吸引了很多食客。', 'zhè jiā cān tīng de chuān cài wèi dào fēi cháng zhèng zōng, xī yǐn le hěn duō shí kè.', 'Món ăn tại nhà hàng này có hương vị chuẩn chuẩn Tây Tạng, thu hút rất nhiều thực khách.'),
  ('正义', '他总是为正义而战，不怕任何困难和挑战。', 'tā zǒng shì wèi zhèng yì ér zhàn, bù pà rèn hé kùn nán hé tiǎo zhàn.', 'Anh ấy luôn đấu tranh cho chính nghĩa, không sợ bất kỳ khó khăn hay thử thách nào.'),
  ('棕色', '秋天来了，树叶逐渐变成漂亮的棕色。', 'qiū tiān lái le, shù yè zhú jiàn biàn chéng piào liàng de zōng sè.', 'Mùa thu đến, lá cây dần dần chuyển sang màu nâu đẹp.'),
  ('栽培', '农民辛勤地栽培庄稼，希望有一个丰收的季节。', 'nóng mín xīn qín de zāi péi zhuāng jià, xī wàng yǒu yī gè fēng shōu de jì jié.', 'Nông dân chăm chỉ vun trồng mùa màng với hy vọng có một mùa bội thu.'),
  ('株', '这片果园里种了很多苹果树，每株都结满了果实。', 'zhè piàn guǒ yuán lǐ zhòng le hěn duō píng guǒ shù, měi zhū dōu jiē mǎn le guǒ shí.', 'Vườn táo này trồng rất nhiều cây táo, mỗi cây đều đầy quả.'),
  ('枝', '他小心地折下了一枝花，送给心爱的人。', 'tā xiǎo xīn de zhé xià le yī zhī huā, sòng gěi xīn ài de rén.', 'Anh ấy cẩn thận hái một cành hoa tặng cho người mình yêu.'),
  ('枕头', '我喜欢用柔软的枕头，这样睡觉才舒服。', 'wǒ xǐ huān yòng róu ruǎn de zhěn tou, zhè yàng shuì jiào cái shū fu.', 'Tôi thích dùng gối mềm mại, như vậy ngủ mới thoải mái.'),
  ('杂技', '杂技演员们展示了令人惊叹的技巧和力量。', 'zá jì yǎn yuán men zhǎn shì le lìng rén jīng tàn de jì qiǎo hé lì liàng.', 'Các diễn viên xiếc trình diễn những kỹ thuật và sức mạnh đáng kinh ngạc.'),
  ('杂交', '农业科学家通过杂交培育出抗病新种子。', 'nóng yè kē xué jiā tōng guò zá jiāo péi yù chū kàng bìng xīn zhǒng zi.', 'Các nhà khoa học nông nghiệp lai giống để tạo ra giống hạt kháng bệnh mới.'),
  ('朝气蓬勃', '年轻人充满朝气蓬勃，积极投身社会建设。', 'nián qīng rén chōng mǎn zhāo qì péng bó, jī jí tóu shēn shè huì jiàn shè.', 'Người trẻ đầy bừng bừng khí thế, tích cực tham gia xây dựng xã hội.'),
  ('暂且', '我们暂且先听取专家的建议，之后再做决定。', 'wǒ men zàn qiě xiān tīng qǔ zhuān jiā de jiàn yì, zhī hòu zài zuò jué dìng.', 'Chúng ta tạm thời nghe theo lời khuyên của chuyên gia, sau đó mới quyết định.'),
  ('智能', '现代智能手机功能强大，极大地方便了生活。', 'xiàn dài zhì néng shǒu jī gōng néng qiáng dà, jí dà de fāng biàn le shēng huó.', 'Điện thoại thông minh hiện đại có tính năng mạnh mẽ, rất tiện lợi cho cuộc sống.'),
  ('智商', '虽然智商高很重要，但情商也同样不可忽视。', 'suī rán zhì shāng gāo hěn zhòng yào, dàn qíng shāng yě tóng yàng bù kě hū shì.', 'Dù IQ cao rất quan trọng, nhưng EQ cũng không thể xem nhẹ.'),
  ('智力', '孩子们通过玩游戏来锻炼他们的智力发展。', 'hái zi men tōng guò wán yóu xì lái duàn liàn tā men de zhì lì fā zhǎn.', 'Các em nhỏ phát triển trí lực của mình thông qua chơi trò chơi.'),
  ('昼夜', '工人们昼夜不停地工作，确保工程按时完成。', 'gōng rén men zhòu yè bù tíng de gōng zuò, què bǎo gōng chéng àn shí wán chéng.', 'Công nhân làm việc ngày đêm không nghỉ, đảm bảo công trình hoàn thành đúng hạn.'),
  ('斩钉截铁', '他说话总是斩钉截铁，让人没有任何怀疑。', 'tā shuō huà zǒng shì zhǎn dīng jié tiě, ràng rén méi yǒu rèn hé huái yí.', 'Anh ấy nói chuyện luôn kiên quyết, không để ai nghi ngờ.'),
  ('斟酌', '在做出最终决定之前，我们必须斟酌所有的利弊。', 'zài zuò chū zuì zhōng jué dìng zhī qián, wǒ men bì xū zhēn zhuó suǒ yǒu de lì bì.', 'Trước khi đưa ra quyết định cuối cùng, chúng ta phải suy nghĩ kỹ lưỡng về mọi lợi hại.'),
  ('整顿', '公司决定整顿管理制度以提高工作效率。', 'Gōngsī juédìng zhěngdùn guǎnlǐ zhìdù yǐ tígāo gōngzuò xiàolǜ.', 'Công ty quyết định chỉnh đốn hệ thống quản lý để nâng cao hiệu quả công việc.'),
  ('政策', '政府出台了新的经济发展政策以刺激市场活力。', 'Zhèngfǔ chūtái le xīn de jīngjì fāzhǎn zhèngcè yǐ cìjī shìchǎng huólì.', 'Chính phủ ban hành chính sách phát triển kinh tế mới để kích thích sức sống thị trường.'),
  ('政权', '政权的更替对国家未来影响深远。', 'Zhèngquán de gēngtì duì guójiā wèilái yǐngxiǎng shēnyuǎn.', 'Sự thay đổi chính quyền có ảnh hưởng sâu rộng đến tương lai đất nước.'),
  ('支配', '他的时间被工作完全支配，几乎没有自己的生活。', 'Tā de shíjiān bèi gōngzuò wánquán zhīpèi, jīhū méiyǒu zìjǐ de shēnghuó.', 'Thời gian của anh ấy hoàn toàn bị công việc chi phối, gần như không có cuộc sống riêng.'),
  ('支流', '这条河有许多支流汇集，形成复杂的水系。', 'Zhè tiáo hé yǒu xǔduō zhīliú huìjí, xíngchéng fùzá de shuǐxì.', 'Con sông này có nhiều nhánh sông hợp lại, tạo thành hệ thống thủy phức tạp.'),
  ('支柱', '农业是我国经济的支柱产业之一。', 'Nóngyè shì wǒguó jīngjì de zhīzhù chǎnyè zhī yī.', 'Nông nghiệp là một trong những ngành trụ cột của nền kinh tế nước tôi.'),
  ('支撑', '在困难时期，家人的支持是我最大的支撑。', 'Zài kùnnán shíqī, jiārén de zhīchí shì wǒ zuìdà de zhīchēng.', 'Trong thời kỳ khó khăn, sự ủng hộ của gia đình là trụ cột lớn nhất của tôi.'),
  ('支援', '灾区急需物资支援以缓解当地困境。', 'Zāiqū jíxū wùzī zhīyuán yǐ huǎnjiě dāngdì kùnjìng.', 'Khu vực bị thảm họa rất cần sự chi viện vật tư để giảm nhẹ khó khăn địa phương.'),
  ('支出', '这个月公司的支出超过了预算，需重新调整。', 'Zhège yuè gōngsī de zhīchū chāoguò le yùsuàn, xū chóngxīn tiáozhěng.', 'Chi tiêu của công ty tháng này vượt quá ngân sách, cần phải điều chỉnh lại.'),
  ('攒', '他每个月都会攒一部分钱，为未来做准备。', 'Tā měi ge yuè dōu huì zǎn yí bùfen qián, wèi wèilái zuò zhǔnbèi.', 'Anh ấy mỗi tháng đều tiết kiệm một phần tiền để chuẩn bị cho tương lai.'),
  ('摘要', '会议资料中包含了详细的报告摘要和数据分析。', 'Huìyì zīliào zhōng bāohán le xiángxì de bàogào zhāiyào hé shùjù fēnxī.', 'Tài liệu họp gồm bản đề cương báo cáo chi tiết và phân tích dữ liệu.'),
  ('揍', '如果有人欺负你，要及时向老师报告，不要自己揍回去。', 'Rúguǒ yǒu rén qīfù nǐ, yào jíshí xiàng lǎoshī bàogào, bùyào zìjǐ zòu huíqù.', 'Nếu ai đó bắt nạt bạn, hãy báo ngay với giáo viên, đừng tự đánh trả lại.'),
  ('振奋', '这次比赛的胜利让球队成员都感到非常振奋。', 'Zhè cì bǐsài de shènglì ràng qiúduì chéngyuán dōu gǎndào fēicháng zhènfèn.', 'Chiến thắng trong trận đấu này khiến các thành viên đội bóng đều rất hào hứng.'),
  ('振兴', '政府制定了一系列政策来促进农村经济的振兴。', 'Zhèngfǔ zhìdìng le yī xìliè zhèngcè lái cùjìn nóngcūn jīngjì de zhènxīng.', 'Chính phủ đã đặt ra một loạt chính sách để thúc đẩy chấn hưng kinh tế nông thôn.'),
  ('挣扎', '在逆境中，他不停地挣扎寻找出路。', 'Zài nìjìng zhōng, tā bù tíng de zhēngzhá xúnzhǎo chūlù.', 'Trong nghịch cảnh, anh ấy không ngừng vất vả đấu tranh tìm lối đi.'),
  ('指责', '领导公开指责了部门的失误，希望及时改正。', 'Lǐngdǎo gōngkāi zhǐzé le bùmén de shīwù, xīwàng jíshí gǎizhèng.', 'Lãnh đạo công khai chỉ trích sai sót của phòng ban, mong được sửa chữa kịp thời.'),
  ('指示', '上级部门已通过文件指示我们下周开始项目。', 'Shàngjí bùmén yǐ tōngguò wénjiàn zhǐshì wǒmen xià zhōu kāishǐ xiàngmù.', 'Cấp trên đã chỉ thị qua văn bản để chúng tôi khởi động dự án từ tuần tới.'),
  ('指甲', '她把指甲剪得整整齐齐，看起来非常干净。', 'Tā bǎ zhǐjiǎ jiǎn dé zhěngzhěng qíqí, kàn qǐlái fēicháng gānjìng.', 'Cô ấy cắt móng tay rất gọn gàng, trông rất sạch sẽ.'),
  ('指标', '公司设定了本季度的销售指标，要求严格完成。', 'Gōngsī shèdìng le běn jìdù de xiāoshòu zhǐbiāo, yāoqiú yángé wánchéng.', 'Công ty đặt ra chỉ tiêu bán hàng quý này, yêu cầu hoàn thành nghiêm túc.'),
  ('指望', '年轻人不能只指望父母，要学会独立生活。', 'Niánqīng rén bù néng zhǐ zhǐwàng fùmǔ, yào xuéhuì dúlì shēnghuó.', 'Người trẻ không thể chỉ trông chờ vào bố mẹ, phải học cách sống độc lập.'),
  ('指定', '公司指定我负责这个重要项目的协调工作。', 'Gōngsī zhǐdìng wǒ fùzé zhège zhòngyào xiàngmù de xiétiáo gōngzuò.', 'Công ty chỉ định tôi chịu trách nhiệm điều phối dự án quan trọng này.'),
  ('指南针', '古代的航海家主要依靠指南针来确定航行方向。', 'Gǔdài de hánghǎi jiā zhǔyào yīkào zhǐnánzhēn lái quèdìng hángxíng fāngxiàng.', 'Những nhà hàng hải cổ đại chủ yếu dựa vào la bàn để xác định phương hướng.'),
  ('指令', '上级下达的指令必须严格执行，不能有任何误差。', 'Shàngjí xiàdá de zhǐlìng bìxū yángé zhíxíng, bùnéng yǒu rènhé wùchā.', 'Mệnh lệnh cấp trên ban hành phải được chấp hành nghiêm túc, không được có sai sót.'),
  ('拽', '小朋友不愿走路，一直拽着妈妈的手不放。', 'Xiǎopéngyǒu bù yuàn zǒulù, yīzhí zhuāi zhe māmā de shǒu bù fàng.', 'Đứa bé không muốn đi bộ, cứ kéo tay mẹ không buông.'),
  ('招标', '政府部门对新建桥梁工程进行了公开招标。', 'Zhèngfǔ bùmén duì xīn jiàn qiáoliáng gōngchéng jìnxíngle gōngkāi zhāobiāo.', 'Bộ phận chính phủ đã tiến hành đấu thầu công khai cho công trình xây cầu mới.'),
  ('招收', '这所大学每年招收成千上万的本科生。', 'Zhè suǒ dàxué měinián zhāoshōu chéng qiān shàng wàn de běnkē shēng.', 'Trường đại học này mỗi năm tuyển sinh hàng nghìn sinh viên đại học.'),
  ('拄', '老爷爷拄着拐杖慢慢地走过斑马线。', 'Lǎo yéyé zhǔ zhe guǎizhàng mànman de zǒu guò bānmǎxiàn.', 'Ông lão chống gậy từ tốn đi qua vạch qua đường.'),
  ('折腾', '因为失眠，她整夜在床上折腾得很不舒服。', 'Yīnwèi shīmián, tā zhěng yè zài chuáng shàng zhēteng dé hěn bù shūfú.', 'Vì mất ngủ nên cả đêm cô ấy trằn trọc rất khó chịu.'),
  ('折磨', '长期的疾病折磨让他身心俱疲。', 'Chángqī de jíbìng zhémo ràng tā shēn xīn jù pí.', 'Bệnh tật lâu dài giày vò khiến anh ấy mệt mỏi cả thân tâm.'),
  ('折', '请把这张纸对折成两半，然后再剪开。', 'Qǐng bǎ zhè zhāng zhǐ duìzhé chéng liǎng bàn, ránhòu zài jiǎn kāi.', 'Làm ơn gấp tờ giấy này làm đôi, sau đó cắt ra.'),
  ('执行', '法院决定执行这项判决，确保法律的权威。', 'Fǎyuàn juédìng zhíxíng zhè xiàng pànjué, quèbǎo fǎlǜ de quánwēi.', 'Tòa án quyết định chấp hành bản án này để đảm bảo quyền uy của pháp luật.'),
  ('执着', '他对梦想的执着让人敬佩，从不轻言放弃。', 'Tā duì mèngxiǎng de zhízhuó ràng rén jìngpèi, cóng bù qīng yán fàngqì.', 'Sự cố chấp với ước mơ của anh ấy khiến người ta kính phục, không bao giờ dễ dàng bỏ cuộc.'),
  ('扎实', '他的专业知识非常扎实，得到了老师的高度评价。', 'Tā de zhuānyè zhīshì fēicháng zhāshi, dédàole lǎoshī de gāodù píngjià.', 'Kiến thức chuyên môn của anh ấy rất vững chắc, nhận được đánh giá cao từ giáo viên.'),
  ('扎', '医生用针扎了他的手臂进行抽血检查。', 'Yīshēng yòng zhēn zhāle tā de shǒubì jìnxíng chōuxuè jiǎnchá.', 'Bác sĩ dùng kim chích vào cánh tay anh ấy để xét nghiệm lấy máu.'),
  ('战略', '企业必须制定合理的战略来应对市场竞争。', 'Qǐyè bìxū zhìdìng hélǐ de zhànlüè lái yìngduì shìchǎng jìngzhēng.', 'Doanh nghiệp phải xây dựng chiến lược hợp lý để ứng phó với cạnh tranh thị trường.'),
  ('战术', '教练详细讲解了这场比赛的战术布置。', 'Jiàoliàn xiángxì jiǎngjiěle zhè chǎng bǐsài de zhànshù bùzhì.', 'Huấn luyện viên giải thích chi tiết bố trí chiến thuật của trận đấu này.'),
  ('战斗', '士兵们在前线进行了激烈的战斗，保卫了家园。', 'Shìbīngmen zài qiánxiàn jìnxíngle jīliè de zhàndòu, bǎowèi le jiāyuán.', 'Các chiến sĩ đã tiến hành chiến đấu ác liệt trên tiền tuyến, bảo vệ quê hương.'),
  ('战役', '这次战役是决定战争胜负的关键。', 'Zhè cì zhànyì shì juédìng zhànzhēng shèngfù de guānjiàn.', 'Chiến dịch này là then chốt quyết định thắng bại của chiến tranh.'),
  ('总而言之', '总而言之，我们必须加快步伐，完成既定目标。', 'Zǒng ér yán zhī, wǒmen bìxū jiākuài bùfá, wánchéng jìdìng mùbiāo.', 'Nói tóm lại, chúng ta phải tăng tốc độ để hoàn thành mục tiêu đề ra.'),
  ('总和', '把这些数据的总和计算出来，才能得出准确结果。', 'Bǎ zhèxiē shùjù de zǒnghé jìsuàn chūlái, cáinéng dé chū zhǔnquè jiéguǒ.', 'Phải tính tổng số của những dữ liệu này mới có thể ra kết quả chính xác.'),
  ('忠诚', '他对公司的忠诚赢得了所有同事的尊重。', 'Tā duì gōngsī de zhōngchéng yíngdéle suǒyǒu tóngshì de zūnzhòng.', 'Anh ấy trung thành với công ty nên được mọi đồng nghiệp kính trọng.'),
  ('忠实', '这位作家的报道非常忠实，无法被质疑。', 'Zhè wèi zuòjiā de bàodào fēicháng zhōngshí, wúfǎ bèi zhíyí.', 'Bài báo của nhà văn này rất trung thực, không thể bị nghi ngờ.'),
  ('志气', '年轻人应该有远大的志气，勇敢面对挑战。', 'Niánqīng rén yīnggāi yǒu yuǎndà de zhìqì, yǒnggǎn miànduì tiǎozhàn.', 'Người trẻ nên có chí khí lớn lao, dũng cảm đối mặt thử thách.'),
  ('征服', '攀登珠穆朗玛峰是一项极具挑战性的征服任务。', 'Pāndēng Zhūmùlǎngmǎ fēng shì yī xiàng jí jù tiǎozhàn xìng de zhēngfú rènwù.', 'Chinh phục đỉnh Everest là một nhiệm vụ đầy thử thách.'),
  ('征收', '政府决定对高收入者征收更高的税费。', 'Zhèngfǔ juédìng duì gāo shōurù zhě zhēngshōu gèng gāo de shuìfèi.', 'Chính phủ quyết định trưng thu thuế cao hơn đối với người có thu nhập cao.'),
  ('座右铭', '他的座右铭是“坚持不懈，永不放弃”。', 'Tā de zuòyòumíng shì “jiānchí bùxiè, yǒng bù fàngqì”.', 'Lời răn dạy của anh ấy là “kiên trì không ngừng, không bao giờ bỏ cuộc”.'),
  ('庄重', '婚礼现场布置得非常庄重，气氛感人。', 'Hūnlǐ xiànchǎng bùzhì de fēicháng zhuāngzhòng, qìfēn gǎnrén.', 'Không gian lễ cưới được trang trí rất trang trọng, bầu không khí xúc động.'),
  ('庄稼', '今年庄稼长势良好，农民们非常满意。', 'Jīnnián zhuāngjià zhǎngshì liánghǎo, nóngmín men fēicháng mǎnyì.', 'Hoa màu năm nay phát triển tốt, bà con nông dân rất hài lòng.'),
  ('庄严', '国旗在庄严的仪式中缓缓升起。', 'Guóqí zài zhuāngyán de yíshì zhōng huǎnhuǎn shēng qǐ.', 'Quốc kỳ được nâng lên một cách trang nghiêm trong buổi lễ.'),
  ('幢', '这条街上有三幢高楼大厦林立。', 'Zhè tiáo jiē shàng yǒu sān zhuàng gāolóu dàshà línlì.', 'Trên con phố này có ba tòa nhà cao tầng đứng san sát nhau.'),
  ('帐篷', '我们在山顶搭起帐篷，准备过夜。', 'Wǒmen zài shāndǐng dā qǐ zhàngpéng, zhǔnbèi guòyè.', 'Chúng tôi dựng lều trên đỉnh núi chuẩn bị qua đêm.'),
  ('州', '这个州以美丽的自然风光著称，吸引大量游客。', 'Zhège zhōu yǐ měilì de zìrán fēngguāng zhùchēng, xīyǐn dàliàng yóukè.', 'Châu này nổi tiếng với cảnh đẹp thiên nhiên và thu hút nhiều du khách.'),
  ('崭新', '他买了一辆崭新的汽车，非常激动。', 'Tā mǎile yī liàng zhǎnxīn de qìchē, fēicháng jīdòng.', 'Anh ấy mua một chiếc xe ô tô mới tinh, rất phấn khích.'),
  ('展示', '艺术展上，画家们展示了自己的最新作品。', 'Yìshù zhǎn shàng, huàjiāmen zhǎnshìle zìjǐ de zuìxīn zuòpǐn.', 'Tại triển lãm nghệ thuật, các họa sĩ trưng bày tác phẩm mới nhất của mình.'),
  ('展现', '她的表演完美地展现了角色的复杂情感。', 'Tā de biǎoyǎn wánměi de zhǎnxiànle juésè de fùzá qínggǎn.', 'Buổi biểu diễn của cô ấy hoàn hảo tái hiện cảm xúc phức tạp của nhân vật.'),
  ('展望', '公司对未来的发展充满了美好的展望。', 'Gōngsī duì wèilái de fāzhǎn chōngmǎnle měihǎo de zhǎnwàng.', 'Công ty đầy hy vọng về triển vọng phát triển trong tương lai.'),
  ('尊严', '每个人都应该得到基本的尊严和尊重。', 'Měi gèrén dōu yīnggāi dédào jīběn de zūnyán hé zūnzhòng.', 'Mỗi người đều nên được hưởng phẩm giá và sự tôn trọng cơ bản.'),
  ('宰', '农场主准备宰几头牛供应市场需求。', 'Nóngchǎng zhǔ zhǔnbèi zǎi jǐ tóu niú gōngyìng shìchǎng xūqiú.', 'Chủ trang trại chuẩn bị giết vài con bò để cung cấp cho thị trường.'),
  ('宗旨', '这个组织的宗旨是促进国际间的友好合作。', 'Zhège zǔzhī de zōngzhǐ shì cùjìn guójì jiān de yǒuhǎo hézuò.', 'Tôn chỉ của tổ chức này là thúc đẩy hợp tác hữu nghị quốc tế.'),
  ('宗教', '宗教信仰在不同文化中扮演着重要角色。', 'Zōngjiào xìnyǎng zài bùtóng wénhuà zhōng bànyǎn zhe zhòngyào juésè.', 'Đức tin tôn giáo đóng vai trò quan trọng trong các nền văn hóa khác nhau.'),
  ('子弹', '警方在现场找到数发未发射的子弹作为证据。', 'Jǐngfāng zài xiànchǎng zhǎodào shù fā wèi fāshè de zǐdàn zuòwéi zhèngjù.', 'Cảnh sát đã tìm thấy nhiều viên đạn chưa bắn tại hiện trường làm bằng chứng.'),
  ('姿态', '她在舞台上的优雅姿态赢得了观众的赞赏。', 'Tā zài wǔtái shàng de yōuyǎ zītài yíngdé le guānzhòng de zànshǎng.', 'Tư thế uyển chuyển của cô ấy trên sân khấu đã giành được sự ngưỡng mộ của khán giả.'),
  ('壮观', '秋天的黄山景色真是壮观，让人流连忘返。', 'Qiūtiān de Huángshān jǐngsè zhēn shì zhuàngguān, ràng rén liúliánwàngfǎn.', 'Khung cảnh mùa thu ở Hoàng Sơn thật đồ sộ, khiến người ta lưu luyến không muốn rời.'),
  ('壮烈', '烈士们为了国家献出了生命，精神十分壮烈。', 'Lièshì men wèile guójiā xiànchū le shēngmìng, jīngshén shífēn zhuàngliè.', 'Các liệt sĩ đã hy sinh vì đất nước, tinh thần rất lừng lẫy.'),
  ('壮丽', '这座古老建筑的外观非常壮丽，吸引了众多游客。', 'Zhè zuò gǔlǎo jiànzhù de wàiguān fēicháng zhuànglì, xīyǐn le zhòngduō yóukè.', 'Ngoại quan của tòa kiến trúc cổ này rất tráng lệ, thu hút rất nhiều du khách.'),
  ('增添', '新装修的客厅为家里增添了更多的温馨和舒适。', 'Xīn zhuāngxiū de kètīng wèi jiālǐ zēngtiān le gèng duō de wēnxīn hé shūshì.', 'Phòng khách mới được trang trí làm tăng thêm sự ấm cúng và thoải mái cho ngôi nhà.'),
  ('坠', '树枝因为大雪的重量而逐渐坠了下来。', 'Shùzhī yīnwèi dàxuě de zhòngliàng ér zhújiàn zhuì le xiàlái.', 'Nhánh cây từ từ trĩu xuống vì trọng lượng của tuyết lớn.'),
  ('在意', '他很在意别人对他的评价，总是力求做到完美。', 'Tā hěn zàiyì biérén duì tā de píngjià, zǒng shì lìqiú zuò dào wánměi.', 'Anh ấy rất để ý đến đánh giá của người khác về mình, luôn cố gắng hoàn hảo.'),
  ('噪音', '施工现场的噪音影响了附近居民的正常生活。', 'Shīgōng xiànchǎng de zàoyīn yǐngxiǎng le fùjìn jūmín de zhèngcháng shēnghuó.', 'Tiếng ồn ở công trường xây dựng đã làm ảnh hưởng đến cuộc sống bình thường của cư dân lân cận.'),
  ('嘴唇', '他的嘴唇因为寒风而冻得发紫。', 'Tā de zuǐchún yīnwèi hánfēng ér dòng de fā zǐ.', 'Môi anh ấy tím tái vì gió lạnh.'),
  ('嘱咐', '妈妈临走时嘱咐我一定要按时吃饭照顾好自己。', 'Māmā lín zǒu shí zhǔfù wǒ yídìng yào ànshí chīfàn zhàogù hǎo zìjǐ.', 'Mẹ dặn dò tôi phải ăn uống đúng giờ và tự chăm sóc bản thân khi mẹ đi.'),
  ('咋', '你咋不早告诉我这个消息，让我准备一下？', 'Nǐ zǎ bù zǎo gàosù wǒ zhège xiāoxi, ràng wǒ zhǔnbèi yíxià?', 'Sao cậu không nói cho tôi tin này sớm để tôi chuẩn bị?'),
  ('周边', '这家饭店位置优越，周边配套设施齐全。', 'Zhè jiā fàndiàn wèizhì yōuyuè, zhōubiān pèitào shèshī qíquán.', 'Nhà hàng này có vị trí thuận lợi, các tiện ích xung quanh rất đầy đủ.'),
  ('周转', '公司资金周转出现问题，影响了正常运营。', 'Gōngsī zījīn zhōuzhuǎn chūxiàn wèntí, yǐngxiǎng le zhèngcháng yùnyíng.', 'Vấn đề về việc quay vòng vốn của công ty đã ảnh hưởng đến hoạt động bình thường.'),
  ('周期', '产品的开发周期一般需要几个月的时间。', 'Chǎnpǐn de kāifā zhōuqī yìbān xūyào jǐ gè yuè de shíjiān.', 'Chu kỳ phát triển sản phẩm thường cần vài tháng.'),
  ('周折', '虽然经历了许多周折，他最终还是完成了目标。', 'Suīrán jīnglì le xǔduō zhōuzhé, tā zuìzhōng háishì wánchéng le mùbiāo.', 'Dù trải qua nhiều trắc trở, cuối cùng anh ấy vẫn hoàn thành được mục tiêu.'),
  ('周年', '公司庆祝成立十周年，举办了盛大的庆典活动。', 'Gōngsī qìngzhù chénglì shí zhōunián, jǔbàn le shèngdà de qìngdiǎn huódòng.', 'Công ty tổ chức kỷ niệm 10 năm thành lập với các hoạt động lễ lớn.'),
  ('周密', '他为比赛制定了周密的计划，没有遗漏任何细节。', 'Tā wèi bǐsài zhìdìng le zhōumì de jìhuà, méiyǒu yílòu rènhé xìjié.', 'Anh ấy đã lập kế hoạch chặt chẽ cho cuộc thi, không bỏ sót bất kỳ chi tiết nào.'),
  ('占领', '敌军成功占领了关键的高地，改变了战局。', 'Dí jūn chénggōng zhànlǐng le guānjiàn de gāodì, gǎibiàn le zhànjú.', 'Quân địch đã chiếm lĩnh thành công vùng cao quan trọng, thay đổi cục diện chiến tranh.'),
  ('占据', '这家公司占据了市场的大部分份额，具有领先优势。', 'Zhè jiā gōngsī zhànjù le shìchǎng de dà bùfèn fèn''é, jùyǒu lǐngxiān yōushì.', 'Công ty này chiếm phần lớn thị trường và có ưu thế dẫn đầu.'),
  ('卓越', '他的表现非常卓越，获得了领导的高度评价。', 'Tā de biǎoxiàn fēicháng zhuóyuè, huòdéle lǐngdǎo de gāodù píngjià.', 'Anh ấy thể hiện rất lỗi lạc, nhận được đánh giá cao từ lãnh đạo.'),
  ('助理', '她是经理的助理，负责处理日常事务和协调工作。', 'Tā shì jīnglǐ de zhùlǐ, fùzé chǔlǐ rìcháng shìwù hé xiétiáo gōngzuò.', 'Cô ấy là trợ lý của giám đốc, chịu trách nhiệm xử lý các công việc hàng ngày và phối hợp công việc.'),
  ('助手', '在这次手术中，医生的助手发挥了重要作用。', 'Zài zhè cì shǒushù zhōng, yīshēng de zhùshǒu fāhuīle zhòngyào zuòyòng.', 'Trong ca phẫu thuật này, trợ thủ của bác sĩ đã phát huy vai trò quan trọng.'),
  ('制裁', '国际社会对该国实施了经济制裁以促使其改变政策。', 'Guójì shèhuì duì gāi guó shíshīle jīngjì zhìcái yǐ cùshǐ qí gǎibiàn zhèngcè.', 'Cộng đồng quốc tế đã áp dụng biện pháp trừng phạt kinh tế với quốc gia đó để thúc đẩy thay đổi chính sách.'),
  ('制约', '资源的不足制约了企业的发展速度。', 'Zīyuán de bùzú zhìyuēle qǐyè de fāzhǎn sùdù.', 'Sự thiếu hụt nguồn lực đã kìm hãm tốc độ phát triển của doanh nghiệp.'),
  ('制止', '警方成功制止了这场可能发生的骚乱。', 'Jǐngfāng chénggōng zhìzhǐle zhè chǎng kěnéng fāshēng de sāoluàn.', 'Cảnh sát đã thành công trong việc ngăn chặn cuộc bạo loạn có thể xảy ra này.'),
  ('制服', '工厂的员工都穿着统一的制服，显得很整齐。', 'Gōngchǎng de yuángōng dōu chuānzhuó tǒngyī de zhìfú, xiǎnde hěn zhěngqí.', 'Nhân viên nhà máy đều mặc đồng phục thống nhất, trông rất chỉnh tề.'),
  ('准则', '诚信是我们企业经营的基本准则。', 'Chéngxìn shì wǒmen qǐyè jīngyíng de jīběn zhǔnzé.', 'Chính trực là chuẩn mực cơ bản trong kinh doanh của công ty chúng tôi.'),
  ('再接再厉', '取得进步后，他决定再接再厉，争取更大成功。', 'Qǔdé jìnbù hòu, tā juédìng zàijiēzàilì, zhēngqǔ gèng dà chénggōng.', 'Sau khi đạt được tiến bộ, anh ấy quyết định không ngừng cố gắng để giành được thành công lớn hơn.'),
  ('值班', '夜班医生需要24小时值班，确保患者安全。', 'Yèbān yīshēng xūyào 24 xiǎoshí zhíbān, quèbǎo huànzhě ānquán.', 'Bác sĩ ca đêm cần trực ban 24 giờ để đảm bảo an toàn cho bệnh nhân.'),
  ('债券', '投资者购买政府债券以获得稳定的收益。', 'Tóuzī zhě gòumǎi zhèngfǔ zhàiquàn yǐ huòdé wěndìng de shōuyì.', 'Nhà đầu tư mua công trái của chính phủ để có thu nhập ổn định.'),
  ('侦探', '那位侦探通过细致调查成功破获了案件。', 'Nà wèi zhēntàn tōngguò xìzhì diàochá chénggōng pòhuòle ànjiàn.', 'Thám tử ấy đã phá án thành công thông qua điều tra tỉ mỉ.'),
  ('侄子', '我的侄子今年刚刚上小学，学习很努力。', 'Wǒ de zhízǐ jīnnián gānggāng shàng xiǎoxué, xuéxí hěn nǔlì.', 'Cháu trai tôi năm nay vừa mới vào học tiểu học, học rất chăm chỉ.'),
  ('作风', '公司领导注重培养员工的务实作风和团队精神。', 'Gōngsī lǐngdǎo zhùzhòng péiyǎng yuángōng de wùshí zuòfēng hé tuánduì jīngshén.', 'Lãnh đạo công ty chú trọng rèn luyện tác phong thực tế và tinh thần đồng đội cho nhân viên.'),
  ('作息', '保持规律的作息时间有助于提高工作效率。', 'Bǎochí guīlǜ de zuòxí shíjiān yǒuzhù yú tígāo gōngzuò xiàolǜ.', 'Duy trì thời gian làm việc và nghỉ ngơi đều đặn giúp nâng cao hiệu quả công việc.'),
  ('作弊', '考试中发现有人作弊，学校依法处理了此事。', 'Kǎoshì zhōng fāxiàn yǒu rén zuòbì, xuéxiào yīfǎ chǔlǐle cǐ shì.', 'Trong kỳ thi phát hiện người gian lận, nhà trường đã xử lý theo pháp luật.'),
  ('作废', '过期的优惠券将自动作废，无法再使用。', 'Guòqī de yōuhuìquàn jiāng zìdòng zuòfèi, wúfǎ zài shǐyòng.', 'Phiếu ưu đãi hết hạn sẽ tự động bị hủy, không thể dùng nữa.'),
  ('住宅', '他们刚买了一套新住宅，准备搬进去生活。', 'Tāmen gāng mǎile yī tào xīn zhùzhái, zhǔnbèi bān jìnqù shēnghuó.', 'Họ vừa mua một căn nhà mới để chuẩn bị chuyển vào sống.'),
  ('传记', '这本传记详细记录了科学家的成长经历和贡献。', 'Zhè běn zhuànjì xiángxì jìlùle kēxuéjiā de chéngzhǎng jīnglì hé gòngxiàn.', 'Cuốn truyện ký này ghi chép chi tiết quá trình trưởng thành và đóng góp của nhà khoa học.'),
  ('众所周知', '众所周知，健康饮食对保持身体非常重要。', 'Zhòngsuǒ zhōuzhī, jiànkāng yǐnshí duì bǎochí shēntǐ fēicháng zhòngyào.', 'Mọi người đều biết rằng chế độ ăn uống lành mạnh rất quan trọng để giữ gìn sức khỏe.'),
  ('争议', '这个计划引起了公众的激烈争议。', 'Zhège jìhuà yǐnqǐle gōngzhòng de jīliè zhēngyì.', 'Kế hoạch này đã gây ra tranh luận kịch liệt trong công chúng.'),
  ('争端', '两国由于边界问题爆发了严重争端。', 'Liǎng guó yóuyú biānjiè wèntí bàofāle yánzhòng zhēngduān.', 'Hai nước bùng phát tranh chấp nghiêm trọng vì vấn đề biên giới.'),
  ('争气', '他努力学习，希望能在比赛中争气。', 'Tā nǔlì xuéxí, xīwàng néng zài bǐsài zhōng zhēngqì.', 'Anh ấy cố gắng học tập, hy vọng có thể không chịu thua kém trong cuộc thi.'),
  ('争夺', '多家公司正在争夺这份重要合同。', 'Duō jiā gōngsī zhèngzài zhēngduó zhè fèn zhòngyào hétóng.', 'Nhiều công ty đang tranh đoạt hợp đồng quan trọng này.'),
  ('争先恐后', '学生们争先恐后地报名参加志愿活动。', 'Xuéshēngmen zhēngxiān kǒnghòu de bàomíng cānjiā zhìyuàn huódòng.', 'Các học sinh tranh lên trước, sợ bị chậm chễ mà đăng ký tham gia hoạt động tình nguyện.'),
  ('之际', '在毕业之际，他感慨万分。', 'Zài bìyè zhī jì, tā gǎnkǎi wànfēn.', 'Trong hoàn cảnh tốt nghiệp, anh ấy rất xúc động.'),
  ('主管', '他是公司的主管，负责项目管理。', 'Tā shì gōngsī de zhǔguǎn, fùzé xiàngmù guǎnlǐ.', 'Anh ấy là chủ quản của công ty, chịu trách nhiệm quản lý dự án.'),
  ('主流', '这种思想已经成为社会的主流观点。', 'Zhè zhǒng sīxiǎng yǐjīng chéngwéi shèhuì de zhǔliú guāndiǎn.', 'Tư tưởng này đã trở thành xu hướng chính của xã hội.'),
  ('主权', '维护国家主权是每个公民的责任。', 'Wéihù guójiā zhǔquán shì měi gè gōngmín de zérèn.', 'Bảo vệ chủ quyền quốc gia là trách nhiệm của mỗi công dân.'),
  ('主导', '技术创新在公司的发展中起主导作用。', 'Jìshù chuàngxīn zài gōngsī de fāzhǎn zhōng qǐ zhǔdǎo zuòyòng.', 'Đổi mới công nghệ đóng vai trò chủ đạo trong sự phát triển của công ty.'),
  ('主办', '这次音乐节由市政府主办，每年举办一次。', 'Zhè cì yīnyuè jié yóu shìzhèngfǔ zhǔbàn, měi nián jǔbàn yícì.', 'Liên hoan âm nhạc lần này do chính quyền thành phố đăng cai, tổ chức một lần mỗi năm.'),
  ('主义', '自由主义强调个人的权利和自由。', 'Zìyóu zhǔyì qiángdiào gèrén de quánlì hé zìyóu.', 'Chủ nghĩa tự do nhấn mạnh quyền lợi và tự do của cá nhân.'),
  ('中立', '在这场争论中，她选择保持中立态度。', 'Zài zhè chǎng zhēnglùn zhōng, tā xuǎnzé bǎochí zhōnglì tàidù.', 'Trong cuộc tranh luận này, cô ấy lựa chọn giữ thái độ trung lập.'),
  ('中断', '由于恶劣天气，航班被中断了几个小时。', 'Yóuyú èliè tiānqì, hángbān bèi zhōngduànle jǐ gè xiǎoshí.', 'Do thời tiết xấu, các chuyến bay đã bị ngắt quãng vài tiếng đồng hồ.'),
  ('做主', '重要决定需要经理来做主。', 'Zhòngyào juédìng xūyào jīnglǐ lái zuò zhǔ.', 'Quyết định quan trọng cần người quản lý làm chủ.'),
  ('中央', '中央政府宣布了新的经济政策。', 'Zhōngyāng zhèngfǔ xuānbùle xīn de jīngjì zhèngcè.', 'Chính quyền trung ương đã công bố chính sách kinh tế mới.'),
  ('专题', '本期杂志设有环保专题栏目。', 'Běn qī zázhì shè yǒu huánbǎo zhuāntí lánmù.', 'Tạp chí kỳ này có chuyên đề về bảo vệ môi trường.'),
  ('专长', '他的专长是编程和软件开发。', 'Tā de zhuāncháng shì biānchéng hé ruǎnjiàn kāifā.', 'Chuyên môn của anh ấy là lập trình và phát triển phần mềm.'),
  ('专程', '她专程从外地赶来参加婚礼。', 'Tā zhuānchéng cóng wàidì gǎnlái cānjiā hūnlǐ.', 'Cô ấy đặc biệt từ tỉnh khác đến dự đám cưới.'),
  ('专利', '这项发明已经申请了国际专利保护。', 'Zhè xiàng fāmíng yǐjīng shēnqǐngle guójì zhuānlì bǎohù.', 'Phát minh này đã đăng ký bảo hộ bằng sáng chế quốc tế.')
),
updated_template_cards as (
  update public.template_cards as card
  set
    example_cn = coalesce(nullif(btrim(card.example_cn), ''), example.example_cn),
    example_pinyin = coalesce(nullif(btrim(card.example_pinyin), ''), example.example_pinyin),
    example_vi = coalesce(nullif(btrim(card.example_vi), ''), example.example_vi)
  from public.template_decks as deck,
    hsk6_example_backfill as example
  where card.template_deck_id = deck.id
    and deck.slug = 'hsk6-co-ban'
    and card.chinese = example.chinese
    and (
      nullif(btrim(card.example_cn), '') is null
      or nullif(btrim(card.example_pinyin), '') is null
      or nullif(btrim(card.example_vi), '') is null
    )
  returning card.id
)
update public.cards as card
set
  example_cn = coalesce(nullif(btrim(card.example_cn), ''), example.example_cn),
  example_pinyin = coalesce(nullif(btrim(card.example_pinyin), ''), example.example_pinyin),
  example_vi = coalesce(nullif(btrim(card.example_vi), ''), example.example_vi)
from public.decks as deck,
  hsk6_example_backfill as example
where card.deck_id = deck.id
  and card.user_id = deck.user_id
  and (
    deck.source_template_slug = 'hsk6-co-ban'
    or (deck.source_template_slug is null and deck.name = 'HSK6 cơ bản')
  )
  and card.chinese = example.chinese
  and (
    nullif(btrim(card.example_cn), '') is null
    or nullif(btrim(card.example_pinyin), '') is null
    or nullif(btrim(card.example_vi), '') is null
  );
